# ── Regex for correction by time-reference (catches "22:03分發送給我的天氣內容") ──
_CORRECTION_TIME_REF_RE = re.compile(
    r"(?:\d{1,2}[：:]\d{2}|昨天|剛才|剛剛|前面|上次|之前|早上|晚上|下午)"
    r"[分點時]?"
    r".*(?:發送|推送|推播|通知|傳送|送出|發的|推的|送的|傳的)"
    r".*(?:內容|訊息|消息|東西|那個|部分)",
    re.DOTALL,
)
_CORRECTION_QUESTION_RE = re.compile(
    r"(?:你|妳|你們|系統)"
    r".*(?:推送|推播|發送|通知|傳送)"
    r".*(?:前|之前|時)"
    r".*(?:沒有|沒|不會|不用)?"
    r".*(?:確認|檢查|驗證|核實)",
    re.DOTALL,
)
# Generic complaint: system action + negative qualifier (or vice versa)
_CORRECTION_GENERIC_COMPLAINT_RE = re.compile(
    r"(?:"
    # P1: complaint modifier + system action
    r"(?:一直|又|怎麼|为什么|為什麼|為何|幹嘛|干嘛)"
    r".{0,6}(?:推播|推送|發送|发送|通知)"
    r"|"
    # P2: system-action content + negative qualifier
    r"(?:推播|推送|發送|发送|通知)"
    r".{0,8}(?:奇怪|不對|不对|不太對|不太对|亂|乱|怪怪|有問題|有问题|錯了|錯誤|错了|错误|莫名其妙|不需要|不想要)"
    r"|"
    # P3: negative qualifier + system-action content
    r"(?:奇怪|莫名其妙|亂七八糟|乱七八糟)"
    r".{0,6}(?:推播|推送|發送|发送|通知|內容|内容)"
    r"|"
    # P4: keep receiving unwanted
    r"(?:一直收到|一直跳出|一直彈出|一直弹出)"
    r".{0,6}(?:推播|推送|通知|訊息|消息)"
    r")",
)
_CORRECTION_CONTENT_CLARIFY_RE = re.compile(
    r"(?:"
    r"(?:不清楚|不記得|记不得|想不起來|想不起来|不知道)"
    r".{0,16}(?:內容|哪句|那句|哪段|那段|剛才|刚才|剛剛|刚刚|前面|你發的|妳發的|推播的|推送的|訊息|消息)"
    r".{0,16}(?:提醒|提一下|再說一次|再说一次|說清楚|说清楚|講清楚|讲清楚|具體|具体)"
    r"|"
    r"(?:提醒|提一下|再說一次|再说一次|說清楚|说清楚|講清楚|讲清楚|具體|具体)"
    r".{0,16}(?:內容|哪句|那句|哪段|那段|剛才|刚才|剛剛|刚刚|前面|你發的|妳發的|推播的|推送的|訊息|消息)"
    r")",
    re.DOTALL,
)
_CORRECTION_INTERNAL_TOKEN_RE = re.compile(
    r"(?:wake-seed|HEARTBEAT(?:\.md|_OK)?|memory_class|followup_state|incident_type|hook_type|session_key)",
    re.I,
)
_CONTENT_TASK_ACTION_RE = re.compile(
    r"(?:想|要|準備|打算|等等要|等等想|待會要|待会要|等下要|稍後要|稍后要)"
    r".{0,16}(?:post|po文|po|發文|发文|發貼文|发贴文|寫|写|整理|補|补|做)"
    r".{0,18}(?:內容|内容|文案|標題|标题|貼文|贴文|文章|稿|主題|主题|那篇)",
    re.I,
)
_CONTENT_TASK_CONTEXT_RE = re.compile(
    r"(?:上次|之前|先前)"
    r".{0,16}(?:想好|想過|想过|提過|提过|說過|说过|留過|留过)"
    r".{0,16}(?:標題|标题|內容|内容|文案|主題|主题)"
    r"|(?:去翻|翻一下|查一下|回去翻)"
    r".{0,12}(?:記憶|记忆|紀錄|记录)"
    r"|(?:還記得|还记得).{0,8}(?:標題|标题|內容|内容|那篇|那個|那个)",
    re.I,
)


def match_phrase_family(text: str) -> Optional[dict]:
    """Match text against PHRASE_FAMILIES. Returns family info dict or None.
    Checks all families, returns the first match with longest matched phrase."""
    if not text:
        return None
    best_match = None
    best_len = 0
    lowered = text.lower()
    for family_name, family in PHRASE_FAMILIES.items():
        for phrase in family["phrases"]:
            phrase_match = phrase in text
            if not phrase_match and any("a" <= ch.lower() <= "z" for ch in phrase):
                phrase_match = phrase.lower() in lowered
            if phrase_match and len(phrase) > best_len:
                best_match = {
                    "family": family_name,
                    "matched_phrase": phrase,
                    "state": family["state"],
                    "event_kind": family["event_kind"],
                    "open_loop": family["open_loop"],
                    "followup_focus_code": family["followup_focus_code"],
                    "signal_type": family["signal_type"],
                    "can_silent_expire": family["can_silent_expire"],
                    "staging_ttl_hours": family.get("staging_ttl_hours", 36),
                }
                best_len = len(phrase)
    return best_match

