def looks_like_continuity_pollution_text(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    if looks_like_internal_control_text(raw):
        return True
    if looks_like_internal_summary_residue(raw):
        return True
    return any(pattern.search(raw) for pattern in CONTINUITY_POLLUTION_PATTERNS)

