# Default delay (hours) when no specific timeline is implied by the commitment
MODEL_COMMITMENT_DEFAULT_DELAY_HOURS = 4

# Mapping from commitment keywords to implied delay in hours
MODEL_COMMITMENT_DELAY_MAP = {
    "稍後處理": 2,
    "稍后处理": 2,
    "commitment_deferred": 2,
    "承諾下次": 24,
    "承诺下次": 24,
    "commitment_next_time": 24,
    "承諾排程": 12,
    "承诺排程": 12,
    "commitment_schedule": 12,
    "承諾提醒": 6,
    "承诺提醒": 6,
    "commitment_remind": 6,
}


def detect_model_commitments(text: str) -> list:
    """Scan model output text for self-commitment patterns.

    A-bucket addition: returns a list of dicts, each with:
      - pattern: the regex that matched
      - label: semantic label for the commitment
      - matched_text: the actual text fragment that matched
      - action_context: up to 60 chars of surrounding context
    """
    if not text or not isinstance(text, str):
        return []
    results = []
    seen_labels = set()
    for pattern, label in MODEL_COMMITMENT_PATTERNS:
        m = re.search(pattern, text)
        if m and label not in seen_labels:
            seen_labels.add(label)
            start = max(0, m.start() - 15)
            end = min(len(text), m.end() + 45)
            results.append({
                "pattern": pattern,
                "label": label,
                "matched_text": m.group(0),
                "action_context": text[start:end].strip(),
            })
    return results


def create_commitment_hooks(hook_store: dict, commitments: list, now_dt: Optional[datetime] = None) -> list:
    """Create self_commitment_followup hooks for detected model commitments.

    A-bucket addition: deduplicates against existing pending hooks with the
    same source_summary. Returns list of newly created hooks.
    """
    if not commitments:
        return []
    now_dt = now_dt or now_local()
    created = []
    existing_summaries = {
        h.get("source_summary")
        for h in hook_store.get("hooks", [])
        if h.get("status") == "pending" and h.get("type") == "self_commitment_followup"
    }
    for commitment in commitments:
        summary = f"[model-commitment] {commitment['action_context']}"
        if summary in existing_summaries:
            continue
        delay_hours = MODEL_COMMITMENT_DELAY_MAP.get(
            commitment["label"],
            MODEL_COMMITMENT_DEFAULT_DELAY_HOURS,
        )
        trigger_dt = now_dt + timedelta(hours=delay_hours)
        hook = build_hook(
            "self_commitment_followup",
            trigger_dt,
            summary,
            payload={
                "commitment_label": commitment["label"],
                "matched_text": commitment["matched_text"],
                "delay_hours": delay_hours,
                "source": "model_self_commitment",
            },
            note=f"Auto-detected model commitment: {commitment['label']}",
        )
        hook_store.setdefault("hooks", []).append(hook)
        existing_summaries.add(summary)
        created.append(hook)
    return created


# ---------------------------------------------------------------------------
# A-bucket: Recurring task mechanism
# Periodic scheduled tasks checked on every heartbeat tick.
# ---------------------------------------------------------------------------
RECURRING_TASK_DEFAULTS = {
    "id": "",
    "description": "",
    "frequency": "daily",  # "daily" | "weekly" | "every_N_hours"
    "frequency_value": 24,  # hours for every_N_hours; 1 for daily; 7 for weekly
    "active": True,
    "last_completed_at": None,
    "next_due_at": None,
    "action_type": "reminder",
    "action_params": {},
}


def load_recurring_tasks() -> list:
    if RECURRING_TASKS_PATH.exists():
        with open(RECURRING_TASKS_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                return data.get("tasks", [])
            return data if isinstance(data, list) else []
    return []


def save_recurring_tasks(tasks: list) -> None:
    RECURRING_TASKS_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(RECURRING_TASKS_PATH, "w", encoding="utf-8") as f:
        json.dump(tasks, f, ensure_ascii=False, indent=2)


def _calc_next_due(task: dict, from_dt: datetime) -> str:
    freq = task.get("frequency", "daily")
    val = task.get("frequency_value", 24)
    if freq == "daily":
        nxt = from_dt + timedelta(hours=24)
    elif freq == "weekly":
        nxt = from_dt + timedelta(days=7)
    elif freq == "every_N_hours":
        nxt = from_dt + timedelta(hours=val)
    else:
        nxt = from_dt + timedelta(hours=24)
    return nxt.isoformat(timespec="seconds")


def check_recurring_tasks(now_dt: datetime) -> list:
    """Return list of overdue recurring tasks. Creates hooks if needed."""
    tasks = load_recurring_tasks()
    hook_store = load_hooks()
    overdue = []
    existing_task_ids = {
        h.get("payload", {}).get("recurring_task_id")
        for h in hook_store.get("hooks", [])
        if h.get("status") == "pending" and h.get("type") == "recurring_task_reminder"
    }
    changed = False
    for task in tasks:
        if not task.get("active", True):
            continue
        due_at = task.get("next_due_at")
        if due_at is None:
            # First run: set initial due time
            task["next_due_at"] = _calc_next_due(task, now_dt)
            changed = True
            continue
        try:
            due_dt = datetime.fromisoformat(due_at)
        except (ValueError, TypeError):
            continue
        if now_dt >= due_dt:
            overdue.append(task)
            if task["id"] not in existing_task_ids:
                hook = build_hook(
                    "recurring_task_reminder",
                    now_dt,
                    f"[recurring-task] {task.get('description', task['id'])}",
                    payload={
                        "recurring_task_id": task["id"],
                        "frequency": task.get("frequency"),
                        "action_type": task.get("action_type"),
                        "action_params": task.get("action_params", {}),
                        "source": "recurring_task",
                    },
                    note=f"Recurring task overdue: {task.get('description', task['id'])}",
                )
                hook_store.setdefault("hooks", []).append(hook)
                existing_task_ids.add(task["id"])
                changed = True
    if changed:
        save_recurring_tasks(tasks)
        save_hooks(hook_store)
    return overdue


def complete_recurring_task(task_id: str, now_dt: datetime) -> Optional[dict]:
    """Mark a recurring task as completed and calculate next_due_at."""
    tasks = load_recurring_tasks()
    target = None
    for task in tasks:
        if task["id"] == task_id:
            target = task
            break
    if target is None:
        return None
    target["last_completed_at"] = now_dt.isoformat(timespec="seconds")
    target["next_due_at"] = _calc_next_due(target, now_dt)
    save_recurring_tasks(tasks)
    return target


# ---------------------------------------------------------------------------
# A-bucket: Post-action rules mechanism
# Rules triggered after model produces output/files.
# ---------------------------------------------------------------------------
def load_post_action_rules() -> list:
    if POST_ACTION_RULES_PATH.exists():
        with open(POST_ACTION_RULES_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                return data.get("rules", [])
            return data if isinstance(data, list) else []
    return []


def save_post_action_rules(rules: list) -> None:
    POST_ACTION_RULES_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(POST_ACTION_RULES_PATH, "w", encoding="utf-8") as f:
        json.dump(rules, f, ensure_ascii=False, indent=2)


def check_post_action_rules(file_path: str, trigger_type: str, now_dt: datetime) -> list:
    """Return matching post-action rules and their actions for a given file/trigger."""
    import fnmatch
    rules = load_post_action_rules()
    matched = []
    for rule in rules:
        if not rule.get("active", True):
            continue
        if rule.get("trigger") != trigger_type:
            continue
        condition_glob = rule.get("condition_glob", "*")
        basename = Path(file_path).name if file_path else ""
        if fnmatch.fnmatch(basename, condition_glob):
            matched.append({
                "rule_id": rule["id"],
                "trigger": rule["trigger"],
                "condition_glob": condition_glob,
                "actions": rule.get("actions", []),
                "file_path": file_path,
                "checked_at": now_dt.isoformat(timespec="seconds"),
            })
    return matched


