# A-bucket: Behavioral constraint mechanism
# Pre-action constraints the model must check before acting.
# ---------------------------------------------------------------------------
def load_behavioral_constraints() -> list:
    if BEHAVIORAL_CONSTRAINTS_PATH.exists():
        with open(BEHAVIORAL_CONSTRAINTS_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                return data.get("constraints", [])
            return data if isinstance(data, list) else []
    return []


def save_behavioral_constraints(constraints: list) -> None:
    BEHAVIORAL_CONSTRAINTS_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(BEHAVIORAL_CONSTRAINTS_PATH, "w", encoding="utf-8") as f:
        json.dump(constraints, f, ensure_ascii=False, indent=2)


def check_behavioral_constraints(action_type: str, context: dict, now_dt: datetime) -> list:
    """Check all active behavioral constraints for a given action.

    Returns list of dicts with constraint info and whether satisfied.
    """
    constraints = load_behavioral_constraints()
    results = []
    for c in constraints:
        if not c.get("active", True):
            continue
        scope = c.get("scope", "")
        if scope and scope != action_type:
            continue
        satisfied = True
        violation_detail = ""
        ctype = c.get("type", "")
        check_params = c.get("check_params", {})
        if ctype == "limit":
            for key, max_val in check_params.items():
                actual = context.get(key)
                if actual is not None and isinstance(actual, (int, float)) and actual > max_val:
                    satisfied = False
                    violation_detail = f"{key}={actual} exceeds max {max_val}"
        elif ctype == "prohibition":
            for key in check_params:
                if context.get(key):
                    satisfied = False
                    violation_detail = f"prohibited action: {key}"
        elif ctype == "requirement":
            for key, required_val in check_params.items():
                if context.get(key) != required_val:
                    satisfied = False
                    violation_detail = f"{key} must be {required_val}, got {context.get(key)}"
        results.append({
            "constraint_id": c["id"],
            "description": c.get("description", ""),
            "type": ctype,
            "scope": scope,
            "rule": c.get("rule", ""),
            "satisfied": satisfied,
            "violation_detail": violation_detail,
            "violation_action": c.get("violation_action", "warn"),
            "checked_at": now_dt.isoformat(timespec="seconds"),
        })
    return results


def now_local() -> datetime:
    return datetime.now().astimezone()


def iso_now() -> str:
    return now_local().isoformat(timespec="seconds")


def parse_dt(value: str) -> datetime:
    normalized = value.strip()
    if normalized.endswith("Z"):
        normalized = normalized[:-1] + "+00:00"
    dt = datetime.fromisoformat(normalized)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=now_local().tzinfo)
    return dt


def merge_defaults(default, data):
    if isinstance(default, dict):
        merged = {}
        source = data if isinstance(data, dict) else {}
        for key, value in default.items():
            merged[key] = merge_defaults(value, source.get(key))
        for key, value in source.items():
            if key not in merged:
                merged[key] = value
        return merged
    if isinstance(default, list):
        return data if isinstance(data, list) else deepcopy(default)
    return data if data is not None else deepcopy(default)


def ensure_store() -> None:
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    defaults = {
        SETTINGS_PATH: DEFAULT_SETTINGS,
        PROFILE_PATH: DEFAULT_PROFILE,
        HOOKS_PATH: DEFAULT_HOOKS,
        INCIDENTS_PATH: DEFAULT_INCIDENTS,
        EMOTION_STATE_PATH: DEFAULT_EMOTION_STATE,
        PERSONA_STATE_PATH: DEFAULT_PERSONA_STATE,
        MEMORY_RANK_PATH: DEFAULT_MEMORY_RANK,
        AUTONOMY_STATE_PATH: DEFAULT_AUTONOMY_STATE,
        USER_MODEL_PATH: DEFAULT_USER_MODEL,
        CANDIDATE_BUFFER_PATH: DEFAULT_CANDIDATE_BUFFER,
        TIME_STATE_PATH: {},
    }
    for path, default in defaults.items():
        if not path.exists():
            path.write_text(json.dumps(default, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")


def ensure_parent(path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)


def resolve_env_vars(value: str) -> str:
    raw = str(value or "")
    return re.sub(r"\$\{([^}]+)\}", lambda match: os.environ.get(match.group(1), ""), raw)


def load_json(path: Path, default: dict) -> dict:
    ensure_store()
    if not path.exists():
        return deepcopy(default)
    loaded = json.loads(path.read_text(encoding="utf-8"))
    return merge_defaults(default, loaded)


def save_json(path: Path, data: dict) -> None:
    ensure_parent(path)
    payload = json.dumps(data, ensure_ascii=False, indent=2) + "\n"
    with tempfile.NamedTemporaryFile("w", encoding="utf-8", dir=str(path.parent), prefix=f".{path.name}.", suffix=".tmp", delete=False) as handle:
        handle.write(payload)
        temp_path = Path(handle.name)
    temp_path.replace(path)


def normalize_candidate_record(candidate: dict) -> dict:
    if not isinstance(candidate, dict):
        return candidate
    source_text = str(candidate.get("source_text", "") or "")
    if _summary_contains_raw_json(source_text):
        source_text = _strip_raw_json_from_summary(source_text)
    candidate["source_text"] = trim_summary(source_text, 220) if source_text else ""
    payload = sanitize_summary_like_payload(candidate.get("payload") if isinstance(candidate.get("payload"), dict) else {})
    candidate["payload"] = payload
    event_kind = candidate.get("event_kind") or infer_followup_event_type(
        candidate.get("source_text", ""),
        signal={"signal_type": candidate.get("signal_type"), "topic": candidate.get("topic")},
    )
    event_chain = sanitize_event_chain_payload(
        merge_event_chain(
            candidate.get("event_chain"),
            candidate.get("source_text", ""),
            event_kind,
            topic_label=candidate.get("topic_label") or infer_topic_label(str(candidate.get("normalized_seed_summary", "") or ""), candidate.get("topic", "待追話題")),
        )
    )
    candidate["event_chain"] = event_chain
    candidate["event_kind"] = event_kind
    normalized_existing = usable_seed_summary(_strip_raw_json_from_summary(str(candidate.get("normalized_seed_summary", "") or "")))
    summary = (
        normalized_existing
        or usable_seed_summary(candidate["source_text"])
        or synthesize_event_chain_summary(event_chain, candidate["source_text"])
        or trim_summary(candidate["source_text"], 160)
    )
    candidate["normalized_seed_summary"] = sanitize_runtime_residue_text(summary, 160) if summary else ""
    candidate["topic_label"] = candidate.get("topic_label") or infer_topic_label(candidate["normalized_seed_summary"], candidate.get("topic", "待追話題"))
    candidate["source_layer"] = candidate.get("source_layer") or "candidate"
    candidate["confidence"] = float(candidate.get("confidence", 0.55 if candidate.get("promotion_hint") else 0.42) or 0.42)
    candidate["last_seen_at"] = candidate.get("last_seen_at") or candidate.get("created_at")
    candidate["intent_source"] = candidate.get("intent_source") or "phrase_rule"
    candidate["intent_similarity"] = candidate.get("intent_similarity")
    candidate["intent_exemplar_reference"] = candidate.get("intent_exemplar_reference")
    candidate["event_chain_id"] = candidate.get("event_chain_id") or make_event_chain_id(candidate["event_kind"], candidate.get("normalized_seed_summary") or candidate.get("source_text", ""))
    candidate["normalized_seed_summary"] = candidate.get("normalized_seed_summary") or synthesize_event_chain_summary(candidate["event_chain"], summary or candidate.get("source_text", ""))
    candidate["recent_user_context"] = sanitize_recent_user_context_list(candidate.get("recent_user_context"))
    if not candidate.get("current_status"):
        status = candidate.get("status")
        mapping = {
            "pending": "candidate_only",
            "promoted": "promoted",
            "expired": "expired",
            "discarded": "discarded",
        }
        candidate["current_status"] = mapping.get(status, "candidate_only")
    return candidate


def is_preference_signal_record(record: dict, user_text: str = "") -> bool:
    if not isinstance(record, dict):
        return False
    signal_type = str(record.get("signal_type") or "").strip().lower()
    topic = str(record.get("topic") or record.get("topic_label") or "").strip()
    combined = " ".join(
        [
            str(record.get("normalized_seed_summary") or ""),
            str(record.get("source_seed_text") or ""),
            str(record.get("source_text") or ""),
            topic,
        ]
    ).strip()
    if signal_type == "preference":
        return True
    if any(token in combined for token in ("偏好", "語音", "多說一些", "分段回覆", "emoji", "顏文字")):
        normalized_user = normalize_text_for_match(user_text)
        if normalized_user and any(
            token in normalized_user
            for token in (
                normalize_text_for_match("偏好"),
                normalize_text_for_match("語音"),
                normalize_text_for_match("多說"),
                normalize_text_for_match("分段"),
                normalize_text_for_match("顏文字"),
                normalize_text_for_match("emoji"),
                normalize_text_for_match("設定"),
                normalize_text_for_match("風格"),
            )
        ):
            return False
        return True
    return False


def normalize_incident_record(incident: dict) -> dict:
    if not isinstance(incident, dict):
        return incident
    payload = sanitize_summary_like_payload(incident.get("payload") if isinstance(incident.get("payload"), dict) else {})
    incident["payload"] = payload
    source_summary = str(incident.get("source_summary", "") or "")
    if _summary_contains_raw_json(source_summary):
        source_summary = _strip_raw_json_from_summary(source_summary)
    incident["source_summary"] = trim_summary(source_summary, 220) if source_summary else ""
    normalized_existing = usable_seed_summary(_strip_raw_json_from_summary(str(incident.get("normalized_seed_summary", "") or ""))) or usable_seed_summary(payload.get("normalized_seed_summary", ""))
    topic_label = incident.get("topic_label") or payload.get("topic_label") or infer_topic_label(str(incident.get("normalized_seed_summary", "") or ""), incident.get("type", "待追話題"))
    event_kind = incident.get("event_kind") or payload.get("event_kind") or infer_followup_event_type(
        incident.get("source_summary", ""),
        incident_type=incident.get("type"),
    )
    event_chain = sanitize_event_chain_payload(
        merge_event_chain(
            incident.get("event_chain") or payload.get("event_chain"),
            incident.get("source_summary", ""),
            event_kind,
            topic_label=topic_label,
        )
    )
    summary = (
        normalized_existing
        or usable_seed_summary(incident["source_summary"])
        or synthesize_event_chain_summary(event_chain, incident["source_summary"])
        or trim_summary(incident["source_summary"], 160)
    )
    incident["normalized_seed_summary"] = sanitize_runtime_residue_text(summary, 160) if summary else ""
    incident["topic_label"] = topic_label or infer_topic_label(incident["normalized_seed_summary"], incident.get("type", "待追話題"))
    incident["source_layer"] = incident.get("source_layer") or payload.get("source_layer") or "incident"
    incident["confidence"] = float(incident.get("confidence", payload.get("confidence", 0.82)) or 0.82)
    incident["last_seen_at"] = incident.get("last_seen_at") or payload.get("last_seen_at") or incident.get("created_at")
    incident["event_kind"] = event_kind
    incident["event_chain"] = event_chain
    incident["event_chain_id"] = incident.get("event_chain_id") or payload.get("event_chain_id") or make_event_chain_id(incident["event_kind"], incident.get("normalized_seed_summary") or incident.get("source_summary", ""))
    incident["daily_memory_trace"] = sanitize_summary_like_payload(incident.get("daily_memory_trace") if isinstance(incident.get("daily_memory_trace"), dict) else {})
    status = str(incident.get("status") or "").strip()
    incident["current_status"] = {
        "approved": "active_incident",
        "pending": "active_incident",
        "closed": "historical_completed",
        "done": "historical_completed",
        "cancelled": "historical_only",
        "rejected": "historical_only",
        "resolved": "historical_completed",
    }.get(status, "active_incident")
    refresh_incident_lifecycle(incident)
    return incident


def normalize_hook_record(hook: dict) -> dict:
    if not isinstance(hook, dict):
        return hook
    # Unify "hook_type" → "type" (policies use hook_type, hooks use type)
    if "type" not in hook and "hook_type" in hook:
        hook["type"] = hook.pop("hook_type")
    source_summary = str(hook.get("source_summary", "") or "")
    if _summary_contains_raw_json(source_summary):
        source_summary = _strip_raw_json_from_summary(source_summary)
    hook["source_summary"] = trim_summary(source_summary, 220) if source_summary else ""
    payload = sanitize_summary_like_payload(hook.get("payload") if isinstance(hook.get("payload"), dict) else {})
    hook["payload"] = payload
    normalized_existing = usable_seed_summary(_strip_raw_json_from_summary(str(hook.get("normalized_seed_summary", "") or "")))
    topic_label = hook.get("topic_label") or infer_topic_label(str(hook.get("normalized_seed_summary", "") or ""), hook.get("type", "待追話題"))
    event_kind = hook.get("event_kind") or payload.get("event_kind") or infer_followup_event_type(
        hook.get("source_summary", ""),
        incident_type=payload.get("incident_type"),
    )
    event_chain = sanitize_event_chain_payload(
        merge_event_chain(
            hook.get("event_chain") or payload.get("event_chain"),
            hook.get("source_summary", ""),
            event_kind,
            topic_label=topic_label,
        )
    )
    summary = (
        normalized_existing
        or usable_seed_summary(hook["source_summary"])
        or synthesize_event_chain_summary(event_chain, hook["source_summary"])
        or trim_summary(hook["source_summary"], 160)
    )
    hook["normalized_seed_summary"] = sanitize_runtime_residue_text(summary, 160) if summary else ""
    hook["topic_label"] = topic_label or infer_topic_label(hook["normalized_seed_summary"], hook.get("type", "待追話題"))
    hook["source_layer"] = hook.get("source_layer") or "hook"
    hook["confidence"] = float(hook.get("confidence", 0.95) or 0.95)
    hook["last_seen_at"] = hook.get("last_seen_at") or hook.get("trigger_at") or hook.get("created_at")
    hook["event_kind"] = event_kind
    hook["event_chain"] = event_chain
    hook["event_chain_id"] = hook.get("event_chain_id") or payload.get("event_chain_id") or make_event_chain_id(hook["event_kind"], hook.get("normalized_seed_summary") or hook.get("source_summary", ""))
    hook["daily_memory_trace"] = sanitize_summary_like_payload(hook.get("daily_memory_trace") if isinstance(hook.get("daily_memory_trace"), dict) else {})
    hook["last_rendered_message"] = sanitize_runtime_residue_text(hook.get("last_rendered_message") or "", 220)
    history = hook.get("dispatch_history") if isinstance(hook.get("dispatch_history"), list) else []
    cleaned_history = []
    for entry in history:
        if not isinstance(entry, dict):
            continue
        cleaned_entry = dict(entry)
        if isinstance(cleaned_entry.get("message_preview"), str):
            cleaned_entry["message_preview"] = sanitize_runtime_residue_text(_strip_raw_json_from_summary(cleaned_entry.get("message_preview") or ""), 120)
            if not cleaned_entry["message_preview"]:
                continue
        cleaned_history.append(cleaned_entry)
    hook["dispatch_history"] = cleaned_history
    status = hook.get("status")
    mapping = {
        "pending": "hook_ready",
        "done": "historical_completed",
        "cancelled": "historical_only",
    }
    hook["current_status"] = mapping.get(status, "hook_ready")
    refresh_hook_lifecycle(hook)
    return hook


def normalize_staging_record(record: dict) -> dict:
    if not isinstance(record, dict):
        return record
    canonical = (
        usable_seed_summary(record.get("normalized_seed_summary") or "")
        or usable_seed_summary(record.get("summary") or "")
        or usable_seed_summary(record.get("source_seed_text") or "")
        or normalize_staging_summary(record.get("summary") or record.get("normalized_seed_summary") or record.get("source_seed_text") or "")
    )
    if not canonical:
        return {}
    canonical = sanitize_runtime_residue_text(_strip_raw_json_from_summary(canonical), 160)
    if not canonical:
        return {}
    record["memory_class"] = record.get("memory_class") or "staged_memory"
    record["lifecycle"] = record.get("lifecycle") or "created"
    status = str(record.get("status") or "staged").strip()
    inferred_event_kind = infer_followup_event_type(canonical)
    record["event_kind"] = record.get("event_kind") or inferred_event_kind or "parked_topic"
    existing_chain = sanitize_event_chain_payload(record.get("event_chain")) if isinstance(record.get("event_chain"), dict) else {}
    record["event_chain"] = existing_chain or sanitize_event_chain_payload(build_event_chain(canonical, record["event_kind"]))
    record["causal_memory"] = deepcopy((record.get("event_chain") or {}).get("causal_memory") or {})
    completion_summary = trim_summary(
        str(
            record.get("completion_summary")
            or ((record.get("event_chain") or {}).get("causal_memory") or {}).get("completion_summary")
            or ""
        ).strip(),
        160,
    )
    if completion_summary and status in {"completed", "resolved"}:
        record["summary"] = synthesize_event_chain_summary(record.get("event_chain"), completion_summary)
        record["normalized_seed_summary"] = record["summary"]
        record["source_seed_text"] = record.get("source_seed_text") or canonical
        record["completion_summary"] = completion_summary
    else:
        record["summary"] = canonical
        record["source_seed_text"] = canonical
        record["normalized_seed_summary"] = canonical
    record["event_chain_id"] = record.get("event_chain_id") or make_event_chain_id(record["event_kind"], canonical)
    record["recent_user_context"] = sanitize_recent_user_context_list(record.get("recent_user_context"))
    existing_trace = record.get("daily_memory_trace") if isinstance(record.get("daily_memory_trace"), dict) else None
    care_state_level = str(record.get("care_state_level") or "").strip()
    if status == "staged" and care_state_level in {CARE_STATUS_ONCE, CARE_STATUS_ACTIVE}:
        record["daily_memory_trace"] = None
    elif not isinstance(existing_trace, dict) or not any(existing_trace.get(key) for key in ("path", "entry", "note", "action", "created")):
        record["daily_memory_trace"] = None
    else:
        rebuilt_trace = sanitize_summary_like_payload(existing_trace)
        action = str(existing_trace.get("action") or "staged_created")
        trace_summary = completion_summary if completion_summary and action in {"staged_completed", "tracked_completed"} else record["normalized_seed_summary"]
        rebuilt_trace.update(
            {
                "action": action,
                "memory_class": record["memory_class"],
                "event_kind": record["event_kind"],
                "note": format_skill_daily_memory_note(
                    action,
                    trace_summary,
                    record["memory_class"],
                    event_kind=record["event_kind"],
                    causal_memory=record["causal_memory"],
                ),
            }
        )
        record["daily_memory_trace"] = rebuilt_trace
    record["current_status"] = {
        "staged": care_state_level if care_state_level in {CARE_STATUS_ONCE, CARE_STATUS_ACTIVE} else "session_staged",
        "promoted": "active_followup",
        "completed": "historical_completed",
        "resolved": "historical_completed",
        "expired": "historical_only",
        "discarded": "historical_only",
    }.get(status, record.get("current_status") or "session_staged")
    return record


