def system_timezone_name() -> str:
    tz_env = str(os.environ.get("TZ") or "").strip()
    if tz_env:
        return tz_env
    localtime = Path("/etc/localtime")
    try:
        resolved = localtime.resolve(strict=True)
        marker = "/zoneinfo/"
        resolved_text = str(resolved)
        if marker in resolved_text:
            return resolved_text.split(marker, 1)[1].strip() or "UTC"
    except Exception:
        pass
    current_timezone = Path("/var/db/timezone/zoneinfo/current_timezone")
    try:
        raw = current_timezone.read_text(encoding="utf-8").strip()
        if raw:
            return raw
    except Exception:
        pass
    local_tz = now_local().tzinfo
    if local_tz is None:
        return "UTC"
    key = getattr(local_tz, "key", None)
    if isinstance(key, str) and key.strip():
        return key.strip()
    zone = getattr(local_tz, "zone", None)
    if isinstance(zone, str) and zone.strip():
        return zone.strip()
    name = str(local_tz).strip()
    return name or "UTC"


def parse_fixed_offset_timezone_name(value: str) -> Optional[str]:
    raw = str(value or "").strip()
    if not raw:
        return None
    if re.fullmatch(r"UTC", raw, re.IGNORECASE):
        return "UTC"
    match = re.search(r"\b(?:UTC|GMT)\s*([+-])\s*(\d{1,2})(?::?(\d{2}))?\b", raw, re.IGNORECASE)
    if not match:
        return None
    sign = 1 if match.group(1) == "+" else -1
    hours = int(match.group(2))
    minutes = int(match.group(3) or "00")
    if hours > 23 or minutes > 59:
        return None
    total_minutes = sign * (hours * 60 + minutes)
    abs_minutes = abs(total_minutes)
    canonical_sign = "+" if total_minutes >= 0 else "-"
    canonical_hours, canonical_minutes = divmod(abs_minutes, 60)
    return f"UTC{canonical_sign}{canonical_hours:02d}:{canonical_minutes:02d}"


def routine_schedule_timezone_name() -> str:
    raw = str(routine_schedule_section().get("timezone") or "").strip()
    return raw or system_timezone_name()


def routine_schedule_tzinfo():
    name = routine_schedule_timezone_name()
    fixed_offset = parse_fixed_offset_timezone_name(name)
    if fixed_offset == "UTC":
        return timezone.utc
    if fixed_offset:
        sign = 1 if fixed_offset[3] == "+" else -1
        hours = int(fixed_offset[4:6])
        minutes = int(fixed_offset[7:9])
        return timezone(sign * timedelta(hours=hours, minutes=minutes))
    if ZoneInfo is not None:
        try:
            return ZoneInfo(name)
        except Exception:
            pass
    return now_local().tzinfo


def routine_schedule_local_dt(now_dt: datetime) -> datetime:
    tz = routine_schedule_tzinfo()
    value = now_dt
    if value.tzinfo is None:
        value = value.replace(tzinfo=now_local().tzinfo)
    return value.astimezone(tz)


def parse_clock_hhmm(value: str) -> Optional[tuple[int, int]]:
    raw = str(value or "").strip()
    if not raw or not re.fullmatch(r"\d{1,2}:\d{2}", raw):
        return None
    hour_s, minute_s = raw.split(":", 1)
    try:
        hour = int(hour_s)
        minute = int(minute_s)
    except Exception:
        return None
    if not (0 <= hour <= 23 and 0 <= minute <= 59):
        return None
    return hour, minute


def routine_schedule_sleep_time() -> Optional[tuple[int, int]]:
    return parse_clock_hhmm(routine_schedule_section().get("sleep_time"))


def routine_schedule_wake_time() -> Optional[tuple[int, int]]:
    return parse_clock_hhmm(routine_schedule_section().get("wake_time"))


