def default_routine_phase_policies() -> dict:
    return {
        "sleep": {"proactive_enabled": False, "wake_seed_enabled": False, "interval_hours": None},
        "wake_window": {"proactive_enabled": True, "wake_seed_enabled": True, "interval_hours": 0.5},
        "active_day": {"proactive_enabled": True, "wake_seed_enabled": False, "interval_hours": 3.0},
    }


def routine_phase_policy(phase_name: str) -> dict:
    base = deepcopy(default_routine_phase_policies().get(phase_name) or {})
    phases = routine_schedule_section().get("phases") if isinstance(routine_schedule_section().get("phases"), dict) else {}
    override = phases.get(phase_name) if isinstance(phases.get(phase_name), dict) else {}
    if "proactive_enabled" in override:
        base["proactive_enabled"] = bool(override.get("proactive_enabled"))
    if "wake_seed_enabled" in override:
        base["wake_seed_enabled"] = bool(override.get("wake_seed_enabled"))
    if "interval_hours" in override:
        try:
            base["interval_hours"] = max(float(override.get("interval_hours")), 0)
        except Exception:
            pass
    return base


def set_routine_phase_override(
    emotion_state: dict,
    phase: str,
    now_dt: datetime,
    *,
    until_dt: Optional[datetime] = None,
    duration_minutes: Optional[int] = None,
    reason: str,
    source_text: str = "",
) -> None:
    if until_dt is None and duration_minutes is not None:
        until_dt = now_dt + timedelta(minutes=max(int(duration_minutes), 0))
    if until_dt is None:
        return
    emotion_state["routine_phase_override"] = phase
    emotion_state["routine_phase_override_until"] = until_dt.isoformat(timespec="seconds")
    emotion_state["routine_phase_override_reason"] = reason
    emotion_state["routine_phase_override_source_text"] = trim_summary(source_text, 160) if source_text else None
    emotion_state["routine_phase_override_set_at"] = now_dt.isoformat(timespec="seconds")


def clear_routine_phase_override(emotion_state: dict, now_dt: datetime, reason: str) -> bool:
    phase = str(emotion_state.get("routine_phase_override") or "").strip()
    until_dt = parse_optional_dt(emotion_state.get("routine_phase_override_until"))
    if not phase and until_dt is None:
        return False
    emotion_state["routine_phase_override_cleared_at"] = now_dt.isoformat(timespec="seconds")
    emotion_state["routine_phase_override_clear_reason"] = reason
    for key in (
        "routine_phase_override",
        "routine_phase_override_until",
        "routine_phase_override_reason",
        "routine_phase_override_source_text",
        "routine_phase_override_set_at",
    ):
        emotion_state.pop(key, None)
    return True


def active_routine_phase_override(emotion_state: dict, now_dt: datetime) -> Optional[dict]:
    if not isinstance(emotion_state, dict):
        return None
    phase = str(emotion_state.get("routine_phase_override") or "").strip()
    until_dt = parse_optional_dt(emotion_state.get("routine_phase_override_until"))
    if not phase or until_dt is None:
        return None
    if now_dt >= until_dt:
        return None
    return {
        "phase": phase,
        "until": until_dt.isoformat(timespec="seconds"),
        "reason": emotion_state.get("routine_phase_override_reason"),
        "source_text": emotion_state.get("routine_phase_override_source_text"),
    }


def combine_clock_on_day(base_dt: datetime, clock: tuple[int, int]) -> datetime:
    return base_dt.replace(hour=clock[0], minute=clock[1], second=0, microsecond=0)


def next_clock_dt(now_dt: datetime, clock: tuple[int, int]) -> datetime:
    tz = routine_schedule_tzinfo()
    local_now = now_dt.astimezone(tz)
    candidate = combine_clock_on_day(local_now, clock)
    if candidate <= local_now:
        candidate += timedelta(days=1)
    return candidate.astimezone(now_dt.tzinfo)


def previous_clock_dt(now_dt: datetime, clock: tuple[int, int]) -> datetime:
    tz = routine_schedule_tzinfo()
    local_now = now_dt.astimezone(tz)
    candidate = combine_clock_on_day(local_now, clock)
    if candidate > local_now:
        candidate -= timedelta(days=1)
    return candidate.astimezone(now_dt.tzinfo)


def time_in_clock_window(current_minutes: int, start_minutes: int, end_minutes: int) -> bool:
    if start_minutes == end_minutes:
        return False
    if start_minutes < end_minutes:
        return start_minutes <= current_minutes < end_minutes
    return current_minutes >= start_minutes or current_minutes < end_minutes


def structured_expected_wake_dt(now_dt: datetime) -> Optional[dict]:
    if not routine_schedule_enabled():
        return None
    wake_clock = routine_schedule_wake_time()
    if not wake_clock:
        return None
    wake_dt = next_clock_dt(now_dt, wake_clock)
    return {
        "wake_dt": wake_dt,
        "source": "routine_schedule",
        "source_text": f"routine_schedule.wake_time={wake_clock[0]:02d}:{wake_clock[1]:02d}",
    }


def routine_phase_switch(now_dt: Optional[datetime] = None, emotion_state: Optional[dict] = None) -> dict:
    now_dt = now_dt or now_local()
    emotion_state = emotion_state if isinstance(emotion_state, dict) else load_emotion_state()
    override = active_routine_phase_override(emotion_state, now_dt)
    sleep_clock = routine_schedule_sleep_time()
    wake_clock = routine_schedule_wake_time()
    wake_window_minutes = routine_schedule_wake_window_minutes()
    structured_enabled = routine_schedule_enabled()
    if override:
        phase = override.get("phase") or "active_day"
        return {
            "phase": phase,
            "source": "user_state_override",
            "override": override,
            "policy": routine_phase_policy(phase),
            "wake_window_minutes": wake_window_minutes,
        }
    if structured_enabled and sleep_clock and wake_clock:
        tz = routine_schedule_tzinfo()
        local_now = now_dt.astimezone(tz)
        current_minutes = local_now.hour * 60 + local_now.minute
        sleep_minutes = sleep_clock[0] * 60 + sleep_clock[1]
        wake_minutes = wake_clock[0] * 60 + wake_clock[1]
        wake_dt = previous_clock_dt(now_dt, wake_clock)
        wake_window_end = wake_dt + timedelta(minutes=wake_window_minutes)
        in_sleep = time_in_clock_window(current_minutes, sleep_minutes, wake_minutes)
        if in_sleep:
            phase = "sleep"
        elif wake_dt <= now_dt < wake_window_end:
            phase = "wake_window"
        else:
            phase = "active_day"
        return {
            "phase": phase,
            "source": "routine_schedule",
            "timezone": routine_schedule_timezone_name(),
            "sleep_time": f"{sleep_clock[0]:02d}:{sleep_clock[1]:02d}",
            "wake_time": f"{wake_clock[0]:02d}:{wake_clock[1]:02d}",
            "wake_dt": wake_dt.isoformat(timespec="seconds"),
            "wake_window_end": wake_window_end.isoformat(timespec="seconds"),
            "wake_window_minutes": wake_window_minutes,
            "policy": routine_phase_policy(phase),
        }
    rest = active_rest_suppress(emotion_state, now_dt)
    if rest:
        return {
            "phase": "sleep",
            "source": "memory_fallback",
            "wake_window_minutes": wake_window_minutes,
            "policy": routine_phase_policy("sleep"),
            "rest_suppress": rest,
        }
    expected_wake_dt = parse_optional_dt(emotion_state.get("rest_expected_wake_at"))
    if expected_wake_dt is not None and expected_wake_dt <= now_dt < expected_wake_dt + timedelta(minutes=wake_window_minutes):
        return {
            "phase": "wake_window",
            "source": "memory_fallback",
            "wake_dt": expected_wake_dt.isoformat(timespec="seconds"),
            "wake_window_end": (expected_wake_dt + timedelta(minutes=wake_window_minutes)).isoformat(timespec="seconds"),
            "wake_window_minutes": wake_window_minutes,
            "policy": routine_phase_policy("wake_window"),
        }
    return {
        "phase": "active_day",
        "source": "memory_fallback",
        "wake_window_minutes": wake_window_minutes,
        "policy": routine_phase_policy("active_day"),
    }


def routine_user_day(now_dt: datetime) -> str:
    local_now = routine_schedule_local_dt(now_dt)
    wake_clock = routine_schedule_wake_time()
    if routine_schedule_enabled() and wake_clock:
        current_minutes = local_now.hour * 60 + local_now.minute
        wake_minutes = wake_clock[0] * 60 + wake_clock[1]
        if current_minutes < wake_minutes:
            return (local_now.date() - timedelta(days=1)).isoformat()
    return local_now.date().isoformat()


def estimate_time_state_transition(now_dt: datetime, emotion_state: Optional[dict] = None, phase_result: Optional[dict] = None) -> tuple[Optional[str], Optional[str]]:
    emotion_state = emotion_state if isinstance(emotion_state, dict) else load_emotion_state()
    phase_result = phase_result if isinstance(phase_result, dict) else routine_phase_switch(now_dt, emotion_state)
    rest = active_rest_suppress(emotion_state, now_dt)
    if isinstance(rest, dict) and rest.get("until"):
        return str(rest.get("until")), "rest_resume"
    sleep_clock = routine_schedule_sleep_time()
    wake_clock = routine_schedule_wake_time()
    phase = str(phase_result.get("phase") or "")
    if routine_schedule_enabled() and sleep_clock and wake_clock:
        if phase == "sleep":
            return next_clock_dt(now_dt, wake_clock).isoformat(timespec="seconds"), "wake_window"
        if phase == "wake_window":
            wake_window_end = parse_optional_dt(phase_result.get("wake_window_end"))
            if wake_window_end:
                return wake_window_end.isoformat(timespec="seconds"), "active_day"
            return next_clock_dt(now_dt, sleep_clock).isoformat(timespec="seconds"), "sleep"
        return next_clock_dt(now_dt, sleep_clock).isoformat(timespec="seconds"), "sleep"
    return None, None


def build_time_state(
    now_dt: Optional[datetime] = None,
    *,
    profile: Optional[dict] = None,
    emotion_state: Optional[dict] = None,
    temporal_context: Optional[dict] = None,
    phase_result: Optional[dict] = None,
) -> dict:
    now_dt = now_dt or now_local()
    profile = profile if isinstance(profile, dict) else load_profile()
    emotion_state = emotion_state if isinstance(emotion_state, dict) else load_emotion_state()
    local_now = routine_schedule_local_dt(now_dt)
    temporal = temporal_context if isinstance(temporal_context, dict) else build_temporal_context(profile, emotion_state, now_dt)
    phase_info = phase_result if isinstance(phase_result, dict) else routine_phase_switch(now_dt, emotion_state)
    quiet_hours = proactive_chat_quiet_hours_decision(now_dt)
    rest = active_rest_suppress(emotion_state, now_dt)
    next_transition_at, next_transition_kind = estimate_time_state_transition(now_dt, emotion_state, phase_info)
    timezone_raw = str(routine_schedule_section().get("timezone") or "").strip()
    timezone_source = "user_profile" if timezone_raw else "system_default"
    return {
        "timezone": routine_schedule_timezone_name(),
        "timezone_source": timezone_source,
        "now_utc": now_dt.astimezone(ZoneInfo("UTC") if ZoneInfo is not None else now_dt.tzinfo).isoformat(timespec="seconds"),
        "now_local": local_now.isoformat(timespec="seconds"),
        "user_day": routine_user_day(now_dt),
        "weekday": local_now.strftime("%A"),
        "phase": phase_info.get("phase"),
        "phase_source": phase_info.get("source"),
        "quiet_hours": {
            "active": bool(quiet_hours.get("blocked")),
            "start": quiet_hours.get("start"),
            "end": quiet_hours.get("end"),
            "crosses_midnight": bool(quiet_hours.get("crosses_midnight")),
        },
        "rest_suppress_active": bool(rest),
        "rest_suppress_until": rest.get("until") if isinstance(rest, dict) else None,
        "hours_since_last_user": temporal.get("hours_since_last_user"),
        "last_user_at": temporal.get("last_user_at"),
        "last_user_source": temporal.get("source"),
        "next_transition_at": next_transition_at,
        "next_transition_kind": next_transition_kind,
    }


