def rest_suppress_duration_hours() -> int:
    settings = load_settings()
    section = settings.get("sleep_rest_suppress") if isinstance(settings.get("sleep_rest_suppress"), dict) else {}
    if not section.get("enabled", True):
        return 0
    try:
        return max(int(section.get("duration_hours", REST_SUPPRESS_DURATION_HOURS)), 0)
    except Exception:
        return REST_SUPPRESS_DURATION_HOURS


def carryover_max_turns() -> int:
    settings = load_settings()
    section = settings.get("carryover") if isinstance(settings.get("carryover"), dict) else {}
    if not section.get("enabled", True):
        return 0
    try:
        return max(int(section.get("max_turns", 5)), 1)
    except Exception:
        return 5


def contains_wake_context(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    return any(re.search(pattern, raw, re.IGNORECASE) for pattern in WAKE_CONTEXT_PATTERNS)


def chinese_hour_token_to_int(token: str) -> Optional[int]:
    raw = str(token or "").strip()
    if not raw:
        return None
    if raw.isdigit():
        value = int(raw)
        return value if 0 <= value <= 23 else None
    numerals = {"零": 0, "〇": 0, "一": 1, "二": 2, "兩": 2, "三": 3, "四": 4, "五": 5, "六": 6, "七": 7, "八": 8, "九": 9}
    if raw == "十":
        return 10
    if raw.startswith("十"):
        tail = numerals.get(raw[1:], None)
        return None if tail is None else 10 + tail
    if raw.endswith("十"):
        head = numerals.get(raw[:-1], None)
        return None if head is None else head * 10
    if "十" in raw:
        head_raw, tail_raw = raw.split("十", 1)
        head = numerals.get(head_raw, None)
        tail = numerals.get(tail_raw, None)
        if head is None or tail is None:
            return None
        return head * 10 + tail
    return numerals.get(raw)


def extract_local_hour_phrase(text: str) -> Optional[dict]:
    raw = str(text or "").strip()
    if not raw or not contains_wake_context(raw):
        return None
    matches = list(
        re.finditer(r"(上午|早上|清晨|中午|下午|晚上|夜裡|半夜|凌晨)?\s*([0-9]{1,2}|[零〇一二兩三四五六七八九十]{1,3})\s*點", raw)
    )
    if not matches:
        return None
    match = matches[-1]
    period = str(match.group(1) or "").strip()
    value = chinese_hour_token_to_int(match.group(2))
    if value is None:
        return None
    hour = value
    if period in {"下午", "晚上", "夜裡"} and hour < 12:
        hour += 12
    elif period == "中午" and hour < 11:
        hour += 12
    elif period in {"凌晨", "半夜"} and hour == 12:
        hour = 0
    elif period in {"上午", "早上", "清晨"} and hour == 12:
        hour = 0
    if not 0 <= hour <= 23:
        return None
    return {"hour": hour, "matched": match.group(0).strip(), "period": period}


def wake_related_texts(rest_source_text: str = "") -> list[str]:
    texts: list[str] = []
    persona_state = load_persona_state()
    for text in (
        rest_source_text,
        (persona_state.get("last_text_summary") if isinstance(persona_state, dict) else ""),
    ):
        if contains_wake_context(text):
            texts.append(str(text).strip())
    staging_store = load_session_memory_staging()
    for record in staging_store.get("records", []):
        if not isinstance(record, dict):
            continue
        if record.get("status") not in {"staged", "promoted"}:
            continue
        summary = str(record.get("normalized_seed_summary") or record.get("source_seed_text") or "").strip()
        if contains_wake_context(summary):
            texts.append(summary)
    incident_store = load_incidents()
    for incident in incident_store.get("incidents", []):
        if not isinstance(incident, dict):
            continue
        summary = str(incident.get("normalized_seed_summary") or incident.get("source_summary") or "").strip()
        if contains_wake_context(summary):
            texts.append(summary)
    for row in read_jsonl_tail(LEARNING_LOG_PATH, 120):
        if not isinstance(row, dict):
            continue
        summary = str(row.get("text") or "").strip()
        if contains_wake_context(summary):
            texts.append(summary)
    deduped = []
    seen = set()
    for item in texts:
        if not item or item in seen:
            continue
        seen.add(item)
        deduped.append(item)
    return deduped


def infer_expected_wake_dt(now_dt: datetime, rest_source_text: str = "") -> Optional[dict]:
    candidates = []
    for text in wake_related_texts(rest_source_text):
        parsed = extract_local_hour_phrase(text)
        if not parsed:
            continue
        wake_dt = now_dt.replace(hour=parsed["hour"], minute=0, second=0, microsecond=0)
        if wake_dt <= now_dt:
            wake_dt += timedelta(days=1)
        candidates.append({"wake_dt": wake_dt, "source_text": text, "matched": parsed["matched"]})
    if not candidates:
        return None
    candidates.sort(key=lambda item: item["wake_dt"])
    return candidates[0]


WAKE_SEED_MAX_SOURCE_AGE_HOURS = 48


def wake_seed_source_is_usable(source: dict, now_dt: datetime) -> bool:
    if not isinstance(source, dict):
        return False
    status = str(source.get("status") or "").strip().lower()
    current_status = str(source.get("current_status") or "").strip().lower()
    if status in {"closed", "done", "cancelled", "rejected", "archived"}:
        return False
    if any(marker in current_status for marker in ("closed", "historical", "completed", "archived")):
        return False
    summary = str(source.get("normalized_seed_summary") or source.get("source_summary") or source.get("source_seed_text") or "").strip()
    if not summary:
        return False
    if "[wake-seed]" in summary.lower():
        return False
    seen_dt = parse_optional_dt(
        source.get("last_seen_at")
        or source.get("updated_at")
        or source.get("created_at")
        or source.get("closed_at")
    )
    if seen_dt is None:
        return False
    if now_dt - seen_dt > timedelta(hours=WAKE_SEED_MAX_SOURCE_AGE_HOURS):
        return False
    return True


def find_wake_seed_source(incident_store: dict, staging_store: dict, now_dt: datetime, rest_source_text: str = "") -> Optional[dict]:
    candidates = []
    context_text = str(rest_source_text or "").strip()
    if context_text and (contains_wake_context(context_text) or is_rest_suppress_request(context_text)):
        event_kind = infer_followup_event_type(context_text)
        candidates.append(
            {
                "source_layer": "rest_source",
                "source_id": "rest-suppress-source",
                "summary": trim_summary(context_text, 220),
                "event_kind": event_kind,
                "event_chain": build_event_chain(context_text, event_kind),
                "event_chain_id": make_event_chain_id("wake-seed", context_text),
                "topic_label": infer_topic_label(context_text, "wake follow-up"),
                "last_seen_at": now_dt.isoformat(timespec="seconds"),
                "match_score": 999,
            }
        )
    for incident in incident_store.get("incidents", []):
        if not isinstance(incident, dict):
            continue
        if not wake_seed_source_is_usable(incident, now_dt):
            continue
        summary = str(incident.get("normalized_seed_summary") or incident.get("source_summary") or "").strip()
        if not contains_wake_context(summary):
            continue
        candidates.append(
            {
                "source_layer": "incident",
                "source_id": incident.get("id"),
                "summary": summary,
                "event_kind": incident.get("event_kind") or infer_followup_event_type(summary),
                "event_chain": incident.get("event_chain") if isinstance(incident.get("event_chain"), dict) else build_event_chain(summary, incident.get("event_kind") or infer_followup_event_type(summary)),
                "event_chain_id": incident.get("event_chain_id") or make_event_chain_id("wake-seed", summary),
                "topic_label": incident.get("topic_label") or infer_topic_label(summary, "wake follow-up"),
                "last_seen_at": incident.get("updated_at") or incident.get("created_at") or now_dt.isoformat(timespec="seconds"),
                "match_score": 30,
            }
        )
    for record in staging_store.get("records", []):
        if not isinstance(record, dict):
            continue
        if record.get("status") not in {"staged", "promoted"}:
            continue
        if not wake_seed_source_is_usable(record, now_dt):
            continue
        summary = str(record.get("normalized_seed_summary") or record.get("source_seed_text") or "").strip()
        if not contains_wake_context(summary):
            continue
        candidates.append(
            {
                "source_layer": "session_staging",
                "source_id": record.get("id"),
                "summary": summary,
                "event_kind": record.get("event_kind") or infer_followup_event_type(summary),
                "event_chain": record.get("event_chain") if isinstance(record.get("event_chain"), dict) else build_event_chain(summary, record.get("event_kind") or infer_followup_event_type(summary)),
                "event_chain_id": record.get("event_chain_id") or make_event_chain_id("wake-seed", summary),
                "topic_label": record.get("topic_label") or infer_topic_label(summary, "wake follow-up"),
                "last_seen_at": record.get("updated_at") or record.get("created_at") or now_dt.isoformat(timespec="seconds"),
                "match_score": 20,
            }
        )
    if not candidates:
        return None
    candidates.sort(key=lambda item: (item.get("match_score", 0), str(item.get("last_seen_at") or "")), reverse=True)
    return candidates[0]


def has_pending_linked_hook(hook_store: dict, event_chain_id: Optional[str], source_tag: str = "") -> bool:
    if not event_chain_id:
        return False
    for hook in hook_store.get("hooks", []):
        if not isinstance(hook, dict):
            continue
        if hook.get("status") != "pending":
            continue
        payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        if payload.get("event_chain_id") == event_chain_id:
            if not source_tag or payload.get("source") == source_tag:
                return True
        if hook.get("event_chain_id") == event_chain_id:
            return True
    return False


