SETUP_FIELD_BY_KEY = {field["key"]: field for field in SETUP_FIELDS}

PROFILE_SET_TOP_LEVEL_KEYS = frozenset(
    {
        "sleep_pattern",
        "care_style",
        "reminder_style",
        "task_followup_preference",
        "emoji_style",
        "inactivity_routine",
        "tracking_hints",
    }
)

PROFILE_SET_MUTABLE_PROFILE_ROOTS = frozenset(
    key for key in DEFAULT_PROFILE.keys() if key not in {"version", "updated_at"}
)
PROFILE_SET_MUTABLE_SETTINGS_ROOTS = frozenset(
    key for key in DEFAULT_SETTINGS.keys() if key not in {"version", "updated_at"}
)


def is_setup_needed(profile: Optional[dict] = None, settings: Optional[dict] = None) -> dict:
    """Check which setup fields are still unconfigured. Returns status dict."""
    if profile is None:
        profile = load_profile()
    if settings is None:
        settings = load_settings()
    unconfigured = []
    required_unconfigured = []
    optional_unconfigured = []
    configured = []
    for field in SETUP_FIELDS:
        value = _resolve_nested(profile if field["target"] == "profile" else settings, field["path"])
        source = _resolve_nested(profile if field["target"] == "profile" else settings, field["path"][:-1] + ["source"]) if len(field["path"]) > 1 else None
        is_unset = value is None or (isinstance(source, str) and source == "unconfigured")
        if is_unset:
            unconfigured.append(field["key"])
            if field.get("required"):
                required_unconfigured.append(field["key"])
            else:
                optional_unconfigured.append(field["key"])
        else:
            configured.append(field["key"])
    return {
        "needs_setup": len(required_unconfigured) > 0,
        "unconfigured": unconfigured,
        "required_unconfigured": required_unconfigured,
        "optional_unconfigured": optional_unconfigured,
        "configured": configured,
        "total": len(SETUP_FIELDS),
        "progress": len(configured),
    }


def _resolve_nested(data: dict, path: list):
    """Resolve a nested dict path, returning None if any key is missing."""
    current = data
    for key in path:
        if not isinstance(current, dict):
            return None
        current = current.get(key)
    return current


def _set_nested(data: dict, path: list, value) -> None:
    """Set a value at a nested dict path, creating intermediate dicts as needed."""
    current = data
    for key in path[:-1]:
        if key not in current or not isinstance(current[key], dict):
            current[key] = {}
        current = current[key]
    current[path[-1]] = value


def _mark_parent_source(target: dict, path: list[str], source: str) -> None:
    if len(path) <= 1:
        return
    parent = _resolve_nested(target, path[:-1])
    if isinstance(parent, dict) and "source" in parent:
        parent["source"] = source


def _sync_profile_sleep_pattern_from_settings(profile: dict, settings: dict, source: str = "setup") -> None:
    schedule = settings.setdefault("routine_schedule", {})
    tz_val = str(schedule.get("timezone") or "").strip()
    sleep_val = str(schedule.get("sleep_time") or "").strip()
    wake_val = str(schedule.get("wake_time") or "").strip()
    if not (tz_val and sleep_val and wake_val):
        return
    sp = profile.get("sleep_pattern", {})
    if not isinstance(sp, dict):
        sp = {}
    sp["usual_sleep_time"] = sleep_val
    sp["active_window"] = f"{wake_val}-{sleep_val}"
    sp["sleep_block_window"] = f"{sleep_val}-{wake_val}"
    sp["source"] = source
    profile["sleep_pattern"] = sp
    schedule["enabled"] = True


def _sync_schedule_proactive_defaults_from_settings(settings: dict) -> None:
    schedule = settings.setdefault("routine_schedule", {})
    proactive = settings.setdefault("proactive_chat", {})
    proactive_interval = proactive.get("interval_hours")
    if proactive_interval not in {None, ""}:
        try:
            interval_value = max(float(proactive_interval), 0.0)
            phases = schedule.setdefault("phases", {})
            active_day = phases.setdefault("active_day", {})
            active_day["interval_hours"] = interval_value
        except Exception:
            pass
    proactive_enabled = proactive.get("enabled")
    if proactive_enabled is not None:
        phases = schedule.setdefault("phases", {})
        for phase_name in ("wake_window", "active_day"):
            phase_cfg = phases.setdefault(phase_name, {})
            phase_cfg["proactive_enabled"] = bool(proactive_enabled)


def _apply_setup_field_values(profile: dict, settings: dict, answers: dict, source: str = "setup") -> dict:
    applied = []
    skipped = []
    for field in SETUP_FIELDS:
        key = field["key"]
        if key not in answers:
            continue
        value = answers[key]
        if value is None or (isinstance(value, str) and value.strip() == ""):
            skipped.append(key)
            continue
        target = profile if field["target"] == "profile" else settings
        _set_nested(target, field["path"], value)
        _mark_parent_source(target, field["path"], source)
        applied.append(key)
    _sync_profile_sleep_pattern_from_settings(profile, settings, source=source)
    _sync_schedule_proactive_defaults_from_settings(settings)
    return {"applied": applied, "skipped": skipped}


def _resolve_profile_set_target_path(key: str):
    field = SETUP_FIELD_BY_KEY.get(key)
    if field:
        return field["target"], list(field["path"])
    path = [part.strip() for part in str(key or "").split(".") if part.strip()]
    if len(path) < 2:
        return None, None
    root = path[0]
    if root in PROFILE_SET_MUTABLE_PROFILE_ROOTS:
        return "profile", path
    if root in PROFILE_SET_MUTABLE_SETTINGS_ROOTS:
        return "settings", path
    return None, None


def _apply_profile_set_target_path(profile: dict, settings: dict, key: str, value, source: str = "profile-set") -> dict:
    target_name, path = _resolve_profile_set_target_path(key)
    if not target_name or not path:
        raise SystemExit(f"unsupported profile key: {key}")
    target = profile if target_name == "profile" else settings
    _set_nested(target, path, value)
    _mark_parent_source(target, path, source)
    mirrored_paths: list[str] = []
    if target_name == "settings":
        if path[:2] == ["routine_schedule", "timezone"] or path[:2] == ["routine_schedule", "sleep_time"] or path[:2] == ["routine_schedule", "wake_time"]:
            _sync_profile_sleep_pattern_from_settings(profile, settings, source=source)
            mirrored_paths.append("profile.sleep_pattern")
        if path[:2] == ["proactive_chat", "enabled"] or path[:2] == ["proactive_chat", "interval_hours"]:
            _sync_schedule_proactive_defaults_from_settings(settings)
            mirrored_paths.append("settings.routine_schedule.phases")
    else:
        if path == ["sleep_pattern", "usual_sleep_time"]:
            schedule = settings.setdefault("routine_schedule", {})
            schedule["sleep_time"] = value
            _sync_profile_sleep_pattern_from_settings(profile, settings, source=source)
            mirrored_paths.append("settings.routine_schedule.sleep_time")
        if path == ["sleep_pattern", "usual_wake_time"]:
            schedule = settings.setdefault("routine_schedule", {})
            schedule["wake_time"] = value
            _sync_profile_sleep_pattern_from_settings(profile, settings, source=source)
            mirrored_paths.append("settings.routine_schedule.wake_time")
    return {
        "target": target_name,
        "path": path,
        "mirrored_paths": mirrored_paths,
    }


def apply_setup(answers: dict) -> dict:
    """Apply setup answers to profile and settings. Returns summary of changes."""
    profile = load_profile()
    settings = load_settings()
    result = _apply_setup_field_values(profile, settings, answers, source="setup")
    save_profile(profile)
    save_settings(settings)
    return {"applied": result["applied"], "skipped": result["skipped"], "status": is_setup_needed(profile, settings)}


def infer_timezone_from_text(text: str) -> Optional[str]:
    raw = str(text or "").strip()
    if not raw:
        return None
    zone_match = re.search(r"\b([A-Za-z_]+/[A-Za-z_]+)\b", raw)
    if zone_match:
        candidate = zone_match.group(1)
        if ZoneInfo is None:
            return candidate
        try:
            ZoneInfo(candidate)
            return candidate
        except Exception:
            pass
    fixed_offset = parse_fixed_offset_timezone_name(raw)
    if fixed_offset:
        return fixed_offset
    lowered = raw.lower()
    if any(token in raw for token in ("台灣", "台湾", "台北")) or "taiwan" in lowered or "taipei" in lowered:
        return "Asia/Taipei"
    if re.search(r"\b(?:gmt|utc)\b", raw, re.IGNORECASE):
        return "UTC"
    return None


def _clock_match_to_hhmm(period: str, token: str, half: bool) -> Optional[str]:
    hour = chinese_hour_token_to_int(token)
    if hour is None:
        return None
    period = str(period or "").strip()
    if period in {"下午", "晚上", "夜裡"} and hour < 12:
        hour += 12
    elif period == "中午" and hour < 11:
        hour += 12
    elif period in {"凌晨", "半夜"} and hour == 12:
        hour = 0
    elif period in {"上午", "早上", "清晨"} and hour == 12:
        hour = 0
    if not 0 <= hour <= 23:
        return None
    minute = 30 if half else 0
    return f"{hour:02d}:{minute:02d}"


ENGLISH_HOUR_WORDS = {
    "zero": 0,
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
    "seven": 7,
    "eight": 8,
    "nine": 9,
    "ten": 10,
    "eleven": 11,
    "twelve": 12,
}


def _english_hour_token_to_int(token: str) -> Optional[int]:
    raw = str(token or "").strip().lower()
    if not raw:
        return None
    if raw.isdigit():
        value = int(raw)
        return value if 0 <= value <= 23 else None
    return ENGLISH_HOUR_WORDS.get(raw)


def _english_clock_match_to_hhmm(token: str, *, minute: int = 0, meridiem: str = "", mode: str = "") -> Optional[str]:
    hour = _english_hour_token_to_int(token)
    if hour is None:
        return None
    marker = str(meridiem or "").strip().lower()
    if marker in {"am", "morning"}:
        if hour == 12:
            hour = 0
    elif marker in {"pm", "afternoon", "evening"}:
        if hour < 12:
            hour += 12
    elif marker in {"night"}:
        if hour == 12:
            hour = 0
        elif hour < 12:
            hour += 12
    else:
        # Deterministic fallbacks for natural onboarding phrases when meridiem
        # is omitted but the user clearly ties the phrase to sleep/wake context.
        if mode == "sleep" and hour == 12:
            hour = 0
        elif mode == "wake" and hour == 12:
            hour = 12
    if not 0 <= hour <= 23:
        return None
    return f"{hour:02d}:{minute:02d}"


def extract_english_clock_hint_from_text(text: str, *, mode: str) -> Optional[str]:
    raw = str(text or "").strip()
    if not raw:
        return None
    lowered = raw.lower()
    if mode == "sleep":
        verbs = r"(?:fall\s+asleep|sleep|go\s+to\s+sleep|go\s+to\s+bed|head\s+to\s+bed)"
    else:
        verbs = r"(?:wake\s+up|wake|get\s+up|be\s+up)"
    hour_words = r"(?:[0-9]{1,2}|zero|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)"
    clock_phrases = [
        re.compile(
            rf"{verbs}[^\n.!?]{{0,64}}?\b([0-9]{{1,2}})(?::([0-9]{{2}}))?\s*(am|pm)\b",
            re.IGNORECASE,
        ),
        re.compile(
            rf"\b([0-9]{{1,2}})(?::([0-9]{{2}}))?\s*(am|pm)\b[^\n.!?]{{0,32}}?{verbs}",
            re.IGNORECASE,
        ),
        re.compile(
            rf"{verbs}[^\n.!?]{{0,64}}?\b(?:around|about|roughly|usually|normally)?\s*"
            rf"(?:half\s+past\s+)?({hour_words})(?:\s*(am|pm))?(?:\s+in\s+the\s+(morning|afternoon|evening|night))?",
            re.IGNORECASE,
        ),
        re.compile(
            rf"\b(?:around|about|roughly)?\s*(?:half\s+past\s+)?({hour_words})(?:\s*(am|pm))?"
            rf"(?:\s+in\s+the\s+(morning|afternoon|evening|night))?[^\n.!?]{{0,32}}?{verbs}",
            re.IGNORECASE,
        ),
    ]
    for pattern in clock_phrases:
        matches = list(pattern.finditer(lowered))
        if not matches:
            continue
        match = matches[-1]
        groups = match.groups()
        if len(groups) == 3 and groups[1] and groups[1].isdigit() and groups[2] in {"am", "pm"}:
            hhmm = _english_clock_match_to_hhmm(groups[0], minute=int(groups[1]), meridiem=groups[2], mode=mode)
            if hhmm:
                return hhmm
            continue
        token = groups[0]
        meridiem = ""
        minute = 0
        if len(groups) >= 2 and groups[1]:
            if groups[1] in {"am", "pm"}:
                meridiem = groups[1]
            elif str(groups[1]).isdigit():
                minute = int(groups[1])
        if len(groups) >= 3 and groups[2] and not str(groups[2]).isdigit():
            meridiem = meridiem or groups[2]
        half_past = "half past" in match.group(0)
        hhmm = _english_clock_match_to_hhmm(token, minute=30 if half_past else minute, meridiem=meridiem, mode=mode)
        if hhmm:
            return hhmm
    if mode == "wake":
        noon_match = re.search(r"\b(?:wake\s+up|wake|get\s+up|be\s+up)[^\n.!?]{0,48}\b(noon)\b", lowered, re.IGNORECASE)
        if noon_match:
            return "12:00"
    if mode == "sleep":
        midnight_match = re.search(r"\b(?:fall\s+asleep|sleep|go\s+to\s+sleep|go\s+to\s+bed|head\s+to\s+bed)[^\n.!?]{0,48}\b(midnight)\b", lowered, re.IGNORECASE)
        if midnight_match:
            return "00:00"
    return None


def extract_clock_hint_from_text(text: str, *, mode: str) -> Optional[str]:
    raw = str(text or "").strip()
    if not raw:
        return None
    if mode == "sleep":
        verbs = r"(?:才)?睡(?:覺)?"
    else:
        verbs = r"(?:醒(?:來)?|起(?:來|床)?)"
    pattern = re.compile(
        rf"(凌晨|半夜|清晨|早上|上午|中午|下午|晚上|夜裡)?\s*"
        rf"([0-9]{{1,2}}|[零〇一二兩三四五六七八九十]{{1,3}})\s*點\s*(半)?(?:左右|多)?\s*{verbs}"
    )
    matches = list(pattern.finditer(raw))
    if not matches:
        return extract_english_clock_hint_from_text(raw, mode=mode)
    match = matches[-1]
    hhmm = _clock_match_to_hhmm(match.group(1) or "", match.group(2), bool(match.group(3)))
    if hhmm:
        return hhmm
    return extract_english_clock_hint_from_text(raw, mode=mode)


_LEADING_WEBCHAT_TIMESTAMP_RE = re.compile(
    r"^\s*\[[A-Za-z]{3}\s+\d{4}-\d{2}-\d{2}\s+\d{1,2}:\d{2}\s+GMT[+-]\d+\]\s*"
)


def strip_leading_webchat_timestamp(text: str) -> str:
    raw = str(text or "")
    if not raw:
        return ""
    return _LEADING_WEBCHAT_TIMESTAMP_RE.sub("", raw, count=1).strip()


_UNRESOLVED_REFERENT_FRAGMENT_RE = re.compile(
    r"(?i)^(?:嗯|欸|诶|好|好的|那|如果|現在|现在|先|還是|还是|要不要|想不想|可以|那要不要)?"
    r"[\s，,]*"
    r"(?:這個|这个|那個|那个|這件事|这件事|那件事|這段|这段|那段|this|that|it)"
    r"[\s，,]*"
    r"(?:要不要|想不想|要|先|再|繼續|继续|聊聊|聊嗎|聊吗|接回|talk about it|pick it up|continue|keep going)?"
    r"[\s。！？!?]*$"
)


def looks_like_unresolved_referent_fragment(text: str) -> bool:
    cleaned = normalize_story_text(str(text or "").strip(), 80)
    if not cleaned or len(cleaned) > 72:
        return False
    if any(token in cleaned for token in ("「", "」", "『", "』", ":", "：")):
        return False
    if re.search(r"(?:前面提到|你之前說|你之前说|先前提到|剛剛提到|刚刚提到|earlier|about\s+)", cleaned, re.I):
        return False
    return bool(_UNRESOLVED_REFERENT_FRAGMENT_RE.fullmatch(cleaned))


def _infer_relationship_hint_from_text(text: str) -> Optional[str]:
    raw = strip_leading_webchat_timestamp(text)
    if not raw:
        return None
    lowered = raw.lower()
    if (
        any(token in raw for token in ("同事", "一般工作", "工作上正常聊"))
        or "coworker" in lowered
        or "co-worker" in lowered
        or "as coworkers" in lowered
        or re.search(r"\bcoworker\s+setup\b", lowered)
        or re.search(r"\b(?:professional|work(?:ing)?)\b[^.!?\n]{0,24}\brelaxed\b", lowered)
    ):
        return "coworker"
    if (
        any(token in raw for token in ("合作", "協作", "协作"))
        or "collaborator" in lowered
        or "collaborative" in lowered
    ):
        return "collaborator"
    if (
        any(token in raw for token in ("助手", "幫忙", "帮忙"))
        or "assistant" in lowered
        or "help me out" in lowered
    ):
        return "assistant"
    return None


def _infer_use_case_hint_from_text(text: str) -> Optional[str]:
    raw = strip_leading_webchat_timestamp(text)
    if not raw:
        return None
    lowered = raw.lower()
    work_use_markers = (
        "工作用途",
        "工作為主",
        "工作为主",
        "主要是工作",
        "主要做工作",
        "平常主要是工作",
        "平常以工作為主",
        "平常以工作为主",
        "一般工作用途",
        "工作上用",
        "工作上正常聊",
    )
    if any(token in raw for token in ("開發", "开发", "工程", "規格", "规格", "文件", "程式", "代码", "技術", "技术")):
        return "developer"
    technical_patterns = [
        r"\bdeveloper\b",
        r"\bengineering\b",
        r"\bsoftware\b",
        r"\bcoding\b",
        r"\bprogramming\b",
        r"\bpull request\b",
        r"\bapi\b",
        r"\bschema\b",
        r"\bmigration\b",
        r"\bdashboard\b",
        r"\bfrontend\b",
        r"\bbackend\b",
        r"\binternal docs?\b",
        r"\bspecs?\b",
        r"\bprs?\b",
    ]
    if any(re.search(pattern, lowered) for pattern in technical_patterns):
        return "developer"
    if re.search(r"\b(?:mainly|mostly|primarily)\s+for\s+work\b", lowered):
        return "project-tracking"
    if any(marker in raw for marker in work_use_markers):
        return "project-tracking"
    if any(
        marker in lowered
        for marker in (
            "work stuff",
            "work-related",
            "for work",
            "for my job",
            "project tracking",
            "project-tracking",
            "task tracking",
        )
    ):
        return "project-tracking"
    if any(token in raw for token in ("專案", "项目", "追蹤", "跟進", "跟进")) or "project" in lowered:
        return "project-tracking"
    return None


def infer_onboarding_setup_answers(text: str, profile: Optional[dict] = None, settings: Optional[dict] = None) -> dict:
    raw = strip_leading_webchat_timestamp(text)
    if not raw:
        return {}
    profile = profile if isinstance(profile, dict) else load_profile()
    settings = settings if isinstance(settings, dict) else load_settings()
    status = is_setup_needed(profile, settings)
    unconfigured = set(status.get("unconfigured", []))
    answers: dict = {}

    timezone_hint = infer_timezone_from_text(raw)
    if timezone_hint and "timezone" in unconfigured:
        answers["timezone"] = timezone_hint

    sleep_hint = extract_clock_hint_from_text(raw, mode="sleep")
    if sleep_hint and "sleep_time" in unconfigured:
        answers["sleep_time"] = sleep_hint

    wake_hint = extract_clock_hint_from_text(raw, mode="wake")
    if wake_hint and "wake_time" in unconfigured:
        answers["wake_time"] = wake_hint

    lowered = raw.lower()
    if "relationship" in unconfigured:
        relationship_hint = _infer_relationship_hint_from_text(raw)
        if relationship_hint:
            answers["relationship"] = relationship_hint

    if "use_case" in unconfigured:
        use_case_hint = _infer_use_case_hint_from_text(raw)
        if use_case_hint:
            answers["use_case"] = use_case_hint

    return answers


def update_user_md_from_setup_answers(answers: dict) -> dict:
    if not USER_MD_PATH.exists():
        return {"updated": False, "reason": "USER.md-missing", "path": str(USER_MD_PATH)}
    original = USER_MD_PATH.read_text(encoding="utf-8")
    updated = original
    settings = load_settings()
    profile = load_profile()
    routine = settings.get("routine_schedule") if isinstance(settings.get("routine_schedule"), dict) else {}
    care_style = profile.get("care_style") if isinstance(profile.get("care_style"), dict) else {}
    effective_answers = {
        "timezone": answers.get("timezone") or routine.get("timezone"),
        "relationship": answers.get("relationship") or care_style.get("relationship"),
        "sleep_time": answers.get("sleep_time") or routine.get("sleep_time"),
        "wake_time": answers.get("wake_time") or routine.get("wake_time"),
        "use_case": answers.get("use_case") or answers.get("primary_use_case") or care_style.get("use_case"),
    }

    timezone_value = str(effective_answers.get("timezone") or "").strip()
    if timezone_value:
        updated = re.sub(
            r"^- \*\*Timezone:.*$",
            f"- **Timezone:** {timezone_value}",
            updated,
            flags=re.MULTILINE,
        )

    notes_parts = []
    if effective_answers.get("relationship") == "coworker":
        notes_parts.append("Prefers a straightforward coworker-style interaction.")
    elif effective_answers.get("relationship") == "collaborator":
        notes_parts.append("Prefers a collaborative working relationship.")
    elif effective_answers.get("relationship") == "assistant":
        notes_parts.append("Prefers practical assistant-style help.")
    if effective_answers.get("sleep_time") and effective_answers.get("wake_time"):
        notes_parts.append(
            f"Usually sleeps around {effective_answers['sleep_time']} and wakes around {effective_answers['wake_time']}."
        )
    if effective_answers.get("use_case") == "developer":
        notes_parts.append("Primary use case: developer work.")
    elif effective_answers.get("use_case") == "project-tracking":
        notes_parts.append("Primary use case: project tracking.")
    if notes_parts:
        notes_line = "- **Notes:** " + " ".join(notes_parts)
        if re.search(r"^- \*\*Notes:.*$", updated, re.MULTILINE):
            updated = re.sub(r"^- \*\*Notes:.*$", notes_line, updated, flags=re.MULTILINE)
        else:
            updated = updated.rstrip() + "\n" + notes_line + "\n"

    def _format_hours_for_user_md(value) -> str:
        try:
            hours = float(value)
        except Exception:
            return ""
        if hours <= 0:
            return ""
        minutes = int(round(hours * 60))
        if minutes < 60:
            return f"Every {minutes} minutes"
        if minutes % 60 == 0:
            unit_hours = minutes // 60
            return f"Every {unit_hours} hour" + ("" if unit_hours == 1 else "s")
        return f"Every {hours:.2f} hours"

    def _format_retry_for_user_md(value) -> str:
        try:
            hours = float(value)
        except Exception:
            return ""
        if hours <= 0:
            return ""
        minutes = int(round(hours * 60))
        if minutes < 60:
            return f"Retry after {minutes} minutes if no response"
        if minutes % 60 == 0:
            unit_hours = minutes // 60
            return f"Retry after {unit_hours} hour" + ("" if unit_hours == 1 else "s") + " if no response"
        return f"Retry after {hours:.2f} hours if no response"

    proactive = settings.get("proactive_chat") if isinstance(settings.get("proactive_chat"), dict) else {}
    re_engagement = settings.get("re_engagement") if isinstance(settings.get("re_engagement"), dict) else {}
    sleep_rest = settings.get("sleep_rest_suppress") if isinstance(settings.get("sleep_rest_suppress"), dict) else {}
    active_day = (((routine.get("phases") or {}) if isinstance(routine.get("phases"), dict) else {}).get("active_day") or {})
    proactive_enabled = bool(proactive.get("enabled"))
    proactive_interval_text = _format_hours_for_user_md(
        proactive.get("interval_hours") if proactive_enabled else active_day.get("interval_hours")
    )
    quiet_hours = proactive.get("quiet_hours") if isinstance(proactive.get("quiet_hours"), dict) else {}
    quiet_start = quiet_hours.get("start")
    quiet_end = quiet_hours.get("end")
    quiet_line = ""
    if quiet_start is not None and quiet_end is not None:
        try:
            quiet_line = f"{int(quiet_start):02d}:00-{int(quiet_end):02d}:00"
        except Exception:
            quiet_line = ""
    retry_line = ""
    if str(re_engagement.get("mode") or "") == "timed_retry":
        retry_line = _format_retry_for_user_md(re_engagement.get("retry_after_hours"))
    stop_after = re_engagement.get("max_unanswered_before_park")
    followup_lines = []
    if proactive_enabled or proactive_interval_text:
        followup_lines.append(f"- **Proactive check-ins:** {proactive_interval_text or 'Enabled'}")
    if retry_line:
        followup_lines.append(f"- **Retry logic:** {retry_line}")
    if stop_after not in (None, ""):
        followup_lines.append(f"- **Stop after:** {int(stop_after)} unanswered check-ins")
    if quiet_line:
        followup_lines.append(f"- **Quiet hours:** {quiet_line}")
    if sleep_rest.get('enabled') is not None:
        followup_lines.append(f"- **Sleep-aware suppression:** {'Enabled' if sleep_rest.get('enabled') else 'Disabled'}")
    if followup_lines:
        followup_block = "## Follow-up Preferences\n" + "\n".join(followup_lines) + "\n"
        if re.search(r"(?ms)^## Follow-up Preferences\n.*?(?=^## |\Z)", updated):
            updated = re.sub(r"(?ms)^## Follow-up Preferences\n.*?(?=^## |\Z)", followup_block + "\n", updated)
        else:
            if "## Context" in updated:
                updated = updated.replace("## Context", followup_block + "\n## Context", 1)
            else:
                updated = updated.rstrip() + "\n\n" + followup_block

    if updated == original:
        return {"updated": False, "reason": "no-change", "path": str(USER_MD_PATH)}
    USER_MD_PATH.write_text(updated, encoding="utf-8")
    return {"updated": True, "path": str(USER_MD_PATH)}


def detect_guided_settings_request(text: str) -> dict:
    raw = strip_leading_webchat_timestamp(text)
    normalized = normalize_text_for_match(raw)
    lowered = raw.lower()
    if not raw:
        return {"detected": False, "categories": [], "source": None}

    direct_patterns = [
        r"/care\s+(?:setup|config|status|pause|resume|help)",
        r"幫我調整關心設定",
        r"帮我调整关心设置",
        r"help me adjust my follow-up settings",
        r"フォローアップ設定を調整して",
        r"hilf mir, meine follow-up-einstellungen anzupassen",
        r"aiutami a regolare le impostazioni di follow-up",
        r"ayúdame a ajustar mi configuración de seguimiento",
    ]
    detected = any(re.search(pattern, lowered if pattern.isascii() else normalized, re.I) for pattern in direct_patterns)
    categories = []
    category_hints = {
        "schedule": ["作息", "時間", "时区", "時區", "timezone", "schedule", "睡", "起床", "醒", "晚睡", "夜班"],
        "proactive": ["主動關心", "主动关心", "關心頻率", "关心频率", "care interval", "check in", "pause care", "resume care"],
        "tracking": ["追蹤", "追踪", "跟進", "跟进", "記住", "记住", "continuity", "follow-up"],
        "tone": ["語氣", "语气", "風格", "风格", "tone", "relationship", "同事", "朋友", "助手", "collaborator", "coworker", "assistant", "顏文字", "颜文字", "emoji", "簡體", "简体"],
        "quiet_hours": ["勿擾", "勿扰", "quiet hours", "do not disturb", "dnd"],
    }
    for key, hints in category_hints.items():
        if any(hint.lower() in lowered or hint in normalized for hint in hints):
            categories.append(key)
    if not detected and categories:
        action_patterns = [
            r"\b(?:adjust|change|set|update|configure|review|tweak)\b",
            r"\b(?:turn on|turn off|enable|disable|pause|resume|keep)\b",
            r"(?:幫我|帮我).{0,8}(?:調整|调整|設定|设定|修改|改一下|打開|打开|開啟|开启|關掉|关闭|停用|啟用)",
            r"(?:調整|调整|設定|设定|修改|改一下|打開|打开|開啟|开启|關掉|关闭|停用|啟用)",
            r"(?:不要|別|别).{0,8}(?:簡體|简体|emoji|顏文字|颜文字)",
        ]
        if any(re.search(pattern, lowered if pattern.isascii() else normalized, re.I) for pattern in action_patterns):
            detected = True
    return {
        "detected": detected,
        "categories": categories,
        "source": "natural-language" if detected else None,
        "raw": raw if detected else "",
    }


def _extract_bool_from_request(text: str, *, positive: list[str], negative: list[str]) -> Optional[bool]:
    lowered = str(text or "").lower()
    if not lowered:
        return None
    if any(re.search(pattern, lowered, re.I) for pattern in negative):
        return False
    if any(re.search(pattern, lowered, re.I) for pattern in positive):
        return True
    return None


def _extract_hour_value(token: str) -> Optional[int]:
    raw = str(token or "").strip().lower()
    if not raw:
        return None
    if raw == "noon":
        return 12
    if raw == "midnight":
        return 0
    return _english_hour_token_to_int(raw)


def _extract_number_value(token: str) -> Optional[float]:
    raw = str(token or "").strip().lower()
    if not raw:
        return None
    try:
        return float(raw)
    except Exception:
        pass
    zh_int = chinese_hour_token_to_int(str(token or "").strip())
    if zh_int is not None:
        return float(zh_int)
    integer = _english_hour_token_to_int(raw)
    if integer is not None:
        return float(integer)
    return None


def _extract_simple_hour_window(text: str) -> tuple[Optional[int], Optional[int]]:
    raw_text = str(text or "")
    raw = raw_text.lower()
    if not raw_text:
        return (None, None)
    hour_words = r"(?:[0-9]{1,2}|zero|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve|noon|midnight)"
    pattern = re.compile(
        rf"(?:quiet hours|do not disturb|dnd)[^.!?\n]{{0,40}}?(?:from\s+)?({hour_words})(?:\s*(am|pm))?"
        rf"(?:\s+to\s+|[-~–—])({hour_words})(?:\s*(am|pm))?",
        re.I,
    )
    match = pattern.search(raw)
    if match:
        start_raw, start_meridiem, end_raw, end_meridiem = match.groups()
        start = _extract_hour_value(start_raw)
        end = _extract_hour_value(end_raw)
        if start is not None and end is not None:
            if start_meridiem == "pm" and start < 12:
                start += 12
            elif start_meridiem == "am" and start == 12:
                start = 0
            if end_meridiem == "pm" and end < 12:
                end += 12
            elif end_meridiem == "am" and end == 12:
                end = 0
            return (start % 24, end % 24)
    zh_match = re.search(
        r"(?:安靜時段|安静时段|勿擾|勿扰|免打擾|免打扰|dnd)[^。！？\n]{0,40}?"
        r"(?:設成|设成|設為|设为|改成|改為|改为|從|从)?\s*"
        r"(凌晨|早上|上午|中午|下午|晚上|夜裡|夜里|半夜)?\s*([0-9]{1,2}|[零〇一二兩三四五六七八九十]{1,3})\s*點"
        r"(?:\s*(?:到|至|-|~|～)\s*)"
        r"(凌晨|早上|上午|中午|下午|晚上|夜裡|夜里|半夜)?\s*([0-9]{1,2}|[零〇一二兩三四五六七八九十]{1,3})\s*點",
        raw_text,
    )
    if zh_match:
        start = _clock_match_to_hhmm(zh_match.group(1) or "", zh_match.group(2), False)
        end = _clock_match_to_hhmm(zh_match.group(3) or "", zh_match.group(4), False)
        if start and end:
            try:
                return (int(start.split(":", 1)[0]), int(end.split(":", 1)[0]))
            except Exception:
                pass
    return (None, None)


def infer_guided_settings_answers(text: str, profile: Optional[dict] = None, settings: Optional[dict] = None) -> dict:
    raw = strip_leading_webchat_timestamp(text)
    if not raw:
        return {}
    trigger = detect_guided_settings_request(raw)
    if not trigger.get("detected"):
        return {}
    lowered = raw.lower()
    profile = profile if isinstance(profile, dict) else load_profile()
    settings = settings if isinstance(settings, dict) else load_settings()
    answers: dict = {}

    proactive_bool = _extract_bool_from_request(
        lowered,
        positive=[
            r"\b(?:enable|turn on|turned on|switch on|switched on|keep)\s+proactive\b",
            r"\bproactive check-?ins?\s+(?:enabled|on|turned on)\b",
            r"\bproactive check(?:-|\s)?ins?\s+(?:enabled|on|turned on)\b",
            r"\bcheck(?:-|\s)?ins?\s+(?:enabled|on|turned on)\b",
            r"\b(?:want|need).{0,20}\bproactive check(?:-|\s)?ins?\b.{0,16}\b(?:on|enabled|turned on)\b",
            r"(?:主動關心|主動追蹤|關心|追蹤)[^。！？\n]{0,8}?(?:打開|開啟|开启|開著|开启|啟用)",
            r"(?:打開|開啟|开启|啟用)[^。！？\n]{0,8}?(?:主動關心|主動追蹤|關心|追蹤)",
        ],
        negative=[
            r"\b(?:disable|turn off|turned off|switch off|switched off|pause|stop)\s+proactive\b",
            r"\bproactive check-?ins?\s+(?:disabled|off|turned off)\b",
            r"\bproactive check(?:-|\s)?ins?\s+(?:disabled|off|turned off)\b",
            r"\bno proactive check-?ins?\b",
            r"(?:主動關心|主動追蹤|關心|追蹤)[^。！？\n]{0,8}?(?:關掉|關閉|关闭|停用|暫停|暂停)",
            r"(?:關掉|關閉|关闭|停用|暫停|暂停)[^。！？\n]{0,8}?(?:主動關心|主動追蹤|關心|追蹤)",
        ],
    )
    if proactive_bool is not None:
        answers["proactive_care"] = proactive_bool

    relation = _infer_relationship_hint_from_text(raw)
    if relation:
        answers["relationship"] = relation

    use_case_hint = _infer_use_case_hint_from_text(raw)
    if use_case_hint:
        answers["use_case"] = use_case_hint

    tone = None
    if "professional" in lowered:
        tone = "professional"
    elif "neutral" in lowered:
        tone = "neutral"
    elif "warm" in lowered:
        tone = "warm"
    elif "playful" in lowered:
        tone = "playful"
    if tone:
        answers["care_tone"] = tone

    start_hour, end_hour = _extract_simple_hour_window(raw)
    if start_hour is not None:
        answers["quiet_hours_start"] = start_hour
    if end_hour is not None:
        answers["quiet_hours_end"] = end_hour

    interval_match = re.search(
        r"(?i)\b(?:proactive(?:\s+check(?:-|\s)?ins?)?|check(?:-|\s)?ins?|check(?:ing)?\s+in)\b[^.!?\n]{0,56}?\bevery\s+([0-9]+(?:\.[0-9]+)?|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)\s+(minutes?|mins?|hours?)\b",
        raw,
    )
    if interval_match:
        amount = _extract_number_value(interval_match.group(1))
        unit = str(interval_match.group(2) or "").lower()
        if amount is not None and amount > 0:
            answers["proactive_interval_hours"] = amount / 60.0 if unit.startswith("min") else amount
    zh_interval_match = re.search(
        r"(?:主動關心|主動追蹤|關心|追蹤|追蹤提醒)[^。！？\n]{0,24}?每\s*([0-9]+(?:\.[0-9]+)?|[零〇一二兩三四五六七八九十]{1,3})\s*(分鐘|分|小時|個小時)",
        raw,
    )
    if zh_interval_match:
        amount = _extract_number_value(zh_interval_match.group(1))
        unit = str(zh_interval_match.group(2) or "")
        if amount is not None and amount > 0:
            answers["proactive_interval_hours"] = amount / 60.0 if unit in {"分鐘", "分"} else amount

    if re.search(r"(?i)\b(?:sleep mode|sleep suppress|rest suppress)\b", raw):
        sleep_mode = _extract_bool_from_request(
            raw,
            positive=[r"(?i)\b(?:enable|turn on|keep)\b", r"(?i)\b(?:while sleeping|during sleep)\b"],
            negative=[r"(?i)\b(?:disable|turn off)\b"],
        )
        if sleep_mode is not None:
            answers["sleep_rest_suppress_enabled"] = sleep_mode

    retry_match = re.search(r"(?i)\b(?:retry|retrying|follow(?:-|\s)?up|following up|check in again|check again)\b[^.!?\n]{0,40}?\b(?:every|after|in)\s+([0-9]+(?:\.[0-9]+)?)\s+hours?\b", raw)
    if retry_match:
        try:
            answers["re_engagement_retry_after_hours"] = max(float(retry_match.group(1)), 0.0)
            answers["re_engagement_mode"] = "timed_retry"
        except Exception:
            pass

    retry_minutes_match = re.search(
        r"(?i)\b(?:retry|retrying|follow(?:-|\s)?up|following up|check in again|check again)\b[^.!?\n]{0,40}?\b(?:every|after|in)\s+([0-9]+(?:\.[0-9]+)?|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)\s+minutes?\b",
        raw,
    )
    if retry_minutes_match:
        amount = _extract_number_value(retry_minutes_match.group(1))
        if amount is not None:
            answers["re_engagement_retry_after_hours"] = max(amount / 60.0, 0.0)
            answers["re_engagement_mode"] = "timed_retry"
    zh_retry_match = re.search(
        r"(?:沒回|未回|沒回覆|未回覆)[^。！？\n]{0,16}?(?:就|再)?\s*([0-9]+(?:\.[0-9]+)?|[零〇一二兩三四五六七八九十]{1,3})\s*(分鐘|分|小時|個小時)後(?:再試(?:一次)?|重試|再跟進|再追蹤)",
        raw,
    )
    if zh_retry_match:
        amount = _extract_number_value(zh_retry_match.group(1))
        unit = str(zh_retry_match.group(2) or "")
        if amount is not None:
            answers["re_engagement_retry_after_hours"] = max(amount / 60.0, 0.0) if unit in {"分鐘", "分"} else max(amount, 0.0)
            answers["re_engagement_mode"] = "timed_retry"

    stop_match = re.search(r"(?i)\b(?:stop|stopping|park|parking|give up|giving up)\b[^.!?\n]{0,24}?\bafter\s+([0-9]+)\s+(?:tries|attempts|unanswered(?:\s+check-?ins?)?)\b", raw)
    if stop_match:
        try:
            answers["re_engagement_max_unanswered_before_park"] = max(int(stop_match.group(1)), 1)
        except Exception:
            pass
    zh_stop_match = re.search(
        r"(?:最多|超過|满|滿)\s*([0-9]+|[零〇一二兩三四五六七八九十]{1,3})\s*次(?:沒回|未回|沒回覆|未回覆)[^。！？\n]{0,8}?(?:就|先)?(?:停|停止|先停|先放著|先暫停)",
        raw,
    )
    if zh_stop_match:
        amount = _extract_number_value(zh_stop_match.group(1))
        if amount is not None:
            answers["re_engagement_max_unanswered_before_park"] = max(int(round(amount)), 1)

    followup_delay_match = re.search(
        r"(?i)\b(?:follow(?:-|\s)?up|check in)\b[^.!?\n]{0,20}?\b(?:after|in)\s+([0-9]+(?:\.[0-9]+)?|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)\s+(minutes?|mins?|hours?)\b",
        raw,
    )
    if followup_delay_match:
        amount = _extract_number_value(followup_delay_match.group(1))
        unit = str(followup_delay_match.group(2) or "").lower()
        if amount is not None and amount > 0:
            delay_minutes = amount if unit.startswith("min") else amount * 60.0
            answers["followup_delay_minutes"] = max(int(round(delay_minutes)), 1)

    tracking_days = re.search(r"(?i)\btrack\b[^.!?\n]{0,24}?\bfor\s+([0-9]+)\s+days?\b", raw)
    if tracking_days:
        try:
            answers["followup_parked_auto_close_hours"] = max(int(tracking_days.group(1)) * 24, 0)
        except Exception:
            pass
    tracking_hours = re.search(r"(?i)\btrack\b[^.!?\n]{0,24}?\bfor\s+([0-9]+(?:\.[0-9]+)?)\s+hours?\b", raw)
    if tracking_hours:
        try:
            answers["followup_parked_auto_close_hours"] = max(float(tracking_hours.group(1)), 0.0)
        except Exception:
            pass

    timezone_hint = infer_timezone_from_text(raw)
    if timezone_hint:
        answers["timezone"] = timezone_hint
    return answers


def apply_guided_settings_answers(answers: dict) -> dict:
    profile = load_profile()
    settings = load_settings()
    applied = []
    skipped = []

    setup_payload = {
        key: value
        for key, value in answers.items()
        if key in {
            "use_case",
            "relationship",
            "timezone",
            "sleep_time",
            "wake_time",
            "proactive_care",
            "proactive_interval_hours",
            "quiet_hours_start",
            "quiet_hours_end",
            "care_tone",
            "emoji_forbidden",
            "tracking_keywords",
            "heartbeat_enabled",
        }
    }
    if setup_payload:
        setup_result = apply_setup(setup_payload)
        applied.extend(setup_result.get("applied") or [])
        skipped.extend(setup_result.get("skipped") or [])
        profile = load_profile()
        settings = load_settings()

    extra_appliers = [
        ("sleep_rest_suppress_enabled", settings.setdefault("sleep_rest_suppress", {}), "enabled"),
        ("re_engagement_retry_after_hours", settings.setdefault("re_engagement", {}), "retry_after_hours"),
        ("re_engagement_mode", settings.setdefault("re_engagement", {}), "mode"),
        ("re_engagement_max_unanswered_before_park", settings.setdefault("re_engagement", {}), "max_unanswered_before_park"),
        ("followup_parked_auto_close_hours", settings.setdefault("followup", {}), "parked_auto_close_hours"),
        ("followup_delay_minutes", settings.setdefault("followup_window", {}), "default_minutes"),
    ]
    for answer_key, target, field_key in extra_appliers:
        if answer_key not in answers:
            continue
        value = answers.get(answer_key)
        if value is None or (isinstance(value, str) and value.strip() == ""):
            skipped.append(answer_key)
            continue
        target[field_key] = value
        applied.append(answer_key)

    save_settings(settings)
    save_profile(profile)
    user_md_result = update_user_md_from_setup_answers(answers)
    return {
        "applied": applied,
        "skipped": skipped,
        "status": is_setup_needed(profile, settings),
        "user_md_result": user_md_result,
    }


def build_setup_prompt(status: Optional[dict] = None, trigger: Optional[dict] = None) -> str:
    """Build a guided setup prompt for the model to ask the user setup questions."""
    if status is None:
        status = is_setup_needed()
    trigger = trigger if isinstance(trigger, dict) else {"detected": False, "categories": [], "source": None}
    if not status["needs_setup"] and not trigger.get("detected"):
        return ""
    prompt_keys = set(status["unconfigured"]) if trigger.get("detected") else set(status.get("required_unconfigured") or [])
    questions = []
    for field in SETUP_FIELDS:
        if field["key"] in prompt_keys:
            questions.append(f"- **{field['key']}**: {field['question_zh']}\n  ({field['question_en']})")
    configured_summary = ", ".join(status.get("configured", [])[:8]) or "(none)"
    requested_categories = ", ".join(trigger.get("categories") or []) or "general"
    if trigger.get("detected") and not status["needs_setup"]:
        return (
            "## Guided Settings Mode\n\n"
            "The user is explicitly asking to review or adjust follow-up settings.\n"
            f"Requested category focus: {requested_categories}\n"
            f"Currently configured fields: {configured_summary}\n\n"
            "Do not dump every option at once.\n"
            "1. Acknowledge that settings mode is open.\n"
            "2. Ask which category or exact knob they want to change first.\n"
            "3. Run `setup-check` if you need the latest state.\n"
            "4. Apply only changed fields via `setup-apply --payload-json '{...}'`.\n"
            "5. Confirm what changed in plain language.\n\n"
            "Supported categories:\n"
            "- schedule / 作息\n"
            "- proactive / 主動關心\n"
            "- tracking / 追蹤記憶\n"
            "- tone / 互動風格\n"
            "- quiet_hours / 勿擾\n"
        )
    return (
        "## Initial Setup Guide\n\n"
        "This skill has not been fully configured yet. "
        "Please ask the user about the following settings through natural conversation. "
        "Do NOT ask all questions at once — weave them into the conversation naturally, "
        "starting with the most important ones (timezone, sleep schedule, use case).\n\n"
        "A universal natural-language entry into guided settings mode is supported. "
        "Examples: `幫我調整關心設定`, `帮我调整关心设置`, "
        "`Help me adjust my follow-up settings`, `フォローアップ設定を調整して`, "
        "`Hilf mir, meine Follow-up-Einstellungen anzupassen`, "
        "`Aiutami a regolare le impostazioni di follow-up`, "
        "`Ayúdame a ajustar mi configuración de seguimiento`.\n\n"
        "When the user provides answers, call the `setup-apply` command with a JSON payload.\n\n"
        "### Unconfigured fields:\n"
        + "\n".join(questions)
        + "\n\n"
        "### Guidelines:\n"
        "- If the user declines a setting, skip it — all fields are optional except timezone/sleep/wake.\n"
        "- Group related questions (e.g. sleep_time + wake_time + timezone together).\n"
        "- Explain what each setting does in simple terms.\n"
        "- Let the user choose a simple category first when helpful: schedule / proactive / tracking / tone.\n"
        "- After collecting answers, apply them via: `setup-apply --payload-json '{...}'`\n"
        "- The user can re-run setup at any time to update settings.\n"
    )


