def gc_hooks(data: dict, now_dt: Optional[datetime] = None, keep_recent_terminal: int = 20, keep_terminal_days: int = 14) -> int:
    hooks = data.get("hooks")
    if not isinstance(hooks, list):
        return 0
    now_dt = now_dt or now_local()
    cutoff = now_dt - timedelta(days=keep_terminal_days)
    terminal_statuses = {"done", "cancelled"}

    def _hook_dt(item: dict) -> datetime:
        for key in ("updated_at", "completed_at", "trigger_at", "created_at"):
            dt = parse_optional_dt(item.get(key))
            if dt is not None:
                return dt
        return datetime.min.replace(tzinfo=now_dt.tzinfo)

    terminal_hooks = [item for item in hooks if item.get("status") in terminal_statuses]
    terminal_hooks.sort(key=_hook_dt, reverse=True)
    keep_ids = set()
    for idx, item in enumerate(terminal_hooks):
        hook_dt = _hook_dt(item)
        if idx < keep_recent_terminal or hook_dt >= cutoff:
            hook_id = item.get("id")
            if isinstance(hook_id, str) and hook_id:
                keep_ids.add(hook_id)

    # ── Policy: parked_auto_close — auto-close parked hooks after N hours ──
    auto_close_h = followup_parked_auto_close_hours()
    if auto_close_h > 0:
        auto_close_cutoff = now_dt - timedelta(hours=auto_close_h)
        for item in hooks:
            if item.get("status") != "pending":
                continue
            fstate = get_event_followup_state(item)
            if fstate != FOLLOWUP_STATE_PARKED:
                continue
            last_dt = _last_dispatch_dt(item)
            if last_dt and last_dt < auto_close_cutoff:
                item["status"] = "cancelled"
                item["closure_reason"] = "parked-auto-close"
                item["completed_at"] = now_dt.isoformat(timespec="seconds")
                item["lifecycle"] = TRACKING_LIFECYCLE_FADED
                item["faded_reason"] = "parked-auto-close"
                refresh_hook_lifecycle(item, now_dt=now_dt, reason="parked-auto-close")

    original_count = len(hooks)
    data["hooks"] = [
        item
        for item in hooks
        if item.get("status") not in terminal_statuses or item.get("id") in keep_ids
    ]
    return max(0, original_count - len(data["hooks"]))


