# ── Staging expiry promotion: event_kinds that should not silently expire ──
STAGING_PROMOTABLE_EVENT_KINDS = {"delegated_task", "self_commitment", "parked_topic", "important_task", "watchful_state"}
STAGING_PROMOTION_MIN_SUMMARY_LEN = 10


def _promote_expired_staging_to_hook(record: dict, now_dt: datetime) -> Optional[dict]:
    """When a staging record expires, promote actionable ones to a parked hook
    instead of silently dropping them. Returns the created hook or None."""
    # ── A-Extract 7: records marked can_silent_expire are transient (busy/away) ──
    if record.get("can_silent_expire"):
        return None
    if str(record.get("care_state_level") or "") in {CARE_STATUS_ONCE, CARE_STATUS_ACTIVE}:
        return None
    event_kind = str(record.get("event_kind") or "")
    summary = str(record.get("normalized_seed_summary") or "").strip()
    if event_kind not in STAGING_PROMOTABLE_EVENT_KINDS:
        return None
    if len(summary) < STAGING_PROMOTION_MIN_SUMMARY_LEN:
        return None
    # Don't promote if it looks like structured residue
    if looks_like_structured_context_residue(summary):
        return None
    incident_hint = "emotional_incident" if event_kind == "watchful_state" else "important_task"
    delay_minutes = configured_followup_delay_minutes(incident_hint, summary)
    if delay_minutes is None:
        delay_minutes = 60
    hook_type = "progress_followup" if event_kind in ("delegated_task", "self_commitment", "important_task") else "tomorrow_check"
    hook = build_hook(
        hook_type,
        now_dt + timedelta(minutes=max(int(delay_minutes), 1)),
        summary,
        payload={
            "event_kind": event_kind,
            "event_chain": record.get("event_chain"),
            "event_chain_id": record.get("event_chain_id"),
            "promotion_source": "staging_expiry",
            "original_session_id": record.get("session_id"),
            "promotion_delay_minutes": int(delay_minutes),
        },
        note="auto-promoted from expired staging record",
    )
    hook["followup_state"] = FOLLOWUP_STATE_FRESH
    return hook


def _find_existing_staging_promotion_hook(hook_store: dict, record: dict) -> Optional[dict]:
    summary = str(record.get("normalized_seed_summary") or "").strip()
    event_chain_id = str(record.get("event_chain_id") or "").strip()
    session_id = str(record.get("session_id") or "").strip()
    for hook in hook_store.get("hooks", []):
        if not isinstance(hook, dict):
            continue
        payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        if payload.get("promotion_source") != "staging_expiry":
            continue
        if event_chain_id and payload.get("event_chain_id") == event_chain_id:
            return hook
        if session_id and payload.get("original_session_id") == session_id and hook.get("normalized_seed_summary") == summary:
            return hook
    return None


def reconcile_expired_staging_records(staging_store: dict, hook_store: dict, now_dt: datetime) -> dict:
    records = staging_store.get("records") if isinstance(staging_store.get("records"), list) else []
    kept_records = []
    promoted_count = 0
    expired_count = 0
    changed = False
    for item in records:
        record = normalize_staging_record(item)
        if not isinstance(record, dict) or not record.get("normalized_seed_summary"):
            changed = True
            continue
        expires_at = record.get("expires_at")
        expired = False
        if isinstance(expires_at, str):
            try:
                expired = parse_dt(expires_at) <= now_dt
            except Exception:
                expired = False
        if not expired:
            kept_records.append(record)
            continue
        changed = True
        promoted = None
        if _find_existing_staging_promotion_hook(hook_store, record) is None:
            promoted = _promote_expired_staging_to_hook(record, now_dt)
            if promoted:
                hook_store.setdefault("hooks", []).append(promoted)
                promoted_count += 1
                trace_followup(
                    now_dt,
                    session_id=record.get("session_id"),
                    event_kind=record.get("event_kind"),
                    event_chain_id=record.get("event_chain_id"),
                    source_stage="staging",
                    followup_decision="promoted-on-expiry",
                    trigger_reason="staging-ttl-expired",
                    continuity_source="session_staging",
                    live_dispatch_result="not-applicable",
                    source_id=record.get("session_id"),
                    source_layer="session_staging",
                    summary=record.get("normalized_seed_summary"),
                    **build_trace_writeback_meta(now_dt, entity_type="hook", entity=promoted, action="created", source_path="cron"),
                )
        if promoted is None:
            expired_count += 1
            trace_followup(
                now_dt,
                session_id=record.get("session_id"),
                event_kind=record.get("event_kind"),
                event_chain_id=record.get("event_chain_id"),
                source_stage="staging",
                followup_decision="expired",
                trigger_reason="staging-ttl-expired",
                continuity_source="session_staging",
                live_dispatch_result="not-applicable",
                source_id=record.get("session_id"),
                source_layer="session_staging",
                summary=record.get("normalized_seed_summary"),
            )
    if changed:
        staging_store["records"] = kept_records
    return {"changed": changed, "promoted": promoted_count, "expired": expired_count}


def load_session_memory_staging() -> dict:
    data = load_json(SESSION_MEMORY_STAGING_PATH, DEFAULT_SESSION_MEMORY_STAGING)
