def make_event_chain_id(*parts: str) -> str:
    cleaned = [str(part or "").strip() for part in parts if str(part or "").strip()]
    if cleaned:
        basis = "||".join(cleaned)
    else:
        basis = f"{iso_now()}-{random.random()}"
    return "ECH-" + hashlib.sha1(basis.encode("utf-8")).hexdigest()[:12]


def derive_session_event_chain_id(event_kind: str, source_text: str, session_key: Optional[str] = None) -> str:
    summary = usable_seed_summary(source_text) or normalize_staging_summary(source_text) or normalize_skill_source_text(source_text)
    return make_event_chain_id(event_kind or "parked_topic", str(session_key or "").strip(), summary)


def summarize_event_chain(chain: Optional[dict], fallback_text: str = "") -> str:
    if isinstance(chain, dict):
        parts = [
            str(chain.get(key) or "").strip()
            for key in ("context_before", "event_core", "immediate_result", "followup_focus")
            if str(chain.get(key) or "").strip()
        ]
        if parts:
            return trim_summary("；".join(parts), 180)
    return trim_summary(str(fallback_text or "").strip(), 180)


def count_event_chain_fields(chain: Optional[dict]) -> int:
    if not isinstance(chain, dict):
        return 0
    return sum(
        1
        for key in ("context_before", "event_core", "immediate_result", "followup_focus")
        if str(chain.get(key) or "").strip()
    )


def average_event_chain_length(records: list[dict]) -> float:
    lengths = [count_event_chain_fields(record.get("event_chain")) for record in records if isinstance(record, dict)]
    lengths = [value for value in lengths if value > 0]
    if not lengths:
        return 0.0
    return round(sum(lengths) / len(lengths), 2)


def event_chain_match_score(record: dict, text: str, inferred_event_kind: str = "") -> float:
    if not isinstance(record, dict):
        return 0.0
    summary = str(record.get("normalized_seed_summary") or "")
    source_text = str(record.get("source_seed_text") or record.get("source_summary") or "")
    topic_label = str(record.get("topic_label") or "")
    record_event_kind = str(record.get("event_kind") or "").strip()
    score = 0.0
    normalized = normalize_text_for_match(text)
    summary_normalized = normalize_text_for_match(summary)
    source_normalized = normalize_text_for_match(source_text)
    if normalized and summary_normalized and (summary_normalized in normalized or normalized in summary_normalized):
        score += 14
    if normalized and source_normalized and (source_normalized in normalized or normalized in source_normalized):
        score += 12
    if topic_label and topic_label in text:
        score += 6
    overlap = len(seed_text_ngrams(text) & seed_text_ngrams(f"{summary} {source_text} {topic_label}"))
    score += min(overlap, 4) * 2
    if inferred_event_kind and record_event_kind and inferred_event_kind == record_event_kind:
        score += 4
    if any(item.get("intent") == "return_signal" for item in classify_seed_intents(text).get("intents", [])):
        score += 2 if str(record.get("status") or "") in {"promoted", "staged"} or str(record.get("current_status") or "") in {"active_followup", "active_incident"} else 0
    return round(score, 4)


def trace_followup(
    now_dt: Optional[datetime] = None,
    *,
    session_id: Optional[str] = None,
    event_kind: Optional[str] = None,
    event_chain_id: Optional[str] = None,
    source_stage: str = "",
    followup_decision: Optional[str] = None,
    trigger_reason: Optional[str] = None,
    render_reason: Optional[str] = None,
    closure_reason: Optional[str] = None,
    continuity_source: Optional[str] = None,
    live_dispatch_result: Optional[str] = None,
    source_id: Optional[str] = None,
    source_layer: Optional[str] = None,
    summary: Optional[str] = None,
    entity_type: Optional[str] = None,
    entity_id: Optional[str] = None,
    action: Optional[str] = None,
    status_after: Optional[str] = None,
    source_path: Optional[str] = None,
    memory_class: Optional[str] = None,
    time_state_ref: Optional[str] = None,
    extra: Optional[dict] = None,
) -> None:
    resolved_now = now_dt or now_local()
    row = {
        "timestamp": resolved_now.isoformat(timespec="seconds"),
        "session_id": session_id,
        "event_kind": event_kind,
        "event_chain_id": event_chain_id,
        "source_stage": source_stage,
        "followup_decision": followup_decision,
        "trigger_reason": trigger_reason,
        "render_reason": render_reason,
        "closure_reason": closure_reason,
        "continuity_source": continuity_source,
        "live_dispatch_result": live_dispatch_result,
        "source_id": source_id,
        "source_layer": source_layer,
        "summary": trim_summary(summary or "", 180) if summary else None,
        "entity_type": entity_type,
        "entity_id": entity_id,
        "action": action,
        "status_after": status_after,
        "source_path": source_path,
        "memory_class": memory_class,
        "time_state_ref": time_state_ref,
    }
    if isinstance(extra, dict) and extra:
        row["extra"] = extra
    append_followup_trace(row)


def build_trace_writeback_meta(
    now_dt: datetime,
    *,
    entity_type: str,
    entity: Optional[dict],
    action: str,
    source_path: str,
    time_state: Optional[dict] = None,
) -> dict:
    payload = entity if isinstance(entity, dict) else {}
    resolved_time_state = time_state if isinstance(time_state, dict) else build_time_state(now_dt=now_dt)
    entity_id = (
        str(payload.get("id") or "").strip()
        or str(payload.get("session_id") or "").strip()
        or str(payload.get("source_id") or "").strip()
        or None
    )
    status_after = str(payload.get("status") or payload.get("current_status") or "").strip() or None
    memory_class = str(payload.get("memory_class") or "").strip() or None
    return {
        "entity_type": entity_type,
        "entity_id": entity_id,
        "action": action,
        "status_after": status_after,
        "source_path": source_path,
        "memory_class": memory_class,
        "time_state_ref": resolved_time_state.get("now_local"),
    }


def read_jsonl_tail(path: Path, limit: int = 20) -> list[dict]:
    rows = parse_jsonl_lines(path)
    if limit <= 0:
        return rows
    return rows[-limit:]


def parse_value(raw: str):
    try:
        return json.loads(raw)
    except Exception:
        return raw


def make_hook_id() -> str:
    return f"HK-{now_local().strftime('%Y%m%d-%H%M%S')}-{random.randint(100, 999)}"


def make_incident_id() -> str:
    return f"INC-{now_local().strftime('%Y%m%d-%H%M%S')}-{random.randint(100, 999)}"


def make_candidate_id() -> str:
    return f"CB-{now_local().strftime('%Y%m%d-%H%M%S')}-{random.randint(100, 999)}"


def find_hook(data: dict, hook_id: str):
    for hook in data.get("hooks", []):
        if hook.get("id") == hook_id:
            return hook
    return None


def find_incident(data: dict, incident_id: str):
    for incident in data.get("incidents", []):
        if incident.get("id") == incident_id:
            return incident
    return None


def hook_dispatch_cooldown_minutes(hook: dict) -> int:
    payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
    override = payload.get(TEST_DISPATCH_COOLDOWN_KEY)
    settings = load_settings()
    dispatch = settings.get("dispatch") if isinstance(settings.get("dispatch"), dict) else {}
    try:
        minutes = int(override)
    except Exception:
        minutes = int(dispatch.get("cooldown_minutes", FOLLOWUP_DISPATCH_COOLDOWN_MINUTES))
    return max(minutes, 0)


def hook_dispatch_cap(hook: dict) -> int:
    payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
    override = payload.get(TEST_DISPATCH_CAP_KEY)
    settings = load_settings()
    dispatch = settings.get("dispatch") if isinstance(settings.get("dispatch"), dict) else {}
    try:
        cap = int(override)
    except Exception:
        cap = int(dispatch.get("cap", FOLLOWUP_DISPATCH_LIMIT))
    return max(cap, 1)


def hook_dispatch_guard_decision(hook: dict, now_dt: datetime) -> dict:
    if maybe_fade_hook_after_newer_unmatched_user_turn(hook, now_dt):
        return {
            "allow": False,
            "reason": "followup-lifecycle-faded",
            "followup_state": get_event_followup_state(hook),
            "lifecycle": refresh_hook_lifecycle(hook, now_dt=now_dt),
            "faded_reason": hook.get("faded_reason"),
            "dispatch_count": int(hook.get("dispatch_count", 0) or 0),
            "dispatch_cap": hook_dispatch_cap(hook),
        }
    lifecycle = refresh_hook_lifecycle(hook, now_dt=now_dt)
    if lifecycle == TRACKING_LIFECYCLE_FADED:
        return {
            "allow": False,
            "reason": "followup-lifecycle-faded",
            "followup_state": get_event_followup_state(hook),
            "lifecycle": lifecycle,
            "faded_reason": hook.get("faded_reason"),
            "dispatch_count": int(hook.get("dispatch_count", 0) or 0),
            "dispatch_cap": hook_dispatch_cap(hook),
        }
    # ── followup state gate: parked_waiting hooks ──
    fstate = get_event_followup_state(hook)
    dispatch_count = int(hook.get("dispatch_count", 0) or 0)
    cap = hook_dispatch_cap(hook)
    if dispatch_count >= cap:
        return {
            "allow": False,
            "reason": "dispatch-cap-reached",
            "dispatch_count": dispatch_count,
            "dispatch_cap": cap,
            "cooldown_minutes": hook_dispatch_cooldown_minutes(hook),
        }
    if fstate in FOLLOWUP_STATES_NO_DISPATCH:
        mode = re_engagement_mode()
        if mode == "timed_retry":
            # In timed_retry mode, parked hooks can retry after retry_after_hours
            retry_h = re_engagement_retry_after_hours()
            last_dispatch = _last_dispatch_dt(hook)
            if retry_h <= 0:
                # retry_after_hours=0 means timed_retry is effectively disabled — block like wait_for_reply
                return {
                    "allow": False,
                    "reason": "followup-state-parked-retry-disabled",
                    "followup_state": fstate,
                    "re_engagement_mode": mode,
                    "retry_after_hours": retry_h,
                    "dispatch_count": int(hook.get("dispatch_count", 0) or 0),
                    "dispatch_cap": hook_dispatch_cap(hook),
                }
            if not last_dispatch:
                # No last_dispatch timestamp (migrated/backfilled data) — block safely
                return {
                    "allow": False,
                    "reason": "followup-state-parked-missing-timestamp",
                    "followup_state": fstate,
                    "re_engagement_mode": mode,
                    "retry_after_hours": retry_h,
                    "dispatch_count": int(hook.get("dispatch_count", 0) or 0),
                    "dispatch_cap": hook_dispatch_cap(hook),
                }
            elapsed = (now_dt - last_dispatch).total_seconds() / 3600.0
            if elapsed >= retry_h:
                # Allow retry: unpark the hook for this evaluation
                pass  # fall through to normal dispatch checks below
            else:
                return {
                    "allow": False,
                    "reason": "followup-state-parked-timed-wait",
                    "followup_state": fstate,
                    "re_engagement_mode": mode,
                    "retry_after_hours": retry_h,
                    "hours_since_last_dispatch": round(elapsed, 2),
                    "dispatch_count": int(hook.get("dispatch_count", 0) or 0),
                    "dispatch_cap": hook_dispatch_cap(hook),
                }
        else:
            # wait_for_reply mode: parked hooks do not dispatch
            return {
                "allow": False,
                "reason": "followup-state-parked",
                "followup_state": fstate,
                "re_engagement_mode": mode,
                "dispatch_count": dispatch_count,
                "dispatch_cap": cap,
            }
    last_dispatched_at = hook.get("last_dispatched_at")
    cooldown_minutes = hook_dispatch_cooldown_minutes(hook)
    if isinstance(last_dispatched_at, str) and cooldown_minutes > 0:
        try:
            last_dt = parse_dt(last_dispatched_at)
            if now_dt < last_dt + timedelta(minutes=cooldown_minutes):
                return {
                    "allow": False,
                    "reason": "dispatch-cooldown",
                    "dispatch_count": dispatch_count,
                    "dispatch_cap": cap,
                    "cooldown_minutes": cooldown_minutes,
                    "next_allowed_at": (last_dt + timedelta(minutes=cooldown_minutes)).isoformat(timespec="seconds"),
                }
        except Exception:
            pass
    return {
        "allow": True,
        "reason": "due-ready",
        "dispatch_count": dispatch_count,
        "dispatch_cap": cap,
        "cooldown_minutes": cooldown_minutes,
    }


def due_hooks(data: dict, now_dt: datetime):
    if not followup_enabled():
        return []
    result = []
    for hook in data.get("hooks", []):
        if hook.get("status") != "pending":
            continue
        trigger_at = hook.get("trigger_at")
        if not isinstance(trigger_at, str):
            continue
        try:
            trigger_dt = parse_dt(trigger_at)
        except Exception:
            continue
        if trigger_dt <= now_dt:
            decision = hook_dispatch_guard_decision(hook, now_dt)
            trace_followup(
                now_dt,
                event_kind=hook.get("event_kind"),
                event_chain_id=hook.get("event_chain_id"),
                source_stage="due",
                followup_decision="ready" if decision.get("allow") else "suppressed",
                trigger_reason=decision.get("reason"),
                source_id=hook.get("id"),
                source_layer="hook",
                summary=hook.get("normalized_seed_summary") or hook.get("source_summary"),
                extra={
                    "dispatch_count": decision.get("dispatch_count"),
                    "dispatch_cap": decision.get("dispatch_cap"),
                    "cooldown_minutes": decision.get("cooldown_minutes"),
                    "next_allowed_at": decision.get("next_allowed_at"),
                },
            )
            if decision.get("allow"):
                result.append(hook)
    result.sort(key=lambda item: item.get("trigger_at", ""))
    return result


def iter_hooks(data: dict):
    return data.get("hooks", []) if isinstance(data.get("hooks"), list) else []


def has_summary(data: dict, summary: str) -> bool:
    for hook in iter_hooks(data):
        if hook.get("source_summary") == summary:
            return True
    return False


def parse_jsonl_lines(path: Path):
    if not path.exists():
        return []
    rows = []
    for raw in path.read_text(encoding="utf-8").splitlines():
        raw = raw.strip()
        if not raw:
            continue
        try:
            rows.append(json.loads(raw))
        except Exception:
            continue
    return rows


def parse_recent_jsonl_lines(path: Path, max_bytes: int = 65536):
    if not path.exists():
        return []
    try:
        with path.open("rb") as handle:
            handle.seek(0, os.SEEK_END)
            size = handle.tell()
            if size <= 0:
                return []
            read_size = min(size, max_bytes)
            handle.seek(-read_size, os.SEEK_END)
            chunk = handle.read(read_size)
    except Exception:
        return []
    if not chunk:
        return []
    text = chunk.decode("utf-8", errors="ignore")
    try:
        total_size = path.stat().st_size
    except Exception:
        total_size = len(chunk)
    if read_size < total_size and "\n" in text:
        text = text.split("\n", 1)[1]
    rows = []
    for raw in text.splitlines():
        raw = raw.strip()
        if not raw:
            continue
        try:
            rows.append(json.loads(raw))
        except Exception:
            continue
    return rows


def strip_untrusted_metadata_blocks(text: str) -> str:
    cleaned = text or ""
    patterns = [
        r"Conversation info \(untrusted metadata\):\s*```json.*?```",
        r"Sender \(untrusted metadata\):\s*```json.*?```",
        r"Replied message \(untrusted,\s*for context\):\s*```json.*?(?=\n{2,}|\Z)",
        r"Conversation info \(untrusted metadata\):\s*```json.*?(?=\n{2,}|\Z)",
        r"Sender \(untrusted metadata\):\s*```json.*?(?=\n{2,}|\Z)",
        r"<inherited-rules>\s*.*?(?=\n{2,}|\Z)",
        r"Stable rules inherited from .* reflections\.[^\n]*",
    ]
    for pattern in patterns:
        cleaned = re.sub(pattern, "", cleaned, flags=re.S)
    control_patterns = [
        r"## New-session carryover \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Pending follow-up topics \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Night-owl schedule context \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Household schedule awareness \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Recent dispatch awareness \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Recent dispatch reason \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Event action result \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Active tracked events \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Active User Preferences \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Capability status \(trusted structured state\).*?(?=\n## |\Z)",
        r"## Recall honesty \(trusted structured state\).*?(?=\n## |\Z)",
    ]
    for pattern in control_patterns:
        cleaned = re.sub(pattern, "", cleaned, flags=re.S | re.I)
    cleaned = re.sub(r"^\s*Read HEARTBEAT\.md.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"^\s*Current time:.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"^\s*Reply with ONLY the slug,.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"Remembering this platform action and result; will pick up next steps on return\.?", "", cleaned, flags=re.I)
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned)
    return cleaned.strip()


_INLINE_SESSION_TIMESTAMP_PREFIX_RE = re.compile(
    r"^\s*\[(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun|[A-Za-z]{3,9}|週[一二三四五六日天]|星期[一二三四五六日天]).{0,48}?GMT[+-]\d+\]\s*",
    re.I,
)


def strip_inline_session_timestamp_prefix(text: str) -> str:
    cleaned = str(text or "")
    while True:
        updated = _INLINE_SESSION_TIMESTAMP_PREFIX_RE.sub("", cleaned, count=1)
        if updated == cleaned:
            break
        cleaned = updated.lstrip()
    return cleaned


def is_internal_context_refresh_text(text: str) -> bool:
    sample = normalize_text_for_match(strip_inline_session_timestamp_prefix(str(text or "")))
    return sample in {"contextrefresh", "context_refresh", "context-refresh"}


def normalize_skill_source_text(text: str) -> str:
    cleaned = strip_inline_session_timestamp_prefix(str(text or ""))
    if is_internal_context_refresh_text(cleaned):
        return ""
    return cleaned.strip()


def extract_visible_human_tail(text: str) -> str:
    raw = normalize_skill_source_text(text)
    if not raw.strip():
        return ""
    paragraphs = [chunk.strip() for chunk in re.split(r"\n{2,}", raw) if chunk.strip()]
    for chunk in reversed(paragraphs):
        sample = chunk.strip()
        if not sample:
            continue
        if sample.startswith("```"):
            continue
        if sample.startswith("## "):
            continue
        if sample.startswith("<") and sample.endswith(">"):
            continue
        if sample.startswith("Conversation info (untrusted metadata):"):
            continue
        if sample.startswith("Sender (untrusted metadata):"):
            continue
        if sample.startswith("Replied message (untrusted"):
            continue
        if sample.startswith("Current time:"):
            continue
        if sample.startswith("A new session was started via /new or /reset"):
            continue
        if structured_context_residue_marker_for_text(sample):
            continue
        cleaned = sample
        cleaned = re.sub(r"^```json\s*", "", cleaned, flags=re.I)
        cleaned = re.sub(r"```$", "", cleaned).strip()
        cleaned = strip_internal_residue_lines(cleaned).strip()
        if not cleaned:
            continue
        if looks_like_internal_summary_residue(cleaned):
            continue
        return cleaned
    return ""


STRUCTURED_CONTEXT_RESIDUE_MARKERS = (
    "<inherited-rules>",
    "Stable rules inherited from ",
    "Replied message (untrusted",
    "Conversation info (untrusted metadata)",
    "Sender (untrusted metadata)",
    "## Active tracked events",
    "## New-session carryover",
    "## Pending follow-up topics",
    "## Night-owl schedule context",
    "## Household schedule awareness",
    "## Recent dispatch awareness",
    "## Recent dispatch reason",
    "## Event action result",
    "## Active User Preferences",
    "## Capability status",
    "## Recall honesty",
    "trusted structured state",
)


def structured_context_residue_marker_for_text(text: str) -> Optional[str]:
    if not isinstance(text, str) or not text.strip():
        return None
    for marker in STRUCTURED_CONTEXT_RESIDUE_MARKERS:
        if marker in text:
            return marker
    lowered = text.lower()
    if "trusted structured" in lowered:
        return "trusted structured"
    return None


def looks_like_structured_context_residue(text: str) -> bool:
    cleaned = strip_untrusted_metadata_blocks(text or "")
    return structured_context_residue_marker_for_text(cleaned) is not None


def looks_like_internal_summary_residue(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    return any(p.search(raw) for p in INTERNAL_SUMMARY_RESIDUE_PATTERNS)


def strip_internal_residue_lines(text: str) -> str:
    """Remove lines matching internal residue patterns, keep remaining readable content."""
    if not text or not text.strip():
        return ""
    lines = text.split("\n")
    kept = []
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        if any(p.search(stripped) for p in INTERNAL_SUMMARY_RESIDUE_PATTERNS):
            continue
        kept.append(line)
    return "\n".join(kept).strip()


# ── A-Extract 1: internal-only render contract ──
# Internal labels, mechanism names, and session markers must NEVER appear
# in user-facing rendered text.  This function strips them before any
# render template interpolation.
_INTERNAL_RENDER_LABEL_RE = re.compile(
    r"(?:"
    r"\[(?:staging-promoted(?:-on-expiry)?|staging-expired|staging-reactivated)[^\]]*\]\s*"
    r"\[incident:[^\]]*\]\s*"                          # [incident:INC-xxx]
    r"|新session[開开]始[，,;；\s]*"                     # 新session開始，
    r"|hook[_\s]?判[断斷][錯错]?[误誤]?[，,;；\s]*"       # hook判断錯誤，
    r"|(?:dispatch|hook|incident|candidate|staging)[_\s]?"
    r"(?:count|type|state|buffer|record|id|reason)"     # dispatch_count etc.
    r"|(?:followup[_.]state|care_phase|event_kind|source_layer|memory_class)"
    r"|(?:routine_phase|proactive_enabled|proactive_event_kind)"
    r"|(?:current_status|staging_snapshot|session_key|content_type)"
    r"|(?:pending topic|light continuity|continuity)"
    r"|(?:held_for_followup|state_acknowledged|delegated_followup|sensitive_context_recorded)"
    r"|(?:resume_when_user_returns|watch_state_change|check_action_progress)"
    r"|(?:track_safety_and_impact|resume_when_context_fits|remember_for_later|wait_for_decision|continue_when_relevant)"
    r"|待續主題"
    r"|\|?\s*(?:state|open|focus|time|writeback):[^\s|;；,]*"
    r"|carryover_causal_context[^\n]*"
    r"|carryover_source[^\n]*"
    r"|carryover_summary_present[^\n]*"
    r"|carryover_key_quotes[^\n]*"
    r"|new_session_carryover_applied[^\n]*"
    r")",
    re.IGNORECASE,
)

def _looks_like_fragment_bundle(text: str) -> bool:
    """Detect semicolon-joined raw conversation fragment bundles.

    Fragment bundles like '妳不是才說過要跟我說完嗎；沒有；現在在講什麼；吃飽了'
    are compressed multi-turn snippets that should never appear verbatim
    in user-facing output.  They must be replaced with humanized fallback
    so the model can speak from structured continuity context instead.

    Detection criteria (any match):
    1. ≥3 parts with ≥2 short (≤4 char) parts — classic short-fragment bundle
    2. ≥5 parts — many-turn conversation dump (even if parts are longer)
    3. ≥3 parts with system instruction content — mixed conversation + instructions
    """
    if not text or len(text) < 6:
        return False
    # Split on semicolons AND ellipsis-like separators (... / … / ⋯ / ⋯⋯)
    parts = re.split(r"[；;]|\.{2,}|[…⋯]+", text)
    non_empty = [p.strip() for p in parts if p.strip()]
    if len(non_empty) < 3:
        return False
    short_parts = sum(1 for p in non_empty if len(p) <= 4)
    # Classic: ≥3 parts with ≥2 short fragments
    if short_parts >= 2:
        return True
    # Many-turn dump: ≥5 semicolon parts is almost always a conversation dump
    if len(non_empty) >= 5:
        return True
    # System instruction mix: ≥3 parts with system instructions present
    if any(_SYSTEM_INSTRUCTION_RE.search(p) for p in non_empty):
        return True
    return False


_RAW_SUMMARY_FALLBACK = "你前面提到的事"

def _looks_like_raw_summary(text: str) -> bool:
    """Detect raw internal summary text that should not be rendered as-is.

    Raw summaries are compressed notes (e.g. '對方說看訊息很累希望分段回覆')
    written in third-person without natural punctuation.  They must never
    appear directly in user-facing 「」 quotes or template slots.
    """
    if not text or len(text) < 6:
        return False
    # Has sentence-ending punctuation or question particles → likely natural language, not raw
    if re.search(r"[。！？!?嗎呢吧啊]", text):
        return False
    # Starts with relationship/pronoun + 說/说 → third-person note
    # But exclude direct-address patterns like 妳不是才說/你說過 (natural speech)
    if re.match(r"(?:你|他|她|對方|使用者|用[戶户]|[\u4e00-\u9fff]{2,4})(?:說|说)", text):
        # Natural speech: direct address with negation or question intent
        if re.match(r"(?:你|妳)(?:不是|說過|是不是|怎麼)", text):
            return False
        return True
    # Multiple compressed verbs with no connector → note-style
    if re.search(r"(?:說|说).{2,8}(?:希望|想要|需要|覺得|觉得|不想|不要|要求)", text):
        return True
    return False


def strip_internal_labels_for_render(text: str) -> str:
    """Strip internal labels/markers from text before render template interpolation.

    If the cleaned text still looks like a raw internal summary (not natural
    speech), replace with a humanized fallback.
    """
    if not isinstance(text, str) or not text.strip():
        return text
    cleaned = _INTERNAL_RENDER_LABEL_RE.sub("", text)
    cleaned = re.sub(r"^[，,;；\s]+", "", cleaned)
    cleaned = re.sub(r"\s{2,}", " ", cleaned).strip()
    if not cleaned:
        return _RAW_SUMMARY_FALLBACK
    # B-Stop 2: fragment check first — fragments contain natural speech that
    # would false-positive on raw-summary detection
    if _looks_like_fragment_bundle(cleaned):
        humanized = _humanize_fragment_summary(cleaned)
        return humanized if humanized else _RAW_SUMMARY_FALLBACK
    if _looks_like_raw_summary(cleaned):
        return _RAW_SUMMARY_FALLBACK
    return cleaned


def sanitize_runtime_residue_text(text: str, max_len: int = 160) -> str:
    cleaned = strip_untrusted_metadata_blocks(str(text or ""))
    cleaned = re.sub(r"</?final>", "", cleaned, flags=re.I)
    cleaned = re.sub(r"\[\[[^\]]+\]\]", "", cleaned)
    cleaned = re.sub(r"\b(?:Replied message|Conversation info|Sender)\s*\(untrusted[^)]*\)?\s*:?", "", cleaned, flags=re.I)
    cleaned = re.sub(r"\bfor context\)\s*:?", "", cleaned, flags=re.I)
    cleaned = re.sub(r"\bjson\s*\{\s*\"(?:sender_label|message_id|sender_id|sender|body|text|hook_id|source|type)\"[^|；;\n]*", "", cleaned, flags=re.I)
    cleaned = re.sub(r"\"(?:sender_label|message_id|sender_id|sender|body|text|hook_id|source|type)\"\s*:\s*\"?[^|；;\n]*", "", cleaned, flags=re.I)
    cleaned = re.sub(r"^\s*Read HEARTBEAT\.md.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"^\s*Current time:.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"^\s*Reply with ONLY the slug,.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"Remembering this platform action and result; will pick up next steps on return\.?", "", cleaned, flags=re.I)
    cleaned = re.sub(r"Continue from login, posting, commenting, or interaction results\.?", "", cleaned, flags=re.I)
    cleaned = re.sub(r"\s+", " ", cleaned).strip(" \n\t;；|")
    if not cleaned:
        return ""
    if structured_context_residue_marker_for_text(cleaned):
        return ""
    if any(pattern.search(cleaned) for pattern in INTERNAL_SUMMARY_RESIDUE_PATTERNS):
        return ""
    if looks_like_continuity_pollution_text(cleaned):
        return ""
    if len(cleaned) > max_len:
        cleaned = cleaned[: max_len - 1].rstrip() + "…"
    return cleaned


INTERNAL_CONTROL_TEXT_PATTERNS = [
    re.compile(r"^\s*\[cron:[^\]]+\]", re.I),
    re.compile(r"Read HEARTBEAT\.md", re.I),
    re.compile(r"Current time:", re.I),
    re.compile(r"Reply with ONLY the slug", re.I),
    re.compile(r"Run your Session Startup sequence", re.I),
    re.compile(r"A new session was started via /new or /reset", re.I),
    re.compile(r"<(?:inherited-rules|relevant-memories)>", re.I),
    re.compile(r"trusted structured state", re.I),
    re.compile(r"Stable rules inherited from ", re.I),
    re.compile(r"Remembering this platform action and result; will pick up next steps on return", re.I),
    re.compile(r"Continue from login, posting, commenting, or interaction results", re.I),
    re.compile(r"Personal Hooks Checker", re.I),
    # Internal operational seed sentinels that must never enter tracked flow.
    re.compile(r"^\s*(?:早安\s+)?cron(?:\s+任務執行)?\s*$", re.I),
    re.compile(r"^\s*(?:heartbeat(?:_ok)?|no[_\s-]?hook|no[_\s-]?reply|context-refresh)\s*$", re.I),
    re.compile(r"^\s*(?:backup|備份|备份)(?:任務|任务)?(?:執行|执行|完成|成功|ok)?\s*$", re.I),
]


def looks_like_internal_control_text(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    if structured_context_residue_marker_for_text(raw):
        return True
    if any(pattern.search(raw) for pattern in INTERNAL_CONTROL_TEXT_PATTERNS):
        return True
    if any(pattern.search(raw) for pattern in STARTUP_LEAK_PATTERNS):
        return True
    if any(pattern.search(raw) for pattern in META_REPORT_PATTERNS):
        return True
    if any(pattern.search(raw) for pattern in NEW_SESSION_BOOTSTRAP_PATTERNS):
        return True

    cleaned = strip_untrusted_metadata_blocks(raw)
    cleaned = strip_internal_residue_lines(cleaned)
    cleaned = re.sub(r"^\s*Read HEARTBEAT\.md.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"^\s*Current time:.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"^\s*Reply with ONLY the slug,.*$", "", cleaned, flags=re.M | re.I)
    cleaned = re.sub(r"\s+", " ", cleaned).strip(" \n\t;；|")
    if not cleaned:
        return True
    if looks_like_internal_summary_residue(cleaned):
        return True
    return False


def hook_has_canonical_delivery_confirmation(hook: Optional[dict]) -> bool:
    if not isinstance(hook, dict):
        return False
    payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
    if parse_optional_dt(payload.get("last_delivery_confirmed_at")) is not None:
        return True
    channel = str(payload.get("last_dispatch_channel") or "").strip()
    if channel:
        return True
    if parse_optional_dt(hook.get("last_delivery_at")) is not None:
        return True
    return False


def sanitize_event_chain_payload(event_chain: dict) -> dict:
    if not isinstance(event_chain, dict):
        return {}
    def _sanitize(value):
        if isinstance(value, str):
            text = value
            if _summary_contains_raw_json(text):
                text = _strip_raw_json_from_summary(text)
            return sanitize_runtime_residue_text(text, 320)
        if isinstance(value, dict):
            nested = {}
            for key, item in value.items():
                sanitized = _sanitize(item)
                if isinstance(sanitized, str):
                    if sanitized:
                        nested[key] = sanitized
                elif sanitized not in (None, {}, []):
                    nested[key] = sanitized
            return nested
        if isinstance(value, list):
            items = []
            for item in value:
                sanitized = _sanitize(item)
                if isinstance(sanitized, str):
                    if sanitized:
                        items.append(sanitized)
                elif sanitized not in (None, {}, []):
                    items.append(sanitized)
            return items
        return value

    cleaned = _sanitize(event_chain)
    return cleaned if isinstance(cleaned, dict) else {}


def sanitize_carryover_store(carryover: dict) -> dict:
    if not isinstance(carryover, dict):
        return {}
    cleaned_store = {}
    _now = now_local()
    for session_key, payload in carryover.items():
        if not isinstance(payload, dict):
            continue
        if ":heartbeat" in str(session_key or ""):
            continue
        # ── Stale locked carryover TTL: auto-expire applied carryovers older than 48h ──
        if payload.get("new_session_carryover_applied") and payload.get("locked_for_new_session"):
            _applied_at = payload.get("last_applied_at") or payload.get("updated_at")
            if isinstance(_applied_at, str):
                try:
                    if parse_dt(_applied_at) < _now - timedelta(hours=48):
                        continue
                except Exception:
                    pass
        messages = []
        raw_messages = payload.get("messages") if isinstance(payload.get("messages"), list) else []
        for message in raw_messages:
            if not isinstance(message, dict):
                continue
            role = message.get("role")
            text = sanitize_runtime_residue_text(message.get("text") or "", 200)
            if role == "assistant" and re.match(
                r"^(?:The user\b|I should\b|I'll\b|Let me\b|使用者|用戶|我(?:記得|來|應該|會|想|要|先|幫)|讓我)",
                text,
            ):
                text = ""
            if role not in {"user", "assistant"} or not text:
                continue
            messages.append({**message, "text": text})
        preferred_messages = [
            item
            for item in messages
            if item.get("role") == "user" and is_carryover_anchor_eligible_text(item.get("text", ""))
        ]
        assistant_only = bool(messages) and not preferred_messages and all(item.get("role") == "assistant" for item in messages)
        summary = ""
        if preferred_messages:
            summary = " | ".join(
                f"{'你' if item.get('role') == 'user' else '我'}：{item.get('text')}"
                for item in preferred_messages[-4:]
            )[:280]
        if not summary:
            summary = sanitize_runtime_residue_text(payload.get("summary") or "", 280)
            if summary and not is_carryover_anchor_eligible_text(summary):
                summary = ""
            if re.search(r"(?:\bThe user\b|\bI should\b|\bI'll\b|\bLet me\b|^使用者|^用戶|^我(?:記得|來|應該|會|想|要|先|幫)|^讓我)", summary, re.I):
                summary = ""
        if assistant_only:
            summary = ""
        key_quotes = []
        preferred_quotes = [item.get("text") for item in preferred_messages if item.get("role") == "user"]
        raw_quotes = preferred_quotes[:2] if preferred_quotes else (payload.get("key_quotes", []) if isinstance(payload.get("key_quotes"), list) else [])
        for quote in raw_quotes:
            sanitized = sanitize_runtime_residue_text(quote, 140)
            if sanitized and is_carryover_anchor_eligible_text(sanitized):
                key_quotes.append(sanitized)
        if not summary and not key_quotes and not preferred_messages:
            continue
        summary_focus = build_anchor_excerpt(re.sub(r"^(?:你|我)：", "", summary).strip()) if summary else (key_quotes[-1] if key_quotes else "")
        cleaned_messages = _carryover_anchor_turns_snapshot(messages, summary_focus, limit_turns=4) if messages else []
        trace = payload.get("daily_memory_trace") if isinstance(payload.get("daily_memory_trace"), dict) else {}
        cleaned_trace = dict(trace) if isinstance(trace, dict) else {}
        if cleaned_trace:
            context_turns = [
                normalize_story_text(str(item or "").strip(), 120)
                for item in (cleaned_trace.get("context_turns") or [])
                if str(item or "").strip() and is_carryover_anchor_eligible_text(str(item or "").strip())
            ]
            if context_turns:
                cleaned_trace["context_turns"] = context_turns[:4]
            elif "context_turns" in cleaned_trace:
                cleaned_trace.pop("context_turns", None)
            trace_turns = _carryover_anchor_turns_snapshot(cleaned_trace.get("dialogue_turns") or [], summary_focus, limit_turns=4)
            cleaned_trace["dialogue_turns"] = cleaned_messages or trace_turns
            if summary_focus and isinstance(cleaned_trace.get("note"), str) and "待放主題：" in cleaned_trace["note"]:
                cleaned_trace["note"] = re.sub(r"(待放主題：).*$", rf"\1{summary_focus}", cleaned_trace["note"])
        cleaned_store[str(session_key)] = {
            **payload,
            "messages": cleaned_messages or messages,
            "summary": summary,
            "key_quotes": key_quotes,
            "summary_present": bool(summary),
            "assistant_only": assistant_only,
            "daily_memory_trace": cleaned_trace or payload.get("daily_memory_trace"),
        }
    return cleaned_store


def extract_text_from_message(message: dict) -> str:
    content = message.get("content")
    if not isinstance(content, list):
        return ""
    texts = []
    for item in content:
        if isinstance(item, dict) and item.get("type") == "text" and isinstance(item.get("text"), str):
            texts.append(item["text"])
    return strip_untrusted_metadata_blocks("\n".join(texts)).strip()


def last_user_interaction():
    if not SESSIONS_INDEX_PATH.exists():
        return None
    try:
        sessions = json.loads(SESSIONS_INDEX_PATH.read_text(encoding="utf-8"))
    except Exception:
        return None
    entry = sessions.get(PRIMARY_SESSION_KEY) if PRIMARY_SESSION_KEY else None
    if not isinstance(entry, dict):
        for key, value in sessions.items():
            if isinstance(key, str) and isinstance(value, dict):
                if SESSION_KEY_PREFIX and key.startswith(SESSION_KEY_PREFIX):
                    entry = value
                    break
                if not SESSION_KEY_PREFIX and ":direct:" in key:
                    entry = value
                    break
    if not isinstance(entry, dict):
        return None
    session_file = entry.get("sessionFile")
    if not isinstance(session_file, str):
        return None
    rows = parse_jsonl_lines(Path(session_file))
    last = None
    for row in rows:
        if row.get("type") != "message":
            continue
        message = row.get("message")
        if not isinstance(message, dict) or message.get("role") != "user":
            continue
        ts = row.get("timestamp")
        if not isinstance(ts, str):
            continue
        try:
            dt = parse_dt(ts)
        except Exception:
            continue
        text = sanitize_recent_window_turn_text(extract_text_from_message(message))
        if not text:
            continue
        if is_non_anchor_user_text(text):
            continue
        if looks_like_internal_control_text(text):
            continue
        last = {
            "timestamp": dt,
            "text": text,
            "raw": row,
        }
    return last


def trim_summary(text: str, max_len: int = 80) -> str:
    text = " ".join(text.split())
    return text[:max_len] if len(text) > max_len else text


def normalize_story_text(text: str, max_len: int = 220) -> str:
    cleaned = re.sub(r"\s+", " ", str(text or "")).strip()
    if len(cleaned) <= max_len:
        return cleaned
    return cleaned[: max_len - 1].rstrip() + "…"


def strip_leading_discourse_marker_for_opener(text: str) -> str:
    candidate = str(text or "").strip()
    if not candidate:
        return ""
    candidate = re.sub(
        r"^(?:但|可是|不過|另外|而且|然後|順便|至於|話說|回到|回頭講|再來|以及)[，、,\s]+",
        "",
        candidate,
        flags=re.I,
    )
    candidate = re.sub(
        r"^(?:(?:but|and|so|then|also|anyway|meanwhile|plus|by the way|back to)\b[\s,:-]*)+",
        "",
        candidate,
        flags=re.I,
    )
    return candidate.strip()


OPENING_PENDING_HINT_PATTERNS = [
    re.compile(pattern, re.I)
    for pattern in [
        r"還沒", r"还没", r"未", r"待", r"要補", r"要补", r"補上", r"补上", r"補完", r"补完",
        r"晚點", r"晚一点", r"等等", r"之後", r"之后", r"回頭", r"回头", r"稍後", r"稍后",
        r"卡在", r"卡住", r"沒收尾", r"没收尾", r"沒定案", r"没定案", r"還差", r"还差",
        r"still need", r"need to", r"left to", r"remaining", r"not done", r"unfinished",
        r"later", r"come back", r"follow up", r"roll back", r"rollback",
    ]
]

OPENING_SKIP_CLAUSE_PATTERNS = [
    re.compile(pattern, re.I)
    for pattern in [
        r"^先記著這件事$",
        r"^先记着这件事$",
        r"^先放著$",
        r"^先放着$",
        r"^later$",
        r"^for later$",
        r"^resume when user returns$",
        r"^held for later follow-?up$",
    ]
]


OPENING_LOW_SIGNAL_CLAUSE_PATTERNS = [
    re.compile(pattern, re.I)
    for pattern in [
        r"^起床了[。！？?!]?$",
        r"^我起床了[。！？?!]?$",
        r"^先讓我放鬆一下[。！？?!]?$",
        r"^先让我放松一下[。！？?!]?$",
        r"^晚一點再聊[。！？?!]?$",
        r"^晚一点再聊[。！？?!]?$",
        r"^晚點再聊[。！？?!]?$",
        r"^晚点再聊[。！？?!]?$",
        r"^先放著(?:吧)?[。！？?!]?$",
        r"^先放着(?:吧)?[。！？?!]?$",
        r"^先這樣(?:吧)?[。！？?!]?$",
        r"^先这样(?:吧)?[。！？?!]?$",
        r"^等等再說(?:吧)?[。！？?!…]*$",
        r"^等等再说(?:吧)?[。！？?!…]*$",
        r"^之後再聊[。！？?!]?$",
        r"^之后再聊[。！？?!]?$",
        r"^稍後再聊[。！？?!]?$",
        r"^稍后再聊[。！？?!]?$",
        r"^先忙(?:一下|一些事)?[。！？?!]?$",
        r"^later$",
        r"^talk later$",
        r"^catch up later$",
        r"^back later$",
        r"^let me unwind first$",
        r"^(?:根據|按照).{0,10}(?:我們的關係|我们的关系)[。！？?!]?$",
        r"^(?:你|妳).{0,8}(?:要聊什麼|想聊什麼|要說什麼|想說什麼)[。！？?!]?$",
        r"^(?:今天|現在)?(?:都)?在忙什麼(?:呀|啊|呢)?[。！？?!]?$",
        r"^(?:倒是)?想問問(?:你|妳)?[，, ]*(?:今天|現在)?(?:都)?在忙什麼(?:呀|啊|呢)?[。！？?!]?$",
    ]
]


def is_low_signal_opener_clause(text: str) -> bool:
    cleaned = normalize_story_text(text, 120)
    if not cleaned:
        return True
    if any(pattern.search(cleaned) for pattern in OPENING_LOW_SIGNAL_CLAUSE_PATTERNS):
        return True
    semantic_tail = re.sub(
        r"(先|晚點|晚一点|晚一點|等等|之後|之后|稍後|稍后|再|聊|說|说|吧|一下|一些事|我|先忙|放鬆|放松|起床了|later|talk|catch up|back|unwind|first)",
        "",
        cleaned,
        flags=re.I,
    )
    semantic_tail = re.sub(r"[\s，,。！？!?；;、:：…]", "", semantic_tail)
    if len(semantic_tail) <= 2 and any(
        token in cleaned
        for token in (
            "先讓我放鬆一下",
            "先让我放松一下",
            "晚一點再聊",
            "晚一点再聊",
            "先放著",
            "先放着",
            "起床了",
            "先忙",
            "later",
            "talk later",
        )
    ):
        return True
    return False


def _opener_clause_candidates(record: Optional[dict], anchor_text: str = "") -> list[str]:
    if not isinstance(record, dict):
        return [anchor_text] if anchor_text else []
    event_chain = record.get("event_chain") if isinstance(record.get("event_chain"), dict) else {}
    causal = event_chain.get("causal_memory") if isinstance(event_chain.get("causal_memory"), dict) else {}
    dialogue_turns = resolve_record_anchor_turns(record)
    dialogue_assistant_items = [str(item.get("text") or "").strip() for item in dialogue_turns if isinstance(item, dict) and item.get("role") == "assistant"]
    dialogue_user_items = [str(item.get("text") or "").strip() for item in dialogue_turns if isinstance(item, dict) and item.get("role") == "user"]
    raw_items: list[str] = []
    raw_items.extend(
        [
            str(event_chain.get("context_before") or "").strip(),
            str(event_chain.get("event_core") or "").strip(),
            str(record.get("anchor_excerpt") or "").strip(),
            str(record.get("normalized_seed_summary") or "").strip(),
            str(record.get("source_seed_text") or "").strip(),
            str(anchor_text or "").strip(),
        ]
    )
    raw_items.extend(dialogue_assistant_items)
    raw_items.extend(dialogue_user_items)
    raw_items.extend(str(item or "").strip() for item in sanitize_recent_user_context_list(record.get("recent_user_context")))
    raw_items.extend(str(item or "").strip() for item in (causal.get("facts") or []) if isinstance(item, str))
    clauses: list[str] = []
    seen: set[str] = set()
    for item in raw_items:
        cleaned = strip_internal_labels_for_render(item)
        if not cleaned:
            continue
        for clause in split_story_clauses(cleaned) or [cleaned]:
            normalized_clause = strip_leading_discourse_marker_for_opener(normalize_story_text(clause, 120))
            match_key = normalize_text_for_match(normalized_clause)
            if not normalized_clause or not match_key or match_key in seen:
                continue
            if is_meta_return_signal_text(normalized_clause):
                continue
            if any(pattern.search(normalized_clause) for pattern in OPENING_SKIP_CLAUSE_PATTERNS):
                continue
            if is_low_signal_opener_clause(normalized_clause):
                continue
            seen.add(match_key)
            clauses.append(normalized_clause)
    return clauses


def _normalize_subject_clause_for_opener(clause: str) -> str:
    cleaned = strip_leading_discourse_marker_for_opener(clause)
    cleaned = re.sub(r"^(?:我現在(?:人?在|正在|在)?|我(?:那時候)?(?:正在|在|還在)?|那時候我(?:正在|在)?|當時我(?:正在|在)?|當時(?:正在|在)?|現在(?:人?在|正在|在)?)(?=\S)", "", cleaned)
    cleaned = re.sub(r"^(?:在|正在)(?=\S)", "", cleaned)
    cleaned = re.sub(r"^(?:(?:I|we|you)\s+(?:was|were)\s+(?:in\s+the\s+middle\s+of\s+)?|I'?m\s+|we'?re\s+|you'?re\s+)", "", cleaned, flags=re.I)
    return cleaned.strip(" ，,。")


def _looks_like_question_clause_for_opener(clause: str) -> bool:
    text = str(clause or "").strip()
    if not text:
        return False
    if "？" in text or "?" in text:
        return True
    if re.search(r"(?:嗎|么)$", text):
        return True
    if re.search(r"(?:要聊什麼|想聊什麼|要說什麼|想說什麼|在忙什麼|去哪裡|去哪里|怎麼|怎么|為什麼|为什么|要不要|是不是|還記得嗎|记得吗)$", text):
        return True
    if re.match(r"(?i)^(?:what|where|why|how|when|do you|did you|are you|can you)\b", text):
        return True
    return False


def _looks_like_profile_setup_clause_for_opener(clause: str) -> bool:
    text = str(clause or "").strip()
    if not text:
        return False
    lowered = text.lower()
    if any(token in text for token in ("時區", "通常", "起床", "睡", "同事", "工作追蹤", "紐約", "台北", "台灣", "人在")):
        return True
    if any(
        token in lowered
        for token in (
            "timezone",
            "coworker",
            "project-tracking",
            "for work",
            "sleep around",
            "wake around",
            "wake up around",
            "usually sleep",
            "usually wake",
            "america/new_york",
            "utc+",
            "gmt+",
        )
    ):
        return True
    return False


def _normalize_pending_clause_for_opener(clause: str) -> str:
    cleaned = strip_leading_discourse_marker_for_opener(clause)
    replacements = [
        (r"我晚點還要", "還要"),
        (r"我之後還要", "還要"),
        (r"我還要", "還要"),
        (r"我還得", "還得"),
        (r"我得再", "得再"),
        (r"我得", "得"),
        (r"我之後要", "之後要"),
    ]
    for pattern, repl in replacements:
        cleaned = re.sub(pattern, repl, cleaned)
    cleaned = re.sub(r"^(?:(?:I|we)\s+still\s+need\s+to\s+)", "still need to ", cleaned, flags=re.I)
    cleaned = re.sub(r"^(?:(?:I|we)\s+need\s+to\s+)", "need to ", cleaned, flags=re.I)
    return cleaned.strip(" ，,。")


def _select_pending_clause_for_opener(clauses: list[str]) -> str:
    for clause in reversed(clauses):
        if any(pattern.search(clause) for pattern in OPENING_PENDING_HINT_PATTERNS):
            return _normalize_pending_clause_for_opener(clause)
    if clauses:
        return _normalize_pending_clause_for_opener(clauses[-1])
    return ""


def _select_user_pending_clause_for_opener(record: Optional[dict], anchor_text: str = "") -> str:
    if not isinstance(record, dict):
        return ""
    raw_items: list[str] = []
    dialogue_turns = resolve_record_anchor_turns(record)
    raw_items.extend(
        str(item.get("text") or "").strip()
        for item in dialogue_turns
        if isinstance(item, dict) and item.get("role") == "user"
    )
    raw_items.extend(str(item or "").strip() for item in sanitize_recent_user_context_list(record.get("recent_user_context"), limit_turns=4))
    raw_items.extend(
        item for item in [
            str(anchor_text or "").strip(),
            str(record.get("anchor_excerpt") or "").strip(),
            str(record.get("normalized_seed_summary") or "").strip(),
            str(record.get("source_seed_text") or "").strip(),
        ] if item
    )
    seen: set[str] = set()
    clauses: list[str] = []
    for item in raw_items:
        cleaned = strip_internal_labels_for_render(item)
        if not cleaned:
            continue
        for clause in split_story_clauses(cleaned) or [cleaned]:
            normalized_clause = strip_leading_discourse_marker_for_opener(normalize_story_text(clause, 120))
            match_key = normalize_text_for_match(normalized_clause)
            if not normalized_clause or not match_key or match_key in seen:
                continue
            if is_meta_return_signal_text(normalized_clause):
                continue
            if is_low_signal_opener_clause(normalized_clause):
                continue
            seen.add(match_key)
            clauses.append(normalized_clause)
    for clause in reversed(clauses):
        if any(pattern.search(clause) for pattern in OPENING_PENDING_HINT_PATTERNS):
            return _normalize_pending_clause_for_opener(clause)
    return ""


def _select_subject_clause_for_opener(clauses: list[str], pending_clause: str) -> str:
    pending_key = normalize_text_for_match(pending_clause)
    for clause in clauses:
        candidate = _normalize_subject_clause_for_opener(clause)
        if not candidate:
            continue
        if _looks_like_question_clause_for_opener(candidate):
            continue
        if _looks_like_profile_setup_clause_for_opener(candidate):
            continue
        candidate_key = normalize_text_for_match(candidate)
        if not candidate_key or candidate_key == pending_key:
            continue
        if any(pattern.search(candidate) for pattern in OPENING_PENDING_HINT_PATTERNS):
            continue
        return candidate
    return ""


def _pending_clause_is_self_predicative(clause: str) -> bool:
    return bool(
        clause
        and re.search(
            r"(還要|还要|還沒|还没|未|待|要補|要补|補上|补上|later|still need|need to|left to|remaining|unfinished|still missing|missing)",
            clause,
            flags=re.I,
        )
    )


def build_causal_rejoin_line(record: Optional[dict], reference_word: str, *, anchor_text: str = "", use_english: bool = False) -> str:
    clauses = _opener_clause_candidates(record, anchor_text=anchor_text)
    event_kind = str((record or {}).get("event_kind") or "").strip()
    pending_clause = _select_user_pending_clause_for_opener(record, anchor_text=anchor_text)
    if not pending_clause and event_kind != "parked_topic":
        pending_clause = _select_pending_clause_for_opener(clauses)
    subject_clause = _select_subject_clause_for_opener(clauses, pending_clause)
    if event_kind == "parked_topic" and subject_clause and ("？" in subject_clause or "?" in subject_clause):
        subject_clause = ""
    if use_english:
        if subject_clause and pending_clause:
            if _pending_clause_is_self_predicative(pending_clause):
                return f"I still have that earlier thread in mind. You were in the middle of {subject_clause}, and {pending_clause}."
            return f"I still have that earlier thread in mind. You were in the middle of {subject_clause}, and {pending_clause} still seems to be the missing step."
        if pending_clause:
            if _pending_clause_is_self_predicative(pending_clause):
                return f"I still have that earlier thread in mind. {pending_clause}."
            return f"I still have that earlier thread in mind. {pending_clause} still seems to be the piece hanging there."
        if subject_clause:
            return f"I still have that earlier thread in mind around {subject_clause}."
        return ""
    if subject_clause and pending_clause:
        if _pending_clause_is_self_predicative(pending_clause):
            return f"我還接著你{reference_word}那條主線。你那時候在{subject_clause}，而且 {pending_clause}。"
        return f"我還接著你{reference_word}那條主線。你那時候在{subject_clause}，而且 {pending_clause} 這一步還掛著。"
    if pending_clause:
        if _pending_clause_is_self_predicative(pending_clause):
            return f"我還接著你{reference_word}那條主線。{pending_clause}。"
        return f"我還接著你{reference_word}那條主線。{pending_clause} 這一步還掛著。"
    if subject_clause:
        return f"我還接著你{reference_word}那條主線，當時是在{subject_clause}。"
    return ""


def build_time_sense_lead(
    time_state: Optional[dict],
    *,
    use_english: bool = False,
    allow_time_lead: bool = False,
    unresolved: bool = False,
) -> str:
    if not allow_time_lead or not isinstance(time_state, dict) or not unresolved:
        return ""
    phase = str(time_state.get("phase") or "active_day")
    next_transition_kind = str(time_state.get("next_transition_kind") or "").strip()
    next_transition_dt = parse_optional_dt(time_state.get("next_transition_at"))
    local_now = parse_optional_dt(time_state.get("now_local")) or now_local()
    minutes_to_transition = None
    if next_transition_dt is not None:
        minutes_to_transition = max(int((next_transition_dt - local_now).total_seconds() // 60), 0)
    late_hour = local_now.hour >= 23 or local_now.hour < 6
    early_hour = 5 <= local_now.hour < 9
    if use_english:
        if phase == "sleep":
            return "It's getting late, and this still sounds like it's hanging there."
        if next_transition_kind == "sleep" and minutes_to_transition is not None and minutes_to_transition <= 60:
            return "You're getting close to your usual wind-down point, and this thread still sounds unfinished."
        if phase == "wake_window" or early_hour:
            return "You're here pretty early, and this still sounds like it's on your mind."
        if late_hour:
            return "At this hour, it still sounds like this thread is hanging there."
        return ""
    if phase == "sleep":
        return "都這個時間了，這條線大概還掛在你心上。"
    if next_transition_kind == "sleep" and minutes_to_transition is not None and minutes_to_transition <= 60:
        return "差不多快到你平常收尾的時間了，這條線看起來還掛著。"
    if phase == "wake_window" or early_hour:
        return "這麼早就來了，像是這條線還掛在你心上。"
    if late_hour:
        return "都這個時間了，這條線大概還掛著。"
    return ""


def split_story_clauses(text: str) -> list[str]:
    cleaned = normalize_story_text(text, 320)
    if not cleaned:
        return []
    parts = [part.strip(" ，,、。！？；;") for part in re.split(r"[，,。！？；;]+", cleaned) if part.strip(" ，,、。！？；;")]
    return [part for part in parts if part]


