def has_self_managed_tracking_decline(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    compact = re.sub(r"\s+", "", raw)
    return any(re.search(pattern, compact, re.IGNORECASE) for pattern in SELF_MANAGED_TRACKING_PATTERNS)


def strip_self_managed_tracking_clauses(text: str) -> str:
    raw = normalize_skill_source_text(text)
    if not raw:
        return ""
    kept: list[str] = []
    for clause in split_story_clauses(raw):
        cleaned = clause.strip()
        if not cleaned:
            continue
        if has_self_managed_tracking_decline(cleaned):
            continue
        kept.append(cleaned)
    return "；".join(kept).strip("； ")


def extract_post_pivot_focus_text(text: str) -> str:
    raw = normalize_skill_source_text(text)
    if not raw:
        return ""
    clauses = split_story_clauses(raw)
    if not clauses:
        return ""
    for index, clause in enumerate(clauses):
        lowered = clause.lower()
        for marker in THREAD_PIVOT_MARKERS:
            marker_lower = marker.lower()
            pos = lowered.find(marker_lower)
            if pos < 0:
                continue
            tail = clause[pos + len(marker):].strip(" ：:，,、。！？；;")
            focused: list[str] = []
            if tail:
                focused.append(tail)
            focused.extend(part for part in clauses[index + 1:] if part)
            return "；".join(focused).strip("； ")
    return ""


def looks_like_low_information_track_seed(text: str) -> bool:
    cleaned = normalize_story_text(strip_self_managed_tracking_clauses(text) or text, 160)
    if not cleaned:
        return True
    if any(pattern.fullmatch(cleaned) for pattern in _LOW_INFORMATION_TRACK_ONLY_PATTERNS):
        return True
    stripped = cleaned
    for token in (
        "幫我記著", "帮我记着", "幫我記得", "帮我记得", "幫我留意", "帮我留意",
        "替我記著", "替我记着", "放在心上", "先幫我記著", "先帮我记着",
        "之後提醒我", "之后提醒我", "再接", "再聊", "再討論", "再讨论",
    ):
        stripped = stripped.replace(token, " ")
    stripped = re.sub(
        r"(不知道|不清楚|忘了|想不起來|記不得|记不得|沒印象|没有印象|先|再|晚點|晚点|之後|之后|回來|回来|醒來後|醒来后|一下|吧|啦|喔|哦|嗎|吗|好嗎|好吗|就好|就行|就可以)",
        " ",
        stripped,
        flags=re.I,
    )
    stripped = re.sub(r"[\s，,、。！？!?；;:：…]+", "", stripped)
    return len(stripped) <= 2


def _is_low_information_focus_clause(clause: str) -> bool:
    cleaned = normalize_story_text(clause, 120)
    if not cleaned:
        return True
    if looks_like_low_information_track_seed(cleaned):
        return True
    return any(pattern.fullmatch(cleaned) for pattern in _LOW_INFORMATION_FOCUS_CLAUSE_PATTERNS)


def strip_non_focus_clauses(text: str) -> str:
    raw = normalize_skill_source_text(text)
    if not raw:
        return ""
    kept: list[str] = []
    for clause in split_story_clauses(raw):
        cleaned = clause.strip(" ：:，,、。！？；;")
        if not cleaned or _is_low_information_focus_clause(cleaned):
            continue
        kept.append(cleaned)
    return "；".join(kept).strip("； ")


def has_explicit_focus_reframe(text: str) -> bool:
    raw = normalize_skill_source_text(text)
    if not raw:
        return False
    candidate = _FOCUS_ADDRESSEE_PREFIX_RE.sub("", raw, count=1).strip()
    if not candidate:
        return False
    if re.match(r"^不是[！!，,、。；;\s]*是.+$", candidate, re.I):
        return True
    return any(pattern.match(candidate) for pattern in _EXPLICIT_FOCUS_REFRAME_PATTERNS[1:])


def extract_explicit_refocus_focus_text(text: str) -> str:
    raw = normalize_skill_source_text(text)
    if not raw:
        return ""
    candidate = _FOCUS_ADDRESSEE_PREFIX_RE.sub("", raw, count=1).strip()
    if not candidate or user_explicitly_requests_pending_recall(candidate):
        return ""
    for pattern in _EXPLICIT_FOCUS_REFRAME_PATTERNS:
        match = pattern.match(candidate)
        if not match:
            continue
        focused = str(match.group("focus") or "").strip(" ：:，,、。！？；;")
        focused = re.sub(r"^(?:是|就是|而是|要聊|要談|要谈)\s*", "", focused)
        focused = strip_non_focus_clauses(focused)
        focused = normalize_story_text(focused, 160) if focused else ""
        if focused and not looks_like_low_information_track_seed(focused):
            return focused
        return ""
    return ""


def looks_like_topic_recall_request(text: str) -> bool:
    cleaned = normalize_story_text(text, 180)
    if not cleaned:
        return False
    return bool(_TOPIC_RECALL_REQUEST_RE.search(cleaned))


def clause_has_work_focus(clause: str) -> bool:
    raw = normalize_skill_source_text(clause)
    if not raw:
        return False
    return has_work_focus_signal(raw) or has_work_unresolved_signal(raw) or has_work_next_step_signal(raw)


def has_work_focus_signal(text: str) -> bool:
    raw = normalize_skill_source_text(text)
    if not raw:
        return False
    lowered = raw.lower()
    if any(token in lowered for token in WORK_FOCUS_TOKENS):
        return True
    return any(pattern.search(raw) for pattern in WORK_FOCUS_PATTERNS)


def has_work_unresolved_signal(text: str) -> bool:
    raw = normalize_skill_source_text(text)
    if not raw:
        return False
    if any(marker in raw for marker in WORK_UNRESOLVED_MARKERS):
        return True
    return any(pattern.search(raw) for pattern in WORK_UNRESOLVED_PATTERNS)


def has_work_next_step_signal(text: str) -> bool:
    raw = normalize_skill_source_text(text)
    if not raw:
        return False
    if any(marker in raw for marker in WORK_NEXT_STEP_MARKERS):
        return True
    return any(pattern.search(raw) for pattern in WORK_NEXT_STEP_PATTERNS)


def extract_work_focus_text(text: str) -> str:
    raw = strip_self_managed_tracking_clauses(text) or normalize_skill_source_text(text)
    if not raw:
        return ""
    pivot_text = extract_post_pivot_focus_text(raw)
    candidate = pivot_text or raw
    clauses = split_story_clauses(candidate)
    focused = [clause for clause in clauses if clause_has_work_focus(clause)]
    if focused:
        return "；".join(focused).strip("； ")
    if pivot_text and looks_like_natural_unresolved_work_item(pivot_text):
        return pivot_text
    return candidate


def extract_tracking_focus_text(text: str, incident_type: str = "", event_kind: str = "") -> str:
    raw = normalize_skill_source_text(text)
    if not raw:
        return ""
    if user_explicitly_requests_pending_recall(raw) or looks_like_topic_recall_request(raw):
        return ""
    explicit_focus = extract_explicit_refocus_focus_text(raw)
    if explicit_focus:
        raw = explicit_focus
    work_focus = extract_work_focus_text(raw)
    if incident_type == "important_task":
        candidate = work_focus or raw
        return candidate if is_trackable_followup_focus_text(candidate) and not looks_like_low_information_track_seed(candidate) else ""
    if event_kind in {"delegated_task", "parked_topic", "self_commitment", "recurring_task"}:
        if work_focus and is_trackable_followup_focus_text(work_focus) and not looks_like_low_information_track_seed(work_focus):
            return work_focus
    if work_focus and looks_like_natural_unresolved_work_item(work_focus):
        return work_focus
    stripped = strip_self_managed_tracking_clauses(raw)
    candidate = stripped or raw
    if looks_like_low_information_track_seed(candidate):
        return ""
    if event_kind in {"delegated_task", "self_commitment", "recurring_task"}:
        return candidate if is_trackable_followup_focus_text(candidate) else ""
    return candidate


def latest_valid_user_focus_text(text: str) -> str:
    raw = sanitize_recent_window_turn_text(text)
    if not raw:
        return ""
    if user_explicitly_requests_pending_recall(raw) or looks_like_topic_recall_request(raw):
        return ""
    candidate = (
        extract_explicit_refocus_focus_text(raw)
        or extract_tracking_focus_text(raw, event_kind="parked_topic")
        or extract_work_focus_text(raw)
        or build_anchor_excerpt(raw)
    )
    candidate = normalize_story_text(candidate, 160) if candidate else ""
    if not candidate:
        return ""
    if looks_like_low_information_track_seed(candidate):
        return ""
    if looks_like_continuity_pollution_text(candidate) or looks_like_unresolved_referent_fragment(candidate):
        return ""
    if is_non_anchor_user_text(candidate) or looks_like_meta_report(candidate):
        return ""
    if is_low_information_greeting_text(candidate) or is_meta_return_signal_text(candidate):
        return ""
    return candidate


_AMBIGUOUS_FOLLOW_ON_USER_TURN_RE = re.compile(
    r"^(?:然後呢|然后呢|後來呢|后来呢|所以呢|接著呢|接着呢|那然後呢|那然后呢|那後來呢|那后来呢|"
    r"還有呢|还有呢|再來呢|再来呢|嗯哼|嗯\?|嗯？|妳說什麼|你說什麼|你说什么|妳说什么)$",
    re.I,
)

_CURRENT_FOCUS_CAPTURE_PATTERNS = (
    re.compile(r"(?:想(?:聊|討論|讨论|問|问|知道)|有沒有|有没有|有想法|有沒有想法|有没有想法|想法|建議|建议|查詢|查询|推薦|推荐)", re.I),
    re.compile(r"(?:比較重要|比较重要|重要的是|想跟.{0,8}聊|給.{0,4}討論|给.{0,4}讨论|幫我想|帮我想)", re.I),
    re.compile(r"(?:吃什麼|吃什么|怎麼選|怎么选|選哪個|选哪个)", re.I),
)


def is_ambiguous_follow_on_user_turn(text: str) -> bool:
    cleaned = normalize_story_text(text, 120)
    if not cleaned:
        return False
    normalized = normalize_text_for_match(cleaned)
    if normalized in _PENDING_RESUME_USER_TEXTS:
        return True
    return bool(_AMBIGUOUS_FOLLOW_ON_USER_TURN_RE.fullmatch(cleaned))


def current_turn_blocks_stale_pending(text: str, focus_text: str = "") -> bool:
    raw = normalize_skill_source_text(text)
    focus = normalize_story_text(focus_text or latest_valid_user_focus_text(text), 160)
    if not raw or not focus:
        return False
    if user_explicitly_requests_pending_recall(raw) or looks_like_topic_recall_request(raw):
        return False
    if is_low_information_greeting_text(raw) or is_meta_return_signal_text(raw):
        return False
    if is_ambiguous_follow_on_user_turn(raw):
        return False
    if looks_like_low_information_track_seed(focus):
        return False
    return True


def should_capture_current_focus_topic(user_text: str, focus_text: str) -> bool:
    raw = normalize_skill_source_text(user_text)
    focus = normalize_story_text(focus_text, 160)
    if not raw or not focus:
        return False
    if not current_turn_blocks_stale_pending(raw, focus):
        return False
    if looks_like_meta_report(raw) or is_non_anchor_user_text(raw) or is_operational_source_query(raw):
        return False
    if has_explicit_focus_reframe(raw):
        return True
    if any(pattern.search(raw) for pattern in _CURRENT_FOCUS_CAPTURE_PATTERNS):
        return True
    focus_key = normalize_text_for_match(focus)
    return len(focus_key) >= 10 and any(token in raw for token in ("重要", "重要的", "比較重要", "比较重要", "想聊", "討論", "讨论"))


def has_explicit_important_task_escalation(text: str) -> bool:
    raw = normalize_skill_source_text(text)
    if not raw or has_self_managed_tracking_decline(raw):
        return False
    compact = re.sub(r"\s+", "", raw)
    return any(re.search(pattern, compact, re.IGNORECASE) for pattern in IMPORTANT_TASK_ESCALATION_PATTERNS)


def looks_like_natural_unresolved_work_item(text: str) -> bool:
    raw = normalize_skill_source_text(text)
    if not raw or has_self_managed_tracking_decline(raw):
        return False
    if not is_trackable_followup_focus_text(raw):
        return False
    has_work = has_work_focus_signal(raw)
    has_unresolved = has_work_unresolved_signal(raw)
    has_next_step = has_work_next_step_signal(raw)
    return (has_unresolved and (has_work or has_next_step)) or (has_work and has_next_step)


def trim_summary_at_boundary(text: str, max_len: int = 80) -> str:
    cleaned = " ".join(str(text or "").split()).strip()
    if len(cleaned) <= max_len:
        return cleaned
    excerpt = cleaned[:max_len].rstrip()
    next_char = cleaned[max_len : max_len + 1]
    if excerpt and next_char:
        excerpt_last = excerpt[-1]
        if re.match(r"[A-Za-z0-9_/-]", excerpt_last) and re.match(r"[A-Za-z0-9_/-]", next_char):
            boundary_excerpt = re.sub(r"[A-Za-z0-9_/-]+$", "", excerpt).rstrip(" ，,、；;:/")
            if len(boundary_excerpt) >= max(12, max_len // 2):
                excerpt = boundary_excerpt
    return excerpt


def summarize_anchor_text(text: str, max_len: int = 72, max_clauses: int = 3) -> str:
    cleaned = normalize_story_text(text, max(max_len * 2, 320))
    if not cleaned:
        return ""
    if len(cleaned) <= max_len:
        return cleaned
    clauses = split_story_clauses(cleaned)
    if clauses:
        selected: list[str] = []
        for clause in clauses[: max(1, max_clauses)]:
            candidate = "；".join(selected + [clause])
            if len(candidate) <= max_len or not selected:
                selected.append(clause)
            else:
                break
        clause_summary = "；".join(selected).strip()
        if clause_summary and len(clause_summary) <= max_len:
            return clause_summary
    return trim_summary_at_boundary(cleaned, max_len)


def is_low_signal_new_session_anchor_text(text: str) -> bool:
    cleaned = normalize_story_text(text, 120)
    if not cleaned:
        return True
    if looks_like_low_information_track_seed(cleaned):
        return True
    if is_low_signal_opener_clause(cleaned):
        return True
    if re.search(r"昨天[^。！？!?]{0,24}今天|今天[^。！？!?]{0,24}昨天", cleaned):
        return True
    if re.fullmatch(r"(?:昨天|今天|昨晚|今晚|早上|晚上|凌晨|中午|下午)[^。！？!?]{0,12}(?:事情|那件事|這件事)", cleaned):
        return True
    temporal_heavy = re.sub(r"(昨天|今天|昨晚|今晚|早上|晚上|凌晨|中午|下午|明明|就是|就|的|那件事|這件事|事情|前面|之前|剛剛|剛才|昨夜|今早|今晚)", "", cleaned)
    temporal_heavy = re.sub(r"[\s，,。！？!?；;、:：]", "", temporal_heavy)
    if any(token in cleaned for token in ("昨天", "今天", "昨晚", "今晚", "早上", "晚上", "凌晨")) and len(temporal_heavy) <= 2:
        return True
    return False


def record_has_trusted_user_side_signal(record: Optional[dict]) -> bool:
    if not isinstance(record, dict):
        return False
    if sanitize_recent_user_context_list(record.get("recent_user_context")):
        return True
    anchor_turns = resolve_record_anchor_turns(record)
    if any(
        isinstance(item, dict)
        and item.get("role") == "user"
        and is_carryover_anchor_eligible_text(str(item.get("text") or "").strip())
        for item in anchor_turns
    ):
        return True
    daily_trace = record.get("daily_memory_trace") if isinstance(record.get("daily_memory_trace"), dict) else {}
    trace_turns = load_dialogue_turns_from_daily_memory_trace(daily_trace)
    if any(
        isinstance(item, dict)
        and item.get("role") == "user"
        and is_carryover_anchor_eligible_text(str(item.get("text") or "").strip())
        for item in trace_turns
    ):
        return True
    return False


def is_frontstage_eligible_new_session_record(record: Optional[dict], anchor_text: str = "") -> bool:
    if not isinstance(record, dict):
        return False
    summary = str(
        anchor_text
        or record.get("anchor_excerpt")
        or record.get("normalized_seed_summary")
        or record.get("source_seed_text")
        or ""
    ).strip()
    if not summary:
        return False
    if _summary_contains_raw_json(summary):
        return False
    if is_low_signal_new_session_anchor_text(summary):
        return False
    if is_meta_return_signal_text(summary):
        return False
    event_kind = str(record.get("event_kind") or "").strip()
    source_layer = str(record.get("source_layer") or "").strip().lower()
    current_status = str(record.get("current_status") or record.get("status") or "").strip().lower()
    event_chain = record.get("event_chain") if isinstance(record.get("event_chain"), dict) else {}
    followup_focus_code = str(
        event_chain.get("followup_focus_code")
        or ((event_chain.get("causal_memory") or {}).get("followup_focus_code") if isinstance(event_chain.get("causal_memory"), dict) else "")
        or ""
    ).strip()
    trusted_user_side = record_has_trusted_user_side_signal(record)
    has_real_dispatch = any(
        str(record.get(key) or "").strip()
        for key in ("dispatched_text", "last_rendered_message", "last_dispatch_reason")
    )
    if event_kind == "parked_topic":
        if followup_focus_code in {"resume_when_context_fits", "resume_when_user_returns"} and not trusted_user_side and not has_real_dispatch:
            return False
        if source_layer == "hook" and current_status in {"hook_ready", "active_followup"} and not trusted_user_side and not has_real_dispatch:
            return False
    return True


def infer_followup_event_type(
    text: str,
    signal: Optional[dict] = None,
    incident_type: Optional[str] = None,
    incident_detection: Optional[dict] = None,
) -> str:
    normalized = str(text or "")
    if incident_type in {"safety_incident", "health_incident"}:
        return "sensitive_event"
    if incident_type == "emotional_incident":
        return "watchful_state"
    if incident_type == "important_task":
        return "delegated_task"
    # ── A-Extract 7: phrase family → event_kind (from signal or direct match) ──
    if signal and isinstance(signal.get("phrase_family"), dict):
        return signal["phrase_family"]["event_kind"]
    if not signal and not incident_type and not incident_detection:
        family = match_phrase_family(text)
        if family:
            return family["event_kind"]
    if signal:
        signal_type = signal.get("signal_type")
        intent = signal.get("intent")
        topic = str(signal.get("topic") or "")
        if signal_type == "emotion" or topic in {"累", "陪伴", "支持"}:
            return "watchful_state"
        if intent in {"delegate_to_assistant", "track_for_me"}:
            return "delegated_task"
        if intent in {"memory_overload", "pause_but_keep"} and any(token in normalized for token in ["幫我", "交給妳", "處理", "查", "整理"]):
            return "delegated_task"
    if incident_detection and incident_detection.get("detected"):
        return infer_followup_event_type(
            text,
            signal=signal,
            incident_type=incident_detection.get("incident_type"),
            incident_detection=None,
        )
    if any(token in normalized for token in ["住院", "跌倒", "車禍", "流血", "急診", "受傷", "送醫", "家裡有事"]):
        return "sensitive_event"
    if any(token in normalized for token in [
        "很累", "不想說", "先不想講", "悶", "難受", "心情", "先別碰", "先休息",
        "低落", "消沉", "提不起勁", "心很累", "沮喪",
        "先不用管", "先別管", "不想被打擾", "讓我靜", "先不聊",
    ]):
        return "watchful_state"
    if any(token in normalized for token in ["幫我查", "幫我處理", "幫我整理", "妳先去查", "妳先去弄", "交給妳"]):
        return "delegated_task"
    return "parked_topic"


def build_event_chain(text: str, event_kind: str, topic_label: str = "") -> dict:
    cleaned_text = normalize_skill_source_text(text)
    clauses = split_story_clauses(cleaned_text)
    joined = normalize_story_text(cleaned_text, 220)
    context_before = clauses[0] if len(clauses) >= 2 else ""
    event_core = clauses[-1] if clauses else joined
    causal_memory = build_causal_memory(cleaned_text, event_kind, topic_label=topic_label)
    if not event_core:
        event_core = topic_label or "pending topic"
    immediate_code = IMMEDIATE_RESULT_CODE_MAP.get(event_kind, "held_for_followup")
    followup_focus_code = str(causal_memory.get("followup_focus_code") or "continue_when_relevant")
    return {
        "context_before": context_before,
        "event_core": event_core,
        "immediate_result_code": immediate_code,
        "immediate_result": IMMEDIATE_RESULT_HINT_MAP.get(immediate_code, "Held with room for follow-up."),
        "followup_focus_code": followup_focus_code,
        "followup_focus": str(causal_memory.get("followup_focus") or FOLLOWUP_FOCUS_HINT_MAP["continue_when_relevant"]),
        "causal_memory": causal_memory,
    }


def merge_event_chain(existing: Optional[dict], text: str, event_kind: str, topic_label: str = "") -> dict:
    base = existing if isinstance(existing, dict) else {}
    fresh = build_event_chain(text, event_kind, topic_label=topic_label)
    base_context = str(base.get("context_before") or "").strip()
    fresh_context = str(fresh.get("context_before") or "").strip()
    if fresh_context and fresh_context not in base_context:
        merged_context = "；".join(part for part in [base_context, fresh_context] if part)
    else:
        merged_context = base_context or fresh_context
    base_event = str(base.get("event_core") or "").strip()
    fresh_event = str(fresh.get("event_core") or "").strip()
    if fresh_event and fresh_event not in base_event:
        merged_event = "；".join(part for part in [base_event, fresh_event] if part)
    else:
        merged_event = base_event or fresh_event
    merged = {
        "context_before": merged_context,
        "event_core": merged_event,
        "immediate_result_code": base.get("immediate_result_code") or fresh.get("immediate_result_code") or "held_for_followup",
        "immediate_result": base.get("immediate_result") or fresh["immediate_result"],
    }
    base_focus = str(base.get("followup_focus") or "").strip()
    fresh_focus = str(fresh.get("followup_focus") or "").strip()
    if fresh_focus and fresh_focus not in base_focus:
        merged["followup_focus"] = "；".join(part for part in [base_focus, fresh_focus] if part)
    else:
        merged["followup_focus"] = base_focus or fresh_focus
    merged["followup_focus_code"] = base.get("followup_focus_code") or fresh.get("followup_focus_code") or "continue_when_relevant"
    # A-Extract 3: merge causal_memory
    merged["causal_memory"] = merge_causal_memory(
        base.get("causal_memory"),
        fresh.get("causal_memory", {}),
    )
    return merged


def merge_completion_event_chain(
    existing: Optional[dict],
    completion_text: str,
    event_kind: str,
    topic_label: str = "",
) -> dict:
    merged = merge_event_chain(existing, completion_text, event_kind, topic_label=topic_label)
    completion_summary = trim_summary(normalize_story_text(completion_text, 160), 80)
    causal = merged.get("causal_memory") if isinstance(merged.get("causal_memory"), dict) else {}
    causal = merge_causal_memory(
        causal,
        build_causal_memory(completion_text, event_kind, topic_label=topic_label),
    )
    causal["open_loop"] = "resolved_completion"
    causal["followup_focus_code"] = "remember_for_later"
    causal["followup_focus"] = FOLLOWUP_FOCUS_HINT_MAP["remember_for_later"]
    causal["completion_marker"] = "completed"
    if completion_summary:
        causal["completion_summary"] = completion_summary
    merged["causal_memory"] = causal
    merged["immediate_result_code"] = "task_completed"
    merged["immediate_result"] = "The user reported that this was already completed."
    return merged


def synthesize_event_chain_summary(event_chain: Optional[dict], fallback_text: str) -> str:
    if not isinstance(event_chain, dict):
        fb = normalize_story_text(fallback_text, 180)
        # B-Stop 2: humanize fragment fallback
        if _looks_like_fragment_bundle(fb):
            return _humanize_fragment_summary(fb, event_chain)
        return fb
    # A-Extract 3: prefer causal summary when available
    causal = event_chain.get("causal_memory")
    if isinstance(causal, dict) and causal.get("facts"):
        causal_result = synthesize_causal_summary(causal, fallback_text)
        if causal_result:
            # B-Stop 2: if causal synthesis still looks like a fragment, humanize
            if _looks_like_fragment_bundle(causal_result):
                return _humanize_fragment_summary(causal_result, event_chain)
            return causal_result
    parts = [
        normalize_story_text(event_chain.get("context_before", ""), 80),
        normalize_story_text(event_chain.get("event_core", ""), 100),
        normalize_story_text(event_chain.get("immediate_result", ""), 80),
    ]
    # B-Stop 2: filter out system instruction parts
    parts = [part for part in parts if part and not _SYSTEM_INSTRUCTION_RE.search(part)]
    if not parts:
        return _humanize_fragment_summary(fallback_text, event_chain) if _looks_like_fragment_bundle(fallback_text) else normalize_story_text(fallback_text, 180)
    result = "；".join(parts)
    # B-Stop 2: if joined result is still a fragment bundle, humanize
    if _looks_like_fragment_bundle(result):
        return _humanize_fragment_summary(result, event_chain)
    return result


# ────────────────────────────────────────────────────
# A-Extract 3: causal memory / continuity promotion contract
# ────────────────────────────────────────────────────

_TIME_ANCHOR_RE = re.compile(
    r"(?:今天|昨天|前天|明天|後天|上午|下午|晚上|凌晨|早上|中午|傍晚|剛剛|剛才|等一下|等等|待會|稍後|之後)"
    r"|(?:today|yesterday|tomorrow|tonight|later|soon|afterwards|this morning|this afternoon|this evening)"
    r"|(?:morning|afternoon|evening|night|midnight|noon)"
    r"|(?:\d{1,2}[：:]\d{2})"
    r"|(?:(?:週|周|星期|禮拜)[一二三四五六日天])"
    r"|(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday)"
    r"|(?:mon|tue|wed|thu|fri|sat|sun)\b"
    r"|(?:\d{1,2}[月/]\d{1,2})"
    r"|(?:上[個个]?(?:禮拜|星期|週|周))"
    r"|(?:這[個个]?(?:禮拜|星期|週|周))"
    r"|(?:下[個个]?(?:禮拜|星期|週|周))",
    re.IGNORECASE,
)

_FILLER_RE = re.compile(
    r"^(?:嗯|哦|喔|呃|啊|哈|欸|嘿|噢|唉|齁|蛤|好|OK|ok|對|是|沒有|沒|嗯嗯|好喔|好啊|好的|對啊|是啊)$",
    re.IGNORECASE,
)

_SYSTEM_INSTRUCTION_RE = re.compile(
    r"(?:先記住這次|回來時直接|直接接下一步|平台動作|先記住這次的|回來時直接接)"
    r"|(?:先记住这次|回来时直接|平台动作)"
    r"|(?:^多說一些$|^多说一些$)"
)


def _is_meaningful_clause(text: str) -> bool:
    """A clause is meaningful for continuity if it carries actual content.

    Rejects: fillers, system instructions, name-only, very short noise.
    """
    t = str(text or "").strip()
    if len(t) < 5:
        return False
    if _FILLER_RE.match(t):
        return False
    if _SYSTEM_INSTRUCTION_RE.search(t):
        return False
    return True


def _humanize_fragment_summary(text: str, event_chain: Optional[dict] = None,
                                event_kind: str = "", topic_label: str = "") -> str:
    """Transform a fragment bundle into a clean continuity reference.

    Strategy:
    1. Split fragment, filter to meaningful clauses only
    2. Pick top clauses by length (most informative)
    3. Join with natural connector
    4. If nothing meaningful, fall back to event_kind-based reference

    Classification applied here:
    - fail-close: ALL clauses are noise → event_kind reference
    - humanize: meaningful clauses exist → extract and rejoin
    - tracked-only: original fragment stays in event_chain facts for model context
    """
    # Split on semicolons AND ellipsis-like separators (... / … / ⋯ / ⋯⋯)
    parts = re.split(r"[；;]|\.{2,}|[…⋯]+", text)
    meaningful = [p.strip() for p in parts if _is_meaningful_clause(p.strip())]
    if meaningful:
        # Preserve original causal order, take first 3 meaningful clauses
        selected = meaningful[:3]
        # Rejoin with natural connector (not semicolon)
        result = "，".join(selected)
        if len(result) >= 5:
            return result
    # Try event_chain for meaningful context_before
    if isinstance(event_chain, dict):
        ctx = str(event_chain.get("context_before") or "").strip()
        if ctx and len(ctx) >= 8 and _is_meaningful_clause(ctx):
            return ctx
    # Use topic_label if meaningful
    if topic_label and topic_label not in ("待追話題", "待續主題", "pending topic"):
        return topic_label
    # Event-kind-based structured reference
    _kind_refs = {
        "parked_topic": "之前聊到一半的話題",
        "delegated_task": "之前交代的事情",
        "important_task": "之前提到的重要事項",
        "deferred_topic": "延後再接的話題",
        "health_incident": "之前提到的身體狀況",
        "emotional_event": "之前的心情",
        "watchful_state": "之前在留意的事",
        "sensitive_event": "之前提過的事",
        "operator_feedback": "之前提到的回饋",
    }
    return _kind_refs.get(event_kind, "之前提到的事")

