_OPEN_LOOP_PATTERNS = [
    (re.compile(r"(?:幫我|幫忙|帮我|帮忙)(?:查|找|處理|整理|弄|看一下|研究)"), "delegated_action"),
    (re.compile(r"(?:妳|你)(?:先去|去)(?:查|找|弄|處理|整理|研究)"), "delegated_action"),
    (re.compile(r"(?:交給|交给)(?:妳|你)"), "delegated_action"),
    (re.compile(r"(?:help me|can you|could you)\s+(?:check|find|look into|research|handle|organize)", re.IGNORECASE), "delegated_action"),
    (re.compile(r"(?:等一下|等等|待會|稍後|之後|晚點|晚一點)(?:再|才|來|来)?(?:說|聊|講|弄|處理|看)"), "deferred_topic"),
    (re.compile(r"(?:先不|暫時不|暂时不)(?:說|聊|講|展開|处理)"), "deferred_topic"),
    (re.compile(r"(?:later|not now|let'?s talk later|we can come back to this|afterwards|circle back)", re.IGNORECASE), "deferred_topic"),
    (re.compile(r"(?:記得|记得|別忘|别忘|不要忘)"), "explicit_remember"),
    (re.compile(r"(?:remember this|don'?t let me forget|keep this in mind)", re.IGNORECASE), "explicit_remember"),
    (re.compile(r"(?:還沒|还没)(?:決定|决定|想好|確定|确定)"), "pending_decision"),
    (re.compile(r"(?:不知道|不確定|不确定)(?:要不要|怎麼|怎么|該不該|该不该)"), "pending_decision"),
    (re.compile(r"(?:haven'?t decided|not sure whether|not sure yet|still deciding)", re.IGNORECASE), "pending_decision"),
    # ── A-Extract 7: away / busy / suppress patterns ──
    (re.compile(r"(?:先去忙|去忙了|離開一下|离开一下|出去一趟|先走一下|先閃)"), "user_away_short"),
    (re.compile(r"(?:先去開會|先去开会|去\s*review|去做\s*code|先去搶單|先去抢单|先處理公事|先处理公事|先回去工作)"), "user_away_work"),
    (re.compile(r"(?:等結果|等结果)(?:回來|出來|回来|出来)"), "user_away_work"),
    (re.compile(r"(?:stepping away|heading to a meeting|got a meeting|going back to work|need to review)", re.IGNORECASE), "user_away_work"),
    (re.compile(r"(?:先不用管我|先別管我|先别管我|不想被打擾|不想被打扰|讓我靜|让我静|先不聊了|先不要推)"), "suppress_until_return"),
    (re.compile(r"(?:leave me alone|don'?t bother me|need some space|not in the mood)", re.IGNORECASE), "suppress_until_return"),
    # ── A-Extract 7: resume / return patterns ──
    (re.compile(r"(?:等一下|等下|晚點|晚点)(?:回來|回来)?(?:接|繼續|继续)"), "deferred_topic"),
    (re.compile(r"(?:回來再接|回来再接|回來再繼續|回来再继续|先放這裡等我)"), "deferred_topic"),
]

WRITEBACK_POLICY_MAP: dict[str, str] = {
    "sensitive_event": "immediate",
    "delegated_task": "on_completion_or_24h",
    "watchful_state": "on_state_change",
    "parked_topic": "on_reactivation_or_expiry",
}

IMMEDIATE_RESULT_CODE_MAP: dict[str, str] = {
    "parked_topic": "held_for_followup",
    "watchful_state": "state_acknowledged",
    "delegated_task": "delegated_followup",
    "sensitive_event": "sensitive_context_recorded",
}

IMMEDIATE_RESULT_HINT_MAP: dict[str, str] = {
    "held_for_followup": "Held for later follow-up.",
    "state_acknowledged": "State acknowledged without forcing closure.",
    "delegated_followup": "Marked for later action or verification.",
    "sensitive_context_recorded": "Sensitive context recorded for later continuity.",
}

FOLLOWUP_FOCUS_HINT_MAP: dict[str, str] = {
    "resume_when_user_returns": "Resume the original thread when the user comes back to it.",
    "watch_state_change": "Watch for changes in health, mood, fatigue, or willingness to continue.",
    "check_action_progress": "Check for progress or results on the delegated action.",
    "track_safety_and_impact": "Track safety, health, and downstream impact first.",
    "resume_when_context_fits": "Resume only when the user brings it back or the context clearly fits.",
    "remember_for_later": "Preserve the requested reminder for the next relevant moment.",
    "wait_for_decision": "Wait for more information or a clearer decision before following up.",
    "continue_when_relevant": "Continue from this thread when the context is relevant again.",
}

_COMPLETION_NEGATION_RE = re.compile(
    r"(?:還沒|还没|尚未|還在|还在|沒做|没做|未做|未完成|做不完|沒發|没发|沒送|没送|"
    r"didn'?t|haven'?t|not yet|still haven'?t|still need to)",
    re.IGNORECASE,
)

_COMPLETION_QUESTION_RE = re.compile(
    r"(?:[?？]\s*$|(?:搞定了嗎|搞定了吗|做完了嗎|做完了吗|完成了嗎|完成了吗|"
    r"弄好了嗎|弄好了吗|發了嗎|发了吗|送出了嗎|送出了吗|posted yet|done yet|finished yet))",
    re.IGNORECASE,
)

_COMPLETION_SIGNAL_PATTERNS = [
    re.compile(
        r"(?:我(?:已經|已经)?|剛剛|刚刚|昨天|今天|剛才|刚才)?(?:"
        r"(?<![A-Za-z])po完(?:了)?(?![A-Za-z])|(?<![A-Za-z])po好(?:了)?(?![A-Za-z])|(?<![A-Za-z])po(?:了)?(?![A-Za-z])|發文(?:了)?|发文(?:了)?|"
        r"發(?:了|出去(?:了)?)|发(?:了|出去(?:了)?)|貼(?:了)?|贴(?:了)?|"
        r"送出(?:了|去(?:了)?)|寄出(?:了)?|寄好(?:了)?|提交(?:了)?|提(?:了)?|交(?:了)?|"
        r"做完(?:了)?|完成(?:了)?|搞定(?:了)?|處理好(?:了)?|处理好(?:了)?|"
        r"修好(?:了)?|改好(?:了)?|寫好(?:了)?|写好(?:了)?|補好(?:了)?|补好(?:了)?|補上(?:了)?|补上(?:了)?|"
        r"看完(?:了)?|確認好(?:了)?|确认好(?:了)?|更新好(?:了)?)"
    , re.IGNORECASE),
    re.compile(
        r"(?:already|just|finally)?\s*(?:"
        r"posted(?: it)?|sent(?: it)?|shipped(?: it)?|finished(?: it)?|completed(?: it)?|"
        r"handled(?: it)?|fixed(?: it)?|updated(?: it)?|wrote(?: it)?|merged(?: it)?|"
        r"deployed(?: it)?|did(?: it)?|wrapped(?: it)?\s+up|got it done)"
    , re.IGNORECASE),
    re.compile(r"\b(?:it'?s done|it is done|all done|done now|finished now)\b", re.IGNORECASE),
]

COMPLETION_SOURCE_STATUSES = {"staged", "promoted", "completed", "resolved"}


def detect_followup_completion_signal(text: str) -> Optional[dict]:
    raw = normalize_story_text(normalize_skill_source_text(text), 220)
    if not raw:
        return None
    if _COMPLETION_QUESTION_RE.search(raw):
        return None
    if _COMPLETION_NEGATION_RE.search(raw):
        return None
    matched = None
    for pattern in _COMPLETION_SIGNAL_PATTERNS:
        match = pattern.search(raw)
        if match:
            matched = match.group(0).strip()
            break
    if not matched:
        return None
    summary = trim_summary(raw, 160)
    return {
        "matched": matched,
        "summary": summary,
        "result_code": "task_completed",
        "result_hint": "The user reported that the task or pending item was already completed.",
    }


def _extract_facts(text: str) -> list[str]:
    """Extract factual clauses, filtering out fillers, system instructions, and noise."""
    # A-Extract 4: strip internal labels before clause splitting
    cleaned = _INTERNAL_RENDER_LABEL_RE.sub("", normalize_skill_source_text(text))
    cleaned = re.sub(r"^[，,;；\s]+", "", cleaned).strip()
    if not cleaned:
        return []
    clauses = split_story_clauses(cleaned)
    facts: list[str] = []
    for clause in clauses:
        stripped = clause.strip()
        if not stripped or len(stripped) < 2:
            continue
        if _FILLER_RE.match(stripped):
            continue
        # B-Stop 2: reject system instructions and name-only clauses
        if _SYSTEM_INSTRUCTION_RE.search(stripped):
            continue
        if len(stripped) <= 3 and not re.search(r"[。！？!?]", stripped):
            continue
        facts.append(normalize_story_text(stripped, 80))
    return facts[:6]


def _infer_user_state(text: str) -> str:
    """Detect user's current state from text keywords."""
    normalized = normalize_skill_source_text(text)
    for state_label, keywords in _STATE_KEYWORDS.items():
        if any(kw in normalized for kw in keywords):
            return state_label
    return "neutral"


def _extract_open_loop(text: str, event_kind: str) -> str:
    """Identify unresolved item from text."""
    normalized = normalize_skill_source_text(text)
    for pattern, loop_type in _OPEN_LOOP_PATTERNS:
        m = pattern.search(normalized)
        if m:
            return loop_type
    if event_kind == "delegated_task":
        return "delegated_action"
    if event_kind == "watchful_state":
        return "state_monitoring"
    if event_kind == "sensitive_event":
        return "safety_tracking"
    return "topic_continuation"


_TIME_NEGATION_RE = re.compile(r"(?:不用|別|不要|沒有|不是|不必|不分|不用分|don'?t|no need)", re.IGNORECASE)


def _extract_time_anchor(text: str) -> str:
    """Extract temporal reference from text, skipping negated contexts."""
    raw = normalize_skill_source_text(text)
    for m in _TIME_ANCHOR_RE.finditer(raw):
        prefix = raw[max(0, m.start() - 5):m.start()]
        if _TIME_NEGATION_RE.search(prefix):
            continue
        return m.group(0)
    return ""


def _derive_followup_focus(event_kind: str, text: str, open_loop: str = "") -> str:
    """Dynamic followup focus derived from context, not static template."""
    code = _derive_followup_focus_code(event_kind, open_loop)
    return FOLLOWUP_FOCUS_HINT_MAP.get(code, FOLLOWUP_FOCUS_HINT_MAP["continue_when_relevant"])


def _derive_followup_focus_code(event_kind: str, open_loop: str = "") -> str:
    if open_loop == "delegated_action":
        return "check_action_progress"
    if open_loop == "deferred_topic":
        return "resume_when_context_fits"
    if open_loop == "explicit_remember":
        return "remember_for_later"
    if open_loop == "pending_decision":
        return "wait_for_decision"
    # ── A-Extract 7: away / busy / suppress focus codes ──
    if open_loop in ("user_away_short", "user_away_work"):
        return "resume_when_user_returns"
    if open_loop == "suppress_until_return":
        return "watch_state_change"
    focus_code_map = {
        "parked_topic": "resume_when_user_returns",
        "watchful_state": "watch_state_change",
        "delegated_task": "check_action_progress",
        "sensitive_event": "track_safety_and_impact",
    }
    return focus_code_map.get(event_kind, "continue_when_relevant")


def _derive_send_intent(event_kind: str, open_loop: str = "") -> str:
    if open_loop == "resolved_completion":
        return "none"
    if open_loop in {"delegated_action", "state_monitoring", "safety_tracking"}:
        return "check_in"
    if open_loop == "pending_decision":
        return "clarify"
    if open_loop in {"deferred_topic", "explicit_remember", "user_away_short", "user_away_work", "suppress_until_return"}:
        return "continue"
    if event_kind in {"watchful_state", "sensitive_event", "delegated_task"}:
        return "check_in"
    if event_kind == "parked_topic":
        return "continue"
    return "continue"


def _build_causal_anchor_summary(text: str, event_kind: str, facts: list[str]) -> str:
    clean_facts = [f for f in facts if isinstance(f, str) and _is_meaningful_clause(f)]
    if clean_facts:
        return summarize_anchor_text("；".join(clean_facts[:2]), 72, max_clauses=2)
    fallback = normalize_story_text(normalize_skill_source_text(text), 160)
    if not fallback:
        fallback = FOLLOWUP_EVENT_TYPES_EN.get(event_kind) or FOLLOWUP_EVENT_TYPES.get(event_kind) or event_kind or "pending topic"
    return summarize_anchor_text(fallback, 72, max_clauses=2)


def build_causal_memory(text: str, event_kind: str, topic_label: str = "") -> dict:
    """Build structured causal memory from user text.

    Returns dict with 6 fields:
        facts          – list[str]: factual clauses (no fillers)
        state          – str: user's current state
        open_loop      – str: what's unresolved
        time_anchor    – str: temporal reference
        followup_focus – str: what to focus on when following up
        writeback_policy – str: when to write to formal memory
    """
    last_user_update = normalize_story_text(normalize_skill_source_text(text), 120)
    facts = _extract_facts(text)
    open_loop = _extract_open_loop(text, event_kind)
    focus_code = _derive_followup_focus_code(event_kind, open_loop)
    return {
        "facts": facts,
        "state": _infer_user_state(text),
        "open_loop": open_loop,
        "time_anchor": _extract_time_anchor(text),
        "anchor_summary": _build_causal_anchor_summary(text, event_kind, facts),
        "last_user_update": last_user_update,
        "send_intent": _derive_send_intent(event_kind, open_loop),
        "followup_focus_code": focus_code,
        "followup_focus": FOLLOWUP_FOCUS_HINT_MAP.get(focus_code, FOLLOWUP_FOCUS_HINT_MAP["continue_when_relevant"]),
        "writeback_policy": WRITEBACK_POLICY_MAP.get(event_kind, "on_reactivation_or_expiry"),
    }


def merge_causal_memory(existing: Optional[dict], new: dict) -> dict:
    """Merge two causal_memory dicts, keeping latest state and accumulating facts."""
    if not isinstance(existing, dict):
        return new
    if not isinstance(new, dict):
        return existing
    # accumulate facts (dedup, cap at 8)
    old_facts = existing.get("facts") or []
    new_facts = new.get("facts") or []
    seen: set[str] = set()
    merged_facts: list[str] = []
    for f in old_facts + new_facts:
        normalized = normalize_text_for_match(f)
        if normalized not in seen:
            seen.add(normalized)
            merged_facts.append(f)
    merged_facts = merged_facts[:8]
    # state: latest wins (unless neutral)
    new_state = new.get("state", "neutral")
    merged_state = new_state if new_state != "neutral" else existing.get("state", "neutral")
    # open_loop: latest non-continuation wins
    new_loop = new.get("open_loop", "topic_continuation")
    merged_loop = new_loop if new_loop != "topic_continuation" else existing.get("open_loop", "topic_continuation")
    # time_anchor: latest non-empty wins
    merged_anchor = new.get("time_anchor") or existing.get("time_anchor", "")
    # followup_focus: latest wins
    merged_focus = new.get("followup_focus") or existing.get("followup_focus", "")
    merged_focus_code = new.get("followup_focus_code") or existing.get("followup_focus_code", "continue_when_relevant")
    merged_anchor_summary = str(new.get("anchor_summary") or existing.get("anchor_summary") or "").strip()
    merged_last_user_update = str(new.get("last_user_update") or existing.get("last_user_update") or "").strip()
    merged_send_intent = str(new.get("send_intent") or existing.get("send_intent") or "continue").strip() or "continue"
    # writeback_policy: most urgent wins
    policy_priority = ["immediate", "on_completion_or_24h", "on_state_change", "on_reactivation_or_expiry"]
    old_policy = existing.get("writeback_policy", "on_reactivation_or_expiry")
    new_policy = new.get("writeback_policy", "on_reactivation_or_expiry")
    old_idx = policy_priority.index(old_policy) if old_policy in policy_priority else 3
    new_idx = policy_priority.index(new_policy) if new_policy in policy_priority else 3
    merged_policy = policy_priority[min(old_idx, new_idx)]
    return {
        "facts": merged_facts,
        "state": merged_state,
        "open_loop": merged_loop,
        "time_anchor": merged_anchor,
        "anchor_summary": merged_anchor_summary,
        "last_user_update": merged_last_user_update,
        "send_intent": merged_send_intent,
        "followup_focus_code": merged_focus_code,
        "followup_focus": merged_focus,
        "writeback_policy": merged_policy,
    }


def synthesize_causal_summary(causal: Optional[dict], fallback_text: str) -> str:
    """Produce a human-readable summary from causal_memory, for normalized_seed_summary."""
    if not isinstance(causal, dict):
        return normalize_story_text(normalize_skill_source_text(fallback_text), 180)
    facts = causal.get("facts") or []
    if not facts:
        return normalize_story_text(normalize_skill_source_text(fallback_text), 180)
    # B-Stop 2: filter facts to meaningful clauses only
    clean_facts = [f for f in facts if isinstance(f, str) and _is_meaningful_clause(f)]
    if not clean_facts:
        return normalize_story_text(normalize_skill_source_text(fallback_text), 180)
    core = "；".join(clean_facts[:causal_memory_summary_max_facts()])
    state = causal.get("state", "neutral")
    time_anchor = str(causal.get("time_anchor") or "").strip()
    parts: list[str] = []
    if core:
        parts.append(core)
    if causal_memory_include_time_anchor() and time_anchor:
        parts.append(f"time:{time_anchor}")
    if causal_memory_include_state_marker() and state != "neutral":
        parts.append(f"state:{state}")
    return normalize_story_text(" | ".join(part for part in parts if part), 200)


def normalize_text_for_match(text: str) -> str:
    normalized = str(text or "").strip()
    normalized = normalized.replace("晚一點", "晚點").replace("妳", "你")
    normalized = normalized.replace("這件事", "這個").replace("那件事", "那個")
    normalized = re.sub(r"\s+", "", normalized)
    return normalized


def looks_like_meta_report(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    if len(raw) >= 240 and any(pattern.search(raw) for pattern in META_REPORT_PATTERNS):
        return True
    return any(pattern.search(raw) for pattern in META_REPORT_PATTERNS)


def load_seed_intent_embed_cache() -> dict:
    return load_json(SEED_INTENT_EMBED_CACHE_PATH, DEFAULT_SEED_INTENT_EMBED_CACHE)


def save_seed_intent_embed_cache(store: dict) -> None:
    store["updated_at"] = now_local().isoformat(timespec="seconds")
    save_json(SEED_INTENT_EMBED_CACHE_PATH, store)


def load_memory_lancedb_embedding_config() -> Optional[dict]:
    return None


def build_seed_intent_embed_signature(config: dict) -> str:
    return "disabled"


def cosine_similarity(a: list[float], b: list[float]) -> float:
    if len(a) != len(b) or not a or not b:
        return 0.0
    dot = sum(x * y for x, y in zip(a, b))
    norm_a = math.sqrt(sum(x * x for x in a))
    norm_b = math.sqrt(sum(y * y for y in b))
    if norm_a == 0.0 or norm_b == 0.0:
        return 0.0
    return dot / (norm_a * norm_b)


def jina_embed_inputs(texts: list[str], config: dict, task: Optional[str]) -> list[list[float]]:
    return []


def get_seed_intent_exemplar_vectors(config: dict) -> dict[str, list[dict]]:
    cache_store = load_seed_intent_embed_cache()
    signature = build_seed_intent_embed_signature(config)
    if cache_store.get("config_signature") != signature:
        cache_store = deepcopy(DEFAULT_SEED_INTENT_EMBED_CACHE)
        cache_store["config_signature"] = signature
    vectors_store = cache_store.setdefault("vectors", {})
    updated = False
    results: dict[str, list[dict]] = {}
    for intent, exemplars in SEED_INTENT_EMBED_EXEMPLARS.items():
        intent_vectors = []
        missing = []
        missing_keys = []
        for exemplar in exemplars:
            cache_key = hashlib.sha256(f"{signature}:passage:{intent}:{exemplar}".encode("utf-8")).hexdigest()
            cached = vectors_store.get(cache_key)
            if isinstance(cached, list) and cached:
                intent_vectors.append({"text": exemplar, "vector": [float(v) for v in cached]})
            else:
                missing.append(exemplar)
                missing_keys.append(cache_key)
        if missing:
            embedded = jina_embed_inputs(missing, config, config.get("task_passage"))
            for cache_key, exemplar, vector in zip(missing_keys, missing, embedded):
                vectors_store[cache_key] = vector
                intent_vectors.append({"text": exemplar, "vector": vector})
            updated = True
        results[intent] = intent_vectors
    if updated:
        save_seed_intent_embed_cache(cache_store)
    return results


def classify_seed_intents_with_embedding(text: str, normalized: str) -> Optional[dict]:
    if not normalized:
        return None
    config = load_memory_lancedb_embedding_config()
    if not config:
        return None
    try:
        query_vector = jina_embed_inputs([text], config, config.get("task_query"))[0]
        exemplar_vectors = get_seed_intent_exemplar_vectors(config)
    except (subprocess.CalledProcessError, subprocess.TimeoutExpired, ValueError, json.JSONDecodeError, FileNotFoundError, OSError):
        return None
    best: Optional[dict] = None
    for intent, exemplars in exemplar_vectors.items():
        for exemplar in exemplars:
            score = cosine_similarity(query_vector, exemplar.get("vector", []))
            if score <= SEED_INTENT_EMBED_THRESHOLD:
                continue
            if best is None or score > best["confidence"]:
                best = {
                    "intent": intent,
                    "strength": "strong" if score >= 0.82 else "weak",
                    "matched": [str(exemplar.get("text") or "")],
                    "confidence": round(float(score), 4),
                    "source": "embedding_fallback",
                    "similarity": round(float(score), 4),
                    "exemplar_reference": str(exemplar.get("text") or ""),
                }
    return best


def classify_seed_intents(text: str) -> dict:
    raw = str(text or "").strip()
    normalized = raw.replace("晚一點", "晚點").replace("妳", "你")
    intents = []
    for intent, levels in SEED_INTENT_RULES.items():
        matched = []
        strength = "weak"
        for phrase in levels.get("strong", []):
            if phrase in normalized:
                matched.append(phrase)
                strength = "strong"
        for phrase in levels.get("weak", []):
            if phrase in normalized and phrase not in matched:
                matched.append(phrase)
        if matched:
            intents.append({
                "intent": intent,
                "strength": strength,
                "matched": matched,
                "source": "phrase_rule",
                "similarity": None,
                "exemplar_reference": None,
            })
    intents.sort(key=lambda item: (0 if item["strength"] == "strong" else 1, item["intent"]))
    confidence = 0.85 if intents and intents[0]["strength"] == "strong" else 0.58 if intents else 0.0
    should_try_embedding = not intents or (intents[0]["intent"] == "weak_seed" and confidence < 0.65)
    if should_try_embedding:
        embedding_intent = classify_seed_intents_with_embedding(raw, normalized)
        if embedding_intent:
            if not intents:
                intents = [embedding_intent]
            else:
                intents.insert(0, embedding_intent)
            confidence = float(intents[0].get("confidence", confidence) or confidence)
    return {
        "intents": intents,
        "top_intent": intents[0]["intent"] if intents else None,
        "top_strength": intents[0]["strength"] if intents else None,
        "top_source": intents[0].get("source") if intents else None,
        "top_similarity": intents[0].get("similarity") if intents else None,
        "top_exemplar_reference": intents[0].get("exemplar_reference") if intents else None,
        "confidence": confidence,
        "explicit_importance": any(phrase in normalized for phrase in EXPLICIT_IMPORTANCE_PHRASES),
        "normalized_text": normalized,
    }


def detect_seed_clarification(
    text: str,
    candidate_signal: Optional[dict],
    seed_intents: Optional[dict] = None,
) -> Optional[str]:
    seed_intents = seed_intents if isinstance(seed_intents, dict) else classify_seed_intents(text)
    if candidate_signal or any(
        item["strength"] == "strong"
        for item in seed_intents.get("intents", [])
        if item.get("intent") not in {"return_signal"}
    ):
        return None
    if any(item.get("intent") in {"weak_seed", "pause_but_keep", "memory_overload"} for item in seed_intents.get("intents", [])):
        seed = sum(ord(ch) for ch in str(text))
        return pick_by_seed(seed, SEED_CLARIFICATION_QUESTIONS)
    return None


def normalize_watchpoint_evidence(text: str) -> str:
    raw = trim_summary(text, 220)
    rules = [
        ("顏文字不是 emoji", "顏文字不是 emoji 替代"),
        ("顏文字不是emoji", "顏文字不是 emoji 替代"),
        ("不要只用 emoji", "不要只用 emoji"),
        ("顏文字要真的跟情緒對上", "顏文字要跟情緒對上"),
        ("顏文字要自然", "顏文字要自然"),
        ("不要太客服", "不要太客服"),
        ("不要像提醒機器人", "不要像提醒機器人"),
        ("不要回成推薦模板", "不要回成推薦模板"),
        ("模板感", "不要太模板"),
    ]
    for phrase, normalized in rules:
        if phrase in raw:
            return normalized
    return raw


def text_has_any(text: str, phrases: list[str]) -> bool:
    lowered = str(text or "").lower()
    for phrase in phrases:
        if phrase in text:
            return True
        if any("a" <= ch.lower() <= "z" for ch in phrase) and phrase.lower() in lowered:
            return True
    return False


def candidate_ttl_hours(signal_type: str) -> int:
    return settings_candidate_ttl_hours(signal_type)


def detect_candidate_signal(text: str, seed_intents: Optional[dict] = None) -> Optional[dict]:
    text = (text or "").strip()
    if not text:
        return None
    if looks_like_meta_report(text):
        return None
    guided_settings = detect_guided_settings_request(text)
    if isinstance(guided_settings, dict) and guided_settings.get("detected"):
        return None
    if has_self_managed_tracking_decline(text):
        sanitized = strip_self_managed_tracking_clauses(text)
        if not sanitized:
            return None
        text = sanitized
    if looks_like_contextual_staging_follow_on(text):
        return None
    focused_text = extract_tracking_focus_text(text)
    # ── A-Extract 7: phrase family matching (takes priority) ──
    family_match = match_phrase_family(text)
    if family_match:
        return {
            "signal_type": family_match["signal_type"],
            "topic": family_match["family"],
            "matched_phrase": family_match["matched_phrase"],
            "promotion_hint": None if family_match["can_silent_expire"] else "explicit_followup_request",
            "intent_source": "phrase_family",
            "intent_similarity": None,
            "intent_exemplar_reference": None,
            "phrase_family": family_match,
        }
    # ── Regex-based correction/pushback detection ──
    # Catches time-referenced system action complaints (e.g., "22:03分發送給我的天氣內容")
    # and system behavior questions (e.g., "妳推送前都沒有確認嗎？")
    correction_re_match = (
        _CORRECTION_TIME_REF_RE.search(text)
        or _CORRECTION_QUESTION_RE.search(text)
        or _CORRECTION_GENERIC_COMPLAINT_RE.search(text)
        or _CORRECTION_CONTENT_CLARIFY_RE.search(text)
        or _CORRECTION_INTERNAL_TOKEN_RE.search(text)
    )
    if correction_re_match:
        family_info = PHRASE_FAMILIES.get("correction_pushback", {})
        return {
            "signal_type": "feedback",
            "topic": "correction_pushback",
            "matched_phrase": correction_re_match.group(0)[:60],
            "promotion_hint": None,  # can_silent_expire — don't force promote
            "intent_source": "correction_regex",
            "intent_similarity": None,
            "intent_exemplar_reference": None,
            "phrase_family": {
                "family": "correction_pushback",
                "matched_phrase": correction_re_match.group(0)[:60],
                "state": family_info.get("state", "neutral"),
                "event_kind": family_info.get("event_kind", "operator_feedback"),
                "open_loop": family_info.get("open_loop", "correction_feedback"),
                "followup_focus_code": family_info.get("followup_focus_code", "acknowledge_and_adjust"),
                "signal_type": "feedback",
                "can_silent_expire": True,
                "staging_ttl_hours": family_info.get("staging_ttl_hours", 72),
            },
        }
    content_task_action = _CONTENT_TASK_ACTION_RE.search(text)
    content_task_context = _CONTENT_TASK_CONTEXT_RE.search(text)
    if content_task_action:
        matched = " / ".join(
            part for part in (
                (content_task_action.group(0) or "").strip(),
                (content_task_context.group(0) or "").strip() if content_task_context else "",
            )
            if part
        )[:80]
        return {
            "signal_type": "task",
            "topic": "內容規劃",
            "matched_phrase": matched,
            "promotion_hint": "explicit_followup_request" if content_task_context else None,
            "intent_source": "content_task_regex",
            "intent_similarity": None,
            "intent_exemplar_reference": None,
        }
    natural_focus = extract_work_focus_text(focused_text or text)
    if looks_like_natural_unresolved_work_item(natural_focus):
        return {
            "signal_type": "task",
            "topic": "自然未收尾工作",
            "matched_phrase": trim_summary(natural_focus, 80),
            "promotion_hint": "explicit_followup_request" if any(marker in natural_focus for marker in ("明天", "晚點", "晚一點", "等等", "再處理", "補完", "补完")) else None,
            "intent_source": "natural_unresolved_work",
            "intent_similarity": None,
            "intent_exemplar_reference": None,
            "source_focus_text": natural_focus,
        }
    normalized = (
        text.replace("晚一點", "晚點")
        .replace("之後再來接我", "再來接我")
        .replace("妳先知道就好", "先知道就好")
    )
    watchful_markers = tuple(DEFERRED_CARE_PHRASES + EXPLICIT_FOLLOWUP_REQUEST_PHRASES + [
        "不想說",
        "不想被勸睡",
        "先陪我放著",
        "陪我放著",
        "先放著",
        "先放在這裡",
    ])
    delegated_markers = (
        "幫我查", "先幫我查", "幫我整理", "整理重點", "幫我處理", "交給妳", "交給你",
        "妳去找", "你去找", "妳要去", "你要去", "去爬文", "去研究",
        "帮我查", "帮我整理", "帮我处理", "帮我研究", "帮我研究", "你去找", "去爬文", "去研究",
        "go find", "go check", "go research",
    )
    for signal_type in CANDIDATE_SIGNAL_PRIORITY:
        for phrase, topic in CANDIDATE_SIGNAL_RULES.get(signal_type, []):
            if phrase in normalized:
                if signal_type == "emotion" and not any(item in normalized for item in watchful_markers):
                    continue
                if signal_type == "support" and not any(item in normalized for item in watchful_markers):
                    continue
                promotion_hint = None
                if any(item in normalized for item in EXPLICIT_FOLLOWUP_REQUEST_PHRASES):
                    promotion_hint = "explicit_followup_request"
                elif signal_type == "task" and (
                    ("明天" in normalized and text_has_any(normalized, DEFERRED_TASK_PHRASES))
                    or ("晚點" in normalized and text_has_any(normalized, DEFERRED_TASK_PHRASES))
                    or ("先不要展開" in normalized and text_has_any(normalized, DEFERRED_TASK_PHRASES))
                ):
                    promotion_hint = "explicit_followup_request"
                elif signal_type in {"emotion", "support"} and any(item in normalized for item in watchful_markers):
                    promotion_hint = "explicit_followup_request"
                return {
                    "signal_type": signal_type,
                    "topic": topic,
                    "matched_phrase": phrase,
                    "promotion_hint": promotion_hint,
                    "intent_source": "phrase_rule",
                    "intent_similarity": None,
                    "intent_exemplar_reference": None,
                }
    if any(marker in normalized for marker in delegated_markers):
        return {
            "signal_type": "task",
            "topic": "交給助理處理",
            "matched_phrase": ",".join(marker for marker in delegated_markers if marker in normalized)[:80],
            "promotion_hint": "explicit_followup_request",
            "intent_source": "phrase_rule",
            "intent_similarity": None,
            "intent_exemplar_reference": None,
        }
    seed_intents = seed_intents if isinstance(seed_intents, dict) else classify_seed_intents(normalized)
    top_intent = seed_intents.get("top_intent")
    top_strength = seed_intents.get("top_strength")
    if not top_intent or top_intent == "return_signal":
        return None
    if top_intent == "weak_seed" and top_strength != "strong" and not seed_intents.get("explicit_importance"):
        return None
    mapping = {
        "defer_topic": ("task", "延後再談"),
        "track_for_me": ("task", "幫我記著"),
        "delegate_to_assistant": ("task", "交給助理處理"),
        "memory_overload": ("task", "先交給助理"),
        "pause_but_keep": ("task", "晚點"),
        "weak_seed": ("task", "先放著"),
    }
    signal_type, topic = mapping.get(top_intent, ("task", "先放著"))
    promotion_hint = None
    if top_intent in {"defer_topic", "track_for_me", "pause_but_keep"} and top_strength == "strong":
        promotion_hint = "explicit_followup_request"
    elif seed_intents.get("explicit_importance"):
        promotion_hint = "explicit_followup_request"
    return {
        "signal_type": signal_type,
        "topic": topic,
        "matched_phrase": ",".join(seed_intents["intents"][0]["matched"][:3]),
        "promotion_hint": promotion_hint,
        "intent": top_intent,
        "intent_strength": top_strength,
        "intent_source": seed_intents.get("top_source") or "phrase_rule",
        "intent_similarity": seed_intents.get("top_similarity"),
        "intent_exemplar_reference": seed_intents.get("top_exemplar_reference"),
    }
    return None


def explicit_tracking_requested(
    seed_intents: Optional[dict] = None,
    candidate_signal: Optional[dict] = None,
    text: str = "",
) -> bool:
    intents = seed_intents if isinstance(seed_intents, dict) else {}
    if isinstance(candidate_signal, dict) and candidate_signal.get("promotion_hint") == "explicit_followup_request":
        return True
    if looks_like_natural_unresolved_work_item(text):
        return True
    if intents.get("explicit_importance"):
        return True
    for item in intents.get("intents", []):
        if item.get("intent") in EXPLICIT_TRACKING_INTENTS and item.get("strength") == "strong":
            return True
    return False


def candidate_prefers_care_state(signal_type: str, event_kind: str, text: str = "") -> bool:
    normalized = normalize_text_for_match(text or "")
    if signal_type in {"emotion", "support"}:
        return True
    if event_kind in {"watchful_state", "sensitive_event"}:
        return True
    if any(token in normalized for token in ("想法", "idea", "靈感", "醒來", "吃什麼", "不舒服", "感冒", "生理期")):
        return True
    return False


def capture_prefers_care_state(
    user_text: str,
    event_kind: str,
    *,
    capture_reason: str = "",
    seed_intents: Optional[dict] = None,
    candidate_signal: Optional[dict] = None,
    incident_detection: Optional[dict] = None,
) -> bool:
    if explicit_tracking_requested(seed_intents, candidate_signal, user_text):
        return False
    incident_type = str((incident_detection or {}).get("incident_type") or "").strip()
    signal_type = str((candidate_signal or {}).get("signal_type") or "").strip()
    if incident_type in {"health_incident", "emotional_incident", "safety_incident"}:
        return True
    if capture_reason in {"current-focus-topic", "explicit-focus-refocus"}:
        return True
    return candidate_prefers_care_state(signal_type, event_kind, text=user_text)


def care_state_status_for_count(count: int) -> str:
    return CARE_STATUS_ACTIVE if count >= CARE_STATE_MIN_SEEN_COUNT else CARE_STATUS_ONCE


def record_cross_time_revisit(record: Optional[dict], now_dt: datetime) -> bool:
    if not isinstance(record, dict):
        return False
    baseline = parse_optional_dt(
        record.get("care_first_seen_at")
        or record.get("created_at")
        or record.get("last_seen_at")
    )
    if baseline is None:
        return False
    if baseline.date() != now_dt.date():
        return True
    return (now_dt - baseline) >= timedelta(hours=CARE_STATE_CROSS_TIME_HOURS)


def apply_care_state_fields(
    target: Optional[dict],
    now_dt: datetime,
    *,
    enabled: bool,
    base_status: str,
    increment: bool = False,
) -> None:
    if not isinstance(target, dict):
        return
    if not enabled:
        target["current_status"] = base_status
        return
    count = int(target.get("care_seen_count", 0) or 0)
    if count <= 0:
        count = 1
    if increment:
        count += 1
    target["care_seen_count"] = count
    target["care_state_level"] = care_state_status_for_count(count)
    target["care_first_seen_at"] = target.get("care_first_seen_at") or now_dt.isoformat(timespec="seconds")
    target["care_last_seen_at"] = now_dt.isoformat(timespec="seconds")
    target["current_status"] = target["care_state_level"]


def classify_skill_memory_outcome(
    text: str,
    incident_detection: Optional[dict],
    candidate_update: Optional[dict],
) -> dict:
    guided_settings = detect_guided_settings_request(text)
    if isinstance(guided_settings, dict) and guided_settings.get("detected"):
        return {
            "classification": "casual_chat",
            "reason": "guided-settings-request",
            "event_kind": None,
        }
    if incident_detection and incident_detection.get("detected"):
        event_kind = infer_followup_event_type(
            text,
            incident_type=incident_detection.get("incident_type"),
            incident_detection=incident_detection,
        )
        return {
            "classification": "tracked_followup",
            "reason": incident_detection.get("incident_type") or "incident-detected",
            "event_kind": event_kind,
        }
    if candidate_update and candidate_update.get("candidate"):
        candidate = candidate_update.get("candidate") or {}
        return {
            "classification": "staged_memory",
            "reason": candidate_update.get("action") or "candidate-updated",
            "event_kind": candidate.get("event_kind") or infer_followup_event_type(text),
        }
    if classify_seed_intents(text).get("top_intent") in {"weak_seed", "pause_but_keep", "memory_overload"}:
        return {
            "classification": "staged_memory",
            "reason": "seed-intent-observed",
            "event_kind": infer_followup_event_type(text),
        }
    return {
        "classification": "casual_chat",
        "reason": "no-staged-or-tracked-state",
        "event_kind": None,
    }


def find_pending_candidate(candidate_store: dict, signal_type: str, topic: str, now_dt: datetime):
    for candidate in reversed(candidate_store.get("candidates", [])):
        if candidate.get("status") != "pending":
            continue
        if candidate.get("signal_type") != signal_type or candidate.get("topic") != topic:
            continue
        expires_at = candidate.get("expires_at")
        if not isinstance(expires_at, str):
            continue
        try:
            expires_dt = parse_dt(expires_at)
        except Exception:
            continue
        if expires_dt >= now_dt:
            return candidate
    return None


def upsert_candidate_from_message(
    candidate_store: dict,
    text: str,
    now_dt: datetime,
    incident_detection: Optional[dict],
    incident_created: bool,
    time_state: Optional[dict] = None,
    seed_intents: Optional[dict] = None,
    session_key: Optional[str] = None,
    followup_reason: Optional[str] = None,
) -> Optional[dict]:
    if looks_like_meta_report(text):
        return None
    if looks_like_structured_context_residue(text):
        return None
    resolved_seed_intents = seed_intents if isinstance(seed_intents, dict) else classify_seed_intents(text)
    signal = detect_candidate_signal(text, seed_intents=resolved_seed_intents)
    if not signal:
        return None
    if incident_created or (incident_detection and incident_detection.get("detected")):
        return None
    signal_type = signal["signal_type"]
    topic = signal["topic"]
    source_text = normalize_skill_source_text(signal.get("source_focus_text") or text)
    summary = usable_seed_summary(source_text) or trim_summary(source_text, 160)
    event_kind = infer_followup_event_type(source_text, signal=signal, incident_detection=incident_detection)
    event_chain = build_event_chain(source_text, event_kind, topic_label=infer_topic_label(summary, topic))
    confidence = 0.85 if signal.get("intent_strength") == "strong" or signal.get("promotion_hint") else 0.58
    care_state_enabled = candidate_prefers_care_state(signal_type, event_kind, text=source_text) and not explicit_tracking_requested(
        resolved_seed_intents,
        signal,
        source_text,
    )
    ttl_hours = candidate_ttl_hours(signal_type)
    expires_at = (now_dt + timedelta(hours=ttl_hours)).isoformat(timespec="seconds")
    continuity_bundle = build_continuity_bundle_fields(
        session_key,
        source_text,
        now_dt,
        seed_intents=resolved_seed_intents,
        followup_reason=followup_reason or signal.get("intent") or signal.get("topic") or signal_type,
    )
    existing = find_pending_candidate(candidate_store, signal_type, topic, now_dt)
    if existing:
        existing["last_seen_at"] = now_dt.isoformat(timespec="seconds")
        existing["expires_at"] = expires_at
        if session_key:
            existing["session_key"] = str(session_key)
        existing["seen_count"] = int(existing.get("seen_count", 1) or 1) + 1
        existing["source_text"] = trim_summary(source_text, 220)
        existing["normalized_seed_summary"] = summary
        existing["topic_label"] = infer_topic_label(summary, topic)
        existing["source_layer"] = "candidate"
        existing["memory_class"] = "staged_memory"
        existing["lifecycle"] = "touched"
        existing["event_kind"] = event_kind
        existing["event_chain_id"] = existing.get("event_chain_id") or derive_session_event_chain_id(event_kind, source_text, session_key)
        existing["event_chain"] = merge_event_chain(existing.get("event_chain"), source_text, event_kind, topic_label=existing["topic_label"])
        existing["normalized_seed_summary"] = synthesize_event_chain_summary(existing.get("event_chain"), source_text)
        existing["confidence"] = max(float(existing.get("confidence", 0.0) or 0.0), confidence)
        existing["intent_source"] = signal.get("intent_source") or existing.get("intent_source") or "phrase_rule"
        existing["intent_similarity"] = signal.get("intent_similarity")
        existing["intent_exemplar_reference"] = signal.get("intent_exemplar_reference")
        apply_continuity_bundle_fields(existing, continuity_bundle)
        apply_care_state_fields(
            existing,
            now_dt,
            enabled=care_state_enabled,
            base_status="candidate_only",
            increment=True,
        )
        existing["daily_memory_trace"] = None
        if signal.get("promotion_hint") in PROMOTION_HINT_VALUES:
            existing["promotion_hint"] = signal["promotion_hint"]
        append_candidate_audit({
            "timestamp": now_dt.isoformat(timespec="seconds"),
            "candidate_id": existing.get("id"),
            "action": "seen_again",
            "reason": f"same-topic:{signal_type}:{topic}",
            "source": existing.get("intent_source"),
            "matched_intent": signal.get("intent"),
            "similarity": signal.get("intent_similarity"),
            "exemplar_reference": signal.get("intent_exemplar_reference"),
        })
        trace_followup(
            now_dt,
            event_kind=existing.get("event_kind"),
            event_chain_id=existing.get("event_chain_id"),
            source_stage="candidate",
            followup_decision="seen_again",
            trigger_reason=f"same-topic:{signal_type}:{topic}",
            continuity_source=existing.get("source_layer"),
            live_dispatch_result="not-applicable",
            source_id=existing.get("id"),
            source_layer="candidate",
            summary=existing.get("normalized_seed_summary"),
            extra={"intent_source": existing.get("intent_source")},
        )
        return {"action": "seen_again", "candidate": existing}

    candidate = {
        "id": make_candidate_id(),
        "created_at": now_dt.isoformat(timespec="seconds"),
        "last_seen_at": now_dt.isoformat(timespec="seconds"),
        "expires_at": expires_at,
        "session_key": str(session_key or "").strip() or None,
        "source_text": trim_summary(source_text, 220),
        "topic": topic,
        "topic_label": infer_topic_label(summary, topic),
        "signal_type": signal_type,
        "memory_class": "staged_memory",
        "lifecycle": "created",
        "normalized_seed_summary": synthesize_event_chain_summary(event_chain, summary),
        "source_layer": "candidate",
        "confidence": confidence,
        "current_status": "candidate_only",
        "event_kind": event_kind,
        "event_chain": event_chain,
        "event_chain_id": derive_session_event_chain_id(event_kind, source_text, session_key),
        "intent_source": signal.get("intent_source") or "phrase_rule",
        "intent_similarity": signal.get("intent_similarity"),
        "intent_exemplar_reference": signal.get("intent_exemplar_reference"),
        "seen_count": 1,
        "status": "pending",
        "promotion_hint": signal.get("promotion_hint"),
    }
    apply_continuity_bundle_fields(candidate, continuity_bundle)
    apply_care_state_fields(
        candidate,
        now_dt,
        enabled=care_state_enabled,
        base_status="candidate_only",
        increment=False,
    )
    candidate["daily_memory_trace"] = None
    candidate_store.setdefault("candidates", []).append(candidate)
    trace_followup(
        now_dt,
        event_kind=candidate.get("event_kind"),
        event_chain_id=candidate.get("event_chain_id"),
        source_stage="candidate",
        followup_decision="created",
        trigger_reason=signal.get("intent") or signal.get("topic") or signal_type,
        continuity_source="candidate",
        live_dispatch_result="not-applicable",
        source_id=candidate.get("id"),
        source_layer="candidate",
        summary=candidate.get("normalized_seed_summary"),
        **build_trace_writeback_meta(
            now_dt,
            entity_type="candidate",
            entity=candidate,
            action="created",
            source_path="ordinary",
            time_state=time_state,
        ),
        extra={"intent_source": candidate.get("intent_source")},
    )
    return {"action": "created", "candidate": candidate}


def is_sleep_window(profile: dict, now_dt: datetime) -> bool:
    sleep_cfg = profile.get("sleep_pattern", {}) if isinstance(profile.get("sleep_pattern"), dict) else {}
    raw = str(sleep_cfg.get("sleep_block_window") or "06:00-12:00")
    try:
        start_raw, end_raw = raw.split("-", 1)
        start_hour = int(start_raw.split(":")[0])
        end_hour = int(end_raw.split(":")[0])
    except Exception:
        start_hour, end_hour = 6, 12
    local_now = routine_schedule_local_dt(now_dt)
    return start_hour <= local_now.hour < end_hour


def default_hook_type_for_incident(incident_type: str, text: str = "") -> Optional[str]:
    if incident_type == "important_task" and "明天要" in text:
        return "tomorrow_check"
    mapping = {
        "health_incident": "health_followup",
        "safety_incident": "health_followup",
        "emotional_incident": "emotional_followup",
        "important_task": "progress_followup",
    }
    return mapping.get(incident_type)


def incident_recent_same_type(store: dict, incident_type: str, now_dt: datetime, cooldown_hours: int) -> bool:
    for incident in reversed(store.get("incidents", [])):
        if incident.get("type") != incident_type:
            continue
        created_at = incident.get("created_at")
        if not isinstance(created_at, str):
            continue
        try:
            created_dt = parse_dt(created_at)
        except Exception:
            continue
        if now_dt - created_dt <= timedelta(hours=cooldown_hours):
            return True
    return False


def _text_looks_like_fragment(text: str) -> bool:
    """Detect broken-clause / philosophical / pronoun-confused text
    that should not be promoted to an incident on weak keyword alone."""
    stripped = text.strip()
    if not stripped:
        return False
    # Short questions are suspicious only when the text also looks clause-broken.
    if len(stripped) < 48 and ("？" in stripped or "?" in stripped):
        if any(token in stripped for token in ("。", "；", "而是", "不是", "可是", "但是")):
            return True
    # Contains multiple unrelated nouns joined by 、 (enumeration of concepts, not a health statement)
    import re as _re
    if _re.search(r"[\u4e00-\u9fff]+、[\u4e00-\u9fff]+、[\u4e00-\u9fff]+", stripped):
        # Three or more enumerated terms — likely abstract/philosophical
        if not any(w in stripped for w in ("痛", "不舒服", "生病", "受傷", "流血", "壓力", "崩潰", "難過")):
            return True
    return False


def _is_routine_statement(text: str) -> bool:
    """Detect ordinary future/schedule/routine mentions that are NOT actionable tasks.
    '明天要上班' is routine; '明天要記得帶文件' is a real task."""
    routine_context = (
        "上班", "上課", "上學", "通勤", "天氣", "放假", "休息日", "週末",
        "上班", "上课", "上学", "通勤", "天气", "放假", "休息日", "周末",
        "work shift", "commute", "weather", "day off",
    )
    # If text mentions routine context AND does NOT contain obligation/action markers, it's routine
    has_routine = any(r in text for r in routine_context)
    obligation_markers = (
        "記得", "帶", "買", "處理", "辦", "繳", "交", "準備", "提醒",
        "记得", "带", "买", "处理", "办", "缴", "交", "准备", "提醒",
        "remember", "bring", "buy", "handle", "prepare", "submit",
    )
    has_obligation = any(o in text for o in obligation_markers)
    return has_routine and not has_obligation


def score_incident_type(text: str, incident_type: str) -> dict:
    scoring_text = text
    if incident_type == "important_task":
        stripped = extract_tracking_focus_text(text, incident_type=incident_type)
        if stripped:
            scoring_text = stripped
    rules = INCIDENT_RULES.get(incident_type, {})
    # De-duplicate keywords: identical 繁/簡 entries should not inflate score
    raw_keyword_hits = [word for word in rules.get("keywords", []) if word in scoring_text]
    keyword_hits = list(dict.fromkeys(raw_keyword_hits))
    raw_hint_hits = [word for word in rules.get("hints", []) if word in scoring_text]
    hint_hits = list(dict.fromkeys(raw_hint_hits))
    score = len(keyword_hits) * 2 + len(hint_hits)
    contextual_bonus = 0
    fatigue_like = text_has_any(text, FATIGUE_SIGNAL_PHRASES)
    deferred_care = text_has_any(text, DEFERRED_CARE_PHRASES)
    emotional_like = any(word in text for word in EMOTIONAL_MODE_KEYWORDS)
    if incident_type == "health_incident" and fatigue_like:
        contextual_bonus += 1
    if incident_type in {"health_incident", "emotional_incident"} and deferred_care and (fatigue_like or emotional_like):
        contextual_bonus += 1
    score += contextual_bonus
    # Generic body mentions alone should not create a health incident.
    if incident_type == "health_incident":
        strong_keyword_hits = [word for word in keyword_hits if word != "身體"]
        if not strong_keyword_hits and not hint_hits and contextual_bonus == 0 and "身體" in keyword_hits:
            score = 0
    if incident_type == "important_task" and score > 0 and not is_trackable_followup_focus_text(scoring_text):
        score = 0
    # ── Routine statement guard: ordinary future/schedule text should not become important_task ──
    if incident_type == "important_task" and has_self_managed_tracking_decline(text) and not looks_like_natural_unresolved_work_item(scoring_text):
        score = 0
    if incident_type == "important_task" and score > 0 and looks_like_natural_unresolved_work_item(scoring_text) and not has_explicit_important_task_escalation(text):
        score = 0
    if incident_type == "important_task" and score > 0 and _is_routine_statement(scoring_text):
        score = 0
    # Fragment guard: a weak single-hit abstract fragment should not cross incident threshold.
    if score > 0 and len(keyword_hits) <= 1 and not hint_hits and contextual_bonus == 0:
        if _text_looks_like_fragment(text):
            score = 0
    return {
        "score": score,
        "keyword_hits": keyword_hits,
        "hint_hits": hint_hits,
        "contextual_bonus": contextual_bonus,
    }


def score_severity(score: int) -> Optional[str]:
    if score >= 4:
        return "high"
    if score >= 2:
        return "medium"
    return None


def severity_rank(severity: Optional[str]) -> int:
    mapping = {"low": 1, "medium": 2, "high": 3}
    return mapping.get(str(severity or "").lower(), 0)


def incident_signal_terms(text: str, incident_type: str, keyword_hits: list[str], hint_hits: list[str]) -> set[str]:
    terms = set(keyword_hits or []) | set(hint_hits or [])
    if incident_type == "emotional_incident":
        for phrase in ["壓力", "撐不住", "難過", "崩潰", "煩", "今晚", "特別明顯", "最近", "現在"]:
            if phrase in text:
                terms.add(phrase)
    if incident_type == "health_incident":
        for phrase in FATIGUE_SIGNAL_PHRASES:
            if phrase in text:
                terms.add(phrase)
    for phrase in DEFERRED_CARE_PHRASES:
        if phrase in text:
            terms.add(phrase)
    return terms


def has_new_context_signal(text: str, existing_text: str) -> bool:
    current = {phrase for phrase in NEW_CONTEXT_SIGNAL_PHRASES if phrase in text}
    existing = {phrase for phrase in NEW_CONTEXT_SIGNAL_PHRASES if phrase in existing_text}
    return bool(current - existing)


def find_cooldown_blocking_incident(
    store: dict,
    incident_type: str,
    now_dt: datetime,
    cooldown_hours: int,
    text: str,
    severity: str,
    keyword_hits: list[str],
    hint_hits: list[str],
):
    current_summary = trim_summary(text, 120)
    current_terms = incident_signal_terms(text, incident_type, keyword_hits, hint_hits)
    for incident in reversed(store.get("incidents", [])):
        if incident.get("type") != incident_type:
            continue
        created_at = incident.get("created_at")
        if not isinstance(created_at, str):
            continue
        try:
            created_dt = parse_dt(created_at)
        except Exception:
            continue
        if now_dt - created_dt > timedelta(hours=cooldown_hours):
            continue
        existing_summary = str(incident.get("source_summary") or "").strip()
        if existing_summary == current_summary:
            return incident
        existing_scored = score_incident_type(existing_summary, incident_type)
        existing_terms = incident_signal_terms(
            existing_summary,
            incident_type,
            existing_scored.get("keyword_hits", []),
            existing_scored.get("hint_hits", []),
        )
        overlap = len(current_terms & existing_terms)
        if severity_rank(severity) > severity_rank(incident.get("severity")):
            continue
        if has_new_context_signal(text, existing_summary):
            continue
        if overlap >= 2:
            return incident
        if overlap >= 1 and severity_rank(severity) <= severity_rank(incident.get("severity")):
            return incident
    return None


def legacy_score_severity(incident_type: str, text: str) -> str:
    if incident_type == "safety_incident":
        return "high" if any(word in text for word in ["流血", "跌倒"]) else "medium"
    if incident_type == "health_incident":
        return "medium"
    if incident_type == "emotional_incident":
        return "high" if any(word in text for word in ["不想活", "崩潰"]) else "medium"
    if incident_type == "important_task":
        return "medium"
    if incident_type in {"deferred_topic", "operator_feedback"}:
        return "low"
    return "low"


def configured_followup_delay_minutes(incident_type: str, text: str = "") -> Optional[int]:
    settings = load_settings()
    window = settings.get("followup_window") if isinstance(settings.get("followup_window"), dict) else {}
    per_kind = window.get("per_event_kind") if isinstance(window.get("per_event_kind"), dict) else {}

    if incident_type == "important_task":
        delegated_cfg = per_kind.get("delegated_task") if isinstance(per_kind.get("delegated_task"), dict) else {}
        raw = delegated_cfg.get("minutes", window.get("default_minutes"))
        try:
            minutes = int(raw)
            if minutes >= 0:
                return minutes
        except Exception:
            pass
        return 60 if "明天要" in text else 240
    if incident_type == "emotional_incident":
        watch_cfg = per_kind.get("watchful_state") if isinstance(per_kind.get("watchful_state"), dict) else {}
        raw = watch_cfg.get("minutes")
        try:
            minutes = int(raw)
            if minutes >= 0:
                return minutes
        except Exception:
            pass
    if incident_type in {"health_incident", "safety_incident"}:
        sensitive_cfg = per_kind.get("sensitive_event") if isinstance(per_kind.get("sensitive_event"), dict) else {}
        raw = sensitive_cfg.get("minutes")
        try:
            minutes = int(raw)
            if minutes >= 0:
                return minutes
        except Exception:
            pass
    return None


def build_followup_policy_for_detected_incident(incident_type: str, severity: str, text: str) -> dict:
    if severity == "low":
        return {"mode": "none"}
    hook_type = default_hook_type_for_incident(incident_type, text)
    if hook_type not in HOOK_TYPES:
        return {"mode": "none"}
    delay_minutes = configured_followup_delay_minutes(incident_type, text)
    if delay_minutes is None:
        if incident_type in {"health_incident", "safety_incident"}:
            delay_minutes = 180 if severity == "high" else 720
        elif incident_type == "emotional_incident":
            delay_minutes = 60 if severity == "high" else 360
        elif incident_type == "important_task":
            delay_minutes = 60 if "明天要" in text else 240
        else:
            delay_minutes = 0
    return {
        "mode": "hook",
        "hook_type": hook_type,
        "delay_minutes": delay_minutes,
    }


def curate_incident_for_memory(incident: dict) -> dict:
    severity = incident.get("severity")
    if severity == "high":
        return {
            "tier": "candidate",
            "status": "candidate",
            "reason": "high severity incident deserves later confirmation before memory approval",
        }
    if severity == "medium":
        return {
            "tier": "optional",
            "status": "candidate",
            "reason": "medium severity incident may matter later but should not auto-enter memory",
        }
    return {
        "tier": "skip",
        "status": "rejected",
        "reason": "low severity incident should stay local as context only",
    }


def rank_incident_for_memory(incident: dict) -> dict:
    incident_type = incident.get("type")
    severity = incident.get("severity")
    rank = "temporary"
    reason = "low severity or weak significance should stay temporary"
    if incident_type == "safety_incident" and severity == "high":
        rank = "critical"
        reason = "high severity safety incident should be treated as critical"
    elif incident_type == "health_incident" and severity == "high":
        rank = "important"
        reason = "high severity health incident should be treated as important"
    elif incident_type == "emotional_incident" and severity == "medium":
        rank = "context"
        reason = "medium emotional incidents are useful context but not long-term priority"
    elif incident_type == "emotional_incident" and severity == "high":
        rank = "important"
        reason = "high emotional incidents deserve stronger follow-up and memory review"
    elif incident_type == "important_task" and severity == "medium":
        rank = "context"
        reason = "important tasks are usually short-term context unless escalated"
    elif incident_type == "important_task" and severity == "high":
        rank = "important"
        reason = "high priority tasks may matter long enough to become important memory candidates"
    allowed = rank in {"important", "critical"}
    return {
        "rank": rank,
        "candidate_allowed": allowed,
        "status": "candidate" if allowed else "rejected",
        "reason": reason,
    }


def append_memory_rank_record(memory_rank_store: dict, incident: dict) -> dict:
    for record in memory_rank_store.get("records", []):
        if record.get("incident_id") == incident.get("id"):
            return record
    ranking = rank_incident_for_memory(incident)
    record = {
        "incident_id": incident.get("id"),
        "incident_type": incident.get("type"),
        "severity": incident.get("severity"),
        "rank": ranking["rank"],
        "candidate_allowed": ranking["candidate_allowed"],
        "status": ranking["status"],
        "reason": ranking["reason"],
        "created_at": iso_now(),
    }
    memory_rank_store.setdefault("records", []).append(record)
    return record


def detect_incident_from_text(text: str, incident_store: dict, now_dt: Optional[datetime] = None) -> Optional[dict]:
    text = (text or "").strip()
    if not text:
        return None
    if looks_like_contextual_staging_follow_on(text):
        return {
            "detected": False,
            "reason": "contextual-follow-on",
        }
    residue_marker = structured_context_residue_marker_for_text(strip_untrusted_metadata_blocks(text))
    if residue_marker:
        return {
            "detected": False,
            "reason": "structured-context-residue",
            "source_marker": residue_marker,
        }
    now_dt = now_dt or now_local()
    cooldown_hours = 6
    priority = ["safety_incident", "health_incident", "emotional_incident", "important_task"]
    candidates = []
    for incident_type in priority:
        incident_text = extract_tracking_focus_text(text, incident_type=incident_type) if incident_type == "important_task" else text
        incident_text = incident_text or text
        scored = score_incident_type(incident_text, incident_type)
        severity = score_severity(scored["score"])
        if severity is None:
            continue
        blocking_incident = find_cooldown_blocking_incident(
            incident_store,
            incident_type,
            now_dt,
            cooldown_hours,
            incident_text,
            severity,
            scored["keyword_hits"],
            scored["hint_hits"],
        )
        if blocking_incident:
            return {
                "detected": False,
                "reason": "cooldown",
                "incident_type": incident_type,
                "blocking_incident_id": blocking_incident.get("id"),
                "blocking_incident_created_at": blocking_incident.get("created_at"),
                "blocking_incident_summary": blocking_incident.get("source_summary"),
            }
        followup_policy = build_followup_policy_for_detected_incident(incident_type, severity, incident_text)
        payload = {"detected_text": trim_summary(incident_text, 120), "incident_type": incident_type}
        if incident_type in {"health_incident", "safety_incident"}:
            payload["condition"] = trim_summary(incident_text, 120)
        elif incident_type == "emotional_incident":
            payload["topic"] = trim_summary(incident_text, 120)
        elif incident_type == "important_task":
            payload["task"] = trim_summary(incident_text, 120)
            if "明天要" in incident_text:
                payload["item"] = trim_summary(incident_text, 120)
        payload["source_focus_text"] = trim_summary(incident_text, 220)
        candidates.append({
            "detected": True,
            "incident_type": incident_type,
            "score": scored["score"],
            "keyword_hits": scored["keyword_hits"],
            "hint_hits": scored["hint_hits"],
            "contextual_bonus": scored.get("contextual_bonus", 0),
            "severity": severity,
            "source_summary": trim_summary(incident_text, 120),
            "followup_policy": followup_policy,
            "payload": payload,
        })
    if not candidates:
        return None
    candidates.sort(key=lambda item: (-item["score"], priority.index(item["incident_type"])))
    return candidates[0]
    return None


def detect_incident_from_text_v1(text: str, incident_store: dict, now_dt: Optional[datetime] = None) -> Optional[dict]:
    text = (text or "").strip()
    if not text:
        return None
    residue_marker = structured_context_residue_marker_for_text(strip_untrusted_metadata_blocks(text))
    if residue_marker:
        return {
            "detected": False,
            "reason": "structured-context-residue",
            "source_marker": residue_marker,
        }
    now_dt = now_dt or now_local()
    priority = ["safety_incident", "health_incident", "emotional_incident", "important_task"]
    for incident_type in priority:
        rules = INCIDENT_RULES.get(incident_type, {})
        if not any(keyword in text for keyword in rules.get("keywords", [])):
            continue
        if incident_recent_same_type(incident_store, incident_type, now_dt, 6):
            return {
                "detected": False,
                "reason": "cooldown",
                "incident_type": incident_type,
            }
        severity = legacy_score_severity(incident_type, text)
        followup_policy = build_followup_policy_for_detected_incident(incident_type, severity, text)
        payload = {"detected_text": trim_summary(text, 120), "incident_type": incident_type}
        if incident_type in {"health_incident", "safety_incident"}:
            payload["condition"] = trim_summary(text, 120)
        elif incident_type == "emotional_incident":
            payload["topic"] = trim_summary(text, 120)
        elif incident_type == "important_task":
            payload["task"] = trim_summary(text, 120)
            if "明天要" in text:
                payload["item"] = trim_summary(text, 120)
        return {
            "detected": True,
            "incident_type": incident_type,
            "severity": severity,
            "source_summary": trim_summary(text, 120),
            "followup_policy": followup_policy,
            "payload": payload,
            "detector": "closed-loop-v1",
        }
    return None


def normalize_followup_policy(raw, incident_type: str, text: str = "") -> dict:
    if not isinstance(raw, dict):
        return {"mode": "none"}
    mode = raw.get("mode") or "none"
    if mode not in {"none", "hook"}:
        mode = "none"
    normalized = {"mode": mode}
    if mode == "hook":
        hook_type = raw.get("hook_type") or default_hook_type_for_incident(incident_type, text)
        if hook_type in HOOK_TYPES:
            normalized["hook_type"] = hook_type
        if isinstance(raw.get("trigger_at"), str):
            normalized["trigger_at"] = raw["trigger_at"].strip()
        if raw.get("delay_minutes") is not None:
            try:
                normalized["delay_minutes"] = int(raw["delay_minutes"])
            except Exception:
                pass
        if isinstance(raw.get("note"), str) and raw["note"].strip():
            normalized["note"] = raw["note"].strip()
    return normalized


def build_hook(hook_type: str, trigger_dt: datetime, summary: str, payload=None, note: str = "") -> dict:
    payload_dict = payload if isinstance(payload, dict) else {}
    normalized_summary = usable_seed_summary(summary) or trim_summary(summary, 160)
    event_kind = payload_dict.get("event_kind") or infer_followup_event_type(summary, incident_type=payload_dict.get("incident_type"))
    event_chain = payload_dict.get("event_chain") if isinstance(payload_dict.get("event_chain"), dict) else build_event_chain(normalized_summary, event_kind)
    event_chain_id = payload_dict.get("event_chain_id") or make_event_chain_id()
    return {
        "id": make_hook_id(),
        "type": hook_type,
        "created_at": iso_now(),
        "trigger_at": trigger_dt.isoformat(timespec="seconds"),
        "source_summary": summary,
        "normalized_seed_summary": normalized_summary,
        "topic_label": infer_topic_label(normalized_summary, hook_type),
        "memory_class": "tracked_followup",
        "source_layer": "hook",
        "confidence": 0.95,
        "current_status": "hook_ready",
        "last_seen_at": trigger_dt.isoformat(timespec="seconds"),
        "event_kind": event_kind,
        "event_chain": event_chain,
        "event_chain_id": event_chain_id,
        "dispatch_count": 0,
        "last_dispatched_at": None,
        "last_user_reply_at": None,
        "lifecycle": TRACKING_LIFECYCLE_ACTIVE,
        "status": "pending",
        "note": note,
        "payload": {**payload_dict, "event_chain_id": event_chain_id},
    }


def build_incident(incident_type: str, severity: str, summary: str, status: str, followup_policy: dict, payload=None, note: str = "") -> dict:
    payload_dict = payload if isinstance(payload, dict) else {}
    normalized_summary = usable_seed_summary(summary) or trim_summary(summary, 160)
    event_kind = payload_dict.get("event_kind") or infer_followup_event_type(summary, incident_type=incident_type)
    event_chain = payload_dict.get("event_chain") if isinstance(payload_dict.get("event_chain"), dict) else build_event_chain(normalized_summary, event_kind)
    event_chain_id = payload_dict.get("event_chain_id") or make_event_chain_id()
    incident = {
        "id": make_incident_id(),
        "type": incident_type,
        "created_at": iso_now(),
        "source_summary": summary,
        "normalized_seed_summary": normalized_summary,
        "topic_label": infer_topic_label(normalized_summary, incident_type),
        "memory_class": "tracked_followup",
        "source_layer": "incident",
        "confidence": float(payload_dict.get("confidence", 0.82) or 0.82),
        "current_status": "active_incident" if status != "rejected" else "historical_only",
        "last_seen_at": iso_now(),
        "lifecycle": TRACKING_LIFECYCLE_ACTIVE if status != "rejected" else TRACKING_LIFECYCLE_FADED,
        "event_kind": event_kind,
        "event_chain": event_chain,
        "event_chain_id": event_chain_id,
        "severity": severity,
        "status": status,
        "followup_policy": followup_policy,
        "note": note,
        "payload": {**payload_dict, "event_chain_id": event_chain_id},
        "linked_hook_ids": [],
    }
    incident["memory_curator"] = curate_incident_for_memory(incident)
    incident["memory_rank"] = rank_incident_for_memory(incident)
    return incident


def incident_payload_for_hook(incident: dict) -> dict:
    payload = incident.get("payload") if isinstance(incident.get("payload"), dict) else {}
    if "incident_id" not in payload and incident.get("id"):
        payload = {**payload, "incident_id": incident.get("id")}
    incident_type = incident.get("type")
    if "incident_type" not in payload and incident_type:
        payload = {**payload, "incident_type": incident_type}
    if incident_type in {"health_incident", "safety_incident"} and "condition" not in payload:
        payload = {**payload, "condition": incident.get("source_summary", "")}
    if incident_type == "important_task":
        if "task" not in payload:
            payload = {**payload, "task": incident.get("source_summary", "")}
        if "明天要" in incident.get("source_summary", "") and "item" not in payload:
            payload = {**payload, "item": incident.get("source_summary", "")}
    if incident_type == "emotional_incident" and "topic" not in payload:
        payload = {**payload, "topic": incident.get("source_summary", "")}
    if "event_kind" not in payload:
        payload = {**payload, "event_kind": incident.get("event_kind")}
    if "event_chain" not in payload and isinstance(incident.get("event_chain"), dict):
        payload = {**payload, "event_chain": incident.get("event_chain")}
    if "event_chain_id" not in payload and incident.get("event_chain_id"):
        payload = {**payload, "event_chain_id": incident.get("event_chain_id")}
    # Snapshot staging context into hook payload for traceability after staging expiry
    if "staging_snapshot" not in payload and isinstance(incident.get("staging_snapshot"), dict):
        payload = {**payload, "staging_snapshot": incident["staging_snapshot"]}
    if ASSISTANT_COMMITMENT_FIELD_KEY not in payload and isinstance(incident.get(ASSISTANT_COMMITMENT_FIELD_KEY), dict):
        payload = {**payload, ASSISTANT_COMMITMENT_FIELD_KEY: deepcopy(incident[ASSISTANT_COMMITMENT_FIELD_KEY])}
    return payload


def create_hook_from_incident(hook_store: dict, incident: dict, trigger_at_override: Optional[str] = None):
    policy = incident.get("followup_policy") if isinstance(incident.get("followup_policy"), dict) else {}
    if policy.get("mode") != "hook":
        return None
    hook_type = policy.get("hook_type") or default_hook_type_for_incident(incident.get("type", ""), incident.get("source_summary", ""))
    if hook_type not in HOOK_TYPES:
        return None
    summary = f"[incident:{incident['id']}] {incident['source_summary']}"
    for hook in iter_hooks(hook_store):
        if hook.get("source_summary") != summary:
            continue
        if str(hook.get("status") or "") not in TERMINAL_HOOK_STATUSES:
            return hook
    if trigger_at_override:
        trigger_dt = parse_dt(trigger_at_override)
    elif isinstance(policy.get("trigger_at"), str):
        trigger_dt = parse_dt(policy["trigger_at"])
    elif isinstance(policy.get("delay_minutes"), int):
        trigger_dt = now_local() + timedelta(minutes=policy["delay_minutes"])
    else:
        trigger_dt = now_local()
    hook = build_hook(
        hook_type,
        trigger_dt,
        summary,
        payload=incident_payload_for_hook(incident),
        note=str(policy.get("note") or incident.get("note") or "").strip(),
    )
    hook_store["hooks"].append(hook)
    return hook


def count_today_incidents(incident_store: dict, now_dt: datetime) -> int:
    count = 0
    for incident in incident_store.get("incidents", []):
        created_at = incident.get("created_at")
        if not isinstance(created_at, str):
            continue
        try:
            created_dt = parse_dt(created_at)
        except Exception:
            continue
        if created_dt.astimezone(now_dt.tzinfo).date() == now_dt.date():
            count += 1
    return count


def detect_conversation_mode(text: str) -> dict:
    text = (text or "").strip()
    if not text:
        return {"conversation_mode": "casual_warm", "reason": "empty-text-default"}
    has_emotional = any(word in text for word in EMOTIONAL_MODE_KEYWORDS)
    has_professional = any(word in text.lower() for word in [word.lower() for word in PROFESSIONAL_KEYWORDS])
    has_warmth = any(word in text for word in SOCIAL_SUPPORT_KEYWORDS)
    if has_emotional and has_professional:
        return {"conversation_mode": "mixed", "reason": "emotional+professional"}
    if has_emotional:
        return {"conversation_mode": "emotional_support", "reason": "emotional-cues"}
    if has_professional:
        return {"conversation_mode": "professional_deep", "reason": "professional-cues"}
    if has_warmth:
        return {"conversation_mode": "casual_warm", "reason": "warmth-cues"}
    return {"conversation_mode": "casual_warm", "reason": "default-casual"}


def update_persona_state(persona_state: dict, text: str) -> dict:
    detection = detect_conversation_mode(text)
    persona_state["conversation_mode"] = detection["conversation_mode"]
    persona_state["last_reason"] = detection["reason"]
    persona_state["last_text_summary"] = trim_summary(text, 120) if text else None
    return persona_state


def clamp01(value: float) -> float:
    return max(0.0, min(1.0, round(value, 4)))


def preferred_length_label(user_model: dict, mode: Optional[str] = None) -> str:
    prefs = user_model.get("response_length_preference", {})
    if isinstance(prefs, dict) and prefs:
        if mode == "emotional_support" and prefs.get("long", 0) >= prefs.get("medium", 0):
            return "long"
        if mode == "professional_deep" and prefs.get("long", 0) >= prefs.get("short", 0):
            return "long"
        return max(prefs, key=lambda key: prefs.get(key, 0))
    return "medium"


def address_name(profile: dict) -> str:
    relation = profile.get("care_style", {}).get("relationship", "你")
    if isinstance(relation, str) and "/" in relation:
        relation = relation.split("/")[0]
    relation = relation or "你"
    return relation


def relation_vocative_prefix(relation: str) -> str:
    rel = str(relation or "").strip()
    if rel in {"", "你", "妳"}:
        return ""
    return f"{rel}，"


_LATIN_WORD_RE = re.compile(r"[A-Za-z]{3,}")
_CJK_CHAR_RE = re.compile(r"[\u3400-\u9fff]")


def prefers_english_text(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    latin_words = len(_LATIN_WORD_RE.findall(raw))
    cjk_chars = len(_CJK_CHAR_RE.findall(raw))
    return latin_words >= 3 and cjk_chars <= 2


def hook_prefers_english(hook: dict, payload: Optional[dict] = None) -> bool:
    payload = payload if isinstance(payload, dict) else (hook.get("payload") if isinstance(hook.get("payload"), dict) else {})
    candidates: list[str] = []
    for field in (
        "source_summary",
        "normalized_seed_summary",
        "anchor_excerpt",
        "note",
    ):
        value = hook.get(field)
        if isinstance(value, str) and value.strip():
            candidates.append(value)
    for field in ("task", "topic", "message", "proactive_context_last_user_text", "proactive_continuity_summary", "proactive_context_summary"):
        value = payload.get(field)
        if isinstance(value, str) and value.strip():
            candidates.append(value)
    for group in (
        hook.get("recent_user_context"),
        payload.get("recent_user_context"),
    ):
        if isinstance(group, list):
            for item in group:
                if isinstance(item, str) and item.strip():
                    candidates.append(item)
    for turn in hook.get("anchor_turns") or []:
        if isinstance(turn, dict) and str(turn.get("role") or "") == "user":
            value = turn.get("text")
            if isinstance(value, str) and value.strip():
                candidates.append(value)
    english_hits = sum(1 for item in candidates if prefers_english_text(item))
    return english_hits > 0


def english_relation_label(relation: str) -> str:
    rel = str(relation or "").strip()
    if rel in {"", "你", "妳", "coworker", "collaborator", "assistant"}:
        return ""
    return rel


