def local_period_bucket(now_dt: datetime) -> str:
    local_now = routine_schedule_local_dt(now_dt)
    hour = local_now.hour
    if 0 <= hour < 5:
        return "late_night"
    if 5 <= hour < 11:
        return "morning"
    if 11 <= hour < 17:
        return "afternoon"
    if 17 <= hour < 22:
        return "evening"
    return "night"


def parse_optional_dt(value) -> Optional[datetime]:
    if not isinstance(value, str) or not value.strip():
        return None
    try:
        return parse_dt(value)
    except Exception:
        return None


def is_rest_suppress_request(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    compact = re.sub(r"\s+", "", raw)
    return any(re.search(pattern, compact, re.IGNORECASE) for pattern in REST_SUPPRESS_PATTERNS)


def is_operational_source_query(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    compact = re.sub(r"\s+", "", raw)
    return any(re.search(pattern, compact, re.IGNORECASE) for pattern in OPERATIONAL_SOURCE_QUERY_PATTERNS)


def is_new_session_bootstrap_text(text: str) -> bool:
    raw = str(text or "").strip()
    if not raw:
        return False
    return any(pattern.search(raw) for pattern in NEW_SESSION_BOOTSTRAP_PATTERNS)


def is_non_anchor_user_text(text: str) -> bool:
    cleaned = sanitize_runtime_residue_text(text, 200)
    if not cleaned:
        return True
    return (
        is_operational_source_query(cleaned)
        or is_new_session_bootstrap_text(cleaned)
        or looks_like_structured_context_residue(text)
        or looks_like_internal_summary_residue(text)
    )


def should_clear_rest_suppress(emotion_state: dict, text: str, now_dt: datetime) -> bool:
    raw = str(text or "").strip()
    compact = re.sub(r"\s+", "", raw)
    if any(re.search(pattern, compact, re.IGNORECASE) for pattern in REST_RESUME_PATTERNS):
        return True
    auto_clear_h = rest_suppress_auto_clear_hours()
    if auto_clear_h <= 0:
        return False
    set_dt = parse_optional_dt(emotion_state.get("rest_suppress_set_at"))
    return bool(set_dt and now_dt - set_dt >= timedelta(hours=auto_clear_h))


def active_rest_suppress(emotion_state: dict, now_dt: Optional[datetime] = None) -> Optional[dict]:
    if not isinstance(emotion_state, dict):
        return None
    if rest_suppress_duration_hours() <= 0:
        return None
    now_dt = now_dt or now_local()
    expected_wake_dt = parse_optional_dt(emotion_state.get("rest_expected_wake_at"))
    if expected_wake_dt is not None and now_dt >= expected_wake_dt:
        return None
    until_dt = parse_optional_dt(emotion_state.get("rest_suppress_until"))
    if until_dt is None or now_dt >= until_dt:
        return None
    return {
        "until": until_dt.isoformat(timespec="seconds"),
        "reason": emotion_state.get("rest_suppress_reason") or "user-rest-request",
        "source_text": emotion_state.get("rest_suppress_source_text"),
        "event_chain_id": emotion_state.get("rest_suppress_event_chain_id"),
        "expected_wake_at": expected_wake_dt.isoformat(timespec="seconds") if expected_wake_dt else None,
        "expected_wake_source": emotion_state.get("rest_expected_wake_source_kind"),
    }


def set_rest_suppress(emotion_state: dict, now_dt: datetime, text: str) -> None:
    duration_hours = rest_suppress_duration_hours()
    if duration_hours <= 0:
        return
    until_dt = now_dt + timedelta(hours=duration_hours)
    wake_expectation = structured_expected_wake_dt(now_dt) or infer_expected_wake_dt(now_dt, text)
    expected_wake_dt = wake_expectation.get("wake_dt") if isinstance(wake_expectation, dict) else None
    if expected_wake_dt is not None and expected_wake_dt < until_dt:
        until_dt = expected_wake_dt
    emotion_state["rest_suppress_until"] = until_dt.isoformat(timespec="seconds")
    emotion_state["rest_suppress_set_at"] = now_dt.isoformat(timespec="seconds")
    emotion_state["rest_suppress_reason"] = "user-rest-request"
    emotion_state["rest_suppress_source_text"] = trim_summary(text, 160)
    emotion_state.pop("wake_seed_emitted_for", None)
    emotion_state.pop("wake_seed_emitted_at", None)
    emotion_state.pop("wake_seed_source_summary", None)
    if expected_wake_dt is not None:
        emotion_state["rest_expected_wake_at"] = expected_wake_dt.isoformat(timespec="seconds")
        emotion_state["rest_expected_wake_source_text"] = trim_summary(str(wake_expectation.get("source_text") or text), 160)
        emotion_state["rest_expected_wake_source_kind"] = str(wake_expectation.get("source") or "memory_fallback")
    set_routine_phase_override(
        emotion_state,
        "sleep",
        now_dt,
        until_dt=expected_wake_dt or until_dt,
        reason="user-rest-request",
        source_text=text,
    )


def clear_rest_suppress(emotion_state: dict, now_dt: datetime, reason: str) -> bool:
    had_state = any(
        emotion_state.get(key)
        for key in (
            "rest_suppress_until",
            "rest_suppress_set_at",
            "rest_expected_wake_at",
        )
    )
    if not had_state:
        return False
    emotion_state["rest_suppress_cleared_at"] = now_dt.isoformat(timespec="seconds")
    emotion_state["rest_suppress_clear_reason"] = reason
    for key in (
        "rest_suppress_until",
        "rest_suppress_set_at",
        "rest_suppress_reason",
        "rest_suppress_source_text",
        "rest_suppress_event_chain_id",
        "rest_expected_wake_at",
        "rest_expected_wake_source_text",
        "rest_expected_wake_source_kind",
    ):
        emotion_state.pop(key, None)
    if emotion_state.get("routine_phase_override") == "sleep":
        clear_routine_phase_override(emotion_state, now_dt, reason)
    return True


def apply_user_presence_state(emotion_state: dict, text: str, now_dt: datetime) -> dict:
    marker = now_dt.isoformat(timespec="seconds")
    operational_query = is_non_anchor_user_text(text)
    rest_request = is_rest_suppress_request(text)
    explicit_wake_resume = any(re.search(pattern, re.sub(r"\s+", "", str(text or "").strip()), re.IGNORECASE) for pattern in REST_RESUME_PATTERNS)
    cleared_rest = False
    rest_active_before = bool(active_rest_suppress(emotion_state, now_dt))
    preserve_rest = False
    if rest_request:
        set_rest_suppress(emotion_state, now_dt, text)
        trace_followup(
            now_dt,
            event_kind="watchful_state",
            source_stage="presence",
            followup_decision="suppressed",
            trigger_reason="user-rest-request",
            continuity_source="user",
            live_dispatch_result="rest-suppress-set",
            summary=text,
            extra={"rest_suppress_until": emotion_state.get("rest_suppress_until")},
        )
    elif not operational_query:
        if rest_active_before and not should_clear_rest_suppress(emotion_state, text, now_dt):
            preserve_rest = True
        else:
            cleared_rest = clear_rest_suppress(emotion_state, now_dt, "normal-user-reply")
        if cleared_rest:
            trace_followup(
                now_dt,
                source_stage="presence",
                followup_decision="resumed",
                trigger_reason="normal-user-reply",
                continuity_source="user",
                live_dispatch_result="rest-suppress-cleared",
                summary=text,
            )
    elif operational_query:
        trace_followup(
            now_dt,
            source_stage="presence",
            followup_decision="ignored-for-absence",
            trigger_reason="operational-source-query",
            continuity_source="user",
            live_dispatch_result="no-absence-reset",
            summary=text,
            )
    elif explicit_wake_resume and not operational_query:
        set_routine_phase_override(
            emotion_state,
            "wake_window",
            now_dt,
            duration_minutes=routine_schedule_wake_window_minutes(),
            reason="explicit-wake-resume",
            source_text=text,
        )
    emotion_state["last_processed_user_at"] = marker
    if not operational_query and not preserve_rest:
        emotion_state["last_interaction_at"] = marker
        emotion_state["last_engaged_user_at"] = marker
    if cleared_rest:
        set_routine_phase_override(
            emotion_state,
            "wake_window",
            now_dt,
            duration_minutes=routine_schedule_wake_window_minutes(),
            reason="rest-suppress-cleared",
            source_text=text,
        )
    return {
        "marker": marker,
        "operational_query": operational_query,
        "rest_request": rest_request,
        "explicit_wake_resume": explicit_wake_resume,
        "rest_suppress_active": bool(active_rest_suppress(emotion_state, now_dt)),
        "rest_suppress_cleared": cleared_rest,
        "rest_suppress_preserved": preserve_rest,
        "routine_phase": routine_phase_switch(now_dt, emotion_state).get("phase"),
    }


def build_temporal_context(profile: Optional[dict] = None, emotion_state: Optional[dict] = None, now_dt: Optional[datetime] = None) -> dict:
    now_dt = now_dt or now_local()
    emotion_state = emotion_state if isinstance(emotion_state, dict) else load_emotion_state()
    last_user = last_user_interaction()
    session_last_user_dt = last_user["timestamp"] if last_user and not is_operational_source_query(last_user.get("text") or "") else None
    state_last_interaction_dt = parse_optional_dt(emotion_state.get("last_engaged_user_at") or emotion_state.get("last_interaction_at"))
    if session_last_user_dt and state_last_interaction_dt:
        last_user_dt = max(session_last_user_dt, state_last_interaction_dt)
        source = "session+emotion_state"
    elif session_last_user_dt:
        last_user_dt = session_last_user_dt
        source = "session"
    else:
        last_user_dt = state_last_interaction_dt
        source = "emotion_state"
    hours_since_last_user = None
    if last_user_dt is not None:
        hours_since_last_user = max(0.0, (now_dt - last_user_dt).total_seconds() / 3600.0)
    return {
        "now": now_dt.isoformat(timespec="seconds"),
        "local_period": local_period_bucket(now_dt),
        "last_user_at": last_user_dt.isoformat(timespec="seconds") if last_user_dt else None,
        "last_user_text": last_user.get("text") if last_user else None,
        "last_user_marker": last_user_dt.isoformat(timespec="seconds") if last_user_dt else None,
        "source": source,
        "hours_since_last_user": round(hours_since_last_user, 3) if hours_since_last_user is not None else None,
    }


def proactive_chat_in_quiet_hours(now_dt: datetime) -> bool:
    decision = proactive_chat_quiet_hours_decision(now_dt)
    return bool(decision.get("blocked"))


def proactive_chat_quiet_hours_decision(now_dt: datetime) -> dict:
    start, end = proactive_chat_quiet_hours()
    local_now = routine_schedule_local_dt(now_dt)
    current_hour = local_now.hour
    if start == end:
        blocked = False
    elif start < end:
        blocked = start <= current_hour < end
    else:
        blocked = current_hour >= start or current_hour < end
    return {
        "blocked": blocked,
        "start": start,
        "end": end,
        "crosses_midnight": start > end,
        "current_hour": current_hour,
    }


def count_today_proactive_hooks(hook_store: dict, now_dt: datetime) -> int:
    count = 0
    for hook in iter_hooks(hook_store):
        if hook.get("type") != "proactive_chat":
            continue
        payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        if not bool(payload.get("last_dispatch_pending")) and not hook_has_canonical_delivery_confirmation(hook):
            continue
        created_dt = parse_optional_dt(hook.get("created_at") or hook.get("trigger_at"))
        if created_dt and created_dt.astimezone(now_dt.tzinfo).date() == now_dt.date():
            count += 1
    return count


def latest_proactive_activity_dt(hook_store: dict) -> Optional[datetime]:
    latest = None
    for hook in iter_hooks(hook_store):
        if hook.get("type") != "proactive_chat":
            continue
        payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        if not bool(payload.get("last_dispatch_pending")) and not hook_has_canonical_delivery_confirmation(hook):
            continue
        for field in ("last_dispatched_at", "last_rendered_at", "trigger_at", "created_at"):
            dt = parse_optional_dt(hook.get(field))
            if dt and (latest is None or dt > latest):
                latest = dt
    return latest


def proactive_chat_should_soft_skip(context: dict) -> Optional[dict]:
    if not proactive_chat_allow_when_no_trackable_thread() and context.get("proactive_event_kind") == "light_contextual_followup":
        return {
            "soft_skip": True,
            "reason": "weak-context-no-trackable-thread",
            "blocked_by": "soft-skip-weak-context",
        }
    return None


def proactive_chat_user_routine_policy(hook_store: dict, now_dt: datetime, context: dict) -> dict:
    today_count = count_today_proactive_hooks(hook_store, now_dt)
    max_per_day = proactive_chat_max_per_day()
    cooldown_minutes = proactive_chat_cooldown_minutes()
    latest_dt = latest_proactive_activity_dt(hook_store)
    next_allowed_at = None
    if latest_dt and cooldown_minutes > 0:
        next_allowed_dt = latest_dt + timedelta(minutes=cooldown_minutes)
        if now_dt < next_allowed_dt:
            next_allowed_at = next_allowed_dt.isoformat(timespec="seconds")
            return {
                "allow": False,
                "soft_skip": False,
                "reason": "cooldown-active",
                "blocked_by": "cooldown-active",
                "today_count": today_count,
                "max_proactive_per_day": max_per_day,
                "cooldown_minutes": cooldown_minutes,
                "next_allowed_at": next_allowed_at,
            }
    if max_per_day > 0 and today_count >= max_per_day:
        return {
            "allow": False,
            "soft_skip": False,
            "reason": "max-proactive-per-day",
            "blocked_by": "max-proactive-per-day",
            "today_count": today_count,
            "max_proactive_per_day": max_per_day,
            "cooldown_minutes": cooldown_minutes,
            "next_allowed_at": next_allowed_at,
        }
    soft_skip = proactive_chat_should_soft_skip(context)
    if soft_skip:
        return {
            "allow": False,
            "soft_skip": True,
            "reason": soft_skip.get("reason"),
            "blocked_by": soft_skip.get("blocked_by"),
            "today_count": today_count,
            "max_proactive_per_day": max_per_day,
            "cooldown_minutes": cooldown_minutes,
            "next_allowed_at": next_allowed_at,
        }
    return {
        "allow": True,
        "soft_skip": False,
        "reason": "routine-policy-allow",
        "blocked_by": None,
        "today_count": today_count,
        "max_proactive_per_day": max_per_day,
        "cooldown_minutes": cooldown_minutes,
        "next_allowed_at": next_allowed_at,
    }


def is_effective_priority_hook_base(hook: dict, now_dt: datetime) -> bool:
    if not isinstance(hook, dict):
        return False
    if hook.get("status") != "pending":
        return False
    if hook.get("type") not in PROACTIVE_PRIORITY_BLOCKING_HOOK_TYPES:
        return False
    if str(hook.get("current_status") or "").startswith("historical"):
        return False
    if hook_dispatch_guard_decision(hook, now_dt).get("reason") == "dispatch-cap-reached":
        return False
    trigger_dt = parse_optional_dt(hook.get("trigger_at"))
    if trigger_dt and trigger_dt < now_dt - timedelta(hours=48) and int(hook.get("dispatch_count", 0) or 0) == 0:
        return False
    return True


def task_hook_holding_snapshot(hook: Optional[dict], now_dt: datetime) -> dict:
    if not isinstance(hook, dict):
        return {"active": False, "reason": "no-task-hook"}
    if hook.get("status") != "pending":
        return {"active": False, "reason": "not-pending"}
    if hook.get("type") not in TASK_PROGRESS_HOOK_TYPES:
        return {"active": False, "reason": "not-task-hook"}
    if str(hook.get("current_status") or "").startswith("historical"):
        return {"active": False, "reason": "historical"}
    dispatch_guard = hook_dispatch_guard_decision(hook, now_dt)
    if not dispatch_guard.get("allow") and dispatch_guard.get("reason") == "dispatch-cap-reached":
        return {"active": False, "reason": "dispatch-cap-reached"}
    if get_event_followup_state(hook) == FOLLOWUP_STATE_PARKED or infer_hook_lifecycle(hook) in {
        TRACKING_LIFECYCLE_PARKED,
        TRACKING_LIFECYCLE_FADED,
    }:
        return {
            "active": False,
            "reason": "parked-task-hook-does-not-hold-thread",
            "dispatch_count": int(hook.get("dispatch_count", 0) or 0),
            "cooldown_minutes": hook_dispatch_cooldown_minutes(hook),
        }

    dispatch_count = int(hook.get("dispatch_count", 0) or 0)
    cooldown_minutes = hook_dispatch_cooldown_minutes(hook)
    last_dispatched_dt = parse_optional_dt(hook.get("last_dispatched_at"))
    created_dt = parse_optional_dt(hook.get("created_at") or hook.get("trigger_at"))
    payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
    rendered_dt = parse_optional_dt(hook.get("last_rendered_at") or payload.get("last_rendered_at"))
    delivery_confirmed = hook_has_canonical_delivery_confirmation(hook)

    if bool(payload.get("last_dispatch_pending")):
        if rendered_dt is None:
            return {
                "active": False,
                "reason": "delivery-unconfirmed-does-not-hold-thread",
                "dispatch_count": dispatch_count,
                "cooldown_minutes": cooldown_minutes,
            }
        pending_age_seconds = max(0.0, (now_dt - rendered_dt).total_seconds())
        if pending_age_seconds <= 120:
            return {
                "active": True,
                "reason": "pending-delivery-holds-thread",
                "dispatch_count": dispatch_count,
                "cooldown_minutes": cooldown_minutes,
                "age_seconds": round(pending_age_seconds, 1),
            }
        return {
            "active": False,
            "reason": "delivery-unconfirmed-does-not-hold-thread",
            "dispatch_count": dispatch_count,
            "cooldown_minutes": cooldown_minutes,
            "age_seconds": round(pending_age_seconds, 1),
        }

    if dispatch_count > 0 and not delivery_confirmed:
        return {
            "active": False,
            "reason": "delivery-unconfirmed-does-not-hold-thread",
            "dispatch_count": dispatch_count,
            "cooldown_minutes": cooldown_minutes,
        }

    if dispatch_count > 0 and last_dispatched_dt is not None and cooldown_minutes > 0:
        age_hours = (now_dt - last_dispatched_dt).total_seconds() / 3600.0
        if age_hours <= (cooldown_minutes / 60.0):
            return {
                "active": True,
                "reason": "recent-task-hook-holds-thread",
                "dispatch_count": dispatch_count,
                "cooldown_minutes": cooldown_minutes,
                "age_hours": round(age_hours, 3),
            }

    if dispatch_count == 0 and created_dt is not None:
        create_age_hours = (now_dt - created_dt).total_seconds() / 3600.0
        if 0 <= create_age_hours <= 6:
            return {
                "active": True,
                "reason": "fresh-task-hook-holds-thread",
                "dispatch_count": dispatch_count,
                "cooldown_minutes": cooldown_minutes,
                "age_hours": round(create_age_hours, 3),
            }

    return {
        "active": False,
        "reason": "parked-task-hook-ready",
        "dispatch_count": dispatch_count,
        "cooldown_minutes": cooldown_minutes,
    }


def is_effective_priority_hook(hook: dict, profile: dict, emotion_state: dict, now_dt: datetime) -> bool:
    if not is_effective_priority_hook_base(hook, now_dt):
        return False
    temporal = temporal_guard_decision_for_hook(hook, profile, emotion_state, now_dt)
    if not temporal.get("allow"):
        return False
    if hook.get("type") in TASK_PROGRESS_HOOK_TYPES:
        return task_hook_holding_snapshot(hook, now_dt).get("active", False)
    return True


def find_effective_priority_hook(hook_store: dict, profile: dict, emotion_state: dict, now_dt: datetime) -> Optional[dict]:
    candidates = [hook for hook in iter_hooks(hook_store) if is_effective_priority_hook(hook, profile, emotion_state, now_dt)]
    if not candidates:
        return None
    candidates.sort(
        key=lambda hook: (
            int(hook.get("dispatch_count", 0) or 0),
            hook.get("last_dispatched_at") or hook.get("trigger_at") or "",
        ),
        reverse=True,
    )
    return candidates[0]


def find_effective_hook_by_types(hook_store: dict, profile: dict, emotion_state: dict, now_dt: datetime, hook_types: set[str]) -> Optional[dict]:
    candidates = []
    for hook in iter_hooks(hook_store):
        if not isinstance(hook, dict):
            continue
        if hook.get("status") != "pending":
            continue
        if hook.get("type") not in hook_types:
            continue
        if str(hook.get("current_status") or "").startswith("historical"):
            continue
        guard = hook_dispatch_guard_decision(hook, now_dt)
        if not guard.get("allow") and guard.get("reason") == "dispatch-cap-reached":
            continue
        temporal = temporal_guard_decision_for_hook(hook, profile, emotion_state, now_dt)
        if not temporal.get("allow"):
            continue
        candidates.append(hook)
    if not candidates:
        return None
    candidates.sort(
        key=lambda hook: (
            int(hook.get("dispatch_count", 0) or 0),
            hook.get("last_dispatched_at") or hook.get("trigger_at") or "",
        ),
        reverse=True,
    )
    return candidates[0]


def find_existing_proactive_hook(hook_store: dict, session_key: str, anchor_marker: str) -> Optional[dict]:
    for hook in iter_hooks(hook_store):
        if hook.get("status") != "pending" or hook.get("type") != "proactive_chat":
            continue
        payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        if payload.get("session_key") != session_key or payload.get("proactive_anchor_marker") != anchor_marker:
            continue
        if bool(payload.get("last_dispatch_pending")):
            return hook
        followup_state = get_event_followup_state(hook)
        lifecycle = infer_hook_lifecycle(hook)
        if followup_state == FOLLOWUP_STATE_PARKED:
            continue
        if lifecycle in {
            TRACKING_LIFECYCLE_PARKED,
            TRACKING_LIFECYCLE_FADED,
            TRACKING_LIFECYCLE_COMPLETED,
        }:
            continue
        return hook
    return None


def proactive_chat_arbiter(
    hook_store: dict,
    profile: dict,
    emotion_state: dict,
    now_dt: datetime,
    *,
    session_key: str,
    interaction_anchor_dt: Optional[datetime],
    proactive_context: Optional[dict] = None,
) -> dict:
    context = proactive_context if isinstance(proactive_context, dict) else build_proactive_context(session_key, now_dt)
    anchor_marker = interaction_anchor_dt.isoformat(timespec="seconds") if interaction_anchor_dt else None
    phase_decision = routine_phase_switch(now_dt, emotion_state)
    phase = phase_decision.get("phase") or "active_day"
    phase_policy = phase_decision.get("policy") if isinstance(phase_decision.get("policy"), dict) else routine_phase_policy(phase)
    interval_hours = phase_policy.get("interval_hours")
    if interval_hours is None:
        interval_hours = proactive_chat_interval_hours()
    quiet_hours = proactive_chat_quiet_hours_decision(now_dt)
    settings_snapshot = {
        "interval_hours": interval_hours,
        "quiet_hours": quiet_hours,
        "use_recent_window_only": proactive_chat_use_recent_window_only(),
        "recent_window_turns": proactive_chat_recent_window_turns(),
        "cooldown_minutes": proactive_chat_cooldown_minutes(),
        "max_proactive_per_day": proactive_chat_max_per_day(),
        "allow_when_no_trackable_thread": proactive_chat_allow_when_no_trackable_thread(),
        "routine_schedule_enabled": routine_schedule_enabled(),
        "routine_phase": phase,
        "routine_phase_source": phase_decision.get("source"),
    }
    if not proactive_chat_enabled():
        return {"allow": False, "reason": "feature-disabled", "context": context, "anchor_marker": anchor_marker, "settings": settings_snapshot}
    if not phase_policy.get("proactive_enabled", True):
        return {
            "allow": False,
            "reason": "routine-phase-proactive-disabled",
            "blocked_by": "routine-phase-proactive-disabled",
            "context": context,
            "anchor_marker": anchor_marker,
            "settings": settings_snapshot,
            "routine_phase": phase_decision,
        }
    rest_suppress = active_rest_suppress(emotion_state, now_dt)
    if rest_suppress:
        return {
            "allow": False,
            "reason": "rest-suppress-active",
            "context": context,
            "anchor_marker": anchor_marker,
            "rest_suppress": rest_suppress,
            "settings": settings_snapshot,
            "routine_phase": phase_decision,
        }
    if quiet_hours.get("blocked"):
        return {"allow": False, "reason": "quiet-hours", "context": context, "anchor_marker": anchor_marker, "quiet_hours": quiet_hours, "settings": settings_snapshot, "routine_phase": phase_decision}
    blocking_hook = find_effective_priority_hook(hook_store, profile, emotion_state, now_dt)
    if blocking_hook:
        return {
            "allow": False,
            "reason": "active-priority-hook",
            "context": context,
            "anchor_marker": anchor_marker,
            "blocking_hook_id": blocking_hook.get("id"),
            "blocking_hook_type": blocking_hook.get("type"),
            "settings": settings_snapshot,
            "routine_phase": phase_decision,
        }
    if not interaction_anchor_dt:
        return {"allow": False, "reason": "missing-anchor", "context": context, "anchor_marker": anchor_marker, "settings": settings_snapshot, "routine_phase": phase_decision}
    if now_dt < interaction_anchor_dt + timedelta(hours=interval_hours):
        return {
            "allow": False,
            "reason": "interval-not-met",
            "context": context,
            "anchor_marker": anchor_marker,
            "next_allowed_at": (interaction_anchor_dt + timedelta(hours=interval_hours)).isoformat(timespec="seconds"),
            "settings": settings_snapshot,
            "routine_phase": phase_decision,
        }
    if not context.get("available"):
        return {"allow": False, "reason": "recent-window-unavailable", "context": context, "anchor_marker": anchor_marker, "settings": settings_snapshot, "routine_phase": phase_decision}
    if anchor_marker and find_existing_proactive_hook(hook_store, session_key, anchor_marker):
        return {"allow": False, "reason": "dedupe-existing-source", "context": context, "anchor_marker": anchor_marker, "settings": settings_snapshot, "routine_phase": phase_decision}
    routine_policy = proactive_chat_user_routine_policy(hook_store, now_dt, context)
    if not routine_policy.get("allow"):
        return {
            "allow": False,
            "reason": routine_policy.get("reason"),
            "blocked_by": routine_policy.get("blocked_by"),
            "soft_skip": routine_policy.get("soft_skip", False),
            "context": context,
            "anchor_marker": anchor_marker,
            "routine_policy": routine_policy,
            "settings": settings_snapshot,
            "next_allowed_at": routine_policy.get("next_allowed_at"),
            "routine_phase": phase_decision,
        }
    return {
        "allow": True,
        "reason": "allow",
        "context": context,
        "anchor_marker": anchor_marker,
        "interval_hours": interval_hours,
        "quiet_hours": quiet_hours,
        "routine_policy": routine_policy,
        "settings": settings_snapshot,
        "routine_phase": phase_decision,
    }


def load_jobs_config() -> dict:
    if not JOBS_PATH.exists():
        return {"jobs": []}
    try:
        data = json.loads(JOBS_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {"jobs": []}
    if not isinstance(data.get("jobs"), list):
        data["jobs"] = []
    return data


def normalize_cron_info_job(job: dict) -> Optional[dict]:
    if not isinstance(job, dict):
        return None
    job_type = str(job.get("kind") or job.get("type") or job.get("category") or "").strip()
    if job_type not in CRON_INFO_JOB_TYPES:
        return None
    if str(job.get("status") or "enabled").lower() in {"disabled", "inactive", "paused"}:
        return None
    due_raw = job.get("next_run_at") or job.get("scheduled_for") or job.get("trigger_at") or job.get("run_at")
    due_dt = parse_optional_dt(due_raw)
    if due_dt is None:
        return None
    return {
        "job_id": job.get("id") or job.get("name") or "cron-info-job",
        "job_type": job_type,
        "summary": str(job.get("summary") or job.get("name") or job_type),
        "due_at": due_dt,
        "raw": job,
    }


def find_due_cron_info_push(now_dt: datetime) -> Optional[dict]:
    jobs = load_jobs_config().get("jobs", [])
    candidates = []
    for job in jobs:
        normalized = normalize_cron_info_job(job)
        if not normalized:
            continue
        if normalized["due_at"] <= now_dt:
            candidates.append(normalized)
    if not candidates:
        return None
    candidates.sort(key=lambda item: item["due_at"])
    return candidates[0]


def build_proactive_chat_candidate(
    hook_store: dict,
    profile: dict,
    emotion_state: dict,
    now_dt: datetime,
    *,
    session_key: str,
    interaction_anchor_dt: Optional[datetime],
) -> dict:
    context = build_proactive_context(session_key, now_dt)
    decision = proactive_chat_arbiter(
        hook_store,
        profile,
        emotion_state,
        now_dt,
        session_key=session_key,
        interaction_anchor_dt=interaction_anchor_dt,
        proactive_context=context,
    )
    return {
        "source": "proactive_chat",
        "allow": bool(decision.get("allow")),
        "reason": decision.get("reason"),
        "blocked_by": None if decision.get("allow") else (decision.get("blocked_by") or decision.get("reason")),
        "decision": decision,
        "context": context,
        "anchor_marker": decision.get("anchor_marker"),
    }


def build_proactive_hook_preview(now_dt: datetime, session_key: str, candidate: dict) -> Optional[dict]:
    """Build a non-persisted proactive hook preview for truth-driven rendering."""
    if not candidate.get("allow"):
        return None
    context = candidate.get("context") or {}
    if not context.get("available"):
        return None
    decision = candidate.get("decision") or {}
    event_kind = context.get("event_kind") or "parked_topic"
    proactive_event_kind = context.get("proactive_event_kind") or "light_contextual_followup"
    topic_label = sanitize_runtime_residue_text(context.get("topic_label") or "", 36) or "前面的事"
    continuity_summary = sanitize_runtime_residue_text(
        context.get("anchor_summary") or context.get("continuity_summary") or context.get("summary") or context.get("last_user_text") or topic_label,
        160,
    )
    contextual_hint = sanitize_runtime_residue_text(context.get("contextual_hint") or "", 120)
    if looks_like_structured_context_residue(continuity_summary) or "<relevant-memories>" in continuity_summary.lower() or "untrusted data" in continuity_summary.lower():
        continuity_summary = ""
    if looks_like_structured_context_residue(topic_label) or "<" in topic_label or "UNTRUSTED DATA" in topic_label.upper():
        topic_label = "前面的事"
    if not continuity_summary and not sanitize_recent_window_turn_text(context.get("last_user_text") or "") and not sanitize_runtime_residue_text(context.get("summary") or "", 160):
        return None
    anchor_marker = decision.get("anchor_marker") or now_dt.isoformat(timespec="seconds")
    anchor_event_chain = context.get("anchor_event_chain") if isinstance(context.get("anchor_event_chain"), dict) else None
    event_chain = deepcopy(anchor_event_chain) if anchor_event_chain else build_event_chain(
        context.get("last_user_update") or continuity_summary or context.get("last_user_text") or topic_label,
        event_kind,
        topic_label=topic_label,
    )
    event_chain_id = (
        str(context.get("anchor_event_chain_id") or "").strip()
        or make_event_chain_id("proactive-chat", session_key, anchor_marker)
    )
    payload = {
        "source": "proactive_chat",
        "turn_origin": "proactive",
        "session_key": session_key,
        "proactive_anchor_marker": anchor_marker,
        "proactive_context_summary": context.get("summary"),
        "proactive_continuity_summary": continuity_summary,
        "proactive_contextual_hint": contextual_hint,
        "proactive_context_turns": context.get("turns"),
        "proactive_context_last_user_text": context.get("last_user_text"),
        "proactive_context_turn_count": context.get("turn_count"),
        "proactive_topic_label": topic_label,
        "proactive_topic_label_source": context.get("topic_label_source"),
        "proactive_event_kind": proactive_event_kind,
        "event_kind": event_kind,
        "event_chain_id": event_chain_id,
        "event_chain": event_chain,
        "anchor_summary": context.get("anchor_summary") or continuity_summary,
        "last_user_update": context.get("last_user_update") or context.get("last_user_text"),
        "open_loop": context.get("open_loop"),
        "send_intent": context.get("send_intent"),
        "anchor_source_layer": context.get("anchor_source_layer"),
        "anchor_source_id": context.get("anchor_source_id"),
        "anchor_lifecycle": context.get("anchor_lifecycle"),
        "anchor_session_key": context.get("anchor_session_key"),
    }
    hook = build_hook("proactive_chat", now_dt, continuity_summary, payload=payload)
    hook["source_layer"] = "proactive_chat"
    hook["event_kind"] = event_kind
    hook["event_chain"] = payload["event_chain"]
    hook["event_chain_id"] = event_chain_id
    hook["topic_label"] = topic_label
    hook["payload"] = payload
    return hook


def build_hook_anchor_snapshot(hook: Optional[dict]) -> dict:
    if not isinstance(hook, dict):
        return {}
    summary = usable_seed_summary(str(hook.get("source_summary") or "").strip()) or str(hook.get("source_summary") or "").strip()
    default_topic_label = str(hook.get("topic_label") or "").strip() or infer_topic_label(summary, "前面的事")
    anchor = build_continuity_anchor_contract(
        hook,
        fallback_text=summary,
        default_event_kind=str(hook.get("event_kind") or "parked_topic"),
        default_topic_label=default_topic_label,
        default_source_layer="hook",
    )
    return {
        "hook_id": hook.get("id"),
        "hook_type": hook.get("type"),
        "hook_summary": summary,
        "anchor_summary": anchor.get("anchor_summary"),
        "last_user_update": anchor.get("last_user_update"),
        "open_loop": anchor.get("open_loop"),
        "event_kind": anchor.get("event_kind"),
        "event_chain_id": anchor.get("event_chain_id"),
        "topic_label": anchor.get("topic_label"),
        "lifecycle": anchor.get("lifecycle"),
        "source_layer": anchor.get("source_layer"),
    }


def build_outbound_candidate_snapshot(
    hook_store: dict,
    profile: dict,
    incident_store: dict,
    emotion_state: dict,
    autonomy_state: dict,
    now_dt: datetime,
    *,
    session_key: str,
    interaction_anchor_dt: Optional[datetime],
) -> dict:
    temporal = build_temporal_context(profile, emotion_state, now_dt)
    phase_decision = routine_phase_switch(now_dt, emotion_state)
    task_hook = find_effective_hook_by_types(hook_store, profile, emotion_state, now_dt, TASK_PROGRESS_HOOK_TYPES)
    emotional_hook = find_effective_hook_by_types(hook_store, profile, emotion_state, now_dt, WATCHFUL_HOOK_TYPES)
    latest_user_focus = build_latest_user_focus_snapshot(
        session_key,
        "",
        now_dt,
        limit_turns=max(4, proactive_chat_recent_window_turns()),
    )
    proactive_candidate = build_proactive_chat_candidate(
        hook_store,
        profile,
        emotion_state,
        now_dt,
        session_key=session_key,
        interaction_anchor_dt=interaction_anchor_dt,
    )
    rhythm_candidate = build_rhythm_nudge_candidate(
        hook_store,
        profile,
        incident_store,
        emotion_state,
        autonomy_state,
        now_dt,
        interaction_anchor_dt,
    )
    cron_candidate = find_due_cron_info_push(now_dt)
    task_hook_holding = task_hook_holding_snapshot(task_hook, now_dt) if task_hook else {"active": False, "reason": "no-task-hook"}
    parked_task_hook = task_hook if task_hook and not task_hook_holding.get("active") else None
    if task_hook and latest_user_focus_preempts_hook(task_hook, latest_user_focus, now_dt):
        task_hook_holding = {
            "active": False,
            "reason": "newer-user-focus-preempts-task-hook",
            "dispatch_count": int(task_hook.get("dispatch_count", 0) or 0),
            "cooldown_minutes": hook_dispatch_cooldown_minutes(task_hook),
        }
        parked_task_hook = None
    return {
        "temporal": temporal,
        "phase_decision": phase_decision,
        "task_hook": task_hook,
        "task_hook_holding": task_hook_holding,
        "parked_task_hook": parked_task_hook,
        "emotional_hook": emotional_hook,
        "latest_user_focus": latest_user_focus,
        "proactive_candidate": proactive_candidate,
        "rhythm_candidate": rhythm_candidate,
        "cron_candidate": cron_candidate,
    }


# ---------------------------------------------------------------------------
# Heartbeat / scheduled-path decision contract + grounded rendering
# ---------------------------------------------------------------------------

# Decision types returned by heartbeat_scheduled_decision:
#   "none"              — nothing to do, suppress entirely (e.g. sleep phase, no override)
#   "internal_noop"     — awake but no actionable source; suppress frontend output
#   "routine_nudge"     — care-phase triggered (greeting, meal check, wind-down)
#   "proactive_chat"    — proactive chat arbiter allows sending
#   "tracked_followup"  — a due hook exists that should be delivered
#   "user_conversation" — NOT a heartbeat; skip decision gate

HEARTBEAT_DECISION_SUPPRESS = {"none", "internal_noop"}

