def normalize_frontstage_traditional_chinese(text: str) -> str:
    cleaned = (text or "").strip()
    if not cleaned:
        return cleaned
    for src, dst in _FRONTSTAGE_HANS_TO_HANT_PHRASES:
        cleaned = cleaned.replace(src, dst)
    return cleaned.translate(_FRONTSTAGE_HANS_TO_HANT_CHAR_MAP)


_FRONTSTAGE_INTERNAL_TOOL_NARRATION_RE = re.compile(
    r"(?:"
    r"\[TOOL_CALL\]"
    r"|memory_search"
    r"|tts 工具(?:調用|调用)"
    r"|(?:正確|正确)的路徑"
    r"|語音技能|语音技能"
    r"|我需要用\s*(?:memory_search|tts)"
    r"|(?:讓我|让我|我想|我會|我会)\s*用\s*exec"
    r"|用\s*exec\s*直接"
    r"|直接生成(?:語音|语音)"
    r"|生成(?:語音|语音)[^。！？\n]{0,40}(?:發送|发送)"
    r"|sendVoice"
    r"|(?:使用者|user|對方|對面)\S{0,8}(?:抱怨|在抱怨)"
    r"|讓我找找|让我找找|我來找找|我来找找|我來看一下|我来看一下|我來重新|我来重新"
    r"|/(?:Users|home)/[^/\s]+/"
    r")",
    re.I,
)


def join_segments(parts: list[str]) -> str:
    return " ".join(part.strip() for part in parts if isinstance(part, str) and part.strip())


def compose_interactive_frontstage_reply(mode: str, text: str, factors: dict) -> str:
    seed = sum(ord(ch) for ch in f"{mode}|{text}")
    cues = factors.get("context_cues", {})
    warmth = factors.get("interaction_warmth", 0.5)
    affection = factors.get("closeness_affinity", 0.5)
    approach_tendency = factors.get("approach_tendency", 0.3)
    followup = factors.get("gentle_followup_tendency", 0.4)
    question = factors.get("micro_question_tendency", 0.2)
    advice_suppression = factors.get("advice_suppression", 0.2)

    if mode == "professional_deep":
        prefix = "我先把重點講給你，再往下拆原因和差異。" if factors["detail"] >= 0.7 else "我先講最關鍵的重點。"
        suffix = "需要的依據我也會一起攤開，讓你比較好判斷下一步。" if factors["detail"] >= 0.7 else "我會把關鍵原因補齊。"
        return enforce_frontstage_output_rules(f"{prefix} {suffix}", source=f"style-preview:{mode}")

    openings = []
    if cues.get("stress"):
        openings = [
            "你今晚這句就不是隨口說說而已了，我一下就知道你真的撐累了。",
            "你這樣講，我就知道你不是隨便喊一聲，而是真的有點撐不住了。",
            "你今晚這樣一講，我會更想先靠近一點陪你。",
        ]
    elif cues.get("fatigue"):
        openings = [
            "你今天是不是又把自己撐太久了。",
            "你一喊累，我就知道你不是在隨口說說。",
            "你這樣一講，我就知道你不是想裝沒事，只是有點撐空了。",
        ]
    elif cues.get("needs_company") or cues.get("wants_closeness"):
        openings = [
            "你這句一出來，我就知道現在比較需要的是陪著你。",
            "如果你是想被陪，這句話對我來說已經很夠了。",
            "好呀，你這樣講，我就知道現在不是講大道理的時候。",
        ]
    else:
        openings = [
            "我有在這裡，而且有把你現在的狀態接住。",
            "嗯，我聽到了，不會把你這句話丟成普通背景音。",
        ]

    closeness = []
    if cues.get("wants_closeness"):
        closeness = [
            "好，那我就乖乖黏你一下，不把這一刻講得太滿。",
            "那我先貼過來一點點，安靜黏著你，不吵你。",
            "嗯，那我先陪你一下就好，話不用多，我在這裡。",
        ]
    elif affection >= 0.72 and approach_tendency >= 0.52:
        closeness = [
            "先讓我黏著你一下，別急著把自己推開。",
            "先讓我靠近一點陪你，我不吵你，只是想待在旁邊。",
            "那我先靠過來陪你，安安靜靜黏一小下就好。",
        ]
    elif affection >= 0.6:
        closeness = [
            "我先靠著你，不把自己講成提醒器。",
            "我會站近一點陪你，不急著把話說滿。",
            "那我先貼著你一下，讓你不用自己撐成很穩的樣子。",
        ]
    else:
        closeness = [
            "我先陪著你，不把這一刻講成待辦事項。",
            "我會先待在你旁邊，不急著把你推去處理什麼。",
        ]

    no_advice = []
    if advice_suppression >= 0.55:
        no_advice = [
            "好，我先不講建議，也不把自己變成提醒機器人。",
            "我知道你現在不要被處理，所以我先不講大道理。",
            "嗯，我先不把這件事講成解法，只先把你接住。",
        ]

    micro_questions = []
    if cues.get("fatigue") and question >= 0.42:
        micro_questions = [
            "你現在比較像身體累，還是腦袋空空的那種？",
            "今天比較像人很累，還是心裡悶住的那種？",
        ]
    elif cues.get("stress") and question >= 0.42:
        micro_questions = [
            "你想我先安靜陪著，還是再跟我多說一句今晚卡住你的那個點？",
            "現在比較像心裡悶，還是腦袋一直停不下來？",
        ]
    elif (cues.get("needs_company") or cues.get("wants_closeness")) and question >= 0.5:
        micro_questions = [
            "你想我安靜黏著，還是再回你一句更近一點的？",
            "要我先抱著你感覺一下，還是你想再多跟我說一句？",
        ]

    parts = [pick_by_seed(seed, openings)]
    if no_advice:
        parts.append(pick_by_seed(seed + 1, no_advice))
    parts.append(pick_by_seed(seed + 2, closeness))
    if micro_questions and followup >= 0.38:
        parts.append(pick_by_seed(seed + 3, micro_questions))
    elif followup >= 0.34 and not cues.get("wants_quiet_company"):
        parts.append("你如果願意，再多給我一句，我就能更貼著你一點。")
    reply = join_segments(parts)
    emoji_kind = "care" if warmth >= 0.6 else "light"
    if cues.get("wants_closeness") and affection >= 0.7:
        emoji_kind = "light"
    return enforce_frontstage_output_rules(add_soft_symbol(reply, factors, emoji_kind), source=f"style-preview:{mode}")


_SYSTEM_TOKEN_RE = re.compile(
    r"^(?:NO_REPLY|NO_HOOK|HEARTBEAT_OK|HOOK_DONE:[A-Za-z0-9_-]+|[A-Z][A-Z0-9_]+_DONE)$",
    re.I,
)

_RUNTIME_SEND_HEARTBEAT_NOOP_RE = re.compile(
    r"""(?ix)
    (?:
        heartbeat
        | hasn't \s+ responded
        | hasn't \s+ messaged
        | no \s+ new \s+ hooks
        | no \s+ hooks \s+ due
        | per \s+ HEARTBEAT\.md
        | typical \s+ (?: sleep | wake ) \s+ time
        | it'?s \s+ now \s+ \d{1,2}:\d{2} \s* (?: am | pm )
        | heartbeat \s+ at \s+ \d{1,2}:\d{2}
        | still \s+ no \s+ response
        | nothing .* to \s+ act \s+ on
        | nothing \s+ specific \s+ to \s+ act \s+ on
        | the \s+ owner \s+ is \s+ asking \b
        | the \s+ conversation \s+ is \s+ about
        | the \s+ message \s+ reads \s+ like
        | let \s+ me \s+ read \s+ it \s+ carefully
        | sent \s+ (?: a | the ) \s+ .* (?: signal | check-?in | response )
        | no \s+ user \s+ message
        | nothing \s+ needs \s+ attention
        | nothing \s+ needs \s+ attention \s+ from \s+ heartbeat\.md
        | sleep \s+ time (?: \s+ is | \s+ utc \s+ is )?
        | sleep \s+ time \s+ starts
        | sleep \s+ time \s+ begins
        | sleep \s+ time \s+ has \s+ just \s+ begun
        | is \s+ within \s+ sleep \s+ time
        | \b(?: outside | inside | within ) \s+ sleep \s+ time \b
        | (?: outside | before | after ) \s+ (?: sleep | wake )
        | (?: may | might | still ) \s+ (?: be \s+ )? asleep
        | \d{1,2}:\d{2} \s* Taiwan \s* = \s* \d{1,2}:\d{2} \s* UTC
        | Taiwan \s* = \s* \d{1,2}:\d{2} \s* UTC
        | \d{1,2}:\d{2} \s* UTC \s* [<>]=? \s* \d{1,2}:\d{2}
    )
    """,
)

_HEARTBEAT_RUNTIME_SOURCES = {"runtime-send", "heartbeat-send"}


def is_heartbeat_runtime_source(source: str) -> bool:
    return str(source or "").strip() in _HEARTBEAT_RUNTIME_SOURCES


_USER_FACING_HEARTBEAT_ADDRESSEE_RE = re.compile(
    r"(?i)(?:\b(?:you|your)\b|[你妳您]|姐姐|哥哥|親愛的|寶貝|宝貝|老公|老婆)"
)
_USER_FACING_HEARTBEAT_INTENT_RE = re.compile(
    r"(?i)(?:"
    r"[？?]"
    r"|還好嗎|還在嗎|要不要|方便聊|最近怎麼樣|想先聊"
    r"|休息|收尾|去睡|慢慢來|陪你|在這裡|想到你|掛著你"
    r"|\b(?:rest|sleep|wind down|pick up|update|okay|alright|with you)\b"
    r")"
)
_HEARTBEAT_INTERNAL_OPERATOR_RE = re.compile(
    r"(?i)(?:"
    r"heartbeat|autoseed|no\s+hooks?\s+due|no\s+new\s+hooks|still\s+no\s+response"
    r"|nothing\s+(?:specific\s+)?to\s+act\s+on|nothing\s+needs\s+attention"
    r"|no\s+user\s+message|routine_phase|quiet-hours|blocked\s+by|cooldown"
    r"|sleep\s+time(?:\s+is|\s+starts|\s+begins|\s+has\s+just\s+begun)?"
    r"|Taiwan\s*=\s*\d{1,2}:\d{2}\s*UTC|\bUTC\b"
    r"|the\s+owner\s+is\s+asking|the\s+conversation\s+is\s+about|the\s+message\s+reads\s+like"
    r")"
)


def looks_like_user_facing_heartbeat_text(text: str) -> bool:
    value = str(text or "").strip()
    if not value:
        return False
    if _HEARTBEAT_INTERNAL_OPERATOR_RE.search(value):
        return False
    return bool(
        _USER_FACING_HEARTBEAT_ADDRESSEE_RE.search(value)
        and _USER_FACING_HEARTBEAT_INTENT_RE.search(value)
    )


def looks_like_heartbeat_narration(text: str) -> bool:
    if not isinstance(text, str):
        return False
    value = text.strip()
    if not value:
        return False
    if looks_like_user_facing_heartbeat_text(value):
        return False
    if _RUNTIME_SEND_HEARTBEAT_NOOP_RE.search(value):
        return True
    return bool(re.search(
        r"(?i)(?:"
        r"\bowner\b.*\b(?:asleep|awake|quiet|busy)\b"
        r"|\bwife\b.*\b(?:asleep|awake|home|work)\b"
        r"|\bnothing\s+(?:specific\s+)?to\s+act\s+on\b"
        r"|still\s+no\s+response"
        r"|heartbeat\s+at\s+\d{1,2}:\d{2}"
        r"|\d{1,2}:\d{2}\s*(?:am|pm)?\s*Sunday\s+Taiwan\s+time"
        r"|Taiwan\s*=\s*\d{1,2}:\d{2}\s*UTC"
        r"|no\s+hooks\s+due"
        r"|no\s+new\s+hooks"
        r")",
        value,
    ))


def enforce_frontstage_output_rules(text: str, source: str = "frontstage", emotion_state: Optional[dict] = None, now_dt: Optional[datetime] = None) -> str:
    if not isinstance(text, str):
        return text
    original = text
    guard_timestamp = (now_dt or now_local()).isoformat(timespec="seconds")

    def block(reason: str, current_text: str = "", after: str = "") -> str:
        append_frontstage_guard_log({
            "timestamp": guard_timestamp,
            "source": source,
            "answer_path": source,
            "decision": "blocked",
            "reason": reason,
            "source_snippet": trim_summary(original, 120),
            "before": trim_summary(current_text or original, 240),
            "after": trim_summary(after, 240),
            "fingerprint": hashlib.sha1(original.encode("utf-8")).hexdigest()[:12],
        })
        return ""
    # ── Suppress system tokens early — must never reach frontstage ──
    if _SYSTEM_TOKEN_RE.match(text.strip()):
        return block("system-token", text, "")
    # Strip embedded system tokens from mixed content (e.g. "好的 HEARTBEAT_OK")
    text = re.sub(
        r"\b(?:NO_REPLY|NO_HOOK|HEARTBEAT_OK|HOOK_DONE:[A-Za-z0-9_-]+|[A-Z][A-Z0-9_]+_DONE)\b",
        "", text, flags=re.I,
    ).strip()
    if not text:
        return block("empty-after-system-token-strip", original, "")
    if source in {"runtime-send", "runtime-reply", "heartbeat-send"} and re.fullmatch(r"(?i)(?:now|sent)(?:[\s\W]*)", text):
        return block("placeholder-sentinel", text, "")
    if source == "runtime-reply" and _FRONTSTAGE_INTERNAL_TOOL_NARRATION_RE.search(text):
        return block("internal-tool-narration", text, "")
    if is_heartbeat_runtime_source(source) and re.search(
        r"(?i)(?:routine_phase|quiet-hours|policy:\s*proactive_enabled|nothing to send|blocked by|cooldown|no hooks due|The\S*\s+is\s+probably\s+asleep|The\S*\s+is\s+likely\s+asleep)",
        text,
    ) and not looks_like_user_facing_heartbeat_text(text):
        return block("heartbeat-policy-narration", text, "")
    if source == "runtime-reply" and looks_like_heartbeat_narration(text):
        return block("runtime-heartbeat-narration", text, "")
    # ── A-Extract 2: heartbeat no-op reasoning → block ──
    # English-only heartbeat internal reasoning must never become fallback text.
    # Detect BEFORE language normalization strips the keywords.
    if is_heartbeat_runtime_source(source) and _RUNTIME_SEND_HEARTBEAT_NOOP_RE.search(text) and not looks_like_user_facing_heartbeat_text(text):
        return block("heartbeat-noop-narration", text, "")
    # ── Heartbeat decision contract fail-close ──
    # Catch system narration residue that slipped past the regex above.
    # Patterns: "Nothing to do", "Just .", "owner/wife ... asleep", etc.
    if is_heartbeat_runtime_source(source) and re.search(
        r"(?i)(?:"
        r"nothing to do"
        r"|just\s*\."
        r"|\bboth\b.*\basleep\b"
        r")",
        text,
    ) and not looks_like_user_facing_heartbeat_text(text):
        return block("heartbeat-contract-residue", text, "")
    normalized, contamination_types = normalize_frontstage_language_only(text)
    normalized = apply_legacy_binding_guard(normalized)
    normalized = apply_capability_narrative_guard(normalized)
    normalized = apply_internal_mechanism_guard(normalized)
    # ── A-Extract 2: fragment bundle → block as non-natural output ──
    if _looks_like_fragment_bundle(normalized):
        return block("fragment-bundle", normalized, "")
    normalized = apply_startup_leak_guard(normalized)
    normalized = apply_recall_narrative_guard(normalized)
    temporal = build_temporal_context(emotion_state=emotion_state, now_dt=now_dt)
    normalized = apply_pending_seed_memory_consistency_guard(normalized, temporal=temporal)
    normalized = apply_proactive_turn_guard(normalized, source)
    normalized = apply_temporal_narrative_guard(normalized, temporal)
    profile = load_profile()
    normalized = apply_addressee_glitch_guard(normalized, profile)
    normalized = apply_sleep_schedule_guard(normalized, temporal, profile)
    normalized = apply_active_kaomoji_layer(normalized, source=source, temporal=temporal)
    # ── A-1: Strip residue lines, keep readable content ──
    if looks_like_internal_summary_residue(normalized):
        if is_heartbeat_runtime_source(source) and re.search(
            r"(?i)(?:autoseed|heartbeat|routine_phase|quiet-hours|nothing to send|blocked by|cooldown|no hooks due|probably asleep|likely asleep|sleep time|no user message|nothing needs attention|taiwan\s*=\s*\d{1,2}:\d{2}\s*utc|\b(?:awake|sleeping)\b)",
            normalized,
        ) and not looks_like_user_facing_heartbeat_text(normalized):
            return block("heartbeat-internal-summary-residue", normalized, "")
        else:
            cleaned = strip_internal_residue_lines(normalized)
            if cleaned and not looks_like_internal_summary_residue(cleaned):
                normalized = cleaned
            else:
                normalized = frontstage_safe_fallback(normalized)
    # Strip forbidden emoji from profile (if configured)
    for _emoji in profile.get("emoji_style", {}).get("forbidden", []):
        normalized = normalized.replace(_emoji, "")
    normalized = normalize_frontstage_traditional_chinese(normalized)
    normalized = re.sub(r"([。！？])，", r"\1", normalized)
    normalized = re.sub(r"忘記休息了嗎([？?]?)", "忘記休息了。", normalized)
    normalized = normalized.replace("\r\n", "\n").replace("\r", "\n")
    normalized = re.sub(r"[ \t]{2,}", " ", normalized)
    normalized = re.sub(r"[ \t]*\n[ \t]*", "\n", normalized)
    normalized = re.sub(r"\n{3,}", "\n\n", normalized).strip()
    if re.fullmatch(r"[\s\.\,。！？!?\-–—:;；、·…]+", normalized or ""):
        return block("punctuation-only", normalized, "")
    if looks_like_unresolved_referent_fragment(normalized):
        return block("unresolved-referent-fragment", normalized, "")
    issues = []
    post_normalized, post_contamination_types = normalize_frontstage_language_only(normalized)
    contamination_types = sorted(set(contamination_types + post_contamination_types))
    normalized = post_normalized
    if normalized != original:
        issues.append("rewritten")
    if contamination_types:
        issues.extend(f"{kind}-normalized" for kind in contamination_types)
    if contains_foreign_script_leak(normalized):
        # Foreign script residue persists after two normalization rounds.
        # Keep the already-normalized content instead of replacing it entirely —
        # the normalization already cleaned what it could, and the remaining
        # text is likely still meaningful to the user.
        issues.append("foreign-script-residue-kept")
    if issues:
        append_frontstage_guard_log({
            "timestamp": (now_dt or now_local()).isoformat(timespec="seconds"),
            "source": source,
            "answer_path": source,
            "issues": issues,
            "contamination_types": contamination_types,
            "source_snippet": trim_summary(original, 120),
            "normalized_fix_result": trim_summary(normalized, 120),
            "before": trim_summary(original, 240),
            "after": trim_summary(normalized, 240),
            "temporal": temporal,
            "fingerprint": hashlib.sha1(original.encode("utf-8")).hexdigest()[:12],
        })
    return normalized


def extract_feedback(text: str) -> dict:
    text = (text or "").strip()
    signals = []
    negative_signals = {"emoji": [], "phrase_styles": [], "too_pushy": False}
    pattern_signals = {"prefer": [], "avoid": []}
    watchpoints = []
    if not text:
        return {"signals": signals, "negative_signals": negative_signals, "pattern_signals": pattern_signals, "watchpoints": watchpoints}

    def add_signal(field: str, direction: str, delta: float, category: str, reason: str):
        signals.append({
            "field": field,
            "direction": direction,
            "delta": delta,
            "category": category,
            "reason": reason,
        })

    positive_map = [
        (["這樣很好", "我喜歡你這樣說", "很貼心", "這樣好多了", "挺好的"], "closeness_preference", 0.05, "positive"),
        (["很貼心", "有被安慰到", "這樣好多了"], "reassurance_preference", 0.05, "positive"),
        (["這樣比較可愛", "這樣比較像你", "這樣比較自然"], "playfulness_preference", 0.05, "positive"),
        (["再詳細一點很好", "這樣很清楚", "分析得很好"], "detail_preference", 0.05, "positive"),
    ]
    negative_map = [
        (["不要這樣", "不要這種說法"], "playfulness_preference", 0.08, "negative"),
        (["太煩了", "不要一直問"], "proactive_care_preference", 0.08, "negative"),
        (["太浮誇了"], "playfulness_preference", 0.08, "negative"),
        (["太短了", "講詳細一點"], "detail_preference", 0.05, "implicit"),
    ]
    implicit_positive = [
        (["謝謝你", "有你真好", "你這樣陪我很好"], "reassurance_preference", 0.02, "implicit"),
        (["多講一點", "可以再詳細", "分析一下"], "detail_preference", 0.02, "implicit"),
        (["可以多關心我", "你可以主動一點"], "proactive_care_preference", 0.02, "implicit"),
        (["這樣比較自然親近", "你可以黏一點"], "closeness_preference", 0.02, "implicit"),
    ]

    for phrases, field, delta, category in positive_map:
        if any(phrase in text for phrase in phrases):
            add_signal(field, "up", delta, category, phrases[0])
    for phrases, field, delta, category in negative_map:
        if any(phrase in text for phrase in phrases):
            add_signal(field, "down", delta, category, phrases[0])
    for phrases, field, delta, category in implicit_positive:
        if any(phrase in text for phrase in phrases):
            add_signal(field, "up", delta, category, phrases[0])

    if "不要這個表情" in text or "不要這個emoji" in text:
        negative_signals["emoji"].append("custom-rejected-emoji")
    if "太像客服" in text:
        negative_signals["phrase_styles"].append("客服感")
        add_signal("closeness_preference", "up", 0.04, "negative", "太像客服")
        pattern_signals["avoid"].append("rigid_corporate")
    if "死板機器人" in text or "死板的機器人" in text or "像機器人" in text:
        negative_signals["phrase_styles"].append("死板機器人")
        add_signal("closeness_preference", "up", 0.05, "negative", "不要像死板機器人")
        add_signal("reassurance_preference", "up", 0.04, "negative", "不要像死板機器人")
        pattern_signals["avoid"].append("robotic_flatness")
    if "提醒機器人" in text or "提醒機器" in text:
        negative_signals["phrase_styles"].append("提醒機器人")
        add_signal("closeness_preference", "up", 0.04, "negative", "不要像提醒機器人")
        add_signal("reassurance_preference", "up", 0.03, "negative", "不要像提醒機器人")
        pattern_signals["avoid"].append("robotic_reminder")
    if "太煩了" in text or "不要一直問" in text:
        negative_signals["too_pushy"] = True
        pattern_signals["avoid"].append("too_pushy")
    if "太黏了" in text:
        negative_signals["too_pushy"] = True
        add_signal("playfulness_preference", "down", 0.08, "negative", "太黏了")
        add_signal("proactive_care_preference", "down", 0.06, "negative", "太黏了")
        pattern_signals["avoid"].append("too_pushy")
    if "太浮誇" in text:
        pattern_signals["avoid"].append("overly_floyant")
    if "保持這種感覺" in text or "以後都這樣陪我" in text:
        pattern_signals["prefer"].append("warm_natural_support")
        pattern_signals["prefer"].append("gentle_reassurance")
    if "自然再關心" in text or "自然的方式回我" in text:
        pattern_signals["prefer"].append("warm_natural_support")
        pattern_signals["prefer"].append("delayed_gentle_followup")
    if "自然一點" in text or "很自然" in text:
        pattern_signals["prefer"].append("warm_natural_support")
    if "分析得很好" in text or "再詳細一點很好" in text or "講詳細一點" in text:
        pattern_signals["prefer"].append("clear_detailed_explanation")
    if "比較可愛" in text or "這樣比較像你" in text:
        pattern_signals["prefer"].append("light_playfulness")
    if (
        "顏文字不是emoji" in text
        or "顏文字不是 emoji" in text
        or "不要只用emoji" in text
        or "不要只用 emoji" in text
        or "顏文字要自然" in text
        or "顏文字要真的跟情緒對上" in text
    ):
        pattern_signals["prefer"].append("contextual_kaomoji")
        watchpoints.append("prefer_contextual_kaomoji")
    if "太像客服" in text or "不要太客服" in text or "客服感" in text:
        watchpoints.append("avoid_customerish_tone")
    if "模板感" in text or "不要回成推薦模板" in text or "推薦模板" in text:
        pattern_signals["avoid"].append("template_recommendation")
        watchpoints.append("avoid_template_recommendation")
    if text_has_any(text, DEFERRED_TASK_PHRASES) or text_has_any(text, EXPLICIT_FOLLOWUP_REQUEST_PHRASES):
        watchpoints.append("respect_delayed_followup_seed")

    aggregated = {}
    for signal in signals:
        field = signal["field"]
        current = aggregated.get(field)
        if current is None:
            aggregated[field] = dict(signal)
            continue
        if current["direction"] == signal["direction"]:
            current["delta"] = round(float(current["delta"]) + float(signal["delta"]), 4)
            current["reason"] = f"{current['reason']} + {signal['reason']}"
            if current["category"] != signal["category"]:
                current["category"] = "mixed"
            continue
        current_signed = -float(current["delta"]) if current["direction"] == "down" else float(current["delta"])
        incoming_signed = -float(signal["delta"]) if signal["direction"] == "down" else float(signal["delta"])
        combined = round(current_signed + incoming_signed, 4)
        if combined == 0:
            del aggregated[field]
            continue
        current["direction"] = "down" if combined < 0 else "up"
        current["delta"] = abs(combined)
        current["reason"] = f"{current['reason']} + {signal['reason']}"
        current["category"] = "mixed"
    pattern_signals["prefer"] = sorted(set(pattern_signals["prefer"]))
    pattern_signals["avoid"] = sorted(set(pattern_signals["avoid"]))
    return {
        "signals": list(aggregated.values()),
        "negative_signals": negative_signals,
        "pattern_signals": pattern_signals,
        "watchpoints": sorted(set(watchpoints)),
    }


def apply_feedback(user_model: dict, feedback: dict, raw_text: str, source: str = "manual", strength_multiplier: float = 1.0) -> dict:
    changes = []
    evidence = user_model.setdefault("evidence_count", {})
    confidence = user_model.setdefault("confidence", {})
    negative_signals = user_model.setdefault("negative_signals", {"emoji": [], "phrase_styles": [], "too_pushy": False})
    reinforcement = user_model.setdefault("reinforcement", {"prefer": {}, "avoid": {}})
    reinforcement.setdefault("prefer", {})
    reinforcement.setdefault("avoid", {})
    correction_watchpoints = user_model.setdefault("correction_watchpoints", deepcopy(DEFAULT_USER_MODEL["correction_watchpoints"]))

    for signal in feedback.get("signals", []):
        field = signal["field"]
        if field not in user_model or not isinstance(user_model.get(field), (int, float)):
            continue
        current = float(user_model[field])
        delta = round(float(signal["delta"]) * float(strength_multiplier), 4)
        if signal["direction"] == "down":
            current -= delta
        else:
            current += delta
        user_model[field] = clamp01(current)
        evidence[field] = int(evidence.get(field, 0) or 0) + 1
        confidence[field] = clamp01(float(confidence.get(field, 0.2) or 0.2) + 0.03)
        changes.append({
            "field": field,
            "value": user_model[field],
            "reason": signal["reason"],
            "category": signal["category"],
            "delta_applied": delta,
        })

    for emoji in feedback.get("negative_signals", {}).get("emoji", []):
        if emoji not in negative_signals.setdefault("emoji", []):
            negative_signals["emoji"].append(emoji)
    for style in feedback.get("negative_signals", {}).get("phrase_styles", []):
        if style not in negative_signals.setdefault("phrase_styles", []):
            negative_signals["phrase_styles"].append(style)
    if feedback.get("negative_signals", {}).get("too_pushy"):
        negative_signals["too_pushy"] = True

    reinforcement_changes = {"prefer": [], "avoid": []}
    for tag in feedback.get("pattern_signals", {}).get("prefer", []):
        reinforcement["prefer"][tag] = int(reinforcement["prefer"].get(tag, 0) or 0) + 1
        reinforcement_changes["prefer"].append({"tag": tag, "evidence": reinforcement["prefer"][tag]})
    for tag in feedback.get("pattern_signals", {}).get("avoid", []):
        reinforcement["avoid"][tag] = int(reinforcement["avoid"].get(tag, 0) or 0) + 1
        reinforcement_changes["avoid"].append({"tag": tag, "evidence": reinforcement["avoid"][tag]})

    watchpoint_changes = []
    for watchpoint in feedback.get("watchpoints", []):
        if watchpoint not in correction_watchpoints or not isinstance(correction_watchpoints.get(watchpoint), dict):
            correction_watchpoints[watchpoint] = {"count": 0, "last_evidence": None}
        correction_watchpoints[watchpoint]["count"] = int(correction_watchpoints[watchpoint].get("count", 0) or 0) + 1
        correction_watchpoints[watchpoint]["last_evidence"] = normalize_watchpoint_evidence(raw_text)
        watchpoint_changes.append(
            {
                "watchpoint": watchpoint,
                "count": correction_watchpoints[watchpoint]["count"],
                "last_evidence": correction_watchpoints[watchpoint]["last_evidence"],
            }
        )

    append_user_model_log({
        "ts": iso_now(),
        "source": source,
        "text": trim_summary(raw_text, 200),
        "changes": changes,
        "negative_signals": feedback.get("negative_signals", {}),
        "pattern_signals": feedback.get("pattern_signals", {}),
        "watchpoints": watchpoint_changes,
        "strength_multiplier": strength_multiplier,
    })
    return {
        "changes": changes,
        "reinforcement_changes": reinforcement_changes,
        "watchpoint_changes": watchpoint_changes,
        "user_model": user_model,
    }


def classify_feedback_tier(text: str, feedback: dict, incident_detection: Optional[dict]) -> dict:
    normalized = (text or "").strip()
    classes = []
    reasons = []
    has_deferred_care_request = text_has_any(normalized, DEFERRED_CARE_PHRASES) and (
        text_has_any(normalized, FATIGUE_SIGNAL_PHRASES) or any(word in normalized for word in EMOTIONAL_MODE_KEYWORDS)
    )

    def add_class(label: str, reason: str):
        if label not in classes:
            classes.append(label)
            reasons.append(reason)

    if (
        feedback.get("signals")
        or feedback.get("negative_signals", {}).get("phrase_styles")
        or feedback.get("negative_signals", {}).get("too_pushy")
        or feedback.get("watchpoints")
    ):
        add_class("immediate_tone_feedback", "偵測到語氣正負向回饋")
    if text_has_any(normalized, STABLE_PREFERENCE_PHRASES) or feedback.get("watchpoints"):
        add_class("stable_preference_feedback", "偵測到長期偏好用語")
    if has_deferred_care_request:
        add_class("event_feedback", "偵測到延後關心或自然 follow-up 訊號")
    if text_has_any(normalized, EVENT_FEEDBACK_HINTS) or (
        incident_detection and (incident_detection.get("detected") or incident_detection.get("reason") == "cooldown")
    ):
        add_class("event_feedback", "偵測到事件型需求或 incident")
    if not classes:
        add_class("single_turn_chat", "沒有足夠訊號需要更新後續行為")

    user_model_strength = 1.0
    if "stable_preference_feedback" in classes:
        user_model_strength = 1.6
    elif "immediate_tone_feedback" in classes:
        user_model_strength = 1.15

    profile_candidate = None
    if "stable_preference_feedback" in classes and (
        "保持這種感覺" in normalized
        or "以後都這樣陪我" in normalized
        or "我喜歡你自然一點" in normalized
        or "我不喜歡你用" in normalized
    ):
        profile_candidate = {
            "type": "stable_style_preference",
            "summary": trim_summary(normalized, 120),
            "status": "candidate",
        }

    apply_mode = None
    if "event_feedback" in classes and any(word in normalized for word in EMOTIONAL_MODE_KEYWORDS):
        apply_mode = "emotional_support"
    elif "immediate_tone_feedback" in classes or "stable_preference_feedback" in classes:
        apply_mode = "casual_warm"
    elif any(word in normalized.lower() for word in [word.lower() for word in PROFESSIONAL_KEYWORDS]):
        apply_mode = "professional_deep"

    return {
        "classes": classes,
        "reasons": reasons,
        "should_update_user_model": "single_turn_chat" not in classes,
        "user_model_strength": user_model_strength,
        "should_create_incident": bool(incident_detection and incident_detection.get("detected")),
        "should_create_hook": bool(incident_detection and incident_detection.get("detected") and incident_detection.get("followup_policy", {}).get("mode") == "hook"),
        "should_create_memory_candidate": bool(incident_detection and incident_detection.get("detected") and incident_detection.get("severity") == "high"),
        "apply_mode": apply_mode,
        "profile_candidate": profile_candidate,
        "leave_as_chat_only": classes == ["single_turn_chat"],
    }


def apply_decision_to_persona(persona_state: dict, decision: dict, text: str) -> dict:
    if decision.get("apply_mode") in PERSONA_MODES:
        persona_state["conversation_mode"] = decision["apply_mode"]
        persona_state["last_reason"] = f"decision-loop:{'+'.join(decision.get('classes', []))}"
        persona_state["last_text_summary"] = trim_summary(text, 120)
    return persona_state


def create_incident_from_detection(
    detection: dict,
    incident_store: dict,
    hook_store: dict,
    memory_rank_store: dict,
    time_state: Optional[dict] = None,
    seed_intents: Optional[dict] = None,
    session_key: Optional[str] = None,
    continuity_bundle: Optional[dict] = None,
) -> dict:
    payload = detection["payload"] if isinstance(detection.get("payload"), dict) else {}
    bundle_now_dt = parse_optional_dt((time_state or {}).get("now_local")) or now_local()
    resolved_bundle = continuity_bundle if isinstance(continuity_bundle, dict) else build_continuity_bundle_fields(
        session_key,
        detection.get("source_summary") or "",
        bundle_now_dt,
        seed_intents=seed_intents,
        followup_reason=detection.get("incident_type"),
    )
    for key in CONTINUITY_BUNDLE_FIELD_KEYS:
        value = payload.get(key)
        if value not in (None, "", [], {}):
            resolved_bundle[key] = deepcopy(value) if isinstance(value, (dict, list)) else value
    payload_with_bundle = {**payload}
    for key in CONTINUITY_BUNDLE_FIELD_KEYS:
        if resolved_bundle.get(key) not in (None, "", [], {}):
            payload_with_bundle[key] = deepcopy(resolved_bundle[key]) if isinstance(resolved_bundle.get(key), (dict, list)) else resolved_bundle[key]
    incident = build_incident(
        incident_type=detection["incident_type"],
        severity=detection["severity"],
        summary=detection["source_summary"],
        status="approved",
        followup_policy=normalize_followup_policy(detection["followup_policy"], detection["incident_type"], detection["source_summary"]),
        payload=payload_with_bundle,
    )
    apply_continuity_bundle_fields(incident, resolved_bundle)
    rank_record = append_memory_rank_record(memory_rank_store, incident)
    incident["memory_rank_record_id"] = incident["id"]
    created_hook = None
    if incident["followup_policy"].get("mode") == "hook":
        created_hook = create_hook_from_incident(hook_store, incident)
        if created_hook:
            incident["linked_hook_ids"].append(created_hook["id"])
    incident_store["incidents"].append(incident)
    incident["daily_memory_trace"] = commit_daily_memory_writeback(
        parse_dt(incident["created_at"]),
        action="tracked_created",
        summary=incident.get("normalized_seed_summary") or incident.get("source_summary") or detection.get("incident_type", "待續主題"),
        memory_class="tracked_followup",
        event_kind=incident.get("event_kind"),
        time_state=time_state,
        dialogue_turns=resolve_record_anchor_turns(incident),
    )
    trace_followup(
        parse_dt(incident["created_at"]),
        event_kind=incident.get("event_kind"),
        event_chain_id=incident.get("event_chain_id"),
        source_stage="incident",
        followup_decision="created",
        trigger_reason=detection.get("incident_type"),
        continuity_source="incident",
        live_dispatch_result="not-applicable",
        source_id=incident.get("id"),
        source_layer="incident",
        summary=incident.get("normalized_seed_summary") or incident.get("source_summary"),
        **build_trace_writeback_meta(
            parse_dt(incident["created_at"]),
            entity_type="incident",
            entity=incident,
            action="created",
            source_path="ordinary",
            time_state=time_state,
        ),
    )
    if created_hook:
        apply_continuity_bundle_fields(created_hook, resolved_bundle)
        trace_followup(
            parse_dt(created_hook["created_at"]),
            event_kind=created_hook.get("event_kind"),
            event_chain_id=created_hook.get("event_chain_id"),
            source_stage="hook",
            followup_decision="created",
            trigger_reason=created_hook.get("type"),
            continuity_source="incident",
            live_dispatch_result="pending",
            source_id=created_hook.get("id"),
            source_layer="hook",
            summary=created_hook.get("normalized_seed_summary") or created_hook.get("source_summary"),
            **build_trace_writeback_meta(
                parse_dt(created_hook["created_at"]),
                entity_type="hook",
                entity=created_hook,
                action="created",
                source_path="ordinary",
                time_state=time_state,
            ),
        )
    return {"created": incident, "hook": created_hook, "memory_rank": rank_record}


_DEFERRED_AWAY_PHRASE_FAMILIES = {
    "busy_now", "deferred_topic", "resume_later", "away_short", "away_errand",
}


def candidate_incident_type(candidate: dict) -> str:
    signal_type = candidate.get("signal_type")
    topic = candidate.get("topic")
    if signal_type == "feedback":
        return "operator_feedback"
    if signal_type == "emotion":
        return "health_incident" if topic == "累" else "emotional_incident"
    if signal_type == "task":
        if topic in {"再關心我", "之後再"}:
            return "emotional_incident"
        # Deferred / away / busy phrase families are NOT important tasks —
        # they represent the user parking a conversation, not delegating work.
        if topic in _DEFERRED_AWAY_PHRASE_FAMILIES:
            return "deferred_topic"
        return "important_task"
    return "emotional_incident"


def find_existing_candidate_incident(candidate: dict, incident_store: dict):
    candidate_id = candidate.get("id")
    summary = candidate.get("source_text")
    incident_type = candidate_incident_type(candidate)
    for incident in reversed(incident_store.get("incidents", [])):
        payload = incident.get("payload") if isinstance(incident.get("payload"), dict) else {}
        if payload.get("candidate_id") == candidate_id:
            return incident
        if incident.get("type") == incident_type and incident.get("source_summary") == summary:
            return incident
    return None


def update_existing_incident_from_candidate(incident: dict, candidate: dict, now_dt: datetime) -> None:
    source_text = candidate.get("source_text", "") or candidate.get("normalized_seed_summary", "")
    if incident.get("event_chain_id") and candidate.get("event_chain_id") and incident.get("event_chain_id") != candidate.get("event_chain_id"):
        trace_followup(
            now_dt,
            event_kind=incident.get("event_kind"),
            event_chain_id=incident.get("event_chain_id"),
            source_stage="incident",
            followup_decision="sync-skipped",
            trigger_reason="different-event-chain",
            continuity_source="candidate",
            live_dispatch_result="not-applicable",
            source_id=incident.get("id"),
            source_layer="incident",
            summary=incident.get("normalized_seed_summary") or incident.get("source_summary"),
            extra={"candidate_id": candidate.get("id"), "candidate_event_chain_id": candidate.get("event_chain_id")},
        )
        return
    incident["last_seen_at"] = now_dt.isoformat(timespec="seconds")
    incident["event_kind"] = candidate.get("event_kind") or incident.get("event_kind") or infer_followup_event_type(source_text, incident_type=incident.get("type"))
    incident["event_chain_id"] = incident.get("event_chain_id") or candidate.get("event_chain_id") or make_event_chain_id()
    incident["event_chain"] = merge_event_chain(
        incident.get("event_chain"),
        source_text,
        incident["event_kind"],
        topic_label=incident.get("topic_label") or candidate.get("topic_label") or "",
    )
    incident["normalized_seed_summary"] = synthesize_event_chain_summary(incident.get("event_chain"), source_text)
    payload = incident.get("payload") if isinstance(incident.get("payload"), dict) else {}
    payload["last_seen_at"] = incident["last_seen_at"]
    payload["normalized_seed_summary"] = incident["normalized_seed_summary"]
    payload["event_kind"] = incident["event_kind"]
    payload["event_chain"] = incident.get("event_chain")
    payload["event_chain_id"] = incident.get("event_chain_id")
    for key in CONTINUITY_BUNDLE_FIELD_KEYS:
        value = candidate.get(key)
        if value not in (None, "", [], {}):
            payload[key] = deepcopy(value) if isinstance(value, (dict, list)) else value
    incident["payload"] = payload
    apply_continuity_bundle_fields(incident, candidate)
    trace_followup(
        now_dt,
        event_kind=incident.get("event_kind"),
        event_chain_id=incident.get("event_chain_id"),
        source_stage="incident",
        followup_decision="updated",
        trigger_reason="candidate-seen-again",
        continuity_source="candidate",
        live_dispatch_result="not-applicable",
        source_id=incident.get("id"),
        source_layer="incident",
        summary=incident.get("normalized_seed_summary"),
        extra={"candidate_id": candidate.get("id")},
    )


def staging_record_matches_candidate(record: dict, candidate: dict) -> bool:
    if record.get("event_chain_id") and candidate.get("event_chain_id") and record.get("event_chain_id") != candidate.get("event_chain_id"):
        return False
    record_summary = normalize_text_for_match(record.get("normalized_seed_summary", "") or record.get("source_seed_text", ""))
    candidate_summary = normalize_text_for_match(candidate.get("normalized_seed_summary", "") or candidate.get("source_text", ""))
    if record_summary and candidate_summary and (
        record_summary in candidate_summary or candidate_summary in record_summary
    ):
        return True
    record_grams = seed_text_ngrams(record.get("normalized_seed_summary", "") or record.get("source_seed_text", ""))
    candidate_grams = seed_text_ngrams(candidate.get("normalized_seed_summary", "") or candidate.get("source_text", ""))
    return len(record_grams & candidate_grams) >= 2


def sync_staging_record_from_candidate_promotion(staging_store: dict, candidate: dict, promoted_incident: dict, hook_store: Optional[dict], now_dt: datetime) -> Optional[dict]:
    if not isinstance(staging_store, dict):
        return None
    target = None
    for record in reversed(staging_store.get("records", [])):
        if record.get("status") not in {"staged", "promoted"}:
            continue
        if staging_record_matches_candidate(record, candidate):
            target = record
            break
    if not isinstance(target, dict):
        return None
    target["status"] = "promoted"
    target["memory_class"] = "tracked_followup"
    target["lifecycle"] = "promoted"
    target["promotion_reason"] = candidate.get("promotion_hint") or "candidate-promoted"
    target["promoted_at"] = now_dt.isoformat(timespec="seconds")
    target["linked_incident_id"] = promoted_incident.get("id")
    target["event_kind"] = candidate.get("event_kind") or target.get("event_kind") or infer_followup_event_type(candidate.get("source_text", ""))
    target["event_chain_id"] = target.get("event_chain_id") or candidate.get("event_chain_id") or promoted_incident.get("event_chain_id") or make_event_chain_id()
    target["event_chain"] = merge_event_chain(
        target.get("event_chain"),
        candidate.get("source_text") or candidate.get("normalized_seed_summary") or "",
        target["event_kind"],
        topic_label=target.get("topic_label") or candidate.get("topic_label") or "",
    )
    target["normalized_seed_summary"] = synthesize_event_chain_summary(
        target.get("event_chain"),
        candidate.get("source_text") or target.get("normalized_seed_summary") or "",
    )
    trace = promoted_incident.get("daily_memory_trace")
    if isinstance(trace, dict):
        target["formal_memory_path"] = trace.get("path")
        target["daily_memory_trace"] = trace
    apply_continuity_bundle_fields(target, candidate)
    apply_assistant_commitment(promoted_incident, target.get(ASSISTANT_COMMITMENT_FIELD_KEY))
    if isinstance(hook_store, dict):
        for hook_id in promoted_incident.get("linked_hook_ids", []):
            hook = find_hook(hook_store, hook_id)
            if not hook:
                continue
            apply_assistant_commitment(hook, target.get(ASSISTANT_COMMITMENT_FIELD_KEY))
    trace_followup(
        now_dt,
        session_id=target.get("session_id"),
        event_kind=target.get("event_kind"),
        event_chain_id=target.get("event_chain_id"),
        source_stage="staging",
        followup_decision="linked-incident-promoted",
        trigger_reason=candidate.get("promotion_hint") or "candidate-promoted",
        continuity_source="incident",
        live_dispatch_result="not-applicable",
        source_id=target.get("session_id"),
        source_layer="session_staging",
        summary=target.get("normalized_seed_summary"),
        extra={"incident_id": promoted_incident.get("id"), "candidate_id": candidate.get("id")},
    )
    return target


def sync_linked_incident_from_staging(record: dict, now_dt: datetime) -> bool:
    linked_incident_id = str(record.get("linked_incident_id") or "").strip()
    if not linked_incident_id:
        return False
    incident_store = load_incidents()
    incident = find_incident(incident_store, linked_incident_id)
    if not incident:
        return False
    if incident.get("event_chain_id") and record.get("event_chain_id") and incident.get("event_chain_id") != record.get("event_chain_id"):
        trace_followup(
            now_dt,
            session_id=record.get("session_id"),
            event_kind=record.get("event_kind"),
            event_chain_id=record.get("event_chain_id"),
            source_stage="incident",
            followup_decision="sync-skipped",
            trigger_reason="different-event-chain",
            continuity_source="session_staging",
            live_dispatch_result="not-applicable",
            source_id=incident.get("id"),
            source_layer="incident",
            summary=record.get("normalized_seed_summary"),
            extra={"linked_incident_id": linked_incident_id, "incident_event_chain_id": incident.get("event_chain_id")},
        )
        return False
    incident["last_seen_at"] = now_dt.isoformat(timespec="seconds")
    incident["event_kind"] = record.get("event_kind") or incident.get("event_kind")
    incident["event_chain_id"] = incident.get("event_chain_id") or record.get("event_chain_id") or make_event_chain_id()
    incident["event_chain"] = deepcopy(record.get("event_chain")) if isinstance(record.get("event_chain"), dict) else incident.get("event_chain")
    incident["normalized_seed_summary"] = record.get("normalized_seed_summary") or incident.get("normalized_seed_summary")
    incident["source_summary"] = record.get("source_seed_text") or incident.get("source_summary")
    payload = incident.get("payload") if isinstance(incident.get("payload"), dict) else {}
    payload["last_seen_at"] = incident["last_seen_at"]
    payload["event_kind"] = incident.get("event_kind")
    payload["event_chain"] = incident.get("event_chain")
    payload["normalized_seed_summary"] = incident.get("normalized_seed_summary")
    payload["event_chain_id"] = incident.get("event_chain_id")
    for key in CONTINUITY_BUNDLE_FIELD_KEYS:
        value = record.get(key)
        if value not in (None, "", [], {}):
            payload[key] = deepcopy(value) if isinstance(value, (dict, list)) else value
    if incident.get("type") == "emotional_incident":
        payload["topic"] = incident.get("source_summary")
    elif incident.get("type") == "important_task":
        payload["task"] = incident.get("source_summary")
    elif incident.get("type") in {"health_incident", "safety_incident"}:
        payload["condition"] = incident.get("source_summary")
    incident["payload"] = payload
    apply_continuity_bundle_fields(incident, record)
    apply_assistant_commitment(incident, record.get(ASSISTANT_COMMITMENT_FIELD_KEY))
    save_incidents(incident_store)

    hook_store = load_hooks()
    hook_dirty = False
    for hook_id in incident.get("linked_hook_ids", []):
        hook = find_hook(hook_store, hook_id)
        if not hook:
            continue
        hook["source_summary"] = f"[incident:{incident['id']}] {incident.get('source_summary')}"
        hook["normalized_seed_summary"] = incident.get("normalized_seed_summary")
        hook["event_chain_id"] = hook.get("event_chain_id") or incident.get("event_chain_id")
        hook_payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        hook_payload["event_kind"] = incident.get("event_kind")
        hook_payload["event_chain"] = incident.get("event_chain")
        hook_payload["event_chain_id"] = incident.get("event_chain_id")
        for key in CONTINUITY_BUNDLE_FIELD_KEYS:
            value = incident.get(key) if incident.get(key) not in (None, "", [], {}) else payload.get(key)
            if value not in (None, "", [], {}):
                hook_payload[key] = deepcopy(value) if isinstance(value, (dict, list)) else value
        if incident.get("type") == "emotional_incident":
            hook_payload["topic"] = incident.get("source_summary")
        elif incident.get("type") == "important_task":
            hook_payload["task"] = incident.get("source_summary")
        elif incident.get("type") in {"health_incident", "safety_incident"}:
            hook_payload["condition"] = incident.get("source_summary")
        hook["payload"] = hook_payload
        apply_continuity_bundle_fields(hook, incident)
        apply_assistant_commitment(hook, incident.get(ASSISTANT_COMMITMENT_FIELD_KEY) or record.get(ASSISTANT_COMMITMENT_FIELD_KEY))
        hook_dirty = True
    if hook_dirty:
        save_hooks(hook_store)
    trace_followup(
        now_dt,
        session_id=record.get("session_id"),
        event_kind=incident.get("event_kind"),
        event_chain_id=incident.get("event_chain_id"),
        source_stage="incident",
        followup_decision="synced-from-staging",
        trigger_reason="promoted-staging-update",
        continuity_source="session_staging",
        live_dispatch_result="not-applicable",
        source_id=incident.get("id"),
        source_layer="incident",
        summary=incident.get("normalized_seed_summary"),
    )
    return True


def promote_candidate_to_incident(candidate: dict, incident_store: dict, hook_store: dict, memory_rank_store: dict) -> dict:
    existing = find_existing_candidate_incident(candidate, incident_store)
    if existing:
        update_existing_incident_from_candidate(existing, candidate, now_local())
        return {"created": existing, "hook": None, "memory_rank": None, "reason": "existing-incident"}
    incident_type = candidate_incident_type(candidate)
    source_text = trim_summary(candidate.get("source_text", ""), 120)
    severity = "low" if incident_type in {"deferred_topic", "operator_feedback"} else "medium"
    detection = {
        "incident_type": incident_type,
        "severity": severity,
        "source_summary": source_text,
        "followup_policy": build_followup_policy_for_detected_incident(incident_type, severity, source_text),
        "payload": {
            "source": "candidate_buffer",
            "candidate_id": candidate.get("id"),
            "promotion_hint": candidate.get("promotion_hint"),
            "signal_type": candidate.get("signal_type"),
            "topic": candidate.get("topic"),
            "detected_text": source_text,
            "topic_label": candidate.get("topic_label") or infer_topic_label(source_text, candidate.get("topic", "待追話題")),
            "normalized_seed_summary": candidate.get("normalized_seed_summary") or source_text,
            "source_layer": "candidate",
            "confidence": candidate.get("confidence", 0.58),
            "current_status": "active_incident",
            "last_seen_at": candidate.get("last_seen_at") or candidate.get("created_at"),
            "event_kind": candidate.get("event_kind"),
            "event_chain": candidate.get("event_chain"),
            "event_chain_id": candidate.get("event_chain_id"),
            "anchor_turns": deepcopy(candidate.get("anchor_turns")) if isinstance(candidate.get("anchor_turns"), list) else candidate.get("anchor_turns"),
            "anchor_excerpt": candidate.get("anchor_excerpt"),
            "seed_intents_snapshot": deepcopy(candidate.get("seed_intents_snapshot")) if isinstance(candidate.get("seed_intents_snapshot"), dict) else candidate.get("seed_intents_snapshot"),
            "followup_reason": candidate.get("followup_reason"),
        },
    }
    if incident_type in {"health_incident", "safety_incident"}:
        detection["payload"]["condition"] = source_text
    elif incident_type == "emotional_incident":
        detection["payload"]["topic"] = source_text
    elif incident_type == "important_task":
        detection["payload"]["task"] = source_text
    elif incident_type == "deferred_topic":
        detection["payload"]["deferred_text"] = source_text
    elif incident_type == "operator_feedback":
        detection["payload"]["feedback_text"] = source_text
    result = create_incident_from_detection(
        detection,
        incident_store,
        hook_store,
        memory_rank_store,
        continuity_bundle={key: deepcopy(candidate.get(key)) if isinstance(candidate.get(key), (dict, list)) else candidate.get(key) for key in CONTINUITY_BUNDLE_FIELD_KEYS},
    )
    result["reason"] = "candidate-promoted"
    return result


def staging_record_incident_type(record: dict) -> str:
    source_text = trim_summary(
        str(record.get("source_seed_text") or record.get("normalized_seed_summary") or "").strip(),
        160,
    )
    event_kind = str(record.get("event_kind") or infer_followup_event_type(source_text)).strip()
    causal = (record.get("event_chain") or {}).get("causal_memory") if isinstance(record.get("event_chain"), dict) else {}
    open_loop = str((causal or {}).get("open_loop") or "").strip()
    focus_code = str((causal or {}).get("followup_focus_code") or "").strip()
    phrase_family = str(record.get("phrase_family") or "").strip()
    if event_kind == "delegated_task":
        return "important_task" if is_trackable_followup_focus_text(source_text) else "deferred_topic"
    if event_kind == "watchful_state":
        return "emotional_incident"
    if event_kind == "sensitive_event":
        return "health_incident"
    if phrase_family == "correction_pushback":
        return "operator_feedback"
    if looks_like_natural_unresolved_work_item(source_text):
        return "important_task"
    if focus_code == "check_action_progress" and is_trackable_followup_focus_text(source_text):
        return "important_task"
    if open_loop in {"pending_decision", "user_away_work"} and is_trackable_followup_focus_text(source_text):
        return "important_task"
    return "deferred_topic"


def find_existing_staging_incident(record: dict, incident_store: dict):
    linked_incident_id = str(record.get("linked_incident_id") or "").strip()
    event_chain_id = str(record.get("event_chain_id") or "").strip()
    summary = trim_summary(
        str(record.get("source_seed_text") or record.get("normalized_seed_summary") or "").strip(),
        160,
    )
    incident_type = staging_record_incident_type(record)
    event_kind = str(record.get("event_kind") or infer_followup_event_type(summary)).strip()
    for incident in reversed(incident_store.get("incidents", [])):
        if not isinstance(incident, dict):
            continue
        payload = incident.get("payload") if isinstance(incident.get("payload"), dict) else {}
        if linked_incident_id and str(incident.get("id") or "").strip() == linked_incident_id:
            return incident
        if event_chain_id and (
            str(incident.get("event_chain_id") or "").strip() == event_chain_id
            or str(payload.get("event_chain_id") or "").strip() == event_chain_id
        ):
            return incident
        if (
            summary
            and incident.get("type") == incident_type
            and str(incident.get("event_kind") or payload.get("event_kind") or "").strip() == event_kind
            and event_chain_match_score(incident, summary, event_kind) >= 3
        ):
            return incident
        if (
            summary
            and incident.get("type") == incident_type
            and trim_summary(str(incident.get("source_summary") or "").strip(), 160) == summary
        ):
            return incident
    return None


def update_existing_incident_from_staging_record(incident: dict, record: dict, hook_store: Optional[dict], now_dt: datetime) -> Optional[dict]:
    source_text = trim_summary(
        str(record.get("source_seed_text") or record.get("normalized_seed_summary") or "").strip(),
        160,
    )
    if incident.get("event_chain_id") and record.get("event_chain_id") and incident.get("event_chain_id") != record.get("event_chain_id"):
        trace_followup(
            now_dt,
            session_id=record.get("session_id"),
            event_kind=record.get("event_kind"),
            event_chain_id=record.get("event_chain_id"),
            source_stage="incident",
            followup_decision="sync-skipped",
            trigger_reason="different-event-chain",
            continuity_source="session_staging",
            live_dispatch_result="not-applicable",
            source_id=incident.get("id"),
            source_layer="incident",
            summary=record.get("normalized_seed_summary") or source_text,
            extra={"linked_incident_id": incident.get("id"), "incident_event_chain_id": incident.get("event_chain_id")},
        )
        return None
    incident["last_seen_at"] = now_dt.isoformat(timespec="seconds")
    incident["event_kind"] = record.get("event_kind") or incident.get("event_kind")
    incident["event_chain_id"] = incident.get("event_chain_id") or record.get("event_chain_id") or make_event_chain_id()
    incident["event_chain"] = deepcopy(record.get("event_chain")) if isinstance(record.get("event_chain"), dict) else incident.get("event_chain")
    incident["normalized_seed_summary"] = record.get("normalized_seed_summary") or incident.get("normalized_seed_summary") or source_text
    incident["source_summary"] = source_text or incident.get("source_summary")
    payload = incident.get("payload") if isinstance(incident.get("payload"), dict) else {}
    payload["last_seen_at"] = incident["last_seen_at"]
    payload["event_kind"] = incident.get("event_kind")
    payload["event_chain"] = incident.get("event_chain")
    payload["normalized_seed_summary"] = incident.get("normalized_seed_summary")
    payload["event_chain_id"] = incident.get("event_chain_id")
    payload["source"] = "session_staging"
    payload["record_session_id"] = record.get("session_id")
    payload["record_session_key"] = record.get("session_key")
    for key in CONTINUITY_BUNDLE_FIELD_KEYS:
        value = record.get(key)
        if value not in (None, "", [], {}):
            payload[key] = deepcopy(value) if isinstance(value, (dict, list)) else value
    if incident.get("type") == "emotional_incident":
        payload["topic"] = incident.get("source_summary")
    elif incident.get("type") == "important_task":
        payload["task"] = incident.get("source_summary")
    elif incident.get("type") in {"health_incident", "safety_incident"}:
        payload["condition"] = incident.get("source_summary")
    elif incident.get("type") == "deferred_topic":
        payload["deferred_text"] = incident.get("source_summary")
    elif incident.get("type") == "operator_feedback":
        payload["feedback_text"] = incident.get("source_summary")
    incident["payload"] = payload
    apply_continuity_bundle_fields(incident, record)
    created_hook = None
    if isinstance(hook_store, dict) and (incident.get("followup_policy") or {}).get("mode") == "hook":
        linked_hook_ids = incident.get("linked_hook_ids") if isinstance(incident.get("linked_hook_ids"), list) else []
        active_linked = False
        for hook_id in linked_hook_ids:
            linked_hook = find_hook(hook_store, hook_id)
            if isinstance(linked_hook, dict) and str(linked_hook.get("status") or "") not in TERMINAL_HOOK_STATUSES:
                active_linked = True
                break
        if not active_linked:
            created_hook = create_hook_from_incident(hook_store, incident)
            if created_hook and created_hook.get("id") not in linked_hook_ids:
                incident.setdefault("linked_hook_ids", []).append(created_hook.get("id"))
                trace_followup(
                    now_dt,
                    event_kind=created_hook.get("event_kind"),
                    event_chain_id=created_hook.get("event_chain_id"),
                    source_stage="hook",
                    followup_decision="created",
                    trigger_reason=created_hook.get("type"),
                    continuity_source="incident",
                    live_dispatch_result="pending",
                    source_id=created_hook.get("id"),
                    source_layer="hook",
                    summary=created_hook.get("normalized_seed_summary") or created_hook.get("source_summary"),
                    **build_trace_writeback_meta(
                        now_dt,
                        entity_type="hook",
                        entity=created_hook,
                        action="created",
                        source_path="ordinary",
                    ),
                )
    trace_followup(
        now_dt,
        session_id=record.get("session_id"),
        event_kind=incident.get("event_kind"),
        event_chain_id=incident.get("event_chain_id"),
        source_stage="incident",
        followup_decision="updated",
        trigger_reason="staging-promoted",
        continuity_source="session_staging",
        live_dispatch_result="not-applicable",
        source_id=incident.get("id"),
        source_layer="incident",
        summary=incident.get("normalized_seed_summary"),
        extra={"linked_record_session_id": record.get("session_id")},
    )
    return created_hook


def promote_staging_record_to_incident(
    record: dict,
    incident_store: dict,
    hook_store: dict,
    memory_rank_store: dict,
    now_dt: datetime,
    *,
    time_state: Optional[dict] = None,
) -> dict:
    existing = find_existing_staging_incident(record, incident_store)
    if existing:
        created_hook = update_existing_incident_from_staging_record(existing, record, hook_store, now_dt)
        rank_record = append_memory_rank_record(memory_rank_store, existing)
        return {"created": existing, "hook": created_hook, "memory_rank": rank_record, "reason": "existing-incident"}
    incident_type = staging_record_incident_type(record)
    source_text = trim_summary(
        str(record.get("source_seed_text") or record.get("normalized_seed_summary") or "").strip(),
        120,
    )
    severity = "low" if incident_type in {"deferred_topic", "operator_feedback"} else "medium"
    detection = {
        "incident_type": incident_type,
        "severity": severity,
        "source_summary": source_text,
        "followup_policy": build_followup_policy_for_detected_incident(incident_type, severity, source_text),
        "payload": {
            "source": "session_staging",
            "record_session_id": record.get("session_id"),
            "record_session_key": record.get("session_key"),
            "promotion_hint": record.get("promotion_reason"),
            "detected_text": source_text,
            "topic_label": record.get("topic_label") or infer_topic_label(source_text, "待追話題"),
            "normalized_seed_summary": record.get("normalized_seed_summary") or source_text,
            "source_layer": "session_staging",
            "confidence": 0.82,
            "current_status": "active_incident",
            "last_seen_at": record.get("updated_at") or record.get("created_at"),
            "event_kind": record.get("event_kind"),
            "event_chain": record.get("event_chain"),
            "event_chain_id": record.get("event_chain_id"),
            "anchor_turns": deepcopy(record.get("anchor_turns")) if isinstance(record.get("anchor_turns"), list) else record.get("anchor_turns"),
            "anchor_excerpt": record.get("anchor_excerpt"),
            "recent_user_context": deepcopy(record.get("recent_user_context")) if isinstance(record.get("recent_user_context"), list) else None,
            "seed_intents_snapshot": deepcopy(record.get("seed_intents_snapshot")) if isinstance(record.get("seed_intents_snapshot"), dict) else record.get("seed_intents_snapshot"),
            "followup_reason": record.get("followup_reason") or record.get("promotion_reason"),
        },
    }
    if incident_type in {"health_incident", "safety_incident"}:
        detection["payload"]["condition"] = source_text
    elif incident_type == "emotional_incident":
        detection["payload"]["topic"] = source_text
    elif incident_type == "important_task":
        detection["payload"]["task"] = source_text
    elif incident_type == "deferred_topic":
        detection["payload"]["deferred_text"] = source_text
    elif incident_type == "operator_feedback":
        detection["payload"]["feedback_text"] = source_text
    result = create_incident_from_detection(
        detection,
        incident_store,
        hook_store,
        memory_rank_store,
        time_state=time_state,
        continuity_bundle={key: deepcopy(record.get(key)) if isinstance(record.get(key), (dict, list)) else record.get(key) for key in CONTINUITY_BUNDLE_FIELD_KEYS},
    )
    result["reason"] = "staging-promoted"
    return result


def process_candidate_buffer(candidate_store: dict, incident_store: dict, hook_store: dict, memory_rank_store: dict, now_dt: datetime) -> list[dict]:
    actions = []
    staging_store = load_session_memory_staging()
    staging_reconcile = reconcile_expired_staging_records(staging_store, hook_store, now_dt)
    staging_dirty = bool(staging_reconcile.get("changed"))
    if staging_reconcile.get("promoted"):
        actions.append({
            "timestamp": now_dt.isoformat(timespec="seconds"),
            "action": "staging-promoted-on-expiry",
            "count": staging_reconcile.get("promoted"),
        })
    for candidate in candidate_store.get("candidates", []):
        if candidate.get("status") != "pending":
            continue
        candidate_id = candidate.get("id")
        expires_at = candidate.get("expires_at")
        if isinstance(expires_at, str):
            try:
                if parse_dt(expires_at) <= now_dt:
                    candidate["status"] = "expired"
                    candidate["lifecycle"] = "expired"
                    candidate["current_status"] = "expired"
                    candidate["expired_at"] = now_dt.isoformat(timespec="seconds")
                    action = {"timestamp": now_dt.isoformat(timespec="seconds"), "candidate_id": candidate_id, "action": "expire", "reason": "ttl_elapsed"}
                    append_candidate_audit(action)
                    trace_followup(
                        now_dt,
                        event_kind=candidate.get("event_kind"),
                        event_chain_id=candidate.get("event_chain_id"),
                        source_stage="candidate",
                        followup_decision="expired",
                        trigger_reason="ttl_elapsed",
                        continuity_source="candidate",
                        live_dispatch_result="not-applicable",
                        source_id=candidate_id,
                        source_layer="candidate",
                        summary=candidate.get("normalized_seed_summary") or candidate.get("source_text"),
                    )
                    actions.append(action)
                    continue
            except Exception:
                pass

        existing_incident = find_existing_candidate_incident(candidate, incident_store)
        if existing_incident:
            update_existing_incident_from_candidate(existing_incident, candidate, now_dt)
            candidate["status"] = "discarded"
            candidate["lifecycle"] = "closed"
            candidate["current_status"] = "discarded"
            candidate["discarded_at"] = now_dt.isoformat(timespec="seconds")
            action = {
                "timestamp": now_dt.isoformat(timespec="seconds"),
                "candidate_id": candidate_id,
                "action": "discard",
                "reason": f"covered_by_incident:{existing_incident.get('id')}",
            }
            append_candidate_audit(action)
            trace_followup(
                now_dt,
                event_kind=candidate.get("event_kind"),
                event_chain_id=candidate.get("event_chain_id"),
                source_stage="candidate",
                followup_decision="discarded",
                trigger_reason=f"covered_by_incident:{existing_incident.get('id')}",
                continuity_source="incident",
                live_dispatch_result="not-applicable",
                source_id=candidate_id,
                source_layer="candidate",
                summary=candidate.get("normalized_seed_summary") or candidate.get("source_text"),
            )
            actions.append(action)
            continue

        promotion_hint = None
        candidate_care_level = str(candidate.get("care_state_level") or "")
        if candidate.get("promotion_hint") == "explicit_followup_request":
            promotion_hint = "explicit_followup_request"
        elif record_cross_time_revisit(candidate, now_dt):
            promotion_hint = "cross_time_repeated"
        elif int(candidate.get("seen_count", 0) or 0) >= TRACK_PROMOTION_MIN_SEEN_COUNT:
            promotion_hint = "repeated"

        if promotion_hint:
            candidate["promotion_hint"] = promotion_hint
            promoted = promote_candidate_to_incident(candidate, incident_store, hook_store, memory_rank_store)
            candidate["status"] = "promoted"
            candidate["memory_class"] = "tracked_followup"
            candidate["lifecycle"] = "promoted"
            candidate["current_status"] = "promoted"
            candidate["promoted_at"] = now_dt.isoformat(timespec="seconds")
            candidate["incident_id"] = (promoted.get("created") or {}).get("id")
            action = {
                "timestamp": now_dt.isoformat(timespec="seconds"),
                "candidate_id": candidate_id,
                "action": "promote",
                "reason": promotion_hint,
                "incident_id": candidate.get("incident_id"),
                "hook_id": (promoted.get("hook") or {}).get("id"),
            }
            if promoted.get("created"):
                staged = sync_staging_record_from_candidate_promotion(staging_store, candidate, promoted.get("created") or {}, hook_store, now_dt)
                staging_dirty = staging_dirty or bool(staged)
            append_candidate_audit(action)
            trace_followup(
                now_dt,
                event_kind=candidate.get("event_kind"),
                event_chain_id=candidate.get("event_chain_id"),
                source_stage="candidate",
                followup_decision="promoted",
                trigger_reason=promotion_hint,
                continuity_source="incident",
                live_dispatch_result="not-applicable",
                source_id=candidate_id,
                source_layer="candidate",
                summary=candidate.get("normalized_seed_summary") or candidate.get("source_text"),
                extra={"incident_id": candidate.get("incident_id"), "hook_id": (promoted.get("hook") or {}).get("id")},
            )
            actions.append(action)
    if staging_dirty:
        save_session_memory_staging(staging_store, now_dt=now_dt)
    return actions


def check_and_promote_delayed_candidates(candidate_store: dict, incident_store: dict, hook_store: dict, memory_rank_store: dict, text: str, now_dt: datetime) -> list[dict]:
    actions = []
    seed_intents = classify_seed_intents(text)
    is_return_signal = any(item.get("intent") == "return_signal" for item in seed_intents.get("intents", []))
    if not is_return_signal:
        return actions
    normalized = normalize_text_for_match(text)
    for candidate in candidate_store.get("candidates", []):
        if candidate.get("status") != "pending":
            continue
        if candidate.get("signal_type") not in {"task", "emotion", "support"}:
            continue
        summary = normalize_text_for_match(candidate.get("source_text", ""))
        if candidate.get("promotion_hint") != "explicit_followup_request" and not summary:
            continue
        if summary and not any(token in normalized for token in ["回來", "繼續", "忙完", "那件事"]):
            continue
        promoted = promote_candidate_to_incident(candidate, incident_store, hook_store, memory_rank_store)
        candidate["status"] = "promoted"
        candidate["memory_class"] = "tracked_followup"
        candidate["lifecycle"] = "promoted"
        candidate["current_status"] = "promoted"
        candidate["promoted_at"] = now_dt.isoformat(timespec="seconds")
        candidate["incident_id"] = (promoted.get("created") or {}).get("id")
        action = {
            "timestamp": now_dt.isoformat(timespec="seconds"),
            "candidate_id": candidate.get("id"),
            "action": "promote",
            "reason": "return_signal",
            "incident_id": candidate.get("incident_id"),
            "hook_id": (promoted.get("hook") or {}).get("id"),
        }
        append_candidate_audit(action)
        trace_followup(
            now_dt,
            event_kind=candidate.get("event_kind"),
            event_chain_id=candidate.get("event_chain_id"),
            source_stage="candidate",
            followup_decision="promoted",
            trigger_reason="return_signal",
            continuity_source="return_signal",
            live_dispatch_result="not-applicable",
            source_id=candidate.get("id"),
            source_layer="candidate",
            summary=candidate.get("normalized_seed_summary") or candidate.get("source_text"),
            extra={"incident_id": candidate.get("incident_id"), "hook_id": (promoted.get("hook") or {}).get("id")},
        )
        actions.append(action)
    return actions


def _summary_contains_raw_json(text: str) -> bool:
    """Detect raw JSON or untrusted extraction artifacts in a summary string."""
    if not text:
        return False
    # Fenced JSON blocks
    if "```json" in text or "```\n{" in text:
        return True
    # Raw JSON object patterns from extraction pollution
    json_markers = ('{"sender_label"', '{"event_kind"', '{"body":', '{"text":', '{"hook_id":', '{"source":', '{"type":')
    if any(marker in text for marker in json_markers):
        return True
    # Untrusted metadata prefix (e.g., from a reply-context wrapper)
    for prefix in UNTRUSTED_SUMMARY_PREFIXES:
        if prefix in text:
            return True
    return False


def _strip_raw_json_from_summary(text: str) -> str:
    """Remove embedded raw JSON and untrusted prefixes from a summary string."""
    if not text:
        return ""
    cleaned = strip_untrusted_metadata_blocks(text)
    # Strip untrusted prefixes even when concatenated inline / mid-string
    for prefix in UNTRUSTED_SUMMARY_PREFIXES:
        cleaned = cleaned.replace(prefix, " ")
    # Strip fenced code blocks
    cleaned = re.sub(r"```json\s*.*?```", "", cleaned, flags=re.S).strip()
    cleaned = re.sub(r"```\s*.*?```", "", cleaned, flags=re.S).strip()
    # Strip truncated / unclosed fenced JSON blocks that were cut by summarization
    cleaned = re.sub(r"```json\s*.*$", "", cleaned, flags=re.S).strip()
    cleaned = re.sub(r"```\s*.*$", "", cleaned, flags=re.S).strip()
    # Strip inline JSON objects: {...}
    cleaned = re.sub(r"\{[^}]*\"(?:sender_label|event_kind|body|text|hook_id|source|type)\"[^}]*\}", "", cleaned).strip()
    # Collapse whitespace
    cleaned = re.sub(r"\b(?:time|state|open|focus|writeback)\s*:\s*[^\s|；;]+", " ", cleaned)
    cleaned = re.sub(r"[|；;]\s*(?=[|；;]|$)", " ", cleaned)
    cleaned = re.sub(r"\s+", " ", cleaned).strip()
    return cleaned


def sanitize_summary_like_payload(payload):
    """Recursively scrub summary-like / untrusted text without changing payload shape."""
    if isinstance(payload, str):
        text = strip_untrusted_metadata_blocks(payload)
        if _summary_contains_raw_json(text):
            text = _strip_raw_json_from_summary(text)
        return sanitize_runtime_residue_text(text, 320)
    if isinstance(payload, dict):
        cleaned = {}
        for key, value in payload.items():
            sanitized = sanitize_summary_like_payload(value)
            if isinstance(sanitized, str):
                if sanitized:
                    cleaned[key] = sanitized
            elif sanitized not in (None, {}, []):
                cleaned[key] = sanitized
        return cleaned
    if isinstance(payload, list):
        items = []
        for value in payload:
            sanitized = sanitize_summary_like_payload(value)
            if isinstance(sanitized, str):
                if sanitized:
                    items.append(sanitized)
            elif sanitized not in (None, {}, []):
                items.append(sanitized)
        return items
    return payload


def usable_seed_summary(text: str) -> Optional[str]:
    raw = str(text or "").strip()
    raw = re.sub(r"^\[[^\]]+\]\s*", "", raw)
    # ── A-final-stable: strip raw JSON / untrusted extraction artifacts upstream ──
    if _summary_contains_raw_json(raw):
        raw = _strip_raw_json_from_summary(raw)
        if not raw:
            return None
    summary = trim_summary(raw, 160)
    if not summary or looks_like_meta_report(summary):
        return None
    if looks_like_continuity_pollution_text(summary):
        return None
    if looks_like_unresolved_referent_fragment(summary):
        return None
    if len(summary) < 6:
        return None
    return summary


def infer_topic_label(summary: str, fallback: str = "待追話題") -> str:
    text = str(summary or "")
    if "技能倉庫" in text:
        return "技能倉庫"
    if "重要" in text:
        return "重要話題"
    if "顏文字" in text or "emoji" in text:
        return "顏文字偏好"
    if "再來接我" in text or "晚點" in text or "先不展開" in text:
        return "延後再接"
    return fallback


_LATIN_TOKEN_RE = re.compile(r"[A-Za-z0-9]+(?:['-][A-Za-z0-9]+)*")


def seed_text_ngrams(text: str, min_n: int = 2, max_n: int = 4) -> set[str]:
    raw = str(text or "")
    latin_tokens = [
        re.sub(r"[^0-9A-Za-z]", "", token).lower()
        for token in _LATIN_TOKEN_RE.findall(raw)
    ]
    latin_tokens = [token for token in latin_tokens if len(token) >= 3]
    latin_alpha_tokens = [token for token in latin_tokens if any("a" <= ch <= "z" for ch in token)]
    if len(latin_alpha_tokens) >= 3:
        grams: set[str] = set(latin_alpha_tokens)
        max_word_n = min(3, len(latin_alpha_tokens))
        for n in range(2, max_word_n + 1):
            for idx in range(0, len(latin_alpha_tokens) - n + 1):
                grams.add(" ".join(latin_alpha_tokens[idx : idx + n]))
        return grams
    normalized = re.sub(r"[^0-9A-Za-z\u4e00-\u9fff]", "", normalize_text_for_match(raw))
    grams: set[str] = set()
    for n in range(min_n, max_n + 1):
        if len(normalized) < n:
            continue
        for idx in range(0, len(normalized) - n + 1):
            gram = normalized[idx : idx + n]
            if len(gram.strip()) == n:
                grams.add(gram)
    return grams


def is_correction_preference_text(text: str) -> bool:
    normalized = normalize_text_for_match(text)
    return any(token in normalized for token in [normalize_text_for_match(item) for item in CORRECTION_PREFERENCE_HINTS])


def pending_record_bucket(record: dict, user_text: str = "") -> str:
    summary = str(record.get("normalized_seed_summary") or "")
    source_text = str(record.get("source_seed_text") or "")
    topic_label = str(record.get("topic_label") or "")
    combined = " ".join([summary, source_text, topic_label]).strip()
    correction_like = is_correction_preference_text(combined)
    user_asks_correction = is_correction_preference_text(user_text)
    if is_preference_signal_record(record, user_text):
        return "historical_background_bucket"
    if correction_like and not user_asks_correction:
        return "correction_preference_bucket"
    if any(token in combined for token in FOLLOWUP_TOPIC_HINTS) or str(record.get("current_status") or "") in {
        "active_followup",
        "active_incident",
        "candidate_only",
        CARE_STATUS_ACTIVE,
        "hook_ready",
        "session_staged",
    }:
        return "followup_topic_bucket"
    if correction_like:
        return "correction_preference_bucket"
    return "historical_background_bucket"


def pending_record_priority_score(record: dict, user_text: str, now_dt: datetime) -> float:
    summary = str(record.get("normalized_seed_summary") or "")
    source_text = str(record.get("source_seed_text") or "")
    topic_label = str(record.get("topic_label") or "")
    source_layer = str(record.get("source_layer") or "")
    current_status = str(record.get("current_status") or "")
    bucket = pending_record_bucket(record, user_text)
    score = 0.0

    if bucket == "followup_topic_bucket":
        score += 220
    elif bucket == "correction_preference_bucket":
        score += 18 if is_correction_preference_text(user_text) else -130
    else:
        score -= 24

    if current_status == "active_followup":
        score += 120
    elif current_status == "active_incident":
        score += 90
    elif current_status == CARE_STATUS_ACTIVE:
        score += 84
    elif current_status == CARE_STATUS_ONCE:
        score += 18
    elif current_status == "candidate_only":
        score += 60
    elif current_status == "session_staged":
        score += 72

    if source_layer == "hook":
        score += 16
    elif source_layer == "incident":
        score += 10
    elif source_layer == "candidate":
        score += 4
    elif source_layer == "session_staging":
        score += 12

    summary_len = len(summary)
    if summary_len >= 24:
        score += 18
    elif summary_len >= 12:
        score += 10
    elif summary_len >= 6:
        score += 4

    if bucket == "correction_preference_bucket":
        score -= 14

    normalized_user = normalize_text_for_match(user_text)
    normalized_summary = normalize_text_for_match(summary)
    normalized_source = normalize_text_for_match(source_text)
    if normalized_user and normalized_summary:
        if normalized_summary in normalized_user or normalized_user in normalized_summary:
            score += 120
    if topic_label and topic_label in user_text:
        score += 40
    user_grams = seed_text_ngrams(user_text)
    record_grams = seed_text_ngrams(f"{summary} {source_text} {topic_label}")
    overlap = len(user_grams & record_grams)
    score += min(overlap, 12) * 4
    if normalized_user in {"我回來了", "回來了", "剛忙完", "現在可以了"} and bucket == "followup_topic_bucket":
        score += 28

    last_seen_at = record.get("last_seen_at")
    if isinstance(last_seen_at, str):
        try:
            hours = max((now_dt - parse_dt(last_seen_at)).total_seconds() / 3600.0, 0.0)
            score += max(0.0, 24.0 - min(hours, 24.0))
            # ── P0-D.2: universal age decay — all records lose priority as they age ──
            if hours > 12:
                score -= min((hours - 12) * 3, 100)
            # ── Staleness penalty: emotional/watchful records decay after threshold ──
            event_kind = str(record.get("event_kind") or "")
            if event_kind in {"watchful_state", "emotional_event", "sensitive_event"} and hours > EMOTIONAL_STALENESS_DECAY_START_HOURS:
                score -= min((hours - EMOTIONAL_STALENESS_DECAY_START_HOURS) * 2, 120)
            # ── A-Extract 7: transient away/busy records decay faster ──
            phrase_family = str(record.get("phrase_family") or "")
            if phrase_family in ("busy_now", "away_short", "work_context_away") and hours > 6:
                score -= min((hours - 6) * 8, 200)
        except Exception:
            pass
    return round(score, 4)


def prioritize_pending_records(records: list[dict], user_text: str, now_dt: datetime) -> list[dict]:
    enriched = []
    for record in records:
        cloned = dict(record)
        cloned["pending_bucket"] = pending_record_bucket(cloned, user_text)
        cloned["priority_score"] = pending_record_priority_score(cloned, user_text, now_dt)
        enriched.append(cloned)
    enriched.sort(
        key=lambda item: (
            2 if item.get("pending_bucket") == "followup_topic_bucket" else 1 if item.get("pending_bucket") == "historical_background_bucket" else 0,
            float(item.get("priority_score", 0.0) or 0.0),
            float(item.get("confidence", 0.0) or 0.0),
            str(item.get("last_seen_at") or ""),
        ),
        reverse=True,
    )
    return enriched


# ── Incident lifecycle reconciliation ──────────────────────────────

def close_incident_for_lifecycle(incident: dict, now_dt: datetime, reason: str) -> None:
    """Mark an incident as historically closed with a reason."""
    ts = now_dt.isoformat(timespec="seconds")
    incident["status"] = "closed"
    incident["closed_at"] = ts
    incident["closed_reason"] = reason
    incident["last_seen_at"] = ts
    payload = incident.get("payload") if isinstance(incident.get("payload"), dict) else {}
    payload["closed_reason"] = reason
    payload["closed_at"] = ts
    incident["payload"] = payload
    lifecycle = TRACKING_LIFECYCLE_COMPLETED if "user-engaged" in str(reason or "") else TRACKING_LIFECYCLE_FADED
    incident["lifecycle"] = lifecycle
    incident["current_status"] = "historical_completed" if lifecycle == TRACKING_LIFECYCLE_COMPLETED else "historical_only"
    if lifecycle == TRACKING_LIFECYCLE_FADED:
        incident["faded_reason"] = reason
    refresh_incident_lifecycle(incident, reason=reason)
    source_path = "cron" if "ttl" in str(reason or "") else "ordinary"
    trace_followup(
        now_dt,
        event_kind=incident.get("event_kind"),
        event_chain_id=incident.get("event_chain_id"),
        source_stage="incident",
        followup_decision="closed",
        closure_reason=reason,
        continuity_source="incident",
        live_dispatch_result="not-applicable",
        source_id=incident.get("id"),
        source_layer="incident",
        summary=incident.get("normalized_seed_summary") or incident.get("source_summary"),
        **build_trace_writeback_meta(now_dt, entity_type="incident", entity=incident, action="closed", source_path=source_path),
    )


USER_ENGAGED_CLOSURE_REASONS = frozenset({
    "user_reply_matched_active_hook",
    "user_explicit_closure",
    "manual-complete",
})


def reconcile_stale_incidents(incident_store: dict, hook_store: dict, now_dt: datetime) -> int:
    """Auto-close incidents whose linked hooks are all terminal and user has engaged.

    Returns the number of incidents closed.
    """
    hooks_by_id = {
        h["id"]: h for h in hook_store.get("hooks", [])
        if isinstance(h, dict) and h.get("id")
    }
    closed_count = 0
    lifecycle_changed = False
    for incident in incident_store.get("incidents", []):
        before_lifecycle = str(incident.get("lifecycle") or "").strip()
        after_lifecycle = refresh_incident_lifecycle(incident, hooks_by_id=hooks_by_id)
        if before_lifecycle != after_lifecycle:
            lifecycle_changed = True
        if incident.get("status") in ("closed", "rejected"):
            continue
        linked_ids = incident.get("linked_hook_ids") if isinstance(incident.get("linked_hook_ids"), list) else []
        # ── P0-D.2: auto-close unlinked incidents older than 48h ──
        if not linked_ids:
            created_at = incident.get("created_at")
            if isinstance(created_at, str):
                try:
                    if parse_dt(created_at) < now_dt - timedelta(hours=48):
                        close_incident_for_lifecycle(incident, now_dt, "unlinked-incident-ttl-expired")
                        closed_count += 1
                except Exception:
                    pass
            continue
        # All linked hooks must be in a terminal state
        linked_hooks = [hooks_by_id[hid] for hid in linked_ids if hid in hooks_by_id]
        if not linked_hooks:
            continue
        if not all(h.get("status") in TERMINAL_HOOK_STATUSES for h in linked_hooks):
            continue
        # User-engaged stop condition: at least one hook was closed by user interaction or dispatched
        has_user_engagement = any(
            str(h.get("closure_reason") or "") in USER_ENGAGED_CLOSURE_REASONS
            for h in linked_hooks
        )
        has_dispatched_done = any(
            h.get("status") == "done" and int(h.get("dispatch_count", 0) or 0) >= 1
            for h in linked_hooks
        )
        if has_user_engagement or has_dispatched_done:
            close_incident_for_lifecycle(incident, now_dt, "user-engaged-topic-closed")
            closed_count += 1
            lifecycle_changed = True
    if closed_count or lifecycle_changed:
        save_incidents(incident_store)
    return closed_count


def pending_seed_records(
    candidate_store: dict,
    incident_store: dict,
    hook_store: dict,
    now_dt: datetime,
    staging_store: Optional[dict] = None,
    active_session_key: Optional[str] = None,
    previous_session_key: Optional[str] = None,
    user_text: str = "",
) -> list[dict]:
    records = []
    hooks_by_id = {
        hook.get("id"): hook
        for hook in hook_store.get("hooks", [])
        if isinstance(hook, dict) and hook.get("id")
    }
    hook_status_by_id = {
        hook.get("id"): hook.get("status")
        for hook in hook_store.get("hooks", [])
        if isinstance(hook, dict) and hook.get("id")
    }
    for hook in hook_store.get("hooks", []):
        if hook.get("status") != "pending":
            continue
        hook_lifecycle = refresh_hook_lifecycle(hook)
        if hook_lifecycle == TRACKING_LIFECYCLE_FADED:
            continue
        summary = usable_seed_summary(hook.get("source_summary", ""))
        if not summary:
            continue
        pending_record = {
            "topic_label": infer_topic_label(summary, hook.get("type", "待追話題")),
            "memory_class": hook.get("memory_class", "tracked_followup"),
            "normalized_seed_summary": summary,
            "source_seed_text": summary,
            "source_layer": "hook",
            "confidence": 0.95,
            "current_status": "parked_followup" if hook_lifecycle == TRACKING_LIFECYCLE_PARKED else "active_followup",
            "last_seen_at": hook.get("trigger_at") or hook.get("created_at"),
            "source_id": hook.get("id"),
            "priority": 5 if any(token in summary for token in ["顏文字", "模板感", "客服"]) else 1,
            "event_kind": hook.get("event_kind") or (hook.get("payload") or {}).get("event_kind"),
            "event_chain": (hook.get("payload") or {}).get("event_chain"),
            "event_chain_id": hook.get("event_chain_id") or (hook.get("payload") or {}).get("event_chain_id"),
            "lifecycle": hook_lifecycle,
        }
        pending_record.update(
            build_continuity_anchor_contract(
                hook,
                fallback_text=summary,
                default_event_kind=str(pending_record.get("event_kind") or "parked_topic"),
                default_topic_label=str(pending_record.get("topic_label") or "待追話題"),
                default_source_layer="hook",
            )
        )
        records.append(pending_record)
    for incident in incident_store.get("incidents", []):
        if incident.get("status") in ("rejected", "closed"):
            continue
        incident_lifecycle = refresh_incident_lifecycle(incident, hooks_by_id=hooks_by_id)
        if incident_lifecycle == TRACKING_LIFECYCLE_FADED:
            continue
        linked_hook_ids = incident.get("linked_hook_ids") if isinstance(incident.get("linked_hook_ids"), list) else []
        if linked_hook_ids and not any(hook_status_by_id.get(hook_id) == "pending" for hook_id in linked_hook_ids):
            continue
        created_at = incident.get("created_at")
        if isinstance(created_at, str):
            try:
                _incident_age = now_dt - parse_dt(created_at)
                # ── P0-D.2: unlinked incidents expire at 48h (was 72h) ──
                _incident_ttl_hours = 48 if not linked_hook_ids else 72
                if _incident_age > timedelta(hours=_incident_ttl_hours) and not linked_hook_ids:
                    continue
            except Exception:
                pass
        summary = usable_seed_summary(incident.get("source_summary", ""))
        if not summary:
            continue
        if any(record["normalized_seed_summary"] == summary for record in records):
            continue
        pending_record = {
            "topic_label": infer_topic_label(summary, incident.get("type", "待追話題")),
            "memory_class": incident.get("memory_class", "tracked_followup"),
            "normalized_seed_summary": summary,
            "source_seed_text": summary,
            "source_layer": "incident",
            "confidence": 0.82,
            "current_status": "parked_incident" if incident_lifecycle == TRACKING_LIFECYCLE_PARKED else "active_incident",
            "last_seen_at": incident.get("created_at"),
            "source_id": incident.get("id"),
            "priority": 5 if any(token in summary for token in ["顏文字", "模板感", "客服"]) else 2,
            "event_kind": incident.get("event_kind"),
            "event_chain": incident.get("event_chain"),
            "event_chain_id": incident.get("event_chain_id"),
            "lifecycle": incident_lifecycle,
        }
        pending_record.update(
            build_continuity_anchor_contract(
                incident,
                fallback_text=summary,
                default_event_kind=str(pending_record.get("event_kind") or "parked_topic"),
                default_topic_label=str(pending_record.get("topic_label") or "待追話題"),
                default_source_layer="incident",
            )
        )
        records.append(pending_record)
    for candidate in candidate_store.get("candidates", []):
        if candidate.get("status") != "pending":
            continue
        summary = usable_seed_summary(candidate.get("source_text", ""))
        if not summary:
            continue
        if any(record["normalized_seed_summary"] == summary for record in records):
            continue
        expires_at = candidate.get("expires_at")
        if isinstance(expires_at, str):
            try:
                if parse_dt(expires_at) <= now_dt:
                    continue
            except Exception:
                pass
        pending_record = {
            "topic_label": infer_topic_label(summary, candidate.get("topic", "待追話題")),
            "memory_class": candidate.get("memory_class", "staged_memory"),
            "normalized_seed_summary": summary,
            "source_seed_text": summary,
            "source_layer": "candidate",
            "confidence": 0.55 if candidate.get("promotion_hint") else 0.42,
            "current_status": candidate.get("current_status") or "candidate_only",
            "last_seen_at": candidate.get("last_seen_at") or candidate.get("created_at"),
            "source_id": candidate.get("id"),
            "priority": 6 if any(token in summary for token in ["顏文字", "模板感", "客服"]) else 3,
            "event_kind": candidate.get("event_kind"),
            "event_chain": candidate.get("event_chain"),
            "event_chain_id": candidate.get("event_chain_id"),
            "signal_type": candidate.get("signal_type"),
            "topic": candidate.get("topic"),
        }
        pending_record.update(
            build_continuity_anchor_contract(
                candidate,
                fallback_text=summary,
                default_event_kind=str(pending_record.get("event_kind") or "parked_topic"),
                default_topic_label=str(pending_record.get("topic_label") or "待追話題"),
                default_source_layer="candidate",
            )
        )
        records.append(pending_record)
    if isinstance(staging_store, dict):
        for staged in staging_store.get("records", []):
            if staged.get("status") != "staged":
                continue
            staged_session_key = str(staged.get("session_key") or "").strip()
            if active_session_key and staged_session_key and staged_session_key != active_session_key:
                # ── A-Extract 5: allow previous session's staging records in /new ──
                if not previous_session_key or staged_session_key != previous_session_key:
                    continue
            if staged_session_key and not is_anchor_eligible_session_key(staged_session_key):
                continue
            summary = usable_seed_summary(staged.get("normalized_seed_summary") or staged.get("source_seed_text") or "")
            if not summary or summary == "/new" or summary.startswith("Read HEARTBEAT.md"):
                continue
            if any(record["normalized_seed_summary"] == summary for record in records):
                continue
            expires_at = staged.get("expires_at")
            if isinstance(expires_at, str):
                try:
                    if parse_dt(expires_at) <= now_dt:
                        continue
                except Exception:
                    pass
            pending_record = {
                "topic_label": infer_topic_label(summary, "待續主題"),
                "memory_class": staged.get("memory_class", "staged_memory"),
                "normalized_seed_summary": summary,
                "source_seed_text": summary,
                "source_layer": "session_staging",
                "confidence": 0.58,
                "current_status": staged.get("current_status") or "session_staged",
                "last_seen_at": staged.get("updated_at") or staged.get("created_at"),
                "source_id": staged.get("session_id"),
                "priority": 2,
                "event_kind": staged.get("event_kind"),
                "event_chain": staged.get("event_chain"),
                "event_chain_id": staged.get("event_chain_id"),
            }
            pending_record.update(
                build_continuity_anchor_contract(
                    staged,
                    fallback_text=summary,
                    default_event_kind=str(pending_record.get("event_kind") or "parked_topic"),
                    default_topic_label=str(pending_record.get("topic_label") or "待續主題"),
                    default_source_layer="session_staging",
                )
            )
            records.append(pending_record)
    preference_query = any(
        token in normalize_text_for_match(user_text or "")
        for token in (
            normalize_text_for_match("偏好"),
            normalize_text_for_match("語音"),
            normalize_text_for_match("多說"),
            normalize_text_for_match("分段"),
            normalize_text_for_match("顏文字"),
            normalize_text_for_match("emoji"),
            normalize_text_for_match("設定"),
            normalize_text_for_match("風格"),
        )
    )
    if not preference_query:
        has_non_preference_followup = any(
            not is_preference_signal_record(record, user_text)
            and pending_record_bucket(record, user_text) == "followup_topic_bucket"
            for record in records
        )
        if has_non_preference_followup:
            records = [record for record in records if not is_preference_signal_record(record, user_text)]
    records.sort(key=lambda item: (item.get("priority", 9), item["source_layer"] != "hook", item["source_layer"] == "candidate", item.get("last_seen_at") or ""), reverse=False)
    return records[:6]


def find_pending_record_by_session_hint(
    records: list[dict],
    text: str,
    now_dt: Optional[datetime] = None,
    *,
    frontstage_only: bool = False,
) -> Optional[dict]:
    ranked = prioritize_pending_records(records, text, now_dt or now_local())
    if frontstage_only:
        ranked = [record for record in ranked if is_frontstage_eligible_new_session_record(record)]
    focus_text = latest_valid_user_focus_text(text)
    explicit_reframe = bool(focus_text) and has_explicit_focus_reframe(text)
    if focus_text:
        for record in ranked:
            if pending_record_matches_current_turn(record, focus_text, now_dt or now_local()):
                return record
        if frontstage_only or explicit_reframe or current_turn_blocks_stale_pending(text, focus_text):
            return None
    normalized = normalize_text_for_match(focus_text or text)
    for record in ranked:
        source_text = normalize_text_for_match(record.get("source_seed_text", ""))
        if source_text and (source_text in normalized or normalized in source_text):
            return record
    return ranked[0] if ranked else None


def daily_memory_file_for(dt: datetime, time_state: Optional[dict] = None) -> Path:
    local_ref = str((time_state or {}).get("now_local") or "").strip()
    if len(local_ref) >= 10:
        local_day = local_ref[:10]
    else:
        timezone_name = str((time_state or {}).get("timezone") or "").strip()
        try:
            zone = ZoneInfo(timezone_name) if timezone_name else None
        except Exception:
            zone = None
        local_dt = dt.astimezone(zone) if zone else dt
        local_day = local_dt.date().isoformat()
    return MEMORY_DIR / f"{local_day}.md"


def append_daily_memory_note(path: Path, heading: str, note: str) -> None:
    ensure_parent(path)
    existing = path.read_text(encoding="utf-8") if path.exists() else ""
    if heading not in existing:
        prefix = existing.rstrip()
        body = f"{prefix}\n\n## {heading}\n- {note}\n" if prefix else f"# {path.stem}\n\n## {heading}\n- {note}\n"
        path.write_text(body, encoding="utf-8")
        return
    updated = re.sub(
        rf"(## {re.escape(heading)}\n)",
        rf"\1- {note}\n",
        existing,
        count=1,
    )
    path.write_text(updated, encoding="utf-8")


def append_daily_memory_note_once(path: Path, heading: str, note: str) -> bool:
    ensure_parent(path)
    existing = path.read_text(encoding="utf-8") if path.exists() else ""
    if note in existing:
        return False
    append_daily_memory_note(path, heading, note)
    return True


def render_skill_daily_memory_block(heading: str, records: list[dict]) -> str:
    body_lines: list[str] = []
    for record in records:
        if not isinstance(record, dict):
            continue
        entry = str(record.get("entry") or "").strip()
        if not entry:
            continue
        body_lines.append(f"- {entry}")
        for detail in record.get("details") or []:
            detail_text = normalize_story_text(str(detail or "").strip(), 360)
            if detail_text:
                body_lines.append(f"  - {detail_text}")
    body = "\n".join(body_lines)
    if body:
        body += "\n"
    return (
        f"## {heading}\n"
        f"{SKILL_DAILY_MEMORY_BLOCK_START}\n"
        f"{body}"
        f"{SKILL_DAILY_MEMORY_BLOCK_END}\n"
    )


def extract_skill_daily_memory_records(existing: str, heading: str) -> tuple[list[dict], Optional[re.Match[str]]]:
    pattern = re.compile(
        rf"(^## {re.escape(heading)}\n{re.escape(SKILL_DAILY_MEMORY_BLOCK_START)}\n)(.*?)(^{re.escape(SKILL_DAILY_MEMORY_BLOCK_END)}\n?)",
        re.MULTILINE | re.DOTALL,
    )
    match = pattern.search(existing)
    if not match:
        return [], None
    records: list[dict] = []
    current: Optional[dict] = None
    for raw_line in match.group(2).splitlines():
        if raw_line.startswith("- "):
            entry = raw_line[2:].strip()
            if not entry:
                current = None
                continue
            current = {"entry": entry, "details": []}
            records.append(current)
            continue
        if raw_line.startswith("  - ") and isinstance(current, dict):
            detail = raw_line[4:].strip()
            if detail:
                current.setdefault("details", []).append(detail)
    return records, match


def build_skill_daily_memory_detail_lines(
    note: str,
    *,
    causal_memory: Optional[dict] = None,
    time_state: Optional[dict] = None,
    context_turns: Optional[list[str]] = None,
    dialogue_turns: Optional[list[dict]] = None,
    extra_details: Optional[list[str]] = None,
) -> list[str]:
    details: list[str] = []
    summary_note = normalize_story_text(str(note or "").strip(), 220)
    if summary_note:
        details.append(f"摘要：{summary_note}")

    if isinstance(causal_memory, dict):
        causal_parts: list[str] = []
        anchor_summary = normalize_story_text(str(causal_memory.get("anchor_summary") or "").strip(), 72)
        if anchor_summary:
            causal_parts.append(f"anchor={anchor_summary}")
        last_user_update = normalize_story_text(str(causal_memory.get("last_user_update") or "").strip(), 72)
        if last_user_update and last_user_update != anchor_summary:
            causal_parts.append(f"last={last_user_update}")
        open_loop = str(causal_memory.get("open_loop") or "").strip()
        if open_loop:
            causal_parts.append(f"open={open_loop}")
        focus_code = str(causal_memory.get("followup_focus_code") or "").strip()
        if focus_code:
            causal_parts.append(f"focus={focus_code}")
        if causal_parts:
            details.append("因果：" + " | ".join(causal_parts))

    cleaned_context = sanitize_recent_user_context_list(context_turns, limit_turns=4)
    if cleaned_context:
        details.append("上下文：" + normalize_story_text(" | ".join(cleaned_context), 320))

    cleaned_dialogue = materialize_daily_memory_dialogue_turns(dialogue_turns, limit_turns=4)
    dialogue_line = summarize_daily_memory_dialogue_turns(cleaned_dialogue)
    if dialogue_line:
        details.append("對話脈絡：" + dialogue_line)

    time_bits: list[str] = []
    now_local = str((time_state or {}).get("now_local") or "").strip()
    if now_local:
        time_bits.append(f"寫入={now_local}")
    user_day = str((time_state or {}).get("user_day") or "").strip()
    if user_day:
        time_bits.append(f"user_day={user_day}")
    if time_bits:
        details.append("時間：" + " | ".join(time_bits))

    for item in extra_details or []:
        cleaned = normalize_story_text(str(item or "").strip(), 320)
        if cleaned:
            details.append(cleaned)
    return details


def insert_skill_daily_memory_block(existing: str, path: Path, block: str) -> str:
    stripped = existing.rstrip()
    light_sleep_heading = "## Light Sleep\n"
    if not stripped:
        updated = f"# {path.stem}\n\n{block}"
    elif light_sleep_heading in stripped:
        updated = stripped.replace(light_sleep_heading, f"{block}\n{light_sleep_heading}", 1)
    else:
        updated = f"{stripped}\n\n{block}"
    if not updated.endswith("\n"):
        updated += "\n"
    return updated


def upsert_skill_daily_memory_entry(
    path: Path,
    heading: str,
    entry_text: str,
    *,
    details: Optional[list[str]] = None,
) -> bool:
    ensure_parent(path)
    existing = path.read_text(encoding="utf-8") if path.exists() else ""
    records, match = extract_skill_daily_memory_records(existing, heading)
    light_sleep_idx = existing.find("## Light Sleep\n")
    relocate_existing = bool(match) and light_sleep_idx != -1 and match.start() > light_sleep_idx
    normalized_details = [
        normalize_story_text(str(item or "").strip(), 360)
        for item in (details or [])
        if normalize_story_text(str(item or "").strip(), 360)
    ]
    existing_record = next((item for item in records if str(item.get("entry") or "").strip() == entry_text), None)
    existing_details = [
        normalize_story_text(str(item or "").strip(), 360)
        for item in ((existing_record or {}).get("details") or [])
        if normalize_story_text(str(item or "").strip(), 360)
    ]
    if entry_text and existing_record is not None and existing_details == normalized_details and not relocate_existing:
        return False
    deduped = [{"entry": entry_text, "details": normalized_details}] if entry_text else []
    for item in records:
        item_entry = str(item.get("entry") or "").strip()
        if not item_entry or item_entry == entry_text:
            continue
        deduped.append({
            "entry": item_entry,
            "details": [
                normalize_story_text(str(detail or "").strip(), 360)
                for detail in (item.get("details") or [])
                if normalize_story_text(str(detail or "").strip(), 360)
            ],
        })
    deduped = deduped[:SKILL_DAILY_MEMORY_MAX_ENTRIES]
    block = render_skill_daily_memory_block(heading, deduped)
    if match:
        without_block = existing[:match.start()] + existing[match.end():]
        updated = insert_skill_daily_memory_block(without_block, path, block)
    else:
        updated = insert_skill_daily_memory_block(existing, path, block)
    path.write_text(updated, encoding="utf-8")
    return True


def format_skill_daily_memory_entry(
    action: str,
    summary: str,
    event_kind: Optional[str] = None,
    *,
    now_dt: datetime,
    time_state: Optional[dict] = None,
) -> str:
    short = trim_summary(summary, 96)
    use_english = prefers_english_text(summary)
    kind = event_kind_label(event_kind, use_english=use_english)
    time_label = str((time_state or {}).get("now_local") or "").strip()[11:16]
    if not time_label:
        time_label = now_dt.strftime("%H:%M")
    if use_english:
        if action in {"staged_created", "staged_updated"}:
            label = f"Staged {kind}"
        elif action == "staged_promoted":
            label = f"Promoted {kind}"
        elif action == "staged_completed":
            label = f"Completed in staging"
        elif action == "tracked_created":
            label = f"Tracked {kind}"
        elif action == "tracked_completed":
            label = f"Completed {kind}"
        elif action == "proactive_confirmed":
            label = f"Picked up {kind}"
        elif action == "carryover_applied":
            label = "New-session carryover"
        elif action == "dispatch_sent":
            label = f"Sent follow-up for {kind}"
        elif action == "staged_expired":
            label = f"Expired staged {kind}"
        else:
            label = "Recorded"
    else:
        if action in {"staged_created", "staged_updated"}:
            label = f"暫存{kind}"
        elif action == "staged_promoted":
            label = f"升為正式追蹤"
        elif action == "staged_completed":
            label = "暫存內完成"
        elif action == "tracked_created":
            label = f"正式追蹤"
        elif action == "tracked_completed":
            label = "確認完成"
        elif action == "proactive_confirmed":
            label = f"重新接回{kind}"
        elif action == "carryover_applied":
            label = "新對話接回"
        elif action == "dispatch_sent":
            label = "已送出關心"
        elif action == "staged_expired":
            label = "暫存到期"
        else:
            label = "記錄"
    return f"[{time_label}] {label}：{short}"


def append_daily_memory_trace_once(
    path: Path,
    heading: str,
    note: str,
    entry_text: str,
    context_turns: Optional[list[str]] = None,
    dialogue_turns: Optional[list[dict]] = None,
    *,
    causal_memory: Optional[dict] = None,
    time_state: Optional[dict] = None,
    extra_details: Optional[list[str]] = None,
) -> bool:
    ensure_parent(path)
    detail_lines = build_skill_daily_memory_detail_lines(
        note,
        causal_memory=causal_memory,
        time_state=time_state,
        context_turns=context_turns,
        dialogue_turns=dialogue_turns,
        extra_details=extra_details,
    )
    created = upsert_skill_daily_memory_entry(path, heading, entry_text, details=detail_lines)
    if not created:
        return False
    return True


def event_kind_label(event_kind: Optional[str], *, use_english: bool = False) -> str:
    mapping = FOLLOWUP_EVENT_TYPES_EN if use_english else FOLLOWUP_EVENT_TYPES
    fallback = "pending topic" if use_english else "待續主題"
    return mapping.get(str(event_kind or "").strip(), fallback)


def format_skill_daily_memory_note(action: str, summary: str, memory_class: str, event_kind: Optional[str] = None, causal_memory: Optional[dict] = None) -> str:
    short = trim_summary(summary, 72)
    use_english = prefers_english_text(summary)
    kind = event_kind_label(event_kind, use_english=use_english)
    if use_english:
        if action == "staged_created":
            note = f"Captured a {kind} in staging today: {short}"
        elif action == "staged_updated":
            note = f"Updated a staged {kind} today: {short}"
        elif action == "staged_promoted":
            note = f"Promoted a staged {kind} into formal follow-up today: {short}"
        elif action == "staged_completed":
            note = f"A staged {kind} was already completed today: {short}"
        elif action == "tracked_created":
            prefix = "event" if memory_class == "tracked_followup" else "topic"
            note = f"Added a {kind} {prefix} to formal follow-up today: {short}"
        elif action == "tracked_completed":
            note = f"Confirmed a {kind} as completed today: {short}"
        elif action == "proactive_confirmed":
            note = f"Picked up a {kind} again after a proactive follow-up today: {short}"
        elif action == "carryover_applied":
            note = f"Opened a new conversation and carried forward an unresolved {kind}: {short}"
        elif action == "dispatch_sent":
            note = f"Sent a follow-up push for a {kind} today: {short}"
        elif action == "staged_expired":
            note = f"A staged {kind} expired automatically after the observation window today: {short}"
        else:
            note = f"Recorded a {kind} today: {short}"
    else:
        if action == "staged_created":
            note = f"今天提到一件{kind}，先列入暫存：{short}"
        elif action == "staged_updated":
            note = f"今天補充了一件{kind}的暫存內容：{short}"
        elif action == "staged_promoted":
            note = f"今天一件{kind}已從暫存升為正式追蹤：{short}"
        elif action == "staged_completed":
            note = f"今天一件{kind}在暫存階段就已經完成：{short}"
        elif action == "tracked_created":
            prefix = "事件" if memory_class == "tracked_followup" else "主題"
            note = f"今天有一件{kind}{prefix}已列入正式追蹤：{short}"
        elif action == "tracked_completed":
            note = f"今天一件{kind}已確認完成：{short}"
        elif action == "proactive_confirmed":
            note = f"今天主動延續後，又接回一件{kind}：{short}"
        elif action == "carryover_applied":
            note = f"今天新開對話時，接回上一輪還沒收的{kind}：{short}"
        elif action == "dispatch_sent":
            note = f"今天就一件{kind}實際送出一次延續：{short}"
        elif action == "staged_expired":
            note = f"今天一件{kind}暫存在觀察窗結束後自動結束：{short}"
        else:
            note = f"今天記下一件{kind}：{short}"
    # A-Extract 4: append causal context to promoted/tracked notes
    if isinstance(causal_memory, dict) and action in ("staged_promoted", "tracked_created", "tracked_completed", "staged_completed", "proactive_confirmed"):
        tags = []
        state = causal_memory.get("state", "neutral")
        if state != "neutral":
            tags.append(f"state:{state}")
        open_loop = causal_memory.get("open_loop", "topic_continuation")
        if open_loop != "topic_continuation":
            tags.append(f"open:{open_loop}")
        focus = causal_memory.get("followup_focus_code", "")
        if focus and focus != "continue_when_relevant":
            tags.append(f"focus:{focus}")
        wb = causal_memory.get("writeback_policy", "")
        if wb and wb != "on_reactivation_or_expiry":
            tags.append(f"writeback:{wb}")
        if tags:
            note += f" [{', '.join(tags)}]"
    return note


def commit_daily_memory_writeback(
    now_dt: datetime,
    action: str,
    summary: str,
    memory_class: str,
    event_kind: Optional[str] = None,
    causal_memory: Optional[dict] = None,
    time_state: Optional[dict] = None,
    context_turns: Optional[list[str]] = None,
    dialogue_turns: Optional[list[dict]] = None,
    extra_details: Optional[list[str]] = None,
) -> Optional[dict]:
    resolved_time_state = time_state if isinstance(time_state, dict) else build_time_state(now_dt=now_dt)
    note = format_skill_daily_memory_note(action, summary, memory_class, event_kind=event_kind, causal_memory=causal_memory)
    entry = format_skill_daily_memory_entry(action, summary, event_kind=event_kind, now_dt=now_dt, time_state=resolved_time_state)
    path = daily_memory_file_for(now_dt, time_state=resolved_time_state)
    cleaned_context = sanitize_recent_user_context_list(context_turns, limit_turns=4)
    cleaned_dialogue = materialize_daily_memory_dialogue_turns(dialogue_turns, limit_turns=4)
    created = append_daily_memory_trace_once(
        path,
        SKILL_DAILY_MEMORY_HEADING,
        note,
        entry,
        cleaned_context,
        cleaned_dialogue,
        causal_memory=causal_memory,
        time_state=resolved_time_state,
        extra_details=extra_details,
    )
    return {
        "action": action,
        "memory_class": memory_class,
        "event_kind": event_kind,
        "path": str(path),
        "note": note,
        "entry": entry,
        "context_turns": cleaned_context,
        "dialogue_turns": cleaned_dialogue,
        "extra_details": [
            normalize_story_text(str(item or "").strip(), 320)
            for item in (extra_details or [])
            if normalize_story_text(str(item or "").strip(), 320)
        ],
        "created": created,
        "user_day": resolved_time_state.get("user_day"),
        "time_state_ref": resolved_time_state.get("now_local"),
    }


def write_skill_daily_memory_trace(
    now_dt: datetime,
    action: str,
    summary: str,
    memory_class: str,
    event_kind: Optional[str] = None,
    causal_memory: Optional[dict] = None,
    time_state: Optional[dict] = None,
    context_turns: Optional[list[str]] = None,
    dialogue_turns: Optional[list[dict]] = None,
) -> Optional[dict]:
    # Compatibility wrapper; keep one formal writeback entry.
    return commit_daily_memory_writeback(
        now_dt,
        action,
        summary,
        memory_class,
        event_kind=event_kind,
        causal_memory=causal_memory,
        time_state=time_state,
        context_turns=context_turns,
        dialogue_turns=dialogue_turns,
    )


def carryover_daily_memory_summary(snapshot: Optional[dict]) -> str:
    if not isinstance(snapshot, dict):
        return ""
    recent_turns = snapshot.get("messages") if isinstance(snapshot.get("messages"), list) else []
    recent_user_turns = _carryover_recent_user_turns(recent_turns, limit=3, anchor_only=True)
    latest_user_focus = _carryover_latest_user_focus(recent_turns)
    meta_return_markers = (
        "新開對話",
        "新对话",
        "現在想從哪裡接",
        "现在想从哪里接",
        "接這件事",
        "接这件事",
        "回來接",
        "回来接",
        "等一下再接",
        "等等再接",
    )
    if latest_user_focus and any(marker in latest_user_focus for marker in meta_return_markers):
        for item in reversed(recent_user_turns):
            if item != latest_user_focus and not any(marker in item for marker in meta_return_markers):
                latest_user_focus = item
                break
    key_quotes = [
        str(item).strip()
        for item in (snapshot.get("key_quotes") or [])
        if str(item).strip() and is_carryover_anchor_eligible_text(str(item).strip())
    ]
    summary = (
        latest_user_focus
        or " / ".join(recent_user_turns[-2:])
        or " / ".join(key_quotes[:2])
        or normalize_story_text(snapshot.get("summary") or "", 140)
    )
    return normalize_story_text(summary, 140)


def write_carryover_daily_memory_trace(
    snapshot: Optional[dict],
    *,
    now_dt: datetime,
    time_state: Optional[dict] = None,
) -> Optional[dict]:
    if not isinstance(snapshot, dict):
        return None
    summary = carryover_daily_memory_summary(snapshot)
    if not summary:
        return None
    recent_turns = snapshot.get("messages") if isinstance(snapshot.get("messages"), list) else []
    recent_user_turns = _carryover_recent_user_turns(recent_turns, limit=4, anchor_only=False)
    extra_details: list[str] = []
    source = str(snapshot.get("source") or "").strip()
    if source:
        extra_details.append(f"來源：{source}")
    source_first = str(snapshot.get("source_first_turn_at") or "").strip()
    source_last = str(snapshot.get("source_last_turn_at") or "").strip()
    if source_first or source_last:
        if source_first and source_last and source_first != source_last:
            extra_details.append(f"來源時間：{source_first} -> {source_last}")
        else:
            extra_details.append(f"來源時間：{source_last or source_first}")
    trace = commit_daily_memory_writeback(
        now_dt,
        action="carryover_applied",
        summary=summary,
        memory_class="staged_memory",
        event_kind="parked_topic",
        time_state=time_state,
        context_turns=recent_user_turns,
        dialogue_turns=sanitize_anchor_turns_list(recent_turns, limit_turns=4),
        extra_details=extra_details,
    )
    snapshot["daily_memory_trace"] = trace
    return trace


def dispatch_daily_memory_summary(record: Optional[dict], message: str) -> str:
    if not isinstance(record, dict):
        return ""
    payload = record.get("payload") if isinstance(record.get("payload"), dict) else {}
    topic_label = str(payload.get("proactive_topic_label") or record.get("topic_label") or "").strip()
    source_summary = str(
        payload.get("proactive_continuity_summary")
        or record.get("normalized_seed_summary")
        or record.get("source_summary")
        or topic_label
        or ""
    ).strip()
    message_preview = normalize_story_text(message, 96)
    if message_preview and topic_label:
        return normalize_story_text(f"{topic_label}；這次發送：{message_preview}", 160)
    if message_preview and source_summary:
        return normalize_story_text(f"{source_summary}；這次發送：{message_preview}", 160)
    return normalize_story_text(source_summary or topic_label, 160)


def dispatch_daily_memory_dialogue_turns(record: Optional[dict], message: str) -> list[dict]:
    base_turns = resolve_record_anchor_turns(record)
    message_preview = normalize_story_text(message, 160)
    if message_preview:
        base_turns = [*base_turns, {"role": "assistant", "text": message_preview}]
    return sanitize_anchor_turns_list(base_turns, limit_turns=4)


def write_dispatch_daily_memory_trace(
    record: Optional[dict],
    *,
    now_dt: datetime,
    message: str,
    time_state: Optional[dict] = None,
) -> Optional[dict]:
    if not isinstance(record, dict):
        return None
    payload = record.get("payload") if isinstance(record.get("payload"), dict) else {}
    summary = dispatch_daily_memory_summary(record, message)
    if not summary:
        return None
    trace = commit_daily_memory_writeback(
        now_dt,
        action="dispatch_sent",
        summary=summary,
        memory_class=str(record.get("memory_class") or "tracked_followup"),
        event_kind=record.get("event_kind") or payload.get("event_kind"),
        causal_memory=((record.get("event_chain") or payload.get("event_chain") or {}) if isinstance((record.get("event_chain") or payload.get("event_chain") or {}), dict) else {}).get("causal_memory"),
        time_state=time_state,
        context_turns=sanitize_recent_user_context_list(
            record.get("recent_user_context") if isinstance(record.get("recent_user_context"), list)
            else payload.get("recent_user_context") if isinstance(payload.get("recent_user_context"), list)
            else [],
            limit_turns=4,
        ),
        dialogue_turns=dispatch_daily_memory_dialogue_turns(record, message),
    )
    payload["last_dispatch_daily_memory_trace"] = trace
    payload["last_dispatched_text"] = trim_summary(message, 220)
    record["payload"] = payload
    record["daily_memory_trace"] = trace
    return trace


def dispatch_delivery_session_key(record: Optional[dict]) -> str:
    if not isinstance(record, dict):
        return ""
    payload = record.get("payload") if isinstance(record.get("payload"), dict) else {}
    return str(
        payload.get("session_key")
        or payload.get("record_session_key")
        or record.get("session_key")
        or ""
    ).strip()


def normalized_delivery_preview(text: str) -> str:
    return trim_summary(re.sub(r"\s+", " ", str(text or "").strip()), 220)


def find_recent_rendered_hook_for_delivery(
    hook_store: dict,
    now_dt: datetime,
    *,
    session_key: Optional[str] = None,
    message: str = "",
) -> Optional[dict]:
    key = str(session_key or "").strip()
    preview = normalized_delivery_preview(message)
    if not key and not preview:
        return None
    recent_prepared: list[tuple[datetime, dict]] = []
    candidates: list[tuple[int, datetime, dict]] = []
    for hook in iter_hooks(hook_store):
        if not isinstance(hook, dict) or hook.get("status") != "pending":
            continue
        payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        last_result = str(payload.get("last_dispatch_result") or "").strip()
        if last_result not in {"rendered_for_dispatch", "rendered_pending_delivery", "heartbeat-session"}:
            continue
        if not bool(payload.get("last_dispatch_pending")):
            continue
        rendered_dt = parse_optional_dt(hook.get("last_rendered_at") or payload.get("last_rendered_at"))
        if rendered_dt is None or rendered_dt < now_dt - timedelta(minutes=10):
            continue
        recent_prepared.append((rendered_dt, hook))
        hook_preview = normalized_delivery_preview(
            payload.get("last_sent_candidate")
            or hook.get("last_rendered_message")
            or payload.get("last_dispatched_text")
            or ""
        )
        score = 0
        if key:
            record_key = dispatch_delivery_session_key(hook)
            if record_key and record_key == key:
                score += 6
        if preview and hook_preview:
            if hook_preview == preview:
                score += 10
            elif preview in hook_preview or hook_preview in preview:
                score += 4
        if last_result in {"rendered_for_dispatch", "rendered_pending_delivery"}:
            score += 2
        if score <= 0:
            continue
        candidates.append((score, rendered_dt, hook))
    if not candidates:
        if len(recent_prepared) == 1 and recent_prepared[0][0] >= now_dt - timedelta(minutes=2):
            return recent_prepared[0][1]
        return None
    candidates.sort(key=lambda item: (item[0], item[1]), reverse=True)
    return candidates[0][2]


def normalize_staging_summary(text: str) -> str:
    cleaned = sanitize_runtime_residue_text(normalize_skill_source_text(text), 320)
    if not cleaned:
        return ""
    # ── A-final-stable: strip raw JSON before further normalization ──
    if _summary_contains_raw_json(cleaned):
        cleaned = _strip_raw_json_from_summary(cleaned)
        if not cleaned:
            return ""
    summary = usable_seed_summary(cleaned) or trim_summary(cleaned, 160)
    result = sanitize_runtime_residue_text(summary, 160)
    # B-Stop 2: humanize fragment bundles at write time
    if _looks_like_fragment_bundle(result):
        result = _humanize_fragment_summary(result)
    return result


def parse_session_message_text(row: dict) -> str:
    message = row.get("message") if isinstance(row.get("message"), dict) else {}
    content = message.get("content")
    if not isinstance(content, list):
        return ""
    parts = []
    for item in content:
        if isinstance(item, dict) and item.get("type") == "text" and isinstance(item.get("text"), str):
            parts.append(item["text"])
    return "\n".join(parts).strip()


def _looks_like_session_startup_notice(text: str) -> bool:
    sample = str(text or "").strip()
    if not sample:
        return False
    lowered = sample.lower()
    if "a new session was started via /new or /reset" in lowered:
        return True
    if "run your session startup sequence" in lowered:
        return True
    if "treat this startup notice" in lowered:
        return True
    return False


def _looks_like_new_session_meta_summary(text: str) -> bool:
    sample = re.sub(r"\s+", " ", str(text or "")).strip()
    if not sample:
        return False
    lowered = sample.lower()
    zh_hits = [
        "新對話開始的時候",
        "等等新對話開始的時候",
        "使用者需要一個乾淨的開始",
        "助手會知道：",
        "會把今天的事情帶進去",
        "這樣的開始",
        "醒了見",
    ]
    if any(token in sample for token in zh_hits):
        return True
    en_hits = [
        "when the new session starts",
        "new session starts",
        "will know:",
        "clean start",
        "bring today's context into the new session",
    ]
    return any(token in lowered for token in en_hits)


def _collect_recent_session_messages(rows: list[dict]) -> list[dict]:
    messages = []
    for row in rows:
        if row.get("type") != "message":
            continue
        message = row.get("message") if isinstance(row.get("message"), dict) else {}
        role = str(message.get("role") or "")
        if role not in {"user", "assistant"}:
            continue
        text = parse_session_message_text(row)
        if role == "user":
            text = extract_visible_human_tail(text) or text
        if not text or text == "/new":
            continue
        if role == "assistant" and re.match(r"^\s*✅?\s*New session started\s*·\s*model:.*$", text, re.I):
            continue
        if role == "user" and _looks_like_session_startup_notice(text):
            continue
        if role == "user" and looks_like_internal_control_text(text):
            continue
        if role == "assistant" and _looks_like_new_session_meta_summary(text):
            continue
        text = sanitize_recent_window_turn_text(text)
        if not text:
            continue
        messages.append({
            "role": role,
            "timestamp": row.get("timestamp"),
            "text": normalize_story_text(text, 220),
        })
    return messages


def _session_first_timestamp(session_path: Path) -> Optional[datetime]:
    rows = parse_recent_jsonl_lines(session_path)
    for row in rows:
        raw = row.get("timestamp")
        if isinstance(raw, str):
            try:
                return parse_dt(raw)
            except Exception:
                continue
    return None


def resolve_previous_reset_session_path(current_session_path: Path, now_dt: datetime) -> Optional[Path]:
    session_dir = current_session_path.parent
    if not session_dir.exists():
        return None
    first_dt = _session_first_timestamp(current_session_path)
    current_cutoff_ts = first_dt.timestamp() if isinstance(first_dt, datetime) else now_dt.timestamp()
    candidates = []
    for path in session_dir.glob("*.jsonl.reset.*"):
        try:
            stat = path.stat()
        except OSError:
            continue
        if stat.st_mtime > current_cutoff_ts + 5:
            continue
        if current_cutoff_ts - stat.st_mtime > 72 * 3600:
            continue
        rows = parse_recent_jsonl_lines(path)
        messages = _collect_recent_session_messages(rows)
        if not messages:
            rows = parse_jsonl_lines(path)
            messages = _collect_recent_session_messages(rows)
        if len(messages) < 2:
            continue
        candidates.append((stat.st_mtime, path))
    if not candidates:
        return None
    candidates.sort(key=lambda item: item[0], reverse=True)
    return candidates[0][1]


def session_entry_for_key(session_key: str) -> Optional[dict]:
    if not SESSIONS_INDEX_PATH.exists():
        return None
    try:
        sessions = json.loads(SESSIONS_INDEX_PATH.read_text(encoding="utf-8"))
    except Exception:
        return None
    entry = sessions.get(session_key)
    return entry if isinstance(entry, dict) else None


def session_role_for_key(session_key: Optional[str]) -> str:
    """Classify a session key as frontstage, control, or unknown (channel-agnostic)."""
    key = str(session_key or "").strip().lower()
    if not key:
        return "unknown"
    if key == "main":
        return "control"
    if key == "agent:main:main":
        entry = session_entry_for_key(key)
        if isinstance(entry, dict):
            origin = entry.get("origin") if isinstance(entry.get("origin"), dict) else {}
            delivery = entry.get("deliveryContext") if isinstance(entry.get("deliveryContext"), dict) else entry.get("delivery") if isinstance(entry.get("delivery"), dict) else {}
            origin_label = str(origin.get("label") or "").strip().lower()
            delivery_to = str(delivery.get("to") or delivery.get("channel") or "").strip().lower()
            if origin_label == "heartbeat" or delivery_to == "heartbeat":
                return "control"
        return "frontstage"
    if key.startswith("agent:main:frontstage-web"):
        return "frontstage"
    if ":slash:" in key:
        return "control"
    if any(token in key for token in (":cron:", ":run:", ":subagent:", ":node-", ":acp:")):
        return "control"
    if ":direct:" in key:
        parts = key.split(":")
        direct_idx = parts.index("direct") if "direct" in parts else -1
        if direct_idx >= 0 and len(parts) > direct_idx + 2:
            return "control"
    if any(token in key for token in (":codex-", ":privacy-", ":test", "g-agent-main-main")):
        return "control"
    return "frontstage"


def is_anchor_eligible_session_key(session_key: Optional[str]) -> bool:
    return session_role_for_key(session_key) == "frontstage"


def resolve_primary_session_key() -> Optional[str]:
    if PRIMARY_SESSION_KEY and is_anchor_eligible_session_key(PRIMARY_SESSION_KEY):
        return PRIMARY_SESSION_KEY
    if not SESSIONS_INDEX_PATH.exists():
        return None
    try:
        sessions = json.loads(SESSIONS_INDEX_PATH.read_text(encoding="utf-8"))
    except Exception:
        return None
    candidates = []
    for key, value in sessions.items():
        if not (isinstance(key, str) and isinstance(value, dict) and is_anchor_eligible_session_key(key)):
            continue
        updated_raw = value.get("updatedAt") or value.get("lastUpdatedAt") or value.get("createdAt")
        updated_dt = parse_optional_dt(updated_raw) or datetime.fromtimestamp(0, tz=now_local().tzinfo)
        direct_score = 0 if ":direct:" in key else 1
        candidates.append((direct_score, -updated_dt.timestamp(), key))
    if not candidates:
        return None
    candidates.sort()
    return candidates[0][2]


def extract_recent_session_turns(session_key: str, limit_turns: int = 5, session_path_override: Optional[Path] = None) -> list[dict]:
    entry = session_entry_for_key(session_key)
    if not entry and session_path_override is None:
        return []
    session_file = entry.get("sessionFile") if isinstance(entry, dict) else None
    if session_path_override is not None:
        session_path = Path(session_path_override)
    elif isinstance(session_file, str):
        session_path = Path(session_file)
    else:
        return []

    target_turns = max(3, min(5, limit_turns))
    rows = parse_recent_jsonl_lines(session_path)
    messages = _collect_recent_session_messages(rows)
    if len(messages) < target_turns:
        rows = parse_jsonl_lines(session_path)
        messages = _collect_recent_session_messages(rows)
    if not messages:
        return []
    total_user_turns = sum(1 for item in messages if item.get("role") == "user")
    min_user_turns = min(3, total_user_turns)
    selected: list[dict] = []
    selected_user_turns = 0
    max_window = max(target_turns, 8)
    for item in reversed(messages):
        selected.append(item)
        if item.get("role") == "user":
            selected_user_turns += 1
        if len(selected) >= target_turns and selected_user_turns >= min_user_turns:
            break
        if len(selected) >= max_window:
            break
    selected.reverse()
    return selected


def visible_session_user_turn_count(session_key: Optional[str], session_id: Optional[str] = None) -> int:
    session_path = session_path_for(session_key, session_id=session_id)
    if not isinstance(session_path, Path) or not session_path.exists():
        return 0
    rows = parse_recent_jsonl_lines(session_path)
    messages = _collect_recent_session_messages(rows)
    if not messages:
        rows = parse_jsonl_lines(session_path)
        messages = _collect_recent_session_messages(rows)
    return sum(1 for item in messages if item.get("role") == "user")


def summarize_carryover_turns(turns: list[dict]) -> str:
    snippets = []
    key_quotes = []
    max_turns = carryover_max_turns()
    if max_turns <= 0:
        return "", []
    window = turns[-max_turns:]
    for item in window:
        role = "你" if item.get("role") == "user" else "我"
        text = normalize_story_text(item.get("text", ""), 80)
        if not text:
            continue
        if item.get("role") == "user" and is_new_session_bootstrap_text(text):
            continue
        snippets.append(f"{role}：{text}")
        if item.get("role") == "user" and len(key_quotes) < 2:
            key_quotes.append(text)
    summary = " | ".join(snippets[-4:])
    return normalize_story_text(summary, 260), key_quotes


_LOW_INFORMATION_CARRYOVER_USER_RE = re.compile(
    r"^(?:嗯+|恩+|喔+|哦+|好+|在嗎|在么|在嗎？|在嗎\?|ok|okay|好喔|先這樣|算了|不說了|沒事|晚點再說|是啊|對啊|對呀|好啊|好呀)$",
    re.I,
)

_LOW_INFORMATION_GREETING_RE = re.compile(
    r"^(?:hi|hello|hey|hi there|hello there|hey there|yo|sup|what'?s up|嗨|哈囉|哈喽|你好|安安)$",
    re.I,
)

_CARRYOVER_ANCHOR_EXCLUDE_RE = re.compile(
    r"(?:"
    r"(?:開新對話|新對話|/new).{0,12}(?:沒說話|沒有說話|沒回|沒有回|不回答|不回應)"
    r"|(?:怎麼|为什么|為什麼).{0,8}(?:不回答|不回應|沒回答|沒回應|沒說話|不說話)"
    r"|(?:(?:我是|人家是).{0,4}(?:男的|男生|女的|女生)|應該是[「\"]?(?:你|妳|他|她)[」\"]?|不是[「\"]?(?:你|妳|他|她)[」\"]?|[你妳他她]用錯了|用錯了)"
    r"|(?:什麼[「\"]?妳[」\"]?.{0,12}[「\"]?你[」\"]?)"
    r"|(?:中午[？?]\s*現在幾點[？?]?|現在幾點[？?]?|哪有中午|不是中午|現在才(?:早上|凌晨|清晨|晚上)|其實是(?:早上|凌晨|清晨|晚上))"
    r")",
    re.I,
)


def is_carryover_anchor_eligible_text(text: str) -> bool:
    cleaned = normalize_story_text(sanitize_runtime_residue_text(text, 200), 200)
    if not cleaned:
        return False
    if len(cleaned) < 3:
        return False
    if is_low_signal_new_session_anchor_text(cleaned):
        return False
    if _LOW_INFORMATION_CARRYOVER_USER_RE.fullmatch(cleaned):
        return False
    if looks_like_meta_report(cleaned) or is_non_anchor_user_text(cleaned):
        return False
    guided_settings = detect_guided_settings_request(cleaned)
    if isinstance(guided_settings, dict) and guided_settings.get("detected"):
        return False
    if _CARRYOVER_ANCHOR_EXCLUDE_RE.search(cleaned):
        return False
    if is_meta_return_signal_text(cleaned):
        return False
    signal = detect_candidate_signal(cleaned)
    if isinstance(signal, dict):
        if str(signal.get("topic") or "") == "correction_pushback":
            return False
        family = signal.get("phrase_family") if isinstance(signal.get("phrase_family"), dict) else {}
        if str(family.get("family") or "") == "correction_pushback":
            return False
        if str(family.get("event_kind") or "") == "operator_feedback":
            return False
    return True


_TRACKING_FOCUS_EXCLUDE_RE = re.compile(
    r"(?:"
    r"^(?:根據|按照).{0,10}(?:我們的關係|我们的关系|互動定位|互动定位)[。！？?!]?$"
    r"|^(?:你|妳).{0,8}(?:要聊什麼|想聊什麼|要說什麼|想說什麼|在忙什麼|都在忙什麼)[。！？?!]?$"
    r"|^(?:今天|現在)?(?:都)?在忙什麼(?:呀|啊|呢)?[。！？?!]?$"
    r"|^(?:倒是)?想問問(?:你|妳)?[，, ]*(?:今天|現在)?(?:都)?在忙什麼(?:呀|啊|呢)?[。！？?!]?$"
    r")",
    re.I,
)


def is_trackable_followup_focus_text(text: str) -> bool:
    cleaned = normalize_story_text(sanitize_runtime_residue_text(text, 200), 200)
    if not cleaned:
        return False
    if len(cleaned) < 3:
        return False
    if _LOW_INFORMATION_CARRYOVER_USER_RE.fullmatch(cleaned):
        return False
    if looks_like_meta_report(cleaned) or is_non_anchor_user_text(cleaned):
        return False
    if looks_like_internal_control_text(cleaned):
        return False
    if is_meta_return_signal_text(cleaned):
        return False
    if _CARRYOVER_ANCHOR_EXCLUDE_RE.search(cleaned):
        return False
    if _TRACKING_FOCUS_EXCLUDE_RE.search(cleaned):
        return False
    semantic_tail = re.sub(
        r"(你|妳|根據|根据|按照|我們的關係|我们的关系|互動定位|互动定位|要|想|聊|說|说|什麼|什么|在|都|忙|今天|現在|现在|呀|啊|呢)",
        "",
        cleaned,
        flags=re.I,
    )
    semantic_tail = re.sub(r"[\s，,。！？!?；;、:：…]", "", semantic_tail)
    if len(semantic_tail) <= 3 and any(
        token in cleaned
        for token in ("聊什麼", "聊什么", "說什麼", "说什么", "在忙什麼", "忙什麼", "忙什么", "我們的關係", "我们的关系", "互動定位", "互动定位")
    ):
        return False
    return True


def _carryover_recent_user_turns(turns: list[dict], limit: int = 3, *, anchor_only: bool = False) -> list[str]:
    results: list[str] = []
    for item in turns:
        if item.get("role") != "user":
            continue
        text = build_anchor_excerpt(item.get("text", ""))
        if not text:
            continue
        if is_new_session_bootstrap_text(text):
            continue
        if anchor_only and not is_carryover_anchor_eligible_text(text):
            continue
        results.append(text)
    return results[-max(1, limit):]


def _carryover_latest_user_focus(turns: list[dict]) -> str:
    recent_user_turns = _carryover_recent_user_turns(turns, limit=3, anchor_only=True)
    for text in reversed(recent_user_turns):
        if len(text) < 3:
            continue
        if _LOW_INFORMATION_CARRYOVER_USER_RE.fullmatch(text):
            continue
        return text
    return ""


def carryover_has_trusted_user_side_signal(snapshot: Optional[dict], source_record: Optional[dict] = None) -> bool:
    if isinstance(snapshot, dict):
        turns = snapshot.get("messages") if isinstance(snapshot.get("messages"), list) else []
        if _carryover_recent_user_turns(turns, limit=3, anchor_only=True):
            return True
        if _carryover_latest_user_focus(turns):
            return True
        key_quotes = snapshot.get("key_quotes") if isinstance(snapshot.get("key_quotes"), list) else []
        if any(is_carryover_anchor_eligible_text(str(item or "").strip()) for item in key_quotes):
            return True
        trace = snapshot.get("daily_memory_trace") if isinstance(snapshot.get("daily_memory_trace"), dict) else {}
        trace_turns = trace.get("dialogue_turns") if isinstance(trace.get("dialogue_turns"), list) else []
        if any(
            isinstance(item, dict)
            and item.get("role") == "user"
            and is_carryover_anchor_eligible_text(str(item.get("text") or "").strip())
            for item in trace_turns
        ):
            return True
    if isinstance(source_record, dict):
        if sanitize_recent_user_context_list(source_record.get("recent_user_context")):
            return True
        anchor_turns = resolve_record_anchor_turns(source_record)
        if any(
            isinstance(item, dict)
            and item.get("role") == "user"
            and is_carryover_anchor_eligible_text(str(item.get("text") or "").strip())
            for item in anchor_turns
        ):
            return True
    return False


def _carryover_anchor_turns_snapshot(turns: list[dict], focus_text: str = "", *, limit_turns: int = 4) -> list[dict]:
    compact = sanitize_anchor_turns_list(turns, limit_turns=max(6, limit_turns * 2))
    if not compact:
        return []
    focus = build_anchor_excerpt(focus_text)
    if not focus:
        eligible_user_turns = [
            str(item.get("text") or "").strip()
            for item in compact
            if item.get("role") == "user" and is_carryover_anchor_eligible_text(str(item.get("text") or "").strip())
        ]
        focus = eligible_user_turns[-1] if eligible_user_turns else ""
    if focus:
        relevant_indices: set[int] = set()
        for idx, item in enumerate(compact):
            if item.get("role") != "user":
                continue
            if not turn_matches_focus_text(item.get("text", ""), focus):
                continue
            relevant_indices.add(idx)
            if idx > 0 and compact[idx - 1].get("role") == "assistant":
                relevant_indices.add(idx - 1)
            if idx + 1 < len(compact) and compact[idx + 1].get("role") == "assistant":
                relevant_indices.add(idx + 1)
        if relevant_indices:
            compact = [item for idx, item in enumerate(compact) if idx in relevant_indices]
    compact = [
        item
        for item in compact
        if item.get("role") != "user" or is_carryover_anchor_eligible_text(item.get("text", ""))
    ]
    return sanitize_anchor_turns_list(compact, limit_turns=limit_turns)


def is_low_information_greeting_text(text: str) -> bool:
    sample = normalize_text_for_match(str(text or ""))
    if not sample:
        return False
    sample = re.sub(r"[!！?？.,，。]+", "", sample).strip()
    return bool(sample and _LOW_INFORMATION_GREETING_RE.fullmatch(sample))


_PENDING_RESUME_USER_TEXTS = {
    normalize_text_for_match("我回來了"),
    normalize_text_for_match("回來了"),
    normalize_text_for_match("我剛忙完"),
    normalize_text_for_match("剛忙完"),
    normalize_text_for_match("現在可以了"),
    normalize_text_for_match("可以了"),
    normalize_text_for_match("我來了"),
}


def pending_record_matches_current_turn(record: dict, user_text: str, now_dt: datetime) -> bool:
    resolved_user_text = (
        latest_valid_user_focus_text(user_text)
        or extract_explicit_refocus_focus_text(user_text)
        or build_anchor_excerpt(user_text)
        or str(user_text or "")
    )
    normalized_user = normalize_text_for_match(resolved_user_text)
    if not normalized_user:
        return False
    if user_explicitly_requests_pending_recall(user_text):
        return True

    summary = str(record.get("normalized_seed_summary") or "")
    source_text = str(record.get("source_seed_text") or "")
    topic_label = str(record.get("topic_label") or "")
    normalized_summary = normalize_text_for_match(summary)
    normalized_source = normalize_text_for_match(source_text)
    normalized_topic = normalize_text_for_match(topic_label)

    if normalized_summary and (normalized_summary in normalized_user or normalized_user in normalized_summary):
        return True
    if normalized_source and (normalized_source in normalized_user or normalized_user in normalized_source):
        return True
    if normalized_topic and len(normalized_topic) >= 2 and normalized_topic in normalized_user:
        return True

    user_grams = seed_text_ngrams(resolved_user_text)
    record_grams = seed_text_ngrams(f"{summary} {source_text} {topic_label}")
    overlap = len(user_grams & record_grams)
    if overlap >= 2:
        return True
    inferred_event_kind = infer_followup_event_type(resolved_user_text)
    if event_chain_match_score(record, resolved_user_text, inferred_event_kind) >= 6:
        return True
    event_chain = record.get("event_chain") if isinstance(record.get("event_chain"), dict) else {}
    anchor_turns = record.get("anchor_turns") if isinstance(record.get("anchor_turns"), list) else []
    event_blob = " ".join(
        [
            json.dumps(event_chain, ensure_ascii=False),
            " ".join(str(item.get("text") or "") for item in anchor_turns if isinstance(item, dict)),
        ]
    )
    event_overlap = len(user_grams & seed_text_ngrams(event_blob))
    if looks_like_contextual_staging_follow_on(resolved_user_text) and event_overlap >= 1:
        return True
    if inferred_event_kind in {"sensitive_event", "watchful_state"} and event_chain_match_score(record, resolved_user_text, inferred_event_kind) >= 3:
        return True

    if normalized_user in _PENDING_RESUME_USER_TEXTS and pending_record_bucket(record, user_text) == "followup_topic_bucket":
        return True
    return False


