def parse_optional_epoch_ms(value) -> Optional[datetime]:
    try:
        if value is None:
            return None
        stamp = float(value) / 1000.0
        return datetime.fromtimestamp(stamp, tz=now_local().tzinfo)
    except Exception:
        return None


def load_sessions_index() -> dict:
    try:
        return json.loads(SESSIONS_INDEX_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {}


def dispatch_reason_card_source_turn_range(payload: dict) -> str:
    turns = payload.get("proactive_context_turns")
    if isinstance(turns, list) and turns:
        timestamps = [str(item.get("timestamp") or "").strip() for item in turns if isinstance(item, dict)]
        timestamps = [item for item in timestamps if item]
        turn_count = len(turns)
        if len(timestamps) >= 2:
            return f"{timestamps[0]} -> {timestamps[-1]} ({turn_count} turns)"
        if timestamps:
            return f"{timestamps[0]} ({turn_count} turns)"
        return f"{turn_count} turns"
    trigger_at = str(payload.get("proactive_anchor_marker") or payload.get("trigger_at") or "").strip()
    return trigger_at or "unknown"


def dispatch_reason_card_priority(hook: dict, payload: dict) -> int:
    proactive_event_kind = str(payload.get("proactive_event_kind") or "").strip()
    event_kind = str(payload.get("event_kind") or hook.get("event_kind") or "").strip()
    if proactive_event_kind == "task_continuation" or event_kind == "delegated_task":
        return 1
    if proactive_event_kind == "watchful_checkin" or event_kind in {"watchful_state", "sensitive_event"}:
        return 2
    if proactive_event_kind == "open_thread":
        return 3
    if payload.get("source") == "routine" or hook.get("type") in RHYTHM_NUDGE_HOOK_TYPES or hook.get("type") == "sleep_care":
        return 4
    return 5


def dispatch_reason_trigger_type(hook: dict, payload: dict) -> str:
    source = str(payload.get("source") or "").strip()
    if source == "routine" or hook.get("type") in RHYTHM_NUDGE_HOOK_TYPES or hook.get("type") == "sleep_care":
        return "routine"
    if source in {"proactive_chat", "wake_seed"} or str(payload.get("proactive_event_kind") or "").strip():
        return "event_followup"
    return "time_based"


def dispatch_reason_expected_next_step(hook: dict, payload: dict) -> str:
    proactive_event_kind = str(payload.get("proactive_event_kind") or "").strip()
    event_kind = str(payload.get("event_kind") or hook.get("event_kind") or "").strip()
    if proactive_event_kind == "task_continuation" or event_kind == "delegated_task":
        return "wait_for_user_progress_update"
    if proactive_event_kind == "watchful_checkin" or event_kind in {"watchful_state", "sensitive_event"}:
        return "wait_for_light_status_update"
    if proactive_event_kind == "open_thread":
        return "wait_for_user_to_reopen_or_clarify"
    if payload.get("source") == "routine" or hook.get("type") in RHYTHM_NUDGE_HOOK_TYPES or hook.get("type") == "sleep_care":
        return "wait_for_ack_or_schedule_response"
    return "wait_for_user_reengagement"


def build_dispatch_reason_card(hook: dict, now_dt: Optional[datetime] = None, render_reason: str = "") -> dict:
    payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
    seed = payload.get("dispatch_reason_seed") if isinstance(payload.get("dispatch_reason_seed"), dict) else {}
    source_topic = str(
        seed.get("source_topic")
        or payload.get("proactive_topic_label")
        or hook.get("topic_label")
        or ""
    ).strip() or "recent thread"
    event_summary = str(
        seed.get("event_summary")
        or payload.get("proactive_continuity_summary")
        or payload.get("proactive_context_summary")
        or hook.get("normalized_seed_summary")
        or hook.get("source_summary")
        or source_topic
    ).strip()
    trigger_reason = str(seed.get("trigger_reason") or "").strip()
    if not trigger_reason:
        if hook.get("type") == "proactive_chat":
            interval_hours = payload.get("proactive_interval_hours")
            proactive_event_kind = str(payload.get("proactive_event_kind") or "").strip() or "light_contextual_followup"
            if proactive_event_kind == "task_continuation":
                trigger_reason = f"recent task follow-up after inactivity: {source_topic}"
            elif proactive_event_kind == "watchful_checkin":
                trigger_reason = f"recent watchful thread after inactivity: {source_topic}"
            elif proactive_event_kind == "open_thread":
                trigger_reason = f"recent open thread after inactivity: {source_topic}"
            elif interval_hours:
                trigger_reason = f"interval reached after {interval_hours}h: {source_topic}"
            else:
                trigger_reason = f"recent thread follow-up: {source_topic}"
        elif hook.get("type") == "sleep_care":
            trigger_reason = "routine sleep-care window"
        elif hook.get("type") in RHYTHM_NUDGE_HOOK_TYPES:
            trigger_reason = f"routine rhythm stage: {hook.get('type')}"
        elif payload.get("source") == "wake_seed":
            trigger_reason = f"wake follow-up on: {source_topic}"
        else:
            trigger_reason = render_reason or str(payload.get("last_dispatch_reason") or hook.get("last_render_reason") or hook.get("type") or "dispatch")
    dispatch_time = str(seed.get("dispatch_time") or payload.get("last_dispatched_at") or hook.get("last_dispatched_at") or "").strip()
    if not dispatch_time and now_dt:
        dispatch_time = now_dt.isoformat(timespec="seconds")
    dispatched_text = str(
        seed.get("dispatched_text")
        or payload.get("last_dispatched_text")
        or hook.get("last_rendered_message")
        or ""
    ).strip()
    return {
        "trigger_type": str(seed.get("trigger_type") or dispatch_reason_trigger_type(hook, payload)),
        "trigger_reason": trigger_reason,
        "source_topic": source_topic,
        "source_turn_range": str(seed.get("source_turn_range") or dispatch_reason_card_source_turn_range(payload)),
        "event_summary": trim_summary(event_summary, 180),
        "dispatched_text": trim_summary(dispatched_text, 180),
        "dispatch_time": dispatch_time or "unknown",
        "expected_next_step": str(seed.get("expected_next_step") or dispatch_reason_expected_next_step(hook, payload)),
        "priority": int(seed.get("priority") or dispatch_reason_card_priority(hook, payload)),
    }


def latest_dispatched_hook(hook_store: dict) -> Optional[dict]:
    latest_hook = None
    latest_dt = None
    for hook in hook_store.get("hooks", []):
        if not isinstance(hook, dict):
            continue
        if not hook_has_canonical_delivery_confirmation(hook):
            continue
        dispatched_at = parse_optional_dt(hook.get("last_dispatched_at"))
        if dispatched_at is None:
            continue
        if latest_dt is None or dispatched_at > latest_dt:
            latest_dt = dispatched_at
            latest_hook = hook
    return latest_hook


def latest_heartbeat_dispatch_snapshot(now_dt: Optional[datetime] = None) -> Optional[dict]:
    now_dt = now_dt or now_local()
    store = load_sessions_index()
    if not isinstance(store, dict):
        return None
    latest = None
    latest_dt = None
    for session_key, entry in store.items():
        if not isinstance(entry, dict):
            continue
        text = str(entry.get("lastHeartbeatText") or "").strip()
        if not text or text in {"None", "null"}:
            continue
        text = enforce_frontstage_output_rules(text, source="heartbeat-send")
        if not text:
            continue
        sent_dt = parse_optional_epoch_ms(entry.get("lastHeartbeatSentAt"))
        if sent_dt is None:
            continue
        if latest_dt is None or sent_dt > latest_dt:
            latest_dt = sent_dt
            latest = {
                "session_key": str(session_key),
                "sent_dt": sent_dt,
                "text": text,
            }
    if not latest or latest_dt is None:
        return None
    if (now_dt - latest_dt).total_seconds() / 3600 > 12:
        return None
    return latest


def build_heartbeat_dispatch_card(snapshot: dict) -> dict:
    text = trim_summary(str(snapshot.get("text") or "").replace("\n", " "), 180)
    lowered = text.lower()
    if any(token in text for token in ("天氣", "降雨", "氣溫")) or "weather" in lowered:
        source_topic = "weather update"
        trigger_reason = "recent heartbeat weather dispatch"
    else:
        source_topic = trim_summary(text, 72) or "recent heartbeat dispatch"
        trigger_reason = "recent heartbeat dispatch"
    sent_dt = snapshot.get("sent_dt")
    dispatch_time = sent_dt.isoformat(timespec="seconds") if isinstance(sent_dt, datetime) else "unknown"
    return {
        "trigger_type": "heartbeat_dispatch",
        "trigger_reason": trigger_reason,
        "source_topic": source_topic,
        "source_turn_range": "heartbeat-session",
        "event_summary": text or source_topic,
        "dispatched_text": text or source_topic,
        "dispatch_time": dispatch_time,
        "expected_next_step": "If the user asks about this push, continue that dispatched thread instead of denying it.",
        "priority": 2,
    }


def dispatch_awareness_horizon_hours(hook: dict) -> float:
    payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
    source = str(payload.get("source") or "").strip()
    hook_type = str(hook.get("type") or "").strip()
    if source == "wake_seed" or hook_type == "wake_voice_greeting":
        return 2.0
    return 12.0


def recent_dispatch_contexts(hook_store: dict, now_dt: Optional[datetime] = None, limit: int = 4) -> list[dict]:
    now_dt = now_dt or now_local()
    contexts = []
    hooks = hook_store.get("hooks") if isinstance(hook_store.get("hooks"), list) else []
    for hook in hooks:
        if not isinstance(hook, dict):
            continue
        dispatched_at = parse_optional_dt(hook.get("last_dispatched_at"))
        if dispatched_at is None:
            continue
        if (now_dt - dispatched_at).total_seconds() / 3600 > dispatch_awareness_horizon_hours(hook):
            continue
        payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
        contexts.append(
            {
                "kind": "hook",
                "dispatched_at": dispatched_at,
                "still_pending": str(hook.get("status") or "unknown") in ("pending", "dispatched"),
                "card": payload.get("dispatch_reason_card") if isinstance(payload.get("dispatch_reason_card"), dict) else build_dispatch_reason_card(hook, now_dt=now_dt),
            }
        )
    heartbeat_snapshot = latest_heartbeat_dispatch_snapshot(now_dt)
    if isinstance(heartbeat_snapshot, dict):
        contexts.append(
            {
            "kind": "heartbeat",
            "dispatched_at": heartbeat_snapshot.get("sent_dt"),
            "still_pending": True,
            "card": build_heartbeat_dispatch_card(heartbeat_snapshot),
            }
        )
    contexts = [item for item in contexts if isinstance(item, dict) and isinstance(item.get("dispatched_at"), datetime)]
    clean = []
    seen_keys = set()
    for item in sorted(contexts, key=lambda item: item.get("dispatched_at"), reverse=True):
        if _dispatch_source_is_stale(item, now_dt):
            continue
        card = item.get("card") if isinstance(item.get("card"), dict) else {}
        dedup_key = (
            item.get("kind"),
            item.get("dispatched_at").isoformat(timespec="seconds"),
            str(card.get("dispatched_text") or card.get("event_summary") or card.get("source_topic") or "").strip(),
        )
        if dedup_key in seen_keys:
            continue
        seen_keys.add(dedup_key)
        clean.append(item)
        if len(clean) >= max(1, limit):
            break
    return clean


def latest_dispatch_context(hook_store: dict, now_dt: Optional[datetime] = None) -> Optional[dict]:
    contexts = recent_dispatch_contexts(hook_store, now_dt=now_dt, limit=1)
    return contexts[0] if contexts else None


def _dispatch_source_is_stale(context: dict, now_dt: datetime) -> bool:
    """Check if a dispatch's source hook/incident is stale or rejected.
    Prevents old false dispatches from polluting direct session context."""
    dispatched_at = context.get("dispatched_at")
    if isinstance(dispatched_at, datetime):
        age_hours = (now_dt - dispatched_at).total_seconds() / 3600
        # Dispatches older than 12h should not pollute current context
        if age_hours > 12:
            return True
    card = context.get("card") if isinstance(context.get("card"), dict) else {}
    # If dispatch is already handled and old, skip
    if not context.get("still_pending"):
        if isinstance(dispatched_at, datetime):
            age_hours = (now_dt - dispatched_at).total_seconds() / 3600
            if age_hours > 4:
                return True
    # Raw JSON in source_topic or event_summary = extraction pollution
    source_topic = str(card.get("source_topic") or "")
    event_summary = str(card.get("event_summary") or "")
    for field in (source_topic, event_summary):
        if '```json' in field or '{"sender_label"' in field or '"event_kind"' in field:
            return True
    return False


def build_dispatch_awareness_prompt(hook_store: dict, now_dt: Optional[datetime] = None) -> str:
    """Always-on dispatch awareness for direct sessions.

    Provides lightweight context about the most recent cron/proactive dispatch
    so direct sessions know: what was sent, why, and whether it's still pending.
    Applies a shorter horizon for wake-related dispatches.
    """
    if now_dt is None:
        now_dt = now_local()
    contexts = recent_dispatch_contexts(hook_store, now_dt=now_dt, limit=4)
    if not contexts:
        return ""
    context = contexts[0]
    dispatched_at = context.get("dispatched_at")
    card = context.get("card") if isinstance(context.get("card"), dict) else {}
    still_pending = bool(context.get("still_pending"))
    source_topic = str(card.get("source_topic") or "").strip() or "unknown"
    trigger_reason = str(card.get("trigger_reason") or "").strip() or "proactive"
    event_summary = str(card.get("event_summary") or "").strip()
    dispatched_text = str(card.get("dispatched_text") or "").strip()
    dispatch_time = str(card.get("dispatch_time") or dispatched_at.isoformat(timespec="seconds"))

    lines = [
        "## Recent dispatch awareness (trusted structured state)",
        "A proactive/cron message was recently sent. Use this to maintain continuity with what the user already received, including the actual sent content.",
        f"- dispatch_time: {dispatch_time}",
        f"- source_topic: {source_topic}",
        f"- trigger_reason: {trigger_reason}",
    ]
    if event_summary and event_summary != source_topic:
        lines.append(f"- event_summary: {trim_summary(event_summary, 120)}")
    if dispatched_text:
        lines.append(f"- dispatched_text: {trim_summary(dispatched_text, 120)}")
    lines.append(f"- still_pending: {str(still_pending).lower()}")
    if still_pending:
        expected = str(card.get("expected_next_step") or "").strip()
        if expected:
            lines.append(f"- expected_next: {expected}")
        lines.append("If the user responds to this topic, continue the dispatched thread naturally.")
    else:
        lines.append("This dispatch has been handled. Only reference it if the user brings it up.")
    if len(contexts) > 1:
        lines.append("- recent_dispatches:")
        for item in contexts:
            item_card = item.get("card") if isinstance(item.get("card"), dict) else {}
            item_dt = item.get("dispatched_at")
            item_time = str(item_card.get("dispatch_time") or (item_dt.isoformat(timespec="seconds") if isinstance(item_dt, datetime) else "")).strip()
            item_topic = str(item_card.get("source_topic") or "").strip() or "recent thread"
            item_text = str(item_card.get("dispatched_text") or item_card.get("event_summary") or "").strip()
            item_text = trim_summary(item_text, 90)
            pending_flag = "pending" if item.get("still_pending") else "handled"
            lines.append(f"  - {item_time} | {item_topic} | {pending_flag} | {item_text}")
    return "\n".join(lines)


def mark_hook_dispatched(hook_store: dict, hook: dict, now_dt: datetime, message: str, render_reason: str, live_dispatch_result: str = "rendered_for_dispatch") -> dict:
    target = find_hook(hook_store, hook.get("id"))
    if not target:
        target = hook
    current_count = int(target.get("dispatch_count", 0) or 0)
    target["dispatch_count"] = current_count + 1
    target["last_dispatched_at"] = now_dt.isoformat(timespec="seconds")
    target["current_status"] = "active_followup"
    record_dispatch_history(target, now_dt, message)
    target["followup_state"] = advance_event_followup_state(target, user_replied=False)
    target["last_rendered_at"] = now_dt.isoformat(timespec="seconds")
    target["last_rendered_message"] = trim_summary(message, 220)
    preview = trim_summary(message, 220)
    target["last_render_reason"] = render_reason
    payload = target.get("payload") if isinstance(target.get("payload"), dict) else {}
    payload["last_dispatch_reason"] = render_reason
    payload["last_dispatch_result"] = "rendered_pending_delivery"
    payload["last_dispatch_pending"] = True
    payload["last_dispatched_text"] = preview
    payload["last_sent_candidate"] = preview
    payload["last_rendered_at"] = target.get("last_rendered_at")
    payload["dispatch_reason_card"] = build_dispatch_reason_card(target, now_dt=now_dt, render_reason=render_reason)
    target["payload"] = payload
    target.pop("faded_at", None)
    target.pop("faded_reason", None)
    refresh_hook_lifecycle(target, now_dt=now_dt)
    trace_followup(
        now_dt,
        event_kind=target.get("event_kind"),
        event_chain_id=target.get("event_chain_id"),
        source_stage="render",
        followup_decision="prepared",
        trigger_reason="due-ready",
        render_reason=render_reason,
        continuity_source=target.get("source_layer"),
        live_dispatch_result=live_dispatch_result,
        source_id=target.get("id"),
        source_layer="hook",
        summary=target.get("normalized_seed_summary") or target.get("source_summary"),
        **build_trace_writeback_meta(now_dt, entity_type="hook", entity=target, action="rendered_pending_delivery", source_path="proactive"),
        extra={
            "dispatch_count": target.get("dispatch_count"),
            "dispatch_cap": hook_dispatch_cap(target),
            "message_preview": trim_summary(message, 120),
            "delivery_pending": True,
        },
    )
    return target


def confirm_hook_delivery(
    hook_store: dict,
    hook: dict,
    now_dt: datetime,
    *,
    message: str,
    channel: str = "",
    live_dispatch_result: str = "sent",
) -> dict:
    target = find_hook(hook_store, hook.get("id"))
    if not target:
        target = hook
    preview = trim_summary(message, 220)
    payload = target.get("payload") if isinstance(target.get("payload"), dict) else {}
    last_dt = parse_optional_dt(target.get("last_dispatched_at"))
    rendered_dt = parse_optional_dt(target.get("last_rendered_at") or payload.get("last_rendered_at"))
    confirmed_dt = parse_optional_dt(payload.get("last_delivery_confirmed_at"))
    last_preview = trim_summary(str(payload.get("last_dispatched_text") or target.get("last_rendered_message") or ""), 220)
    channel_value = str(channel or "").strip() or payload.get("last_dispatch_channel")
    pending_delivery = bool(payload.get("last_dispatch_pending"))
    timing_ref = rendered_dt or last_dt
    same_preview = not preview or not last_preview or preview == last_preview

    if pending_delivery and timing_ref is not None and abs((now_dt - timing_ref).total_seconds()) <= 600 and same_preview:
        payload["last_dispatch_result"] = live_dispatch_result
        payload["last_dispatch_pending"] = False
        payload["last_dispatch_channel"] = channel_value
        payload["last_dispatched_text"] = preview or last_preview
        payload["last_delivery_confirmed_at"] = now_dt.isoformat(timespec="seconds")
        target["payload"] = payload
        refresh_hook_lifecycle(target, now_dt=now_dt)
        dispatch_trace = write_dispatch_daily_memory_trace(
            target,
            now_dt=now_dt,
            message=message,
        )
        if isinstance(dispatch_trace, dict):
            payload["last_dispatch_daily_memory_trace"] = dispatch_trace
            target["payload"] = payload
        trace_followup(
            now_dt,
            event_kind=target.get("event_kind"),
            event_chain_id=target.get("event_chain_id"),
            source_stage="delivery",
            followup_decision="dispatch_sent",
            trigger_reason="channel-send-ok",
            continuity_source=target.get("source_layer"),
            live_dispatch_result=live_dispatch_result,
            source_id=target.get("id"),
            source_layer="hook",
            summary=target.get("normalized_seed_summary") or target.get("source_summary"),
            **build_trace_writeback_meta(now_dt, entity_type="hook", entity=target, action="dispatched", source_path="proactive"),
            extra={
                "dispatch_count": target.get("dispatch_count"),
                "dispatch_cap": hook_dispatch_cap(target),
                "message_preview": trim_summary(message, 120),
                "channel": channel,
                "daily_memory_trace": dispatch_trace,
            },
        )
        if target.get("type") == "proactive_chat":
            payload["proactive_writeback_last"] = maybe_write_proactive_daily_memory(
                target,
                now_dt=now_dt,
                timing="dispatch",
            )
            target["payload"] = payload
        return target

    if confirmed_dt is not None and not pending_delivery and timing_ref is not None and abs((now_dt - confirmed_dt).total_seconds()) <= 600 and same_preview:
        payload["last_dispatch_result"] = live_dispatch_result
        payload["last_dispatch_channel"] = channel_value
        target["payload"] = payload
        return target

    payload["last_dispatch_result"] = live_dispatch_result
    payload["last_dispatch_pending"] = False
    payload["last_dispatch_channel"] = channel_value
    payload["last_dispatched_text"] = preview or last_preview
    payload["last_delivery_confirmed_at"] = now_dt.isoformat(timespec="seconds")
    target["payload"] = payload
    refresh_hook_lifecycle(target, now_dt=now_dt)
    payload["last_dispatch_result"] = live_dispatch_result
    dispatch_trace = write_dispatch_daily_memory_trace(
        target,
        now_dt=now_dt,
        message=message,
    )
    if isinstance(dispatch_trace, dict):
        payload["last_dispatch_daily_memory_trace"] = dispatch_trace
        target["payload"] = payload
    trace_followup(
        now_dt,
        event_kind=target.get("event_kind"),
        event_chain_id=target.get("event_chain_id"),
        source_stage="delivery",
        followup_decision="dispatch_sent",
        trigger_reason="channel-send-ok",
        continuity_source=target.get("source_layer"),
        live_dispatch_result=live_dispatch_result,
        source_id=target.get("id"),
        source_layer="hook",
        summary=target.get("normalized_seed_summary") or target.get("source_summary"),
        **build_trace_writeback_meta(now_dt, entity_type="hook", entity=target, action="dispatched", source_path="proactive"),
        extra={
            "dispatch_count": target.get("dispatch_count"),
            "dispatch_cap": hook_dispatch_cap(target),
            "message_preview": trim_summary(message, 120),
            "channel": channel,
            "daily_memory_trace": dispatch_trace,
        },
    )
    if target.get("type") == "proactive_chat":
        payload["proactive_writeback_last"] = maybe_write_proactive_daily_memory(
            target,
            now_dt=now_dt,
            timing="dispatch",
        )
        target["payload"] = payload
    return target


def try_reactivate_parked_hooks(hook_store: dict, text: str, now_dt: datetime) -> Optional[dict]:
    """Check if user text matches a parked_waiting hook and re-activate it."""
    inferred_event_kind = infer_followup_event_type(text)
    intents = classify_seed_intents(text)
    return_signal = any(item.get("intent") == "return_signal" for item in intents.get("intents", []))
    for hook in hook_store.get("hooks", []):
        if hook.get("status") != "pending":
            continue
        lifecycle = infer_hook_lifecycle(hook)
        if get_event_followup_state(hook) != FOLLOWUP_STATE_PARKED and lifecycle != TRACKING_LIFECYCLE_FADED:
            continue
        score = event_chain_match_score(hook, text, inferred_event_kind)
        if return_signal:
            score += 4
        if score >= 6:
            hook["followup_state"] = FOLLOWUP_STATE_REACTIVATED
            mark_dispatch_history_replied(hook, now_dt)
            hook.pop("faded_at", None)
            hook.pop("faded_reason", None)
            hook["lifecycle"] = TRACKING_LIFECYCLE_ACTIVE
            refresh_hook_lifecycle(hook, now_dt=now_dt)
            return hook
    return None


def find_matching_active_hook_for_user_reply(hook_store: dict, text: str, now_dt: datetime) -> Optional[dict]:
    # ── First try to re-activate parked hooks ──
    reactivated = try_reactivate_parked_hooks(hook_store, text, now_dt)
    if reactivated:
        return reactivated
    intents = classify_seed_intents(text)
    return_signal = any(item.get("intent") == "return_signal" for item in intents.get("intents", []))
    inferred_event_kind = infer_followup_event_type(text)
    candidates = []
    for hook in hook_store.get("hooks", []):
        if hook.get("status") != "pending":
            continue
        if infer_hook_lifecycle(hook) == TRACKING_LIFECYCLE_FADED:
            continue
        dispatch_count = int(hook.get("dispatch_count", 0) or 0)
        trigger_at = hook.get("trigger_at")
        due_or_dispatched = dispatch_count > 0
        if isinstance(trigger_at, str):
            try:
                due_or_dispatched = due_or_dispatched or parse_dt(trigger_at) <= now_dt
            except Exception:
                pass
        if not due_or_dispatched:
            continue
        score = event_chain_match_score(hook, text, inferred_event_kind) + (4 if dispatch_count > 0 else 0)
        if return_signal and dispatch_count > 0:
            score += 6
        candidates.append((score, hook))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (item[0], item[1].get("last_dispatched_at") or item[1].get("trigger_at") or ""), reverse=True)
    best_score, best_hook = candidates[0]
    if best_score >= 6:
        return best_hook
    if return_signal:
        dispatched = [hook for _, hook in candidates if int(hook.get("dispatch_count", 0) or 0) > 0]
        if len(dispatched) == 1:
            return dispatched[0]
    return None


def maybe_close_active_hook_from_user_reply(
    hook_store: dict,
    text: str,
    now_dt: datetime,
    session_id: Optional[str] = None,
    time_state: Optional[dict] = None,
) -> Optional[dict]:
    settings = load_settings()
    closure = settings.get("closure") if isinstance(settings.get("closure"), dict) else {}
    if not closure.get("auto_close_on_user_reply", True):
        return None
    if looks_like_internal_control_text(text):
        return None
    hook = find_matching_active_hook_for_user_reply(hook_store, text, now_dt)
    if not hook:
        return None
    if hook.get("status") != "pending":
        return None
    now_ts = now_dt.isoformat(timespec="seconds")
    hook["status"] = "done"
    hook["current_status"] = "historical_completed"
    hook["completed_at"] = hook.get("completed_at") or now_ts
    hook["completion_logged_at"] = hook.get("completion_logged_at") or now_ts
    hook["closure_reason"] = "user_reply_matched_active_hook"
    # ── Mark dispatch history as replied ──
    mark_dispatch_history_replied(hook, now_dt)
    hook["followup_state"] = advance_event_followup_state(hook, user_replied=True)
    hook["lifecycle"] = TRACKING_LIFECYCLE_COMPLETED
    refresh_hook_lifecycle(hook, now_dt=now_dt)
    proactive_writeback = None
    if hook.get("type") == "proactive_chat":
        proactive_writeback = maybe_write_proactive_daily_memory(
            hook,
            now_dt=now_dt,
            timing="user_reply",
            user_text=text,
            session_id=session_id,
        )
    append_hook_completion_audit({
        "ts": now_ts,
        "hook_id": hook.get("id"),
        "action": "complete",
        "reason": "user-reply-matched-active-hook",
        "status": hook.get("status"),
        "completed_at": hook.get("completed_at"),
        "completion_logged_at": hook.get("completion_logged_at"),
    })
    trace_followup(
        now_dt,
        session_id=session_id,
        event_kind=hook.get("event_kind"),
        event_chain_id=hook.get("event_chain_id"),
        source_stage="closure",
        followup_decision="closed",
        closure_reason="user_reply_matched_active_hook",
        continuity_source="active_hook",
        live_dispatch_result="user_reply_received",
        source_id=hook.get("id"),
        source_layer="hook",
        summary=hook.get("normalized_seed_summary") or hook.get("source_summary"),
        **build_trace_writeback_meta(
            now_dt,
            entity_type="hook",
            entity=hook,
            action="closed",
            source_path="ordinary",
            time_state=time_state,
        ),
        extra={"proactive_writeback": proactive_writeback} if proactive_writeback is not None else None,
    )
    return {
        "hook_id": hook.get("id"),
        "event_kind": hook.get("event_kind"),
        "event_chain_id": hook.get("event_chain_id"),
        "closure_reason": "user_reply_matched_active_hook",
        "proactive_writeback": proactive_writeback,
    }


def completion_entity_session_key(entity_type: str, entity: dict) -> str:
    if entity_type == "hook":
        payload = entity.get("payload") if isinstance(entity.get("payload"), dict) else {}
        return str(payload.get("session_key") or "").strip()
    if entity_type == "incident":
        payload = entity.get("payload") if isinstance(entity.get("payload"), dict) else {}
        return str(payload.get("session_key") or "").strip()
    return str(entity.get("session_key") or "").strip()


def completion_entity_updated_at(entity_type: str, entity: dict) -> str:
    if entity_type == "hook":
        return str(entity.get("last_seen_at") or entity.get("last_dispatched_at") or entity.get("trigger_at") or entity.get("created_at") or "")
    if entity_type == "incident":
        return str(entity.get("last_seen_at") or entity.get("closed_at") or entity.get("created_at") or "")
    return str(entity.get("updated_at") or entity.get("completed_at") or entity.get("created_at") or "")


def completion_target_score(entity_type: str, entity: dict, text: str, inferred_event_kind: str, session_key: Optional[str]) -> int:
    score = int(round(event_chain_match_score(entity, text, inferred_event_kind)))
    entity_session = completion_entity_session_key(entity_type, entity)
    if session_key and entity_session and entity_session == str(session_key or "").strip():
        score += 3
    summary = normalize_text_for_match(
        entity.get("normalized_seed_summary")
        or entity.get("source_summary")
        or entity.get("source_seed_text")
        or ""
    )
    normalized_text = normalize_text_for_match(text)
    if summary and normalized_text and (summary in normalized_text or normalized_text in summary):
        score += 3
    if str(entity.get("event_kind") or "") in {"delegated_task", "important_task"}:
        score += 2
    layer_bonus = {"hook": 3, "incident": 2, "staging": 1}
    score += layer_bonus.get(entity_type, 0)
    return score


def find_followup_completion_target(
    hook_store: dict,
    incident_store: dict,
    staging_store: dict,
    text: str,
    now_dt: datetime,
    session_key: Optional[str] = None,
) -> Optional[dict]:
    inferred_event_kind = infer_followup_event_type(text)
    candidates: list[tuple[int, str, str, dict]] = []
    session_key_str = str(session_key or "").strip()

    for hook in hook_store.get("hooks", []):
        if not isinstance(hook, dict) or hook.get("status") != "pending":
            continue
        score = completion_target_score("hook", hook, text, inferred_event_kind, session_key)
        candidates.append((score, completion_entity_updated_at("hook", hook), "hook", hook))

    for incident in incident_store.get("incidents", []):
        if not isinstance(incident, dict) or incident.get("status") in {"closed", "rejected", "cancelled", "done"}:
            continue
        score = completion_target_score("incident", incident, text, inferred_event_kind, session_key)
        candidates.append((score, completion_entity_updated_at("incident", incident), "incident", incident))

    for record in staging_store.get("records", []):
        if not isinstance(record, dict) or record.get("status") not in {"staged", "promoted"}:
            continue
        score = completion_target_score("staging", record, text, inferred_event_kind, session_key)
        candidates.append((score, completion_entity_updated_at("staging", record), "staging", record))

    if not candidates:
        return None
    if session_key_str:
        same_session_candidates = [
            item for item in candidates
            if completion_entity_session_key(item[2], item[3]) == session_key_str
        ]
        if same_session_candidates:
            candidates = same_session_candidates
    candidates.sort(key=lambda item: (item[0], item[1]), reverse=True)
    best_score, _, entity_type, entity = candidates[0]
    if best_score >= 6:
        return {"entity_type": entity_type, "entity": entity, "score": best_score}

    if session_key_str:
        same_session = [
            item for item in candidates
            if completion_entity_session_key(item[2], item[3]) == session_key_str
        ]
        if len(same_session) == 1:
            score, _, entity_type, entity = same_session[0]
            return {"entity_type": entity_type, "entity": entity, "score": score, "fallback": "single-session-entity"}
    return None


def mark_hook_completed_from_user_result(
    hook: dict,
    completion: dict,
    now_dt: datetime,
    *,
    time_state: Optional[dict] = None,
    session_id: Optional[str] = None,
) -> bool:
    if not isinstance(hook, dict):
        return False
    if str(hook.get("status") or "") in TERMINAL_HOOK_STATUSES and hook.get("completion_logged_at"):
        return False
    now_ts = now_dt.isoformat(timespec="seconds")
    completion_summary = trim_summary(str(completion.get("summary") or "").strip(), 160)
    topic_label = hook.get("topic_label") or infer_topic_label(hook.get("normalized_seed_summary") or hook.get("source_summary") or "", hook.get("type", "待追話題"))
    hook["event_chain"] = merge_completion_event_chain(
        hook.get("event_chain"),
        completion_summary or hook.get("normalized_seed_summary") or hook.get("source_summary") or "",
        str(hook.get("event_kind") or ""),
        topic_label=topic_label,
    )
    hook["normalized_seed_summary"] = synthesize_event_chain_summary(
        hook.get("event_chain"),
        completion_summary or hook.get("normalized_seed_summary") or hook.get("source_summary") or "",
    )
    hook["status"] = "done"
    hook["current_status"] = "historical_completed"
    hook["completed_at"] = hook.get("completed_at") or now_ts
    hook["completion_logged_at"] = hook.get("completion_logged_at") or now_ts
    hook["closure_reason"] = hook.get("closure_reason") or "user_explicit_closure"
    hook["lifecycle"] = TRACKING_LIFECYCLE_COMPLETED
    hook["last_seen_at"] = now_ts
    hook["followup_state"] = FOLLOWUP_STATE_REACTIVATED
    payload = hook.get("payload") if isinstance(hook.get("payload"), dict) else {}
    payload["completion_summary"] = completion_summary
    payload["completion_marker"] = "completed"
    payload["completed_at"] = hook.get("completed_at")
    payload["event_chain"] = deepcopy(hook.get("event_chain"))
    payload["event_chain_id"] = hook.get("event_chain_id")
    hook["payload"] = payload
    hook["daily_memory_trace"] = commit_daily_memory_writeback(
        now_dt,
        action="tracked_completed",
        summary=hook.get("normalized_seed_summary") or completion_summary or hook.get("source_summary") or "",
        memory_class="tracked_followup",
        event_kind=hook.get("event_kind"),
        causal_memory=(hook.get("event_chain") or {}).get("causal_memory"),
        time_state=time_state,
        dialogue_turns=resolve_record_anchor_turns(hook),
    )
    append_hook_completion_audit({
        "ts": now_ts,
        "hook_id": hook.get("id"),
        "action": "complete",
        "reason": "user-explicit-closure",
        "status": hook.get("status"),
        "completed_at": hook.get("completed_at"),
        "completion_logged_at": hook.get("completion_logged_at"),
    })
    refresh_hook_lifecycle(hook, now_dt=now_dt)
    trace_followup(
        now_dt,
        session_id=session_id,
        event_kind=hook.get("event_kind"),
        event_chain_id=hook.get("event_chain_id"),
        source_stage="closure",
        followup_decision="closed",
        closure_reason="user_explicit_closure",
        continuity_source="hook",
        live_dispatch_result="user_completion_reported",
        source_id=hook.get("id"),
        source_layer="hook",
        summary=hook.get("normalized_seed_summary") or hook.get("source_summary"),
        **build_trace_writeback_meta(
            now_dt,
            entity_type="hook",
            entity=hook,
            action="closed",
            source_path="ordinary",
            time_state=time_state,
        ),
    )
    return True


