def mark_staging_completed_from_user_result(
    record: dict,
    completion: dict,
    now_dt: datetime,
    *,
    time_state: Optional[dict] = None,
    session_id: Optional[str] = None,
) -> bool:
    if not isinstance(record, dict):
        return False
    if str(record.get("status") or "") in {"completed", "resolved", "expired", "discarded"} and record.get("completed_at"):
        return False
    now_ts = now_dt.isoformat(timespec="seconds")
    completion_summary = trim_summary(str(completion.get("summary") or "").strip(), 160)
    topic_label = record.get("topic_label") or infer_topic_label(record.get("normalized_seed_summary") or record.get("source_seed_text") or "", "待續主題")
    record["event_chain"] = merge_completion_event_chain(
        record.get("event_chain"),
        completion_summary or record.get("normalized_seed_summary") or record.get("source_seed_text") or "",
        str(record.get("event_kind") or ""),
        topic_label=topic_label,
    )
    if isinstance(record.get("event_chain"), dict):
        event_chain = record["event_chain"]
        causal = event_chain.get("causal_memory") if isinstance(event_chain.get("causal_memory"), dict) else {}
        causal["open_loop"] = "resolved_completion"
        causal["followup_focus_code"] = "remember_for_later"
        causal["followup_focus"] = FOLLOWUP_FOCUS_HINT_MAP["remember_for_later"]
        causal["completion_marker"] = "completed"
        if completion_summary:
            causal["completion_summary"] = completion_summary
        event_chain["causal_memory"] = causal
        event_chain["immediate_result_code"] = "task_completed"
        event_chain["immediate_result"] = "The user reported that this was already completed."
        event_chain["followup_focus_code"] = "remember_for_later"
        event_chain["followup_focus"] = FOLLOWUP_FOCUS_HINT_MAP["remember_for_later"]
    record["normalized_seed_summary"] = synthesize_event_chain_summary(
        record.get("event_chain"),
        completion_summary or record.get("normalized_seed_summary") or record.get("source_seed_text") or "",
    )
    record["status"] = "completed"
    record["current_status"] = "historical_completed"
    record["lifecycle"] = "completed"
    record["completed_at"] = record.get("completed_at") or now_ts
    record["updated_at"] = now_ts
    if completion_summary:
        record["completion_summary"] = completion_summary
    memory_class = "tracked_followup" if str(record.get("memory_class") or "") == "tracked_followup" else "staged_memory"
    record["daily_memory_trace"] = commit_daily_memory_writeback(
        now_dt,
        action="tracked_completed" if memory_class == "tracked_followup" else "staged_completed",
        summary=completion_summary or record.get("normalized_seed_summary") or record.get("source_seed_text") or "",
        memory_class=memory_class,
        event_kind=record.get("event_kind"),
        causal_memory=(record.get("event_chain") or {}).get("causal_memory"),
        time_state=time_state,
        context_turns=record.get("recent_user_context"),
        dialogue_turns=record.get("anchor_turns"),
    )
    trace_followup(
        now_dt,
        session_id=session_id or record.get("session_id"),
        event_kind=record.get("event_kind"),
        event_chain_id=record.get("event_chain_id"),
        source_stage="staging",
        followup_decision="closed",
        closure_reason="user_explicit_closure",
        continuity_source="session_staging",
        live_dispatch_result="user_completion_reported",
        source_id=record.get("session_id"),
        source_layer="session_staging",
        summary=record.get("normalized_seed_summary"),
        **build_trace_writeback_meta(
            now_dt,
            entity_type="staging",
            entity=record,
            action="closed",
            source_path="ordinary",
            time_state=time_state,
        ),
    )
    return True


