def cmd_profile_set(args):
    profile = load_profile()
    settings = load_settings()
    value = parse_value(args.value)
    if args.key in PROFILE_SET_TOP_LEVEL_KEYS:
        profile[args.key] = value
        if isinstance(profile.get(args.key), dict) and "source" in profile[args.key]:
            profile[args.key]["source"] = "profile-set"
        save_profile(profile)
        print(json.dumps(profile, ensure_ascii=False, indent=2))
        return
    if args.key in SETUP_FIELD_BY_KEY:
        result = _apply_setup_field_values(profile, settings, {args.key: value}, source="profile-set")
        save_profile(profile)
        save_settings(settings)
        print(json.dumps({
            "key": args.key,
            "value": value,
            "applied": result["applied"],
            "skipped": result["skipped"],
            "profile": profile,
            "settings": settings,
        }, ensure_ascii=False, indent=2))
        return
    resolved = _apply_profile_set_target_path(profile, settings, args.key, value, source="profile-set")
    save_profile(profile)
    save_settings(settings)
    print(json.dumps({
        "key": args.key,
        "value": value,
        "target": resolved["target"],
        "path": resolved["path"],
        "mirrored_paths": resolved["mirrored_paths"],
        "profile": profile,
        "settings": settings,
    }, ensure_ascii=False, indent=2))


