def cmd_due(args):
    store = load_hooks()
    profile = load_profile()
    emotion_state = load_emotion_state()
    staging_store = load_session_memory_staging()
    now_dt = parse_dt(args.now) if args.now else now_local()
    staging_reconcile = reconcile_expired_staging_records(staging_store, store, now_dt)
    if staging_reconcile.get("changed"):
        save_session_memory_staging(staging_store, now_dt=now_dt)
    sanitized = sanitize_pending_hooks_for_temporal_truth(store, profile, emotion_state, now_dt)
