def cmd_decision_loop(args):
    incident_store = load_incidents()
    hook_store = load_hooks()
    memory_rank_store = load_memory_rank()
    candidate_store = load_candidate_buffer()
    autonomy_state = load_autonomy_state()
    user_model = load_user_model()
    persona_state = load_persona_state()
    now_dt = parse_dt(args.now) if args.now else now_local()
    result = execute_decision_loop(
        text=args.text,
        incident_store=incident_store,
        hook_store=hook_store,
        memory_rank_store=memory_rank_store,
        candidate_store=candidate_store,
        autonomy_state=autonomy_state,
        user_model=user_model,
        persona_state=persona_state,
        now_dt=now_dt,
        source=args.source,
    )
    save_user_model(user_model)
    save_persona_state(persona_state)
    if result.get("incident_result", {}).get("created") or result.get("candidate_result", {}).get("promotion_actions"):
        save_incidents(incident_store)
        save_hooks(hook_store)
        save_memory_rank(memory_rank_store)
    if result.get("candidate_result", {}).get("action") != "none":
        save_candidate_buffer(candidate_store)
