def capture_assistant_commitment(session_key: Optional[str], text: str, now_dt: datetime) -> dict:
    key = str(session_key or "").strip()
    if not is_anchor_eligible_session_key(key):
        return {"captured": False, "reason": "ineligible-session"}
    commitment = extract_assistant_commitment(text, now_dt)
    if not commitment:
        return {"captured": False, "reason": "no-commitment"}

    staging_store = load_session_memory_staging()
    hook_store = load_hooks()
    incident_store = load_incidents()
    time_state = build_time_state(now_dt=now_dt)

    target_record = find_recent_staging_record_by_session_key(staging_store, key, now_dt)
    target_hook = None if target_record else find_recent_hook_by_session_key(hook_store, key, now_dt)
    if not target_record and not target_hook:
        return {"captured": False, "reason": "no-target-record"}

    changed = False
    target_entity_type = None
    target_entity = None

    if isinstance(target_record, dict):
        existing = normalize_assistant_commitment(target_record.get(ASSISTANT_COMMITMENT_FIELD_KEY))
        if existing != normalize_assistant_commitment(commitment):
            apply_assistant_commitment(target_record, commitment)
            target_record["updated_at"] = now_dt.isoformat(timespec="seconds")
            changed = True
        target_entity_type = "staging"
        target_entity = target_record
        if str(target_record.get("linked_incident_id") or "").strip():
            sync_linked_incident_from_staging(target_record, now_dt)

    if isinstance(target_hook, dict):
        existing = normalize_assistant_commitment(target_hook.get(ASSISTANT_COMMITMENT_FIELD_KEY))
        if existing != normalize_assistant_commitment(commitment):
            apply_assistant_commitment(target_hook, commitment)
            target_hook["last_seen_at"] = now_dt.isoformat(timespec="seconds")
            changed = True
        if target_entity is None:
            target_entity_type = "hook"
            target_entity = target_hook

    if not changed:
        return {
            "captured": False,
            "reason": "unchanged",
            "commitment": normalize_assistant_commitment(commitment),
            "entity_type": target_entity_type,
            "entity_id": target_entity.get("id") if isinstance(target_entity, dict) else target_record.get("session_id") if isinstance(target_record, dict) else None,
        }

    if isinstance(target_record, dict):
        save_session_memory_staging(staging_store, now_dt=now_dt)
    if isinstance(target_hook, dict):
        save_hooks(hook_store)

    entity_id = None
    if isinstance(target_entity, dict):
        entity_id = target_entity.get("id") or target_entity.get("session_id")
    trace_followup(
        now_dt,
        session_id=key,
        event_kind=target_entity.get("event_kind") if isinstance(target_entity, dict) else None,
        event_chain_id=target_entity.get("event_chain_id") if isinstance(target_entity, dict) else None,
        source_stage="assistant_commitment",
        followup_decision="captured",
        trigger_reason=commitment.get("commitment_type"),
        continuity_source="assistant_output",
        live_dispatch_result="captured",
        source_id=entity_id,
        source_layer=target_entity_type or "assistant_output",
        summary=commitment.get("phrase"),
        **build_trace_writeback_meta(
            now_dt,
            entity_type=target_entity_type or "staging",
            entity=target_entity if isinstance(target_entity, dict) else (target_record or target_hook or {}),
            action="updated",
            source_path="runtime-reply",
            time_state=time_state,
        ),
    )
    return {
        "captured": True,
        "reason": "stored",
        "commitment": normalize_assistant_commitment(commitment),
        "entity_type": target_entity_type,
        "entity_id": entity_id,
    }


