def cmd_runtime_context(args):
    now_dt = parse_dt(args.timestamp) if args.timestamp else now_local()
    session_key = args.session_key or resolve_primary_session_key() or "session-key-unknown"
    session_entry = session_entry_for_key(session_key) if session_key != "session-key-unknown" else None
    resolved_session_id = None
    if isinstance(session_entry, dict):
        session_file = session_entry.get("sessionFile")
        if isinstance(session_file, str):
            resolved_session_id = Path(session_file).stem
    session_id = args.session_id or resolved_session_id or "session-unknown"
    resolved_user_turn_index = int(args.user_turn_index or 0)
    if resolved_user_turn_index <= 0:
        counted_user_turns = visible_session_user_turn_count(session_key, session_id=session_id)
        resolved_user_turn_index = max(1, counted_user_turns)
    result = build_runtime_context(
        session_id=session_id,
        session_key=session_key,
        user_text=args.user_text,
        now_dt=now_dt,
        is_new_session=args.is_new_session,
        user_turn_index=resolved_user_turn_index,
    )
    print(json.dumps(result, ensure_ascii=False, indent=2))


