def cmd_scan_output(args):
    """Scan model output text for self-commitment patterns and create hooks."""
    now_dt = parse_dt(args.now) if args.now else now_local()
    commitments = detect_model_commitments(args.text)
    created_hooks = []
    if commitments:
        store = load_hooks()
        created_hooks = create_commitment_hooks(store, commitments, now_dt)
        if created_hooks:
            save_hooks(store)
    print(json.dumps({
        "commitments_detected": len(commitments),
        "hooks_created": len(created_hooks),
        "commitments": commitments,
        "hooks": [{"id": h["id"], "type": h["type"], "trigger_at": h["trigger_at"], "source_summary": h["source_summary"]} for h in created_hooks],
    }, ensure_ascii=False, indent=2))


