def build_parser():
    parser = argparse.ArgumentParser()
    sub = parser.add_subparsers(dest="cmd", required=True)

    sub.add_parser("init").set_defaults(func=cmd_init)
    sub.add_parser("profile-show").set_defaults(func=cmd_profile_show)
    sub.add_parser("user-model-show").set_defaults(func=cmd_user_model_show)
    sub.add_parser("emotion-show").set_defaults(func=cmd_emotion_show)
    sub.add_parser("persona-show").set_defaults(func=cmd_persona_show)
    sub.add_parser("autonomy-show").set_defaults(func=cmd_autonomy_show)
    sub.add_parser("state-audit").set_defaults(func=cmd_state_audit)
    sub.add_parser("user-model-explain").set_defaults(func=cmd_user_model_explain)
    sub.add_parser("capability-state-show").set_defaults(func=cmd_capability_state_show)
    sub.add_parser("capability-state-explain").set_defaults(func=cmd_capability_state_explain)

    learning_log_show = sub.add_parser("learning-log-show")
    learning_log_show.add_argument("--limit", type=int, default=20)
    learning_log_show.set_defaults(func=cmd_learning_log_show)

    memory_rank_show = sub.add_parser("memory-rank-show")
    memory_rank_show.add_argument("--limit", type=int, default=20)
    memory_rank_show.set_defaults(func=cmd_memory_rank_show)

    pset = sub.add_parser("profile-set")
    pset.add_argument("--key", required=True)
    pset.add_argument("--value", required=True)
    pset.set_defaults(func=cmd_profile_set)

    sub.add_parser("setup-check").set_defaults(func=cmd_setup_check)

    sapply = sub.add_parser("setup-apply")
    sapply.add_argument("--payload-json", required=True)
    sapply.set_defaults(func=cmd_setup_apply)

    aset = sub.add_parser("autonomy-set")
    aset.add_argument("--key", required=True)
    aset.add_argument("--value", required=True)
    aset.set_defaults(func=cmd_autonomy_set)

    add = sub.add_parser("add-hook")
    add.add_argument("--type", required=True)
    add.add_argument("--trigger-at", required=True)
    add.add_argument("--source-summary", required=True)
    add.add_argument("--note")
    add.add_argument("--payload-json")
    add.set_defaults(func=cmd_add_hook)

    due = sub.add_parser("due")
    due.add_argument("--now")
    due.add_argument("--limit", type=int, default=1)
    due.set_defaults(func=cmd_due)

    autoseed = sub.add_parser("autoseed")
    autoseed.add_argument("--now")
    autoseed.set_defaults(func=cmd_autoseed)

    detect = sub.add_parser("detect-incident")
    detect.add_argument("--text", required=True)
    detect.add_argument("--now")
    detect.set_defaults(func=cmd_detect_incident)

    intercept = sub.add_parser("intercept-message")
    intercept.add_argument("--text", required=True)
    intercept.add_argument("--now")
    intercept.set_defaults(func=cmd_intercept_message)

    preagent_sync = sub.add_parser("preagent-sync")
    preagent_sync.add_argument("--text", required=True)
    preagent_sync.add_argument("--timestamp")
    preagent_sync.add_argument("--source", default="runtime-preagent")
    preagent_sync.add_argument("--session-key")
    preagent_sync.set_defaults(func=cmd_preagent_sync)

    feedback_extract = sub.add_parser("feedback-extract")
    feedback_extract.add_argument("--text", required=True)
    feedback_extract.set_defaults(func=cmd_feedback_extract)

    feedback_apply = sub.add_parser("feedback-apply")
    feedback_apply.add_argument("--text", required=True)
    feedback_apply.add_argument("--source", default="manual")
    feedback_apply.set_defaults(func=cmd_feedback_apply)

    decision_evaluate = sub.add_parser("decision-evaluate")
    decision_evaluate.add_argument("--text", required=True)
    decision_evaluate.add_argument("--now")
    decision_evaluate.set_defaults(func=cmd_decision_evaluate)

    decision_loop = sub.add_parser("decision-loop")
    decision_loop.add_argument("--text", required=True)
    decision_loop.add_argument("--now")
    decision_loop.add_argument("--source", default="manual-decision-loop")
    decision_loop.set_defaults(func=cmd_decision_loop)

    style_preview_cmd = sub.add_parser("style-preview")
    style_preview_cmd.add_argument("--mode", required=True, choices=sorted(PERSONA_MODES))
    style_preview_cmd.add_argument("--text")
    style_preview_cmd.set_defaults(func=cmd_style_preview)

    frontstage_guard = sub.add_parser("frontstage-guard")
    frontstage_guard.add_argument("--text", required=True)
    frontstage_guard.add_argument("--source", default="runtime-send")
    frontstage_guard.add_argument("--timestamp")
    frontstage_guard.set_defaults(func=cmd_frontstage_guard)

    capture_commitment = sub.add_parser("capture-commitment")
    capture_commitment.add_argument("--text", required=True)
    capture_commitment.add_argument("--session-key", required=True)
    capture_commitment.add_argument("--timestamp")
    capture_commitment.set_defaults(func=cmd_capture_commitment)

    runtime_context = sub.add_parser("runtime-context")
    runtime_context.add_argument("--session-id")
    runtime_context.add_argument("--session-key")
    runtime_context.add_argument("--user-text", required=True)
    runtime_context.add_argument("--timestamp")
    runtime_context.add_argument("--is-new-session", action="store_true")
    runtime_context.add_argument("--user-turn-index", type=int, default=0)
    runtime_context.set_defaults(func=cmd_runtime_context)

    new_session_fallback = sub.add_parser("new-session-fallback")
    new_session_fallback.add_argument("--session-key", required=True)
    new_session_fallback.add_argument("--session-id")
    new_session_fallback.add_argument("--timestamp")
    new_session_fallback.set_defaults(func=cmd_new_session_fallback)

    hb_decision = sub.add_parser("heartbeat-decision")
    hb_decision.add_argument("--timestamp")
    hb_decision.set_defaults(func=cmd_heartbeat_decision)

    hb_render = sub.add_parser("heartbeat-render")
    hb_render.add_argument("--timestamp")
    hb_render.add_argument("--commit", action="store_true")
    hb_render.set_defaults(func=cmd_heartbeat_render)

    render = sub.add_parser("render")
    render.add_argument("--id", required=True)
    render.set_defaults(func=cmd_render)

    ack_delivery = sub.add_parser("ack-delivery")
    ack_delivery.add_argument("--message", required=True)
    ack_delivery.add_argument("--session-key")
    ack_delivery.add_argument("--channel")
    ack_delivery.add_argument("--id")
    ack_delivery.add_argument("--timestamp")
    ack_delivery.set_defaults(func=cmd_ack_delivery)

    complete = sub.add_parser("complete")
    complete.add_argument("--id", required=True)
    complete.set_defaults(func=cmd_complete)

    cancel = sub.add_parser("cancel")
    cancel.add_argument("--id", required=True)
    cancel.set_defaults(func=cmd_cancel)

    incident_add = sub.add_parser("incident-add")
    incident_add.add_argument("--type", required=True)
    incident_add.add_argument("--severity", required=True)
    incident_add.add_argument("--source-summary", required=True)
    incident_add.add_argument("--status", default="approved")
    incident_add.add_argument("--followup-policy-json")
    incident_add.add_argument("--payload-json")
    incident_add.add_argument("--note")
    incident_add.set_defaults(func=cmd_incident_add)

    incident_list = sub.add_parser("incident-list")
    incident_list.add_argument("--status")
    incident_list.add_argument("--limit", type=int, default=20)
    incident_list.set_defaults(func=cmd_incident_list)

    incident_show = sub.add_parser("incident-show")
    incident_show.add_argument("--id", required=True)
    incident_show.set_defaults(func=cmd_incident_show)

    incident_status = sub.add_parser("incident-set-status")
    incident_status.add_argument("--id", required=True)
    incident_status.add_argument("--status", required=True)
    incident_status.set_defaults(func=cmd_incident_set_status)

    incident_hook = sub.add_parser("incident-create-hook")
    incident_hook.add_argument("--id", required=True)
    incident_hook.add_argument("--trigger-at")
    incident_hook.set_defaults(func=cmd_incident_create_hook)

    curate = sub.add_parser("curate-incident")
    curate.add_argument("--id", required=True)
    curate.set_defaults(func=cmd_curate_incident)

    # A-bucket: model self-commitment scanning
    scan_output = sub.add_parser("scan-output")
    scan_output.add_argument("--text", required=True)
    scan_output.add_argument("--now")
    scan_output.set_defaults(func=cmd_scan_output)

    # A-bucket: recurring task commands
    recurring_check = sub.add_parser("recurring-check")
    recurring_check.add_argument("--now")
    recurring_check.set_defaults(func=cmd_recurring_check)

    recurring_complete = sub.add_parser("recurring-complete")
    recurring_complete.add_argument("--task-id", required=True)
    recurring_complete.add_argument("--now")
    recurring_complete.set_defaults(func=cmd_recurring_complete)

    sub.add_parser("recurring-list").set_defaults(func=cmd_recurring_list)

    # A-bucket: post-action rule commands
    post_action_check = sub.add_parser("post-action-check")
    post_action_check.add_argument("--file", required=True)
    post_action_check.add_argument("--trigger", required=True)
    post_action_check.add_argument("--now")
    post_action_check.set_defaults(func=cmd_post_action_check)

    sub.add_parser("post-action-list").set_defaults(func=cmd_post_action_list)

    # A-bucket: behavioral constraint commands
    constraint_check = sub.add_parser("constraint-check")
    constraint_check.add_argument("--action", required=True)
    constraint_check.add_argument("--context")
    constraint_check.add_argument("--now")
    constraint_check.set_defaults(func=cmd_constraint_check)

    sub.add_parser("constraint-list").set_defaults(func=cmd_constraint_list)

    return parser


def main():
    parser = build_parser()
    args = parser.parse_args()
    ensure_store()
    args.func(args)


if __name__ == "__main__":
    try:
        main()
    except BrokenPipeError:
        pass
